#[derive(Clone, Debug, PartialEq, Eq)]
pub struct MachineTacticDiagnostic {
    pub kind: MachineTacticDiagnosticKind,
    pub message: Box<str>,
    pub expected_hash: Option<Box<Hash>>,
    pub actual_hash: Option<Box<Hash>>,
    pub goal_id: Option<GoalId>,
    pub tactic_kind: Option<String>,
    pub primary_name: Option<Box<Name>>,
    pub meta_id: Option<MetaVarId>,
    pub diagnostic_payloads: Option<Box<MachineTacticDiagnosticPayloads>>,
}

impl MachineTacticDiagnostic {
    pub fn new(kind: MachineTacticDiagnosticKind, message: impl Into<String>) -> Self {
        Self {
            kind,
            message: message.into().into_boxed_str(),
            expected_hash: None,
            actual_hash: None,
            goal_id: None,
            tactic_kind: None,
            primary_name: None,
            meta_id: None,
            diagnostic_payloads: None,
        }
    }

    fn with_expected_actual_payloads(
        mut self,
        payload_kind: DiagnosticPayloadKind,
        expected_payload: &[u8],
        actual_payload: &[u8],
    ) -> Self {
        self = self.with_expected_actual_payload_kinds(
            payload_kind,
            expected_payload,
            payload_kind,
            actual_payload,
        );
        self
    }

    fn with_expected_actual_payload_kinds(
        mut self,
        expected_payload_kind: DiagnosticPayloadKind,
        expected_payload: &[u8],
        actual_payload_kind: DiagnosticPayloadKind,
        actual_payload: &[u8],
    ) -> Self {
        self.expected_hash = Some(Box::new(expected_actual_diagnostic_hash(
            &self.kind,
            DiagnosticHashSide::Expected,
            expected_payload_kind,
            expected_payload,
        )));
        self.actual_hash = Some(Box::new(expected_actual_diagnostic_hash(
            &self.kind,
            DiagnosticHashSide::Actual,
            actual_payload_kind,
            actual_payload,
        )));
        if self.unification_conflict_kind().is_none() {
            if let Some(kind) = default_unification_diagnostic_kind(&self.kind) {
                self.diagnostic_payloads_mut().unification_conflict_kind = Some(kind);
            }
        }
        self
    }

    pub fn with_unification_conflict_kind(mut self, kind: UnificationDiagnosticKind) -> Self {
        self.diagnostic_payloads_mut().unification_conflict_kind = Some(kind);
        self
    }

    pub fn with_rewrite_diagnostic(mut self, diagnostic: RewriteDiagnostic) -> Self {
        self.diagnostic_payloads_mut().rewrite_diagnostic = Some(diagnostic);
        self
    }

    pub fn with_universe_diagnostic(mut self, diagnostic: UniverseDiagnostic) -> Self {
        self.diagnostic_payloads_mut().universe_diagnostic = Some(diagnostic);
        self
    }

    pub fn unification_conflict_kind(&self) -> Option<UnificationDiagnosticKind> {
        self.diagnostic_payloads
            .as_ref()
            .and_then(|payloads| payloads.unification_conflict_kind)
    }

    pub fn rewrite_diagnostic(&self) -> Option<&RewriteDiagnostic> {
        self.diagnostic_payloads
            .as_ref()
            .and_then(|payloads| payloads.rewrite_diagnostic.as_ref())
    }

    pub fn universe_diagnostic(&self) -> Option<&UniverseDiagnostic> {
        self.diagnostic_payloads
            .as_ref()
            .and_then(|payloads| payloads.universe_diagnostic.as_ref())
    }

    fn diagnostic_payloads_mut(&mut self) -> &mut MachineTacticDiagnosticPayloads {
        self.diagnostic_payloads
            .get_or_insert_with(|| Box::new(MachineTacticDiagnosticPayloads::default()))
    }

    fn with_goal(mut self, goal_id: GoalId) -> Self {
        self.goal_id = Some(goal_id);
        self
    }

    fn with_primary_name(mut self, primary_name: Name) -> Self {
        self.primary_name = Some(Box::new(primary_name));
        self
    }

    fn with_meta(mut self, meta_id: MetaVarId) -> Self {
        self.meta_id = Some(meta_id);
        self
    }
}

