#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum MachineGeneratedNameKind {
    ConstructorArgument,
    BranchHypothesis,
    InductionMajor,
    InductionHypothesis,
    HoleGoal,
    HaveLocal,
    SufficesLocal,
    GeneralizedLocal,
}

impl MachineGeneratedNameKind {
    pub const fn stem(self) -> &'static str {
        match self {
            Self::ConstructorArgument => "ctor",
            Self::BranchHypothesis => "branch",
            Self::InductionMajor => "n",
            Self::InductionHypothesis => "ih",
            Self::HoleGoal => "hole",
            Self::HaveLocal => "have",
            Self::SufficesLocal => "suffices",
            Self::GeneralizedLocal => "gen",
        }
    }
}

pub fn deterministic_generated_local_name(
    context: &[MachineLocalDecl],
    kind: MachineGeneratedNameKind,
    hint: Option<&str>,
) -> String {
    let used = context
        .iter()
        .map(|local| local.name.as_str())
        .collect::<BTreeSet<_>>();
    if let Some(hint) = hint {
        if is_available_generated_name(&used, hint) {
            return hint.to_owned();
        }
        let prefix = sanitize_generated_name_stem(hint);
        return deterministic_generated_name_with_prefix(&used, &prefix);
    }
    deterministic_generated_name_with_prefix(&used, kind.stem())
}

fn deterministic_generated_name_with_prefix(used: &BTreeSet<&str>, prefix: &str) -> String {
    if is_available_generated_name(used, prefix) {
        return prefix.to_owned();
    }
    for index in 0.. {
        let candidate = format!("{prefix}{index}");
        if is_available_generated_name(used, &candidate) {
            return candidate;
        }
    }
    unreachable!("unbounded deterministic name search should always find a name")
}

fn is_available_generated_name(used: &BTreeSet<&str>, name: &str) -> bool {
    is_machine_identifier(name) && !is_reserved_spelling(name) && !used.contains(name)
}

fn sanitize_generated_name_stem(value: &str) -> String {
    let mut out = String::new();
    for ch in value.chars() {
        if ch.is_ascii_alphanumeric() || ch == '_' || ch == '\'' {
            out.push(ch);
        }
    }
    if out
        .chars()
        .next()
        .is_some_and(|ch| ch.is_ascii_alphabetic())
    {
        out
    } else {
        "gen".to_owned()
    }
}

