pub fn unification_conflict_set_for_profile(
    diagnostic: &MachineTacticDiagnostic,
    requested_profile: DiagnosticProfile,
    request_path: DiagnosticRequestPath,
    budget: DiagnosticBudget,
) -> Option<UnificationConflictSet> {
    let plan = plan_lazy_diagnostic_profile(requested_profile, request_path);
    if !plan.full_payloads_enabled() {
        return None;
    }
    collect_unification_conflict_set(diagnostic, budget)
}

pub fn collect_unification_conflict_set(
    diagnostic: &MachineTacticDiagnostic,
    budget: DiagnosticBudget,
) -> Option<UnificationConflictSet> {
    let kind = diagnostic
        .unification_conflict_kind()
        .or_else(|| default_unification_diagnostic_kind(&diagnostic.kind))?;
    let phase = unification_phase_from_diagnostic(diagnostic);
    let expected_hash = diagnostic.expected_hash.as_deref().copied();
    let actual_hash = diagnostic.actual_hash.as_deref().copied();
    let constraint = UnificationConstraintDiagnostic {
        id: UnificationConstraintId(0),
        kind,
        phase,
        path: default_unification_path(kind),
        expected_hash,
        actual_hash,
        child_ids: Vec::new(),
    };
    Some(reduce_unification_constraints(vec![constraint], budget))
}

pub fn reduce_unification_constraints(
    mut constraints: Vec<UnificationConstraintDiagnostic>,
    budget: DiagnosticBudget,
) -> UnificationConflictSet {
    for constraint in &mut constraints {
        constraint.child_ids.sort();
        constraint.child_ids.dedup();
    }
    constraints.sort_by(compare_unification_constraints);

    let requested_nodes = constraints.len() as u64;
    let requested_paths = constraints
        .iter()
        .filter(|constraint| !constraint.path.is_empty())
        .count() as u64;
    let requested_steps = requested_nodes;
    let graph_limit = usize::try_from(budget.max_graph_nodes).unwrap_or(usize::MAX);
    let step_limit = usize::try_from(budget.max_diagnostic_steps).unwrap_or(usize::MAX);
    let path_limit = usize::try_from(budget.max_expression_paths).unwrap_or(usize::MAX);
    let node_limit = graph_limit.min(step_limit).min(constraints.len());
    let mut retained = Vec::with_capacity(node_limit);
    let mut retained_paths = 0usize;
    for constraint in constraints {
        if retained.len() >= node_limit {
            break;
        }
        if !constraint.path.is_empty() {
            if retained_paths >= path_limit {
                continue;
            }
            retained_paths += 1;
        }
        retained.push(constraint);
    }
    constraints = retained;
    let retained_ids = constraints
        .iter()
        .map(|constraint| constraint.id)
        .collect::<BTreeSet<_>>();
    for constraint in &mut constraints {
        constraint
            .child_ids
            .retain(|child_id| retained_ids.contains(child_id));
    }

    let subset_kind = if requested_nodes > budget.max_graph_nodes
        || requested_paths > budget.max_expression_paths
        || requested_steps > budget.max_diagnostic_steps
    {
        UnificationConflictSubsetKind::Truncated
    } else if constraints.len() <= 1 {
        UnificationConflictSubsetKind::Minimal
    } else {
        UnificationConflictSubsetKind::Reduced
    };

    let budget_report = budget.report(DiagnosticBudgetUsage {
        graph_nodes: requested_nodes,
        expression_paths: requested_paths,
        rewrite_site_scans: 0,
        pretty_term_bytes: 0,
        repair_proposals: 0,
        diagnostic_steps: requested_steps,
    });

    UnificationConflictSet {
        subset_kind,
        constraints,
        budget_report,
    }
}

fn compare_unification_constraints(
    lhs: &UnificationConstraintDiagnostic,
    rhs: &UnificationConstraintDiagnostic,
) -> Ordering {
    lhs.id
        .cmp(&rhs.id)
        .then_with(|| lhs.path.cmp(&rhs.path))
        .then_with(|| lhs.kind.cmp(&rhs.kind))
        .then_with(|| lhs.phase.cmp(&rhs.phase))
}

fn default_unification_diagnostic_kind(
    kind: &MachineTacticDiagnosticKind,
) -> Option<UnificationDiagnosticKind> {
    match kind {
        MachineTacticDiagnosticKind::UnknownMeta
        | MachineTacticDiagnosticKind::UnresolvedGoal
        | MachineTacticDiagnosticKind::MissingExplicitArgument
        | MachineTacticDiagnosticKind::TooFewApplyArguments => {
            Some(UnificationDiagnosticKind::UnresolvedMetavariable)
        }
        MachineTacticDiagnosticKind::InvalidMetaDependency => {
            Some(UnificationDiagnosticKind::LocalScopeEscape)
        }
        MachineTacticDiagnosticKind::UniverseArgumentMismatch => {
            Some(UnificationDiagnosticKind::UniverseMismatch)
        }
        MachineTacticDiagnosticKind::ExpectedFunctionType
        | MachineTacticDiagnosticKind::ExpectedPiTarget
        | MachineTacticDiagnosticKind::TooManyApplyArguments
        | MachineTacticDiagnosticKind::SubgoalDataArgument => {
            Some(UnificationDiagnosticKind::BinderArityMismatch)
        }
        MachineTacticDiagnosticKind::TypeMismatch
        | MachineTacticDiagnosticKind::ProofExprTypeMismatch => {
            Some(UnificationDiagnosticKind::RigidRigidMismatch)
        }
        MachineTacticDiagnosticKind::TacticFuelExhausted {
            kind: TacticFuelKind::Whnf | TacticFuelKind::Conversion,
        } => Some(UnificationDiagnosticKind::BlockedReduction),
        _ => None,
    }
}

fn unification_phase_from_diagnostic(
    diagnostic: &MachineTacticDiagnostic,
) -> UnificationDiagnosticPhase {
    match diagnostic.tactic_kind.as_deref() {
        Some("apply") | Some("specialize") => UnificationDiagnosticPhase::TacticApply,
        Some("exact") => UnificationDiagnosticPhase::TacticExact,
        Some("refine") | Some("have") | Some("suffices") => {
            UnificationDiagnosticPhase::TacticRefineLike
        }
        Some("change") => UnificationDiagnosticPhase::TacticChange,
        _ if matches!(
            diagnostic.kind,
            MachineTacticDiagnosticKind::KernelRejected
                | MachineTacticDiagnosticKind::ProofExprScopeError
                | MachineTacticDiagnosticKind::ProofExprTypeMismatch
        ) =>
        {
            UnificationDiagnosticPhase::KernelCheck
        }
        _ => UnificationDiagnosticPhase::MachineTermElaboration,
    }
}

fn default_unification_path(kind: UnificationDiagnosticKind) -> Vec<String> {
    match kind {
        UnificationDiagnosticKind::BinderArityMismatch => vec!["AppFunction".to_owned()],
        UnificationDiagnosticKind::UniverseMismatch => vec!["AppFunction".to_owned()],
        UnificationDiagnosticKind::RigidRigidMismatch => vec!["AppArgument(0)".to_owned()],
        UnificationDiagnosticKind::UnresolvedMetavariable
        | UnificationDiagnosticKind::OccursCheckFailure
        | UnificationDiagnosticKind::LocalScopeEscape
        | UnificationDiagnosticKind::BlockedReduction => Vec::new(),
    }
}

pub fn rewrite_diagnostic_for_profile(
    diagnostic: &MachineTacticDiagnostic,
    requested_profile: DiagnosticProfile,
    request_path: DiagnosticRequestPath,
    budget: DiagnosticBudget,
) -> Option<RewriteDiagnostic> {
    let plan = plan_lazy_diagnostic_profile(requested_profile, request_path);
    if !plan.full_payloads_enabled() {
        return None;
    }
    collect_rewrite_diagnostic(diagnostic, budget)
}

pub fn collect_rewrite_diagnostic(
    diagnostic: &MachineTacticDiagnostic,
    budget: DiagnosticBudget,
) -> Option<RewriteDiagnostic> {
    if let Some(payload) = diagnostic.rewrite_diagnostic() {
        return Some(reduce_rewrite_diagnostic(payload.clone(), budget));
    }

    let kind = default_rewrite_diagnostic_kind(diagnostic)?;
    let expected_hash = diagnostic.expected_hash.as_deref().copied();
    let actual_hash = diagnostic.actual_hash.as_deref().copied();
    let repair_operators = default_rewrite_repair_operators(kind);
    let site = RewriteDiagnosticSite {
        id: RewriteDiagnosticId(0),
        kind,
        target_kind: RewriteDiagnosticTargetKind::Goal,
        local_name: None,
        path: default_rewrite_path(kind),
        direction: RewriteDirection::Forward,
        matched_side: RewriteSite::EqTargetLeft,
        replacement_side: RewriteSite::EqTargetRight,
        occurrence_index: Some(0),
        required_unfoldings: Vec::new(),
        congruence_depth: 0,
        expected_hash,
        actual_hash,
        repair_operators,
    };
    let matches_goal = matches!(
        kind,
        RewriteDiagnosticKind::AmbiguousOccurrence | RewriteDiagnosticKind::BudgetRejected
    );
    let diagnostic = RewriteDiagnostic {
        subset_kind: UnificationConflictSubsetKind::Minimal,
        sites: vec![site],
        forward_valid: kind != RewriteDiagnosticKind::InvalidRule,
        backward_valid: kind != RewriteDiagnosticKind::InvalidRule,
        forward_matches_goal: matches_goal,
        backward_matches_goal: matches_goal,
        forward_matches_hypothesis: false,
        backward_matches_hypothesis: false,
        rejected_by_budget_or_progress: kind == RewriteDiagnosticKind::BudgetRejected,
        complete_scan: false,
        no_progress_reason: default_rewrite_no_progress_reason(&diagnostic.kind, kind),
        budget_report: budget.report(DiagnosticBudgetUsage::default()),
    };
    Some(reduce_rewrite_diagnostic(diagnostic, budget))
}

pub fn reduce_rewrite_diagnostic(
    mut diagnostic: RewriteDiagnostic,
    budget: DiagnosticBudget,
) -> RewriteDiagnostic {
    for site in &mut diagnostic.sites {
        site.required_unfoldings.sort();
        site.required_unfoldings.dedup();
        site.repair_operators.sort();
        site.repair_operators.dedup();
    }
    diagnostic.sites.sort_by(compare_rewrite_sites);

    let requested_nodes = diagnostic.sites.len() as u64;
    let requested_paths = diagnostic
        .sites
        .iter()
        .filter(|site| !site.path.is_empty())
        .count() as u64;
    let requested_scans = requested_nodes;
    let requested_repairs = diagnostic
        .sites
        .iter()
        .map(|site| site.repair_operators.len() as u64)
        .sum::<u64>();
    let requested_steps = requested_nodes;
    let graph_limit = usize::try_from(budget.max_graph_nodes).unwrap_or(usize::MAX);
    let step_limit = usize::try_from(budget.max_diagnostic_steps).unwrap_or(usize::MAX);
    let path_limit = usize::try_from(budget.max_expression_paths).unwrap_or(usize::MAX);
    let scan_limit = usize::try_from(budget.max_rewrite_site_scans).unwrap_or(usize::MAX);
    let node_limit = graph_limit
        .min(step_limit)
        .min(scan_limit)
        .min(diagnostic.sites.len());
    let mut retained = Vec::with_capacity(node_limit);
    let mut retained_paths = 0usize;
    for site in diagnostic.sites {
        if retained.len() >= node_limit {
            break;
        }
        if !site.path.is_empty() {
            if retained_paths >= path_limit {
                continue;
            }
            retained_paths += 1;
        }
        retained.push(site);
    }
    let repair_limit = usize::try_from(budget.max_repair_proposals).unwrap_or(usize::MAX);
    let mut retained_repairs = 0usize;
    for site in &mut retained {
        let remaining = repair_limit.saturating_sub(retained_repairs);
        if site.repair_operators.len() > remaining {
            site.repair_operators.truncate(remaining);
        }
        retained_repairs += site.repair_operators.len();
    }

    let truncated = requested_nodes > budget.max_graph_nodes
        || requested_paths > budget.max_expression_paths
        || requested_scans > budget.max_rewrite_site_scans
        || requested_repairs > budget.max_repair_proposals
        || requested_steps > budget.max_diagnostic_steps;
    let subset_kind = if truncated {
        UnificationConflictSubsetKind::Truncated
    } else if retained.len() <= 1 {
        UnificationConflictSubsetKind::Minimal
    } else {
        UnificationConflictSubsetKind::Reduced
    };
    let budget_report = budget.report(DiagnosticBudgetUsage {
        graph_nodes: requested_nodes,
        expression_paths: requested_paths,
        rewrite_site_scans: requested_scans,
        pretty_term_bytes: 0,
        repair_proposals: requested_repairs,
        diagnostic_steps: requested_steps,
    });
    diagnostic.sites = retained;
    diagnostic.subset_kind = subset_kind;
    diagnostic.budget_report = budget_report;
    if diagnostic.budget_report.truncated() {
        diagnostic.complete_scan = false;
    }
    diagnostic
}

fn compare_rewrite_sites(lhs: &RewriteDiagnosticSite, rhs: &RewriteDiagnosticSite) -> Ordering {
    lhs.id
        .cmp(&rhs.id)
        .then_with(|| lhs.path.cmp(&rhs.path))
        .then_with(|| lhs.kind.cmp(&rhs.kind))
        .then_with(|| lhs.target_kind.cmp(&rhs.target_kind))
        .then_with(|| lhs.direction.cmp(&rhs.direction))
}

fn default_rewrite_diagnostic_kind(
    diagnostic: &MachineTacticDiagnostic,
) -> Option<RewriteDiagnosticKind> {
    let rewrite_family = matches!(
        diagnostic.tactic_kind.as_deref(),
        Some("rw") | Some("simp-lite")
    );
    match &diagnostic.kind {
        MachineTacticDiagnosticKind::UnknownSimpRule
        | MachineTacticDiagnosticKind::AmbiguousSimpRule
        | MachineTacticDiagnosticKind::InvalidSimpRule
        | MachineTacticDiagnosticKind::ExpectedEqTarget
        | MachineTacticDiagnosticKind::TooManyApplyArguments => {
            Some(RewriteDiagnosticKind::InvalidRule)
        }
        MachineTacticDiagnosticKind::AmbiguousRewriteRule => Some(RewriteDiagnosticKind::NoMatch),
        MachineTacticDiagnosticKind::SimpNoProgress => Some(RewriteDiagnosticKind::NoProgress),
        MachineTacticDiagnosticKind::SimpStepLimitExceeded => {
            Some(RewriteDiagnosticKind::BudgetRejected)
        }
        MachineTacticDiagnosticKind::TacticFuelExhausted {
            kind: TacticFuelKind::Rewrite | TacticFuelKind::TacticStep,
        } if rewrite_family => Some(RewriteDiagnosticKind::BudgetRejected),
        MachineTacticDiagnosticKind::TypeMismatch if rewrite_family => {
            Some(RewriteDiagnosticKind::NoMatch)
        }
        _ => None,
    }
}

fn default_rewrite_no_progress_reason(
    diagnostic_kind: &MachineTacticDiagnosticKind,
    rewrite_kind: RewriteDiagnosticKind,
) -> Option<RewriteNoProgressReason> {
    match rewrite_kind {
        RewriteDiagnosticKind::InvalidRule => Some(RewriteNoProgressReason::RuleInvalid),
        RewriteDiagnosticKind::NoMatch => Some(RewriteNoProgressReason::NoRuleMatched),
        RewriteDiagnosticKind::AmbiguousOccurrence => {
            Some(RewriteNoProgressReason::AmbiguousOccurrence)
        }
        RewriteDiagnosticKind::NoProgress => Some(RewriteNoProgressReason::EqReflFailed),
        RewriteDiagnosticKind::BudgetRejected => match diagnostic_kind {
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::Rewrite,
            } => Some(RewriteNoProgressReason::RewriteFuelExceeded),
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::TacticStep,
            } => Some(RewriteNoProgressReason::TacticFuelExceeded),
            _ => Some(RewriteNoProgressReason::ProgressRejected),
        },
    }
}

fn default_rewrite_path(kind: RewriteDiagnosticKind) -> Vec<String> {
    match kind {
        RewriteDiagnosticKind::InvalidRule => Vec::new(),
        RewriteDiagnosticKind::NoMatch
        | RewriteDiagnosticKind::AmbiguousOccurrence
        | RewriteDiagnosticKind::NoProgress
        | RewriteDiagnosticKind::BudgetRejected => vec!["RewriteOccurrence(0)".to_owned()],
    }
}

fn default_rewrite_repair_operators(kind: RewriteDiagnosticKind) -> Vec<RewriteRepairOperator> {
    match kind {
        RewriteDiagnosticKind::InvalidRule => Vec::new(),
        RewriteDiagnosticKind::NoMatch => vec![
            RewriteRepairOperator::SelectRewriteOccurrence,
            RewriteRepairOperator::Unfold,
        ],
        RewriteDiagnosticKind::AmbiguousOccurrence => {
            vec![RewriteRepairOperator::SelectRewriteOccurrence]
        }
        RewriteDiagnosticKind::NoProgress => vec![
            RewriteRepairOperator::ReduceSimpSet,
            RewriteRepairOperator::Unfold,
        ],
        RewriteDiagnosticKind::BudgetRejected => vec![RewriteRepairOperator::ReduceSimpSet],
    }
}

pub fn universe_diagnostic_for_profile(
    diagnostic: &MachineTacticDiagnostic,
    requested_profile: DiagnosticProfile,
    request_path: DiagnosticRequestPath,
    budget: DiagnosticBudget,
) -> Option<UniverseDiagnostic> {
    let plan = plan_lazy_diagnostic_profile(requested_profile, request_path);
    if !plan.full_payloads_enabled() {
        return None;
    }
    collect_universe_diagnostic(diagnostic, budget)
}

pub fn collect_universe_diagnostic(
    diagnostic: &MachineTacticDiagnostic,
    budget: DiagnosticBudget,
) -> Option<UniverseDiagnostic> {
    if let Some(payload) = diagnostic.universe_diagnostic() {
        return Some(reduce_universe_diagnostic(payload.clone(), budget));
    }
    default_universe_diagnostic(diagnostic)
        .map(|diagnostic| reduce_universe_diagnostic(diagnostic, budget))
}

pub fn reduce_universe_diagnostic(
    mut diagnostic: UniverseDiagnostic,
    budget: DiagnosticBudget,
) -> UniverseDiagnostic {
    for constraint in &mut diagnostic.constraints {
        constraint.universe_params.sort();
        constraint.universe_params.dedup();
        constraint.universe_metas.sort();
        constraint.universe_metas.dedup();
        constraint.dependency_ids.sort();
        constraint.dependency_ids.dedup();
    }
    diagnostic.constraints.sort_by(compare_universe_constraints);
    diagnostic.unresolved_metas.sort();
    diagnostic.unresolved_metas.dedup();
    diagnostic
        .candidate_instantiations
        .sort_by(compare_universe_instantiation_candidates);
    diagnostic.candidate_instantiations.dedup();
    diagnostic.repair_operators.sort();
    diagnostic.repair_operators.dedup();

    let requested_nodes = diagnostic.constraints.len() as u64;
    let requested_paths = diagnostic
        .constraints
        .iter()
        .filter(|constraint| !constraint.path.is_empty())
        .count() as u64
        + diagnostic
            .candidate_instantiations
            .iter()
            .filter(|candidate| !candidate.source_path.is_empty())
            .count() as u64;
    let requested_repairs =
        diagnostic.candidate_instantiations.len() as u64 + diagnostic.repair_operators.len() as u64;
    let requested_steps = requested_nodes
        + diagnostic.unresolved_metas.len() as u64
        + diagnostic.candidate_instantiations.len() as u64
        + diagnostic.repair_operators.len() as u64;

    let graph_limit = usize::try_from(budget.max_graph_nodes).unwrap_or(usize::MAX);
    let step_limit = usize::try_from(budget.max_diagnostic_steps).unwrap_or(usize::MAX);
    let path_limit = usize::try_from(budget.max_expression_paths).unwrap_or(usize::MAX);
    let node_limit = graph_limit
        .min(step_limit)
        .min(diagnostic.constraints.len());
    let mut retained = Vec::with_capacity(node_limit);
    let mut retained_paths = 0usize;
    for constraint in diagnostic.constraints {
        if retained.len() >= node_limit {
            break;
        }
        if !constraint.path.is_empty() {
            if retained_paths >= path_limit {
                continue;
            }
            retained_paths += 1;
        }
        retained.push(constraint);
    }
    for candidate in &mut diagnostic.candidate_instantiations {
        if candidate.source_path.is_empty() {
            continue;
        }
        if retained_paths >= path_limit {
            candidate.source_path.clear();
        } else {
            retained_paths += 1;
        }
    }
    let retained_ids = retained
        .iter()
        .map(|constraint| constraint.id)
        .collect::<BTreeSet<_>>();
    for constraint in &mut retained {
        constraint
            .dependency_ids
            .retain(|dependency_id| retained_ids.contains(dependency_id));
    }

    let repair_limit = usize::try_from(budget.max_repair_proposals).unwrap_or(usize::MAX);
    if diagnostic.candidate_instantiations.len() > repair_limit {
        diagnostic.candidate_instantiations.truncate(repair_limit);
    }
    let remaining_repairs = repair_limit.saturating_sub(diagnostic.candidate_instantiations.len());
    if diagnostic.repair_operators.len() > remaining_repairs {
        diagnostic.repair_operators.truncate(remaining_repairs);
    }

    let budget_report = budget.report(DiagnosticBudgetUsage {
        graph_nodes: requested_nodes,
        expression_paths: requested_paths,
        rewrite_site_scans: 0,
        pretty_term_bytes: 0,
        repair_proposals: requested_repairs,
        diagnostic_steps: requested_steps,
    });
    let truncated = budget_report.truncated();
    diagnostic.constraints = retained;
    diagnostic.subset_kind = if truncated {
        UnificationConflictSubsetKind::Truncated
    } else if diagnostic.constraints.len() <= 1
        && diagnostic.unresolved_metas.len() <= 1
        && diagnostic.candidate_instantiations.len() <= 1
    {
        UnificationConflictSubsetKind::Minimal
    } else {
        UnificationConflictSubsetKind::Reduced
    };
    if truncated {
        diagnostic.core_kind = UniverseDiagnosticCoreKind::Truncated;
        diagnostic.complete_graph = false;
    }
    diagnostic.budget_report = budget_report;
    diagnostic
}

pub fn universe_diagnostic_identity_hash(diagnostic: &UniverseDiagnostic) -> Hash {
    let mut out = tagged_bytes("npa.machine-tactic.universe-diagnostic.identity.v1");
    encode_unification_subset_kind_to(&mut out, diagnostic.subset_kind);
    encode_universe_core_kind_to(&mut out, diagnostic.core_kind);
    encode_list_len_to(&mut out, diagnostic.constraints.len());
    for constraint in &diagnostic.constraints {
        encode_u64_to(&mut out, constraint.id.0);
        encode_universe_diagnostic_kind_to(&mut out, constraint.kind);
        encode_universe_relation_to(&mut out, constraint.relation);
        encode_level_to(&mut out, &constraint.lhs);
        encode_level_to(&mut out, &constraint.rhs);
        encode_string_list_to(&mut out, &constraint.path);
        encode_string_list_to(&mut out, &constraint.universe_params);
        encode_string_list_to(&mut out, &constraint.universe_metas);
        encode_list_len_to(&mut out, constraint.dependency_ids.len());
        for dependency_id in &constraint.dependency_ids {
            encode_u64_to(&mut out, dependency_id.0);
        }
    }
    encode_string_list_to(&mut out, &diagnostic.unresolved_metas);
    encode_list_len_to(&mut out, diagnostic.candidate_instantiations.len());
    for candidate in &diagnostic.candidate_instantiations {
        encode_string_to(&mut out, &candidate.param);
        encode_level_to(&mut out, &candidate.level);
        encode_string_list_to(&mut out, &candidate.source_path);
        out.push(u8::from(candidate.valid));
        match candidate.rejection_kind {
            Some(kind) => {
                out.push(1);
                encode_universe_diagnostic_kind_to(&mut out, kind);
            }
            None => out.push(0),
        }
    }
    encode_list_len_to(&mut out, diagnostic.repair_operators.len());
    for operator in &diagnostic.repair_operators {
        encode_universe_repair_operator_to(&mut out, *operator);
    }
    out.push(u8::from(diagnostic.complete_graph));
    hash_with_domain(
        "npa.machine-tactic.universe-diagnostic.identity.hash.v1",
        &out,
    )
}

pub fn universe_level_diagnostic_wire(level: &Level) -> String {
    match normalize_level(level.clone()) {
        Level::Zero => "zero".to_owned(),
        Level::Succ(inner) => format!("succ({})", universe_level_diagnostic_wire(&inner)),
        Level::Max(lhs, rhs) => format!(
            "max({},{})",
            universe_level_diagnostic_wire(&lhs),
            universe_level_diagnostic_wire(&rhs)
        ),
        Level::IMax(lhs, rhs) => format!(
            "imax({},{})",
            universe_level_diagnostic_wire(&lhs),
            universe_level_diagnostic_wire(&rhs)
        ),
        Level::Param(name) => format!("param({name})"),
    }
}

fn compare_universe_constraints(
    lhs: &UniverseConstraintDiagnostic,
    rhs: &UniverseConstraintDiagnostic,
) -> Ordering {
    lhs.id
        .cmp(&rhs.id)
        .then_with(|| lhs.path.cmp(&rhs.path))
        .then_with(|| lhs.kind.cmp(&rhs.kind))
        .then_with(|| lhs.relation.cmp(&rhs.relation))
        .then_with(|| {
            level_diagnostic_order_key(&lhs.lhs).cmp(&level_diagnostic_order_key(&rhs.lhs))
        })
        .then_with(|| {
            level_diagnostic_order_key(&lhs.rhs).cmp(&level_diagnostic_order_key(&rhs.rhs))
        })
}

fn compare_universe_instantiation_candidates(
    lhs: &UniverseInstantiationCandidate,
    rhs: &UniverseInstantiationCandidate,
) -> Ordering {
    lhs.param
        .cmp(&rhs.param)
        .then_with(|| lhs.source_path.cmp(&rhs.source_path))
        .then_with(|| {
            level_diagnostic_order_key(&lhs.level).cmp(&level_diagnostic_order_key(&rhs.level))
        })
        .then_with(|| lhs.valid.cmp(&rhs.valid))
        .then_with(|| lhs.rejection_kind.cmp(&rhs.rejection_kind))
}

fn level_diagnostic_order_key(level: &Level) -> Vec<u8> {
    let mut out = Vec::new();
    encode_level_to(&mut out, level);
    out
}

fn default_universe_diagnostic(diagnostic: &MachineTacticDiagnostic) -> Option<UniverseDiagnostic> {
    match diagnostic.kind {
        MachineTacticDiagnosticKind::UniverseArgumentMismatch => Some(UniverseDiagnostic {
            subset_kind: UnificationConflictSubsetKind::Minimal,
            core_kind: UniverseDiagnosticCoreKind::Reduced,
            constraints: vec![UniverseConstraintDiagnostic {
                id: UniverseDiagnosticId(0),
                kind: UniverseDiagnosticKind::UniverseMismatch,
                relation: UniverseConstraintRelation::Eq,
                lhs: Level::param("expected_universe_argument"),
                rhs: Level::param("actual_universe_argument"),
                path: vec!["AppFunction".to_owned(), "UniverseArg(0)".to_owned()],
                universe_params: Vec::new(),
                universe_metas: Vec::new(),
                dependency_ids: Vec::new(),
            }],
            unresolved_metas: Vec::new(),
            candidate_instantiations: Vec::new(),
            repair_operators: vec![UniverseRepairOperator::InstantiateUniverse],
            complete_graph: false,
            budget_report: DiagnosticBudget::default().report(DiagnosticBudgetUsage::default()),
        }),
        _ => None,
    }
}

fn universe_argument_diagnostic_payload(
    expected_params: &[String],
    actual_levels: &[Level],
) -> UniverseDiagnostic {
    let mut constraints = Vec::new();
    let max_len = expected_params.len().max(actual_levels.len()).max(1);
    for index in 0..max_len {
        let lhs = expected_params
            .get(index)
            .map(|param| Level::param(param.clone()))
            .unwrap_or_else(|| Level::param(format!("unexpected_universe_arg_{index}")));
        let rhs = actual_levels
            .get(index)
            .cloned()
            .unwrap_or_else(|| Level::param(format!("missing_universe_arg_{index}")));
        let mut universe_params = BTreeSet::new();
        if let Some(param) = expected_params.get(index) {
            universe_params.insert(param.clone());
        }
        collect_level_universe_params(&lhs, &mut universe_params);
        collect_level_universe_params(&rhs, &mut universe_params);
        let mut universe_metas = BTreeSet::new();
        collect_level_universe_metas(&lhs, &mut universe_metas);
        collect_level_universe_metas(&rhs, &mut universe_metas);
        constraints.push(UniverseConstraintDiagnostic {
            id: UniverseDiagnosticId(index as u64),
            kind: UniverseDiagnosticKind::UniverseMismatch,
            relation: UniverseConstraintRelation::Eq,
            lhs,
            rhs,
            path: vec!["AppFunction".to_owned(), format!("UniverseArg({index})")],
            universe_params: universe_params.into_iter().collect(),
            universe_metas: universe_metas.into_iter().collect(),
            dependency_ids: Vec::new(),
        });
    }

    let mut unresolved_metas = BTreeSet::new();
    for level in actual_levels {
        collect_level_universe_metas(level, &mut unresolved_metas);
    }
    let candidate_instantiations = expected_params
        .iter()
        .enumerate()
        .filter_map(|(index, param)| {
            actual_levels.get(index).map(|level| {
                let unresolved = level_contains_unresolved_universe_meta(level);
                UniverseInstantiationCandidate {
                    param: param.clone(),
                    level: level.clone(),
                    source_path: vec!["AppFunction".to_owned(), format!("UniverseArg({index})")],
                    valid: expected_params.len() == actual_levels.len() && !unresolved,
                    rejection_kind: if expected_params.len() != actual_levels.len() {
                        Some(UniverseDiagnosticKind::InvalidInstantiation)
                    } else if unresolved {
                        Some(UniverseDiagnosticKind::UnresolvedUniverseMeta)
                    } else {
                        None
                    },
                }
            })
        })
        .collect();

    UniverseDiagnostic {
        subset_kind: if constraints.len() <= 1 {
            UnificationConflictSubsetKind::Minimal
        } else {
            UnificationConflictSubsetKind::Reduced
        },
        core_kind: UniverseDiagnosticCoreKind::Reduced,
        constraints,
        unresolved_metas: unresolved_metas.into_iter().collect(),
        candidate_instantiations,
        repair_operators: vec![UniverseRepairOperator::InstantiateUniverse],
        complete_graph: true,
        budget_report: DiagnosticBudget::default().report(DiagnosticBudgetUsage::default()),
    }
}

fn unresolved_universe_meta_diagnostic(metas: Vec<String>) -> UniverseDiagnostic {
    UniverseDiagnostic {
        subset_kind: if metas.len() <= 1 {
            UnificationConflictSubsetKind::Minimal
        } else {
            UnificationConflictSubsetKind::Reduced
        },
        core_kind: UniverseDiagnosticCoreKind::Reduced,
        constraints: Vec::new(),
        unresolved_metas: metas,
        candidate_instantiations: Vec::new(),
        repair_operators: vec![UniverseRepairOperator::InstantiateUniverse],
        complete_graph: true,
        budget_report: DiagnosticBudget::default().report(DiagnosticBudgetUsage::default()),
    }
}

fn universe_constraint_diagnostic(
    kind: UniverseDiagnosticKind,
    constraint: UniverseConstraint,
    core_kind: UniverseDiagnosticCoreKind,
) -> UniverseDiagnostic {
    let mut universe_params = BTreeSet::new();
    let mut universe_metas = BTreeSet::new();
    collect_level_universe_params(&constraint.lhs, &mut universe_params);
    collect_level_universe_params(&constraint.rhs, &mut universe_params);
    collect_level_universe_metas(&constraint.lhs, &mut universe_metas);
    collect_level_universe_metas(&constraint.rhs, &mut universe_metas);
    UniverseDiagnostic {
        subset_kind: UnificationConflictSubsetKind::Minimal,
        core_kind,
        constraints: vec![UniverseConstraintDiagnostic {
            id: UniverseDiagnosticId(0),
            kind,
            relation: constraint.relation,
            lhs: constraint.lhs,
            rhs: constraint.rhs,
            path: vec!["UniverseConstraint(0)".to_owned()],
            universe_params: universe_params.into_iter().collect(),
            universe_metas: universe_metas.into_iter().collect(),
            dependency_ids: Vec::new(),
        }],
        unresolved_metas: Vec::new(),
        candidate_instantiations: Vec::new(),
        repair_operators: vec![UniverseRepairOperator::InstantiateUniverse],
        complete_graph: true,
        budget_report: DiagnosticBudget::default().report(DiagnosticBudgetUsage::default()),
    }
}

fn collect_level_universe_params(level: &Level, params: &mut BTreeSet<String>) {
    match level {
        Level::Zero => {}
        Level::Succ(inner) => collect_level_universe_params(inner, params),
        Level::Max(lhs, rhs) | Level::IMax(lhs, rhs) => {
            collect_level_universe_params(lhs, params);
            collect_level_universe_params(rhs, params);
        }
        Level::Param(name) if !name.starts_with('?') => {
            params.insert(name.clone());
        }
        Level::Param(_) => {}
    }
}

fn collect_level_universe_metas(level: &Level, metas: &mut BTreeSet<String>) {
    match level {
        Level::Zero => {}
        Level::Succ(inner) => collect_level_universe_metas(inner, metas),
        Level::Max(lhs, rhs) | Level::IMax(lhs, rhs) => {
            collect_level_universe_metas(lhs, metas);
            collect_level_universe_metas(rhs, metas);
        }
        Level::Param(name) if name.starts_with('?') => {
            metas.insert(name.clone());
        }
        Level::Param(_) => {}
    }
}

