#[derive(Clone, Debug, PartialEq, Eq)]
pub struct DiagnosticLocalSummary {
    pub stable_id: u32,
    pub binder_index: u32,
    pub machine_name: String,
    pub display_name: Option<String>,
    pub type_hash: Hash,
    pub value_hash: Option<Hash>,
    pub dependency_ids: Vec<u32>,
    pub dependencies_truncated: bool,
    pub type_summary: DiagnosticTermSummary,
    pub value_summary: Option<DiagnosticTermSummary>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct DiagnosticLocalContextSummary {
    pub locals: Vec<DiagnosticLocalSummary>,
    pub total_locals: u64,
    pub truncated: bool,
}

impl DiagnosticLocalContextSummary {
    pub fn canonical_identity_bytes(&self) -> Vec<u8> {
        let mut out = tagged_bytes("npa.machine-tactic.diagnostic-local-context-summary.v1");
        encode_u64_to(&mut out, self.total_locals);
        out.push(u8::from(self.truncated));
        encode_list_len_to(&mut out, self.locals.len());
        for local in &self.locals {
            encode_u64_to(&mut out, u64::from(local.stable_id));
            encode_u64_to(&mut out, u64::from(local.binder_index));
            encode_string_to(&mut out, &local.machine_name);
            encode_hash_to(&mut out, &local.type_hash);
            encode_option_hash_to(&mut out, local.value_hash.as_ref());
            encode_list_len_to(&mut out, local.dependency_ids.len());
            for dependency_id in &local.dependency_ids {
                encode_u64_to(&mut out, u64::from(*dependency_id));
            }
            out.push(u8::from(local.dependencies_truncated));
            encode_diagnostic_term_summary_to(&mut out, &local.type_summary);
            match &local.value_summary {
                Some(summary) => {
                    out.push(1);
                    encode_diagnostic_term_summary_to(&mut out, summary);
                }
                None => out.push(0),
            }
        }
        out
    }

    pub fn identity_hash(&self) -> Hash {
        hash_with_domain(
            "npa.machine-tactic.diagnostic-local-context-summary.hash.v1",
            &self.canonical_identity_bytes(),
        )
    }
}

pub fn diagnostic_term_summary(
    expr: &Expr,
    budget: DiagnosticSummaryBudget,
) -> DiagnosticTermSummary {
    let (node_count, node_truncated) = count_expr_nodes_bounded(expr, budget.max_term_nodes);
    let universe_summary = diagnostic_universe_summary(expr, budget.max_universe_params);
    let universe_truncated = universe_summary.truncated;
    DiagnosticTermSummary {
        core_hash: core_expr_hash(expr),
        head_symbol: diagnostic_head_symbol(expr),
        binder_arity: diagnostic_binder_arity(expr),
        universe_summary,
        node_count,
        truncated: node_truncated || universe_truncated,
    }
}

pub fn diagnostic_local_context_summary(
    context: &[MachineLocalDecl],
    budget: DiagnosticSummaryBudget,
) -> DiagnosticLocalContextSummary {
    diagnostic_local_context_summary_with_display_names(context, &[], budget)
}

pub fn diagnostic_local_context_summary_with_display_names(
    context: &[MachineLocalDecl],
    display_names: &[Option<String>],
    budget: DiagnosticSummaryBudget,
) -> DiagnosticLocalContextSummary {
    let local_limit = budget.max_context_locals.min(context.len());
    let mut locals = Vec::with_capacity(local_limit);
    let mut truncated = context.len() > budget.max_context_locals;

    for (index, local) in context.iter().take(local_limit).enumerate() {
        let mut dependency_ids = collect_local_dependency_ids(local, index);
        let dependencies_truncated = dependency_ids.len() > budget.max_dependencies_per_local;
        if dependencies_truncated {
            dependency_ids.truncate(budget.max_dependencies_per_local);
        }

        let type_summary = diagnostic_term_summary(&local.ty, budget);
        let value_summary = local
            .value
            .as_ref()
            .map(|value| diagnostic_term_summary(value, budget));
        truncated = truncated
            || dependencies_truncated
            || type_summary.truncated
            || value_summary
                .as_ref()
                .is_some_and(|summary| summary.truncated);

        let stable_id = saturating_u32_from_usize(index);
        locals.push(DiagnosticLocalSummary {
            stable_id,
            binder_index: stable_id,
            machine_name: local.name.clone(),
            display_name: display_names.get(index).cloned().flatten(),
            type_hash: core_expr_hash(&local.ty),
            value_hash: local.value.as_ref().map(core_expr_hash),
            dependency_ids,
            dependencies_truncated,
            type_summary,
            value_summary,
        });
    }

    DiagnosticLocalContextSummary {
        locals,
        total_locals: context.len() as u64,
        truncated,
    }
}

