pub fn machine_tactic_goal_id(tactic: &MachineTactic) -> GoalId {
    match tactic {
        MachineTactic::Exact { goal_id, .. }
        | MachineTactic::Intro { goal_id, .. }
        | MachineTactic::Apply { goal_id, .. }
        | MachineTactic::Rewrite { goal_id, .. }
        | MachineTactic::SimpLite { goal_id, .. }
        | MachineTactic::Smt { goal_id, .. }
        | MachineTactic::InductionNat { goal_id, .. }
        | MachineTactic::Constructor { goal_id, .. }
        | MachineTactic::Cases { goal_id, .. }
        | MachineTactic::GeneralInduction { goal_id, .. }
        | MachineTactic::Refine { goal_id, .. }
        | MachineTactic::Have { goal_id, .. }
        | MachineTactic::Suffices { goal_id, .. }
        | MachineTactic::Specialize { goal_id, .. }
        | MachineTactic::Revert { goal_id, .. }
        | MachineTactic::Generalize { goal_id, .. }
        | MachineTactic::Change { goal_id, .. }
        | MachineTactic::Unfold { goal_id, .. }
        | MachineTactic::Congr { goal_id, .. }
        | MachineTactic::Subst { goal_id, .. }
        | MachineTactic::Contradiction { goal_id, .. }
        | MachineTactic::FiniteDecide { goal_id }
        | MachineTactic::Omega { goal_id }
        | MachineTactic::Ring { goal_id }
        | MachineTactic::Bitblast { goal_id } => *goal_id,
    }
}

pub fn machine_tactic_kind(tactic: &MachineTactic) -> Option<&'static str> {
    match tactic {
        MachineTactic::Exact { .. } => Some("exact"),
        MachineTactic::Intro { .. } => Some("intro"),
        MachineTactic::Apply { .. } => Some("apply"),
        MachineTactic::Rewrite { .. } => Some("rw"),
        MachineTactic::SimpLite { .. } => Some("simp-lite"),
        MachineTactic::Smt { .. } => Some("smt"),
        MachineTactic::InductionNat { .. } => Some("induction-nat"),
        MachineTactic::Constructor { .. } => Some("constructor"),
        MachineTactic::Cases { .. } => Some("cases"),
        MachineTactic::GeneralInduction { .. } => Some("general-induction"),
        MachineTactic::Refine { .. } => Some("refine"),
        MachineTactic::Have { .. } => Some("have"),
        MachineTactic::Suffices { .. } => Some("suffices"),
        MachineTactic::Specialize { .. } => Some("specialize"),
        MachineTactic::Revert { .. } => Some("revert"),
        MachineTactic::Generalize { .. } => Some("generalize"),
        MachineTactic::Change { .. } => Some("change"),
        MachineTactic::Unfold { .. } => Some("unfold"),
        MachineTactic::Congr { .. } => Some("congr"),
        MachineTactic::Subst { .. } => Some("subst"),
        MachineTactic::Contradiction { .. } => Some("contradiction"),
        MachineTactic::FiniteDecide { .. } => Some("finite-decide"),
        MachineTactic::Omega { .. } => Some("omega"),
        MachineTactic::Ring { .. } => Some("ring"),
        MachineTactic::Bitblast { .. } => Some("bitblast"),
    }
}

pub fn machine_tactic_candidate_kind(candidate: &MachineTacticCandidate) -> &'static str {
    match candidate {
        MachineTacticCandidate::Exact { .. } => "exact",
        MachineTacticCandidate::Intro { .. } => "intro",
        MachineTacticCandidate::Apply { .. } => "apply",
        MachineTacticCandidate::Rewrite { .. } => "rw",
        MachineTacticCandidate::SimpLite { .. } => "simp-lite",
        MachineTacticCandidate::Smt { .. } => "smt",
        MachineTacticCandidate::InductionNat { .. } => "induction-nat",
        MachineTacticCandidate::Constructor(_) => "constructor",
        MachineTacticCandidate::Cases(_) => "cases",
        MachineTacticCandidate::GeneralInduction(_) => "general-induction",
        MachineTacticCandidate::Refine(_) => "refine",
        MachineTacticCandidate::Have(_) => "have",
        MachineTacticCandidate::Suffices(_) => "suffices",
        MachineTacticCandidate::Specialize(_) => "specialize",
        MachineTacticCandidate::Revert(_) => "revert",
        MachineTacticCandidate::Generalize(_) => "generalize",
        MachineTacticCandidate::Change(_) => "change",
        MachineTacticCandidate::Unfold(_) => "unfold",
        MachineTacticCandidate::Congr(_) => "congr",
        MachineTacticCandidate::Subst(_) => "subst",
        MachineTacticCandidate::Contradiction(_) => "contradiction",
        MachineTacticCandidate::FiniteDecide => "finite-decide",
        MachineTacticCandidate::Omega => "omega",
        MachineTacticCandidate::Ring => "ring",
        MachineTacticCandidate::Bitblast => "bitblast",
    }
}

pub fn validate_machine_tactic_candidate(
    goal_id: GoalId,
    candidate: MachineTacticCandidate,
) -> Result<MachineTactic> {
    let tactic_kind = machine_tactic_candidate_kind(&candidate);
    let result = (|| -> Result<MachineTactic> {
        match candidate {
            MachineTacticCandidate::Exact { term } => Ok(MachineTactic::Exact {
                goal_id,
                term: MachineTermSource::new_checked(term.source)?,
            }),
            MachineTacticCandidate::Intro { name } => {
                validate_intro_name_shape(&name)?;
                Ok(MachineTactic::Intro { goal_id, name })
            }
            MachineTacticCandidate::Apply {
                head,
                universe_args,
                args,
            } => {
                validate_tactic_head_shape(&head)?;
                let args = args
                    .into_iter()
                    .map(validate_candidate_apply_arg)
                    .collect::<Result<Vec<_>>>()?;
                Ok(MachineTactic::Apply {
                    goal_id,
                    head,
                    universe_args,
                    args,
                })
            }
            MachineTacticCandidate::Rewrite {
                rule,
                direction,
                site,
            } => Ok(MachineTactic::Rewrite {
                goal_id,
                rule: validate_candidate_rewrite_rule(rule)?,
                direction,
                site,
            }),
            MachineTacticCandidate::SimpLite { rules } => {
                validate_simp_rule_refs(&rules)?;
                Ok(MachineTactic::SimpLite { goal_id, rules })
            }
            MachineTacticCandidate::Smt { lemmas } => {
                validate_smt_lemma_refs(&lemmas)?;
                Ok(MachineTactic::Smt { goal_id, lemmas })
            }
            MachineTacticCandidate::InductionNat { local_name } => {
                validate_intro_name_shape(&local_name)?;
                Ok(MachineTactic::InductionNat {
                    goal_id,
                    local_name,
                })
            }
            MachineTacticCandidate::Constructor(payload) => {
                validate_constructor_payload(&payload)?;
                Ok(MachineTactic::Constructor { goal_id, payload })
            }
            MachineTacticCandidate::Cases(payload) => Ok(MachineTactic::Cases {
                goal_id,
                payload: validate_cases_payload(payload)?,
            }),
            MachineTacticCandidate::GeneralInduction(payload) => {
                Ok(MachineTactic::GeneralInduction {
                    goal_id,
                    payload: validate_general_induction_payload(payload)?,
                })
            }
            MachineTacticCandidate::Refine(payload) => Ok(MachineTactic::Refine {
                goal_id,
                payload: RefinePayload {
                    term: validate_raw_refine_term(payload.term)?,
                    max_holes: payload.max_holes,
                },
            }),
            MachineTacticCandidate::Have(payload) => Ok(MachineTactic::Have {
                goal_id,
                payload: validate_have_payload(payload)?,
            }),
            MachineTacticCandidate::Suffices(payload) => Ok(MachineTactic::Suffices {
                goal_id,
                payload: validate_suffices_payload(payload)?,
            }),
            MachineTacticCandidate::Specialize(payload) => Ok(MachineTactic::Specialize {
                goal_id,
                payload: validate_specialize_payload(payload)?,
            }),
            MachineTacticCandidate::Revert(payload) => {
                validate_revert_payload(&payload)?;
                Ok(MachineTactic::Revert { goal_id, payload })
            }
            MachineTacticCandidate::Generalize(payload) => Ok(MachineTactic::Generalize {
                goal_id,
                payload: validate_generalize_payload(payload)?,
            }),
            MachineTacticCandidate::Change(payload) => Ok(MachineTactic::Change {
                goal_id,
                payload: validate_change_payload(payload)?,
            }),
            MachineTacticCandidate::Unfold(payload) => {
                validate_tactic_target(&payload.target)?;
                validate_tactic_head_shape(&payload.constant)?;
                Ok(MachineTactic::Unfold { goal_id, payload })
            }
            MachineTacticCandidate::Congr(payload) => {
                validate_tactic_target(&payload.target)?;
                Ok(MachineTactic::Congr { goal_id, payload })
            }
            MachineTacticCandidate::Subst(payload) => {
                validate_intro_name_shape(&payload.equality_local)?;
                validate_tactic_target(&payload.target)?;
                Ok(MachineTactic::Subst { goal_id, payload })
            }
            MachineTacticCandidate::Contradiction(payload) => {
                validate_contradiction_payload(&payload)?;
                Ok(MachineTactic::Contradiction { goal_id, payload })
            }
            MachineTacticCandidate::FiniteDecide => Ok(MachineTactic::FiniteDecide { goal_id }),
            MachineTacticCandidate::Omega => Ok(MachineTactic::Omega { goal_id }),
            MachineTacticCandidate::Ring => Ok(MachineTactic::Ring { goal_id }),
            MachineTacticCandidate::Bitblast => Ok(MachineTactic::Bitblast { goal_id }),
        }
    })();
    result.map_err(|diag| attach_tactic_context(diag, goal_id, Some(tactic_kind)))
}

pub fn validate_machine_tactic_candidate_for_state(
    state: &MachineProofState,
    goal_id: GoalId,
    candidate: MachineTacticCandidate,
    deterministic_budget: TacticBudget,
    profile_version: MachineTacticProfileVersion,
    required_features: &[MachineTacticFeature],
) -> Result<MachineTacticValidation> {
    let tactic = validate_machine_tactic_candidate(goal_id, candidate)?;
    let validation_budget = MachineTacticValidationBudget::from(deterministic_budget);
    validate_machine_tactic_for_state(
        state,
        &tactic,
        validation_budget,
        profile_version,
        required_features,
    )?;
    Ok(MachineTacticValidation {
        tactic,
        validation_budget,
        profile_version,
    })
}

pub fn validate_machine_tactic_for_state(
    state: &MachineProofState,
    tactic: &MachineTactic,
    validation_budget: MachineTacticValidationBudget,
    profile_version: MachineTacticProfileVersion,
    required_features: &[MachineTacticFeature],
) -> Result<()> {
    let goal_id = machine_tactic_goal_id(tactic);
    let tactic_kind = machine_tactic_kind(tactic);
    let result = (|| -> Result<()> {
        validate_machine_proof_state(state)?;
        let goal = state.goal(goal_id)?;
        validate_machine_tactic_profile_and_features(
            tactic,
            profile_version,
            required_features,
            &goal,
        )?;
        validate_machine_tactic_payload_budget(state, &goal, tactic, validation_budget)?;
        validate_machine_tactic_state_refs(state, &goal, tactic)?;
        Ok(())
    })();
    result.map_err(|diag| attach_tactic_context(diag, goal_id, tactic_kind))
}

fn validate_machine_tactic_profile_and_features(
    tactic: &MachineTactic,
    profile_version: MachineTacticProfileVersion,
    required_features: &[MachineTacticFeature],
    goal: &MachineGoal,
) -> Result<()> {
    let Some(tactic_kind) = machine_tactic_kind(tactic) else {
        return Ok(());
    };
    if is_pua_m04_tactic(tactic) && profile_version == MachineTacticProfileVersion::V1 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedMachineTactic,
            format!(
                "machine tactic {tactic_kind:?} requires profile {}",
                MachineTacticProfileVersion::PuaM04V2.as_str()
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    if let Some(feature) = machine_tactic_required_feature(tactic) {
        if !required_features.contains(&feature) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnsupportedMachineTactic,
                format!(
                    "machine tactic {tactic_kind:?} requires feature {}",
                    feature.as_str()
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
    }
    Ok(())
}

fn is_pua_m04_tactic(tactic: &MachineTactic) -> bool {
    !matches!(
        tactic,
        MachineTactic::Exact { .. }
            | MachineTactic::Intro { .. }
            | MachineTactic::Apply { .. }
            | MachineTactic::Rewrite { .. }
            | MachineTactic::SimpLite { .. }
            | MachineTactic::Smt { .. }
            | MachineTactic::InductionNat { .. }
    )
}

fn machine_tactic_required_feature(tactic: &MachineTactic) -> Option<MachineTacticFeature> {
    match tactic {
        MachineTactic::Exact { .. }
        | MachineTactic::Intro { .. }
        | MachineTactic::Apply { .. }
        | MachineTactic::Rewrite { .. }
        | MachineTactic::SimpLite { .. }
        | MachineTactic::Smt { .. }
        | MachineTactic::InductionNat { .. } => None,
        MachineTactic::Constructor { .. }
        | MachineTactic::Cases { .. }
        | MachineTactic::GeneralInduction { .. }
        | MachineTactic::Refine { .. }
        | MachineTactic::Have { .. }
        | MachineTactic::Suffices { .. }
        | MachineTactic::Specialize { .. }
        | MachineTactic::Revert { .. }
        | MachineTactic::Generalize { .. }
        | MachineTactic::Change { .. }
        | MachineTactic::Unfold { .. }
        | MachineTactic::Congr { .. }
        | MachineTactic::Subst { .. }
        | MachineTactic::Contradiction { .. } => {
            Some(MachineTacticFeature::PuaM04StructuralTactics)
        }
        MachineTactic::FiniteDecide { .. } => Some(MachineTacticFeature::FiniteDecide),
        MachineTactic::Omega { .. } => Some(MachineTacticFeature::Omega),
        MachineTactic::Ring { .. } => Some(MachineTacticFeature::Ring),
        MachineTactic::Bitblast { .. } => Some(MachineTacticFeature::Bitblast),
    }
}

fn validate_machine_tactic_payload_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    tactic: &MachineTactic,
    budget: MachineTacticValidationBudget,
) -> Result<()> {
    ensure_payload_byte_budget(
        "candidate canonical payload",
        machine_tactic_canonical_bytes(tactic).len() as u64,
        budget.max_certificate_bytes,
        goal,
    )?;
    ensure_payload_byte_budget(
        "machine term source payload",
        machine_tactic_term_source_bytes(tactic),
        budget.max_term_nodes,
        goal,
    )?;
    ensure_generated_goal_budget(
        state,
        goal,
        machine_tactic_declared_new_goal_bound(tactic),
        budget.max_new_goals,
    )?;
    ensure_meta_allocation_budget(
        state,
        goal,
        machine_tactic_declared_meta_bound(tactic),
        budget.max_meta_allocations,
    )?;
    ensure_count_budget(
        "rewrite site",
        machine_tactic_declared_rewrite_site_bound(tactic),
        budget.max_rewrite_sites,
        TacticFuelKind::Rewrite,
        goal,
    )?;
    ensure_count_budget(
        "simp step",
        machine_tactic_declared_simp_step_bound(tactic),
        budget.max_simp_steps,
        TacticFuelKind::Rewrite,
        goal,
    )?;
    ensure_count_budget(
        "solver step",
        machine_tactic_declared_solver_step_bound(tactic),
        budget.max_solver_steps,
        TacticFuelKind::TacticStep,
        goal,
    )?;
    Ok(())
}

fn ensure_payload_byte_budget(
    label: &'static str,
    requested: u64,
    allowed: u64,
    goal: &MachineGoal,
) -> Result<()> {
    if requested > allowed {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::ExprNode,
            },
            format!("{label} size {requested} exceeds deterministic payload budget {allowed}"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn ensure_generated_goal_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    requested: u64,
    allowed: u64,
) -> Result<()> {
    ensure_count_budget(
        "new goal",
        requested,
        allowed,
        TacticFuelKind::MetaAllocation,
        goal,
    )?;
    let requested = usize::try_from(requested).map_err(|_| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::GoalLimitExceeded,
            "new goal count does not fit the platform usize",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
    })?;
    let resulting_open_goals = state.open_goals.len() - 1 + requested;
    if resulting_open_goals > state.env.options.max_open_goals {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::GoalLimitExceeded,
            format!(
                "candidate may leave {resulting_open_goals} open goals, limit is {}",
                state.env.options.max_open_goals
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn ensure_meta_allocation_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    requested: u64,
    allowed: u64,
) -> Result<()> {
    ensure_count_budget(
        "meta allocation",
        requested,
        allowed,
        TacticFuelKind::MetaAllocation,
        goal,
    )?;
    let requested = usize::try_from(requested).map_err(|_| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::MetaLimitExceeded,
            "meta allocation count does not fit the platform usize",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
    })?;
    if state.metas.len() + requested > state.env.options.max_metas {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::MetaLimitExceeded,
            format!(
                "candidate may create {} metas total, limit is {}",
                state.metas.len() + requested,
                state.env.options.max_metas
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn ensure_count_budget(
    label: &'static str,
    requested: u64,
    allowed: u64,
    fuel_kind: TacticFuelKind,
    goal: &MachineGoal,
) -> Result<()> {
    if requested > allowed {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted { kind: fuel_kind },
            format!("{label} request {requested} exceeds deterministic budget {allowed}"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn machine_tactic_term_source_bytes(tactic: &MachineTactic) -> u64 {
    match tactic {
        MachineTactic::Exact { term, .. } => term_source_bytes(term),
        MachineTactic::Intro { .. }
        | MachineTactic::SimpLite { .. }
        | MachineTactic::Smt { .. }
        | MachineTactic::InductionNat { .. }
        | MachineTactic::Constructor { .. }
        | MachineTactic::Revert { .. }
        | MachineTactic::Unfold { .. }
        | MachineTactic::Congr { .. }
        | MachineTactic::Subst { .. }
        | MachineTactic::Contradiction { .. }
        | MachineTactic::FiniteDecide { .. }
        | MachineTactic::Omega { .. }
        | MachineTactic::Ring { .. }
        | MachineTactic::Bitblast { .. } => 0,
        MachineTactic::Apply { args, .. } => apply_arg_term_source_bytes(args),
        MachineTactic::Rewrite { rule, .. } => apply_arg_term_source_bytes(&rule.args),
        MachineTactic::Cases { payload, .. } => payload
            .motive
            .as_ref()
            .map(term_source_bytes)
            .unwrap_or_default(),
        MachineTactic::GeneralInduction { payload, .. } => payload
            .motive
            .as_ref()
            .map(term_source_bytes)
            .unwrap_or_default(),
        MachineTactic::Refine { payload, .. } => refine_term_source_bytes(&payload.term),
        MachineTactic::Have { payload, .. } => term_source_bytes(&payload.ty)
            .saturating_add(local_lemma_proof_term_source_bytes(&payload.proof)),
        MachineTactic::Suffices { payload, .. } => term_source_bytes(&payload.target)
            .saturating_add(local_lemma_proof_term_source_bytes(&payload.proof)),
        MachineTactic::Specialize { payload, .. } => apply_arg_term_source_bytes(&payload.args),
        MachineTactic::Generalize { payload, .. } => term_source_bytes(&payload.term),
        MachineTactic::Change { payload, .. } => term_source_bytes(&payload.replacement),
    }
}

fn term_source_bytes(term: &MachineTermSource) -> u64 {
    term.source().len() as u64
}

fn refine_term_source_bytes(term: &RefineTermSource) -> u64 {
    term.source().len() as u64
}

fn local_lemma_proof_term_source_bytes(proof: &LocalLemmaProof<MachineTermSource>) -> u64 {
    match proof {
        LocalLemmaProof::ChildGoal => 0,
        LocalLemmaProof::Term(term) => term_source_bytes(term),
    }
}

fn apply_arg_term_source_bytes(args: &[ApplyArg]) -> u64 {
    args.iter()
        .map(|arg| match arg {
            ApplyArg::Term(term) => term_source_bytes(term),
            ApplyArg::Subgoal { .. } | ApplyArg::InferFromTarget => 0,
        })
        .fold(0_u64, u64::saturating_add)
}

fn machine_tactic_declared_new_goal_bound(tactic: &MachineTactic) -> u64 {
    match tactic {
        MachineTactic::Exact { .. }
        | MachineTactic::Smt { .. }
        | MachineTactic::Constructor {
            payload:
                ConstructorPayload {
                    max_new_goals: None,
                    ..
                },
            ..
        }
        | MachineTactic::Contradiction { .. }
        | MachineTactic::FiniteDecide { .. }
        | MachineTactic::Omega { .. }
        | MachineTactic::Ring { .. }
        | MachineTactic::Bitblast { .. } => 0,
        MachineTactic::Intro { .. } => 1,
        MachineTactic::Apply { args, .. } => apply_arg_subgoal_count(args),
        MachineTactic::Rewrite { rule, .. } => 1 + apply_arg_subgoal_count(&rule.args),
        MachineTactic::SimpLite { .. } => 1,
        MachineTactic::InductionNat { .. } => 2,
        MachineTactic::Constructor {
            payload:
                ConstructorPayload {
                    max_new_goals: Some(max_new_goals),
                    ..
                },
            ..
        } => *max_new_goals,
        MachineTactic::Cases { payload, .. } => payload
            .max_new_goals
            .unwrap_or(payload.branch_names.len() as u64),
        MachineTactic::GeneralInduction { payload, .. } => payload.max_new_goals,
        MachineTactic::Refine { payload, .. } => payload.max_holes.unwrap_or_default(),
        MachineTactic::Have { payload, .. } => match &payload.proof {
            LocalLemmaProof::ChildGoal => 2,
            LocalLemmaProof::Term(_) => 1,
        },
        MachineTactic::Suffices { payload, .. } => match &payload.proof {
            LocalLemmaProof::ChildGoal => 2,
            LocalLemmaProof::Term(_) => 1,
        },
        MachineTactic::Specialize { payload, .. } => match payload.result_policy {
            SpecializeResultPolicy::AddLocal => 1,
            SpecializeResultPolicy::ReplaceOriginal => 0,
        },
        MachineTactic::Revert { payload, .. } => {
            if payload.locals.is_empty() {
                0
            } else {
                1
            }
        }
        MachineTactic::Generalize { .. }
        | MachineTactic::Change { .. }
        | MachineTactic::Unfold { .. }
        | MachineTactic::Subst { .. } => 1,
        MachineTactic::Congr { payload, .. } => payload.max_new_goals.unwrap_or_default(),
    }
}

fn machine_tactic_declared_meta_bound(tactic: &MachineTactic) -> u64 {
    match tactic {
        MachineTactic::Refine { payload, .. } => payload.max_holes.unwrap_or_default(),
        _ => machine_tactic_declared_new_goal_bound(tactic),
    }
}

fn machine_tactic_declared_rewrite_site_bound(tactic: &MachineTactic) -> u64 {
    match tactic {
        MachineTactic::Rewrite { .. } => 1,
        MachineTactic::Generalize { payload, .. } => occurrence_path_count(&payload.occurrences),
        MachineTactic::Change { payload, .. } => occurrence_path_count(&payload.occurrences),
        MachineTactic::Unfold { payload, .. } => payload
            .max_delta_steps
            .unwrap_or_else(|| occurrence_path_count(&payload.occurrences)),
        MachineTactic::Subst { payload, .. } => occurrence_path_count(&payload.occurrences),
        _ => 0,
    }
}

fn machine_tactic_declared_simp_step_bound(tactic: &MachineTactic) -> u64 {
    match tactic {
        MachineTactic::SimpLite { rules, .. } if !rules.is_empty() => rules.len() as u64,
        _ => 0,
    }
}

fn machine_tactic_declared_solver_step_bound(tactic: &MachineTactic) -> u64 {
    match tactic {
        MachineTactic::FiniteDecide { .. }
        | MachineTactic::Omega { .. }
        | MachineTactic::Ring { .. }
        | MachineTactic::Bitblast { .. } => 1,
        _ => 0,
    }
}

fn apply_arg_subgoal_count(args: &[ApplyArg]) -> u64 {
    args.iter()
        .filter(|arg| matches!(arg, ApplyArg::Subgoal { .. }))
        .count() as u64
}

fn validate_machine_tactic_state_refs(
    state: &MachineProofState,
    goal: &MachineGoal,
    tactic: &MachineTactic,
) -> Result<()> {
    match tactic {
        MachineTactic::Exact { term, .. } => validate_machine_term_source(term),
        MachineTactic::Intro { name, .. } => {
            validate_intro_name_available(state, &goal.context, name)
                .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))
        }
        MachineTactic::Apply {
            head,
            universe_args,
            args,
            ..
        } => {
            validate_universe_args_wf("apply", &state.root.universe_params, universe_args, goal)?;
            validate_apply_head_static(state, goal, head, universe_args)?;
            validate_apply_args_for_state(args, goal)
        }
        MachineTactic::Rewrite { rule, .. } => {
            validate_universe_args_wf(
                "rw",
                &state.root.universe_params,
                &rule.universe_args,
                goal,
            )?;
            validate_apply_head_static(state, goal, &rule.head, &rule.universe_args)?;
            validate_apply_args_for_state(&rule.args, goal)
        }
        MachineTactic::SimpLite { rules, .. } => {
            resolve_simp_lite_allowlist(state, goal, rules.clone()).map(|_| ())
        }
        MachineTactic::Smt { lemmas, .. } => {
            for lemma in lemmas {
                validate_universe_args_wf(
                    "smt lemma",
                    &state.root.universe_params,
                    &lemma.universe_args,
                    goal,
                )?;
                validate_apply_head_static(state, goal, &lemma.head, &lemma.universe_args)?;
            }
            Ok(())
        }
        MachineTactic::InductionNat { local_name, .. } => {
            resolve_induction_nat_target(goal, local_name)?;
            let family = state.env.nat_family.as_ref().ok_or_else(|| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
                    "induction-nat requires a resolved Nat family",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id)
            })?;
            ensure_resolved_nat_family_heads(state, goal, family)
        }
        MachineTactic::Constructor { payload, .. } => {
            if let ConstructorSelection::Explicit { constructor } = &payload.selection {
                resolve_explicit_constructor_candidate(state, goal, constructor)?;
            }
            Ok(())
        }
        MachineTactic::Cases { payload, .. } => {
            resolve_goal_local_reference(goal, &payload.major_local, "cases major local")?;
            if let Some(motive) = &payload.motive {
                validate_machine_term_source(motive)?;
            }
            Ok(())
        }
        MachineTactic::GeneralInduction { payload, .. } => {
            resolve_goal_local_reference(
                goal,
                &payload.major_local,
                "general-induction major local",
            )?;
            validate_general_induction_recursor_head_reference(state, goal, &payload.recursor)?;
            if let Some(motive) = &payload.motive {
                validate_machine_term_source(motive)?;
            }
            for local in &payload.generalized_locals {
                resolve_goal_local_reference(goal, local, "general-induction generalized local")?;
            }
            Ok(())
        }
        MachineTactic::Refine { payload, .. } => validate_refine_term_source(&payload.term),
        MachineTactic::Have { payload, .. } => {
            validate_local_lemma_name_available(state, goal, &payload.name)?;
            validate_machine_term_source(&payload.ty)?;
            validate_local_lemma_proof_for_state(&payload.proof)
        }
        MachineTactic::Suffices { payload, .. } => {
            validate_machine_term_source(&payload.target)?;
            validate_local_lemma_proof_for_state(&payload.proof)
        }
        MachineTactic::Specialize { payload, .. } => {
            resolve_goal_local_reference(goal, &payload.local_name, "specialize local")?;
            validate_universe_args_wf(
                "specialize",
                &state.root.universe_params,
                &payload.universe_args,
                goal,
            )?;
            validate_apply_args_for_state(&payload.args, goal)?;
            if payload.result_policy == SpecializeResultPolicy::AddLocal {
                if let Some(result_name) = &payload.result_name {
                    validate_intro_name_available(state, &goal.context, result_name)
                        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
                }
            }
            Ok(())
        }
        MachineTactic::Revert { payload, .. } => {
            for local in &payload.locals {
                resolve_goal_local_reference(goal, local, "revert local")?;
            }
            Ok(())
        }
        MachineTactic::Generalize { payload, .. } => {
            validate_tactic_target_for_state(goal, &payload.target)?;
            validate_machine_term_source(&payload.term)
        }
        MachineTactic::Change { payload, .. } => {
            validate_tactic_target_for_state(goal, &payload.target)?;
            validate_machine_term_source(&payload.replacement)
        }
        MachineTactic::Unfold { payload, .. } => {
            validate_tactic_target_for_state(goal, &payload.target)?;
            validate_tactic_head_reference(state, goal, &payload.constant)
        }
        MachineTactic::Congr { payload, .. } => {
            validate_tactic_target_for_state(goal, &payload.target)
        }
        MachineTactic::Subst { payload, .. } => {
            resolve_goal_local_reference(goal, &payload.equality_local, "subst equality local")?;
            validate_tactic_target_for_state(goal, &payload.target)
        }
        MachineTactic::Contradiction { payload, .. } => {
            if let ContradictionMode::Local { major_local } = &payload.mode {
                resolve_goal_local_reference(goal, major_local, "contradiction local")?;
            }
            Ok(())
        }
        MachineTactic::FiniteDecide { .. }
        | MachineTactic::Omega { .. }
        | MachineTactic::Ring { .. }
        | MachineTactic::Bitblast { .. } => Ok(()),
    }
}

fn validate_universe_args_wf(
    label: &'static str,
    universe_params: &[String],
    universe_args: &[Level],
    goal: &MachineGoal,
) -> Result<()> {
    for level in universe_args {
        ensure_level_wf(universe_params, level).map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("{label} universe argument is not well formed: {err:?}"),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
    }
    Ok(())
}

fn validate_apply_args_for_state(args: &[ApplyArg], goal: &MachineGoal) -> Result<()> {
    for arg in args {
        validate_apply_arg(arg).map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    }
    Ok(())
}

fn validate_local_lemma_proof_for_state(proof: &LocalLemmaProof<MachineTermSource>) -> Result<()> {
    match proof {
        LocalLemmaProof::ChildGoal => Ok(()),
        LocalLemmaProof::Term(term) => validate_machine_term_source(term),
    }
}

fn validate_tactic_target_for_state(goal: &MachineGoal, target: &TacticTarget) -> Result<()> {
    match target {
        TacticTarget::Goal => Ok(()),
        TacticTarget::Local { name } => {
            resolve_goal_local_reference(goal, name, "tactic target local").map(|_| ())
        }
    }
}

fn validate_tactic_head_reference(
    state: &MachineProofState,
    goal: &MachineGoal,
    head: &TacticHead,
) -> Result<()> {
    validate_tactic_head_shape(head)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    match head {
        TacticHead::Local { name } => {
            resolve_goal_local_reference(goal, name, "local tactic head").map(|_| ())
        }
        TacticHead::Imported {
            name,
            decl_interface_hash,
        } => {
            resolve_imported_tactic_head_reference(state, goal, name, decl_interface_hash)?;
            Ok(())
        }
        TacticHead::CurrentModule {
            name,
            decl_interface_hash,
        } => {
            resolve_current_tactic_head_reference(state, goal, name, decl_interface_hash)?;
            Ok(())
        }
    }
}

fn validate_general_induction_recursor_head_reference(
    state: &MachineProofState,
    goal: &MachineGoal,
    head: &TacticHead,
) -> Result<()> {
    validate_tactic_head_shape(head)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    match head {
        TacticHead::Local { name } => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            format!(
                "general-induction recursor {name:?} is a local term; only certificate-derived recursor references are allowed"
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
        TacticHead::Imported {
            name,
            decl_interface_hash,
        } => {
            resolve_imported_tactic_head_reference(state, goal, name, decl_interface_hash)?;
            Ok(())
        }
        TacticHead::CurrentModule {
            name,
            decl_interface_hash,
        } => {
            if resolve_current_tactic_head_reference(state, goal, name, decl_interface_hash).is_ok()
            {
                return Ok(());
            }
            let generated_by_current_inductive = state.env.checked_current_decls.iter().any(|decl| {
                decl.signature().decl_interface_hash() == *decl_interface_hash
                    && matches!(
                        decl.core_decl(),
                        Decl::Inductive { data, .. }
                            if data
                                .recursor
                                .as_ref()
                                .is_some_and(|recursor| recursor.name == name.as_dotted())
                    )
            });
            if generated_by_current_inductive {
                Ok(())
            } else {
                Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnknownTacticHead,
                    format!(
                        "current-module general-induction recursor {} with the requested interface hash is unknown",
                        name.as_dotted()
                    ),
                )
                .with_primary_name(name.clone())
                .with_goal(goal.id)
                .with_meta(goal.meta_id))
            }
        }
    }
}

fn resolve_goal_local_reference<'a>(
    goal: &'a MachineGoal,
    name: &str,
    label: &'static str,
) -> Result<&'a MachineLocalDecl> {
    let matches = goal
        .context
        .iter()
        .filter(|local| local.name == name)
        .collect::<Vec<_>>();
    let [local] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownLocalName,
                format!("{label} {name:?} is not in the goal context"),
            )
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousLocalName,
                format!("{label} {name:?} resolves to multiple locals"),
            )
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    Ok(local)
}

fn resolve_imported_tactic_head_reference<'a>(
    state: &'a MachineProofState,
    goal: &MachineGoal,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<&'a VerifiedExportSignature> {
    let matches = state
        .env
        .imports
        .iter()
        .flat_map(|import| import.exports.iter())
        .filter(|export| &export.name == name && &export.decl_interface_hash == decl_interface_hash)
        .collect::<Vec<_>>();
    let [signature] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "imported tactic head {} with the requested interface hash is unknown",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousTacticHead,
                format!("imported tactic head {} is ambiguous", name.as_dotted()),
            )
            .with_primary_name(name.clone())
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    Ok(signature)
}

fn resolve_current_tactic_head_reference<'a>(
    state: &'a MachineProofState,
    goal: &MachineGoal,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<&'a CheckedDeclSignature> {
    let matches = state
        .env
        .checked_current_decls
        .iter()
        .map(|decl| decl.signature())
        .filter(|signature| {
            signature.name() == name && signature.decl_interface_hash() == *decl_interface_hash
        })
        .collect::<Vec<_>>();
    let [signature] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "current-module tactic head {} with the requested interface hash is unknown",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousTacticHead,
                format!(
                    "current-module tactic head {} is ambiguous",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    Ok(signature)
}

fn validate_raw_machine_term(term: RawMachineTerm) -> Result<MachineTermSource> {
    MachineTermSource::new_checked(term.source)
}

fn validate_raw_refine_term(term: RawMachineTerm) -> Result<RefineTermSource> {
    RefineTermSource::new_checked(term.source)
}

fn validate_optional_raw_machine_term(
    term: Option<RawMachineTerm>,
) -> Result<Option<MachineTermSource>> {
    term.map(validate_raw_machine_term).transpose()
}

fn validate_constructor_payload(payload: &ConstructorPayload) -> Result<()> {
    if let ConstructorSelection::Explicit { constructor } = &payload.selection {
        validate_tactic_head_shape(constructor)?;
    }
    Ok(())
}

fn validate_cases_payload(
    payload: CasesPayload<RawMachineTerm>,
) -> Result<CasesPayload<MachineTermSource>> {
    validate_intro_name_shape(&payload.major_local)?;
    validate_branch_names(&payload.branch_names)?;
    Ok(CasesPayload {
        major_local: payload.major_local,
        motive: validate_optional_raw_machine_term(payload.motive)?,
        branch_names: payload.branch_names,
        max_new_goals: payload.max_new_goals,
    })
}

fn validate_general_induction_payload(
    payload: GeneralInductionPayload<RawMachineTerm>,
) -> Result<GeneralInductionPayload<MachineTermSource>> {
    validate_intro_name_shape(&payload.major_local)?;
    validate_tactic_head_shape(&payload.recursor)?;
    validate_local_name_list("generalized locals", &payload.generalized_locals)?;
    validate_branch_names(&payload.branch_names)?;
    Ok(GeneralInductionPayload {
        major_local: payload.major_local,
        recursor: payload.recursor,
        motive: validate_optional_raw_machine_term(payload.motive)?,
        generalized_locals: payload.generalized_locals,
        branch_names: payload.branch_names,
        max_new_goals: payload.max_new_goals,
    })
}

fn validate_have_payload(
    payload: HavePayload<RawMachineTerm>,
) -> Result<HavePayload<MachineTermSource>> {
    validate_intro_name_shape(&payload.name)?;
    Ok(HavePayload {
        name: payload.name,
        ty: validate_raw_machine_term(payload.ty)?,
        proof: validate_local_lemma_proof(payload.proof)?,
        insertion: payload.insertion,
    })
}

fn validate_suffices_payload(
    payload: SufficesPayload<RawMachineTerm>,
) -> Result<SufficesPayload<MachineTermSource>> {
    Ok(SufficesPayload {
        target: validate_raw_machine_term(payload.target)?,
        proof: validate_local_lemma_proof(payload.proof)?,
        continuation: payload.continuation,
    })
}

fn validate_local_lemma_proof(
    proof: LocalLemmaProof<RawMachineTerm>,
) -> Result<LocalLemmaProof<MachineTermSource>> {
    match proof {
        LocalLemmaProof::ChildGoal => Ok(LocalLemmaProof::ChildGoal),
        LocalLemmaProof::Term(term) => validate_raw_machine_term(term).map(LocalLemmaProof::Term),
    }
}

fn validate_specialize_payload(
    payload: SpecializePayload<CandidateApplyArg>,
) -> Result<SpecializePayload<ApplyArg>> {
    validate_intro_name_shape(&payload.local_name)?;
    if let Some(result_name) = &payload.result_name {
        validate_intro_name_shape(result_name)?;
    }
    let args = payload
        .args
        .into_iter()
        .map(validate_candidate_apply_arg)
        .collect::<Result<Vec<_>>>()?;
    Ok(SpecializePayload {
        local_name: payload.local_name,
        universe_args: payload.universe_args,
        args,
        result_name: payload.result_name,
        result_policy: payload.result_policy,
    })
}

fn validate_revert_payload(payload: &RevertPayload) -> Result<()> {
    if payload.locals.is_empty() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            "revert requires at least one local",
        ));
    }
    validate_local_name_list("revert locals", &payload.locals)
}

fn validate_generalize_payload(
    payload: GeneralizePayload<RawMachineTerm>,
) -> Result<GeneralizePayload<MachineTermSource>> {
    validate_tactic_target(&payload.target)?;
    if let Some(name_hint) = &payload.name_hint {
        validate_intro_name_shape(name_hint)?;
    }
    Ok(GeneralizePayload {
        target: payload.target,
        term: validate_raw_machine_term(payload.term)?,
        occurrences: payload.occurrences,
        name_hint: payload.name_hint,
    })
}

fn validate_change_payload(
    payload: ChangePayload<RawMachineTerm>,
) -> Result<ChangePayload<MachineTermSource>> {
    validate_tactic_target(&payload.target)?;
    Ok(ChangePayload {
        target: payload.target,
        replacement: validate_raw_machine_term(payload.replacement)?,
        occurrences: payload.occurrences,
    })
}

fn validate_tactic_target(target: &TacticTarget) -> Result<()> {
    if let TacticTarget::Local { name } = target {
        validate_intro_name_shape(name)?;
    }
    Ok(())
}

fn validate_contradiction_payload(payload: &ContradictionPayload) -> Result<()> {
    if let ContradictionMode::Local { major_local } = &payload.mode {
        validate_intro_name_shape(major_local)?;
    }
    Ok(())
}

fn validate_local_name_list(label: &'static str, names: &[String]) -> Result<()> {
    let mut seen = BTreeSet::new();
    for name in names {
        validate_intro_name_shape(name)?;
        if !seen.insert(name.as_str()) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("duplicate {label} entry {name:?}"),
            ));
        }
    }
    Ok(())
}

fn validate_branch_names(names: &[String]) -> Result<()> {
    validate_local_name_list("branch name", names)
}

pub fn start_machine_proof(
    spec: MachineProofSpec,
    imports: Vec<VerifiedImportRef>,
    checked_current_decls: Vec<CheckedCurrentDecl>,
    options: MachineTacticOptions,
) -> Result<MachineProofState> {
    start_machine_proof_with_kernel_profile(
        MachineKernelProfile::BuiltinNatEqRec,
        spec,
        imports,
        checked_current_decls,
        options,
    )
}

pub fn start_machine_proof_with_kernel_profile(
    kernel_profile: MachineKernelProfile,
    spec: MachineProofSpec,
    imports: Vec<VerifiedImportRef>,
    checked_current_decls: Vec<CheckedCurrentDecl>,
    options: MachineTacticOptions,
) -> Result<MachineProofState> {
    validate_proof_spec(&spec)?;
    if checked_current_decls.len() as u64 != spec.source_index {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidCurrentDeclOrder,
            format!(
                "proof source_index {} requires exactly {} checked prior declarations",
                spec.source_index, spec.source_index
            ),
        ));
    }
    validate_checked_current_decls_for_module(
        &spec.module,
        &spec.theorem_name,
        &checked_current_decls,
    )?;

    let env = MachineTacticEnv::new_with_kernel_profile(
        kernel_profile,
        imports,
        checked_current_decls,
        options,
    )?;
    ensure_type_is_sort(
        env.kernel_env(),
        &Ctx::new(),
        &spec.universe_params,
        &spec.theorem_type,
    )
    .map_err(theorem_type_diag)?;

    let m0 = MetaVarId(0);
    let g0 = GoalId::from(m0);
    let root = ProofRoot {
        module: spec.module,
        theorem_name: spec.theorem_name,
        source_index: spec.source_index,
        universe_params: spec.universe_params,
        theorem_type: spec.theorem_type.clone(),
        body: ProofExpr::Meta(m0),
    };
    let mut metas = BTreeMap::new();
    metas.insert(
        m0,
        MachineMetaVar {
            id: m0,
            goal_id: g0,
            context: Vec::new(),
            target: spec.theorem_type,
            assignment: None,
            creation_index: 0,
        },
    );
    let mut state = MachineProofState {
        state_id: String::new(),
        root,
        open_goals: vec![g0],
        metas: MetaVarStore { metas, next_id: 1 },
        env,
        reserved_local_names: Vec::new(),
        fingerprint: ZERO_HASH,
    };
    refresh_state_identity(&mut state);
    validate_machine_proof_state(&state)?;
    Ok(state)
}

pub fn run_machine_tactic(
    state: &MachineProofState,
    tactic: MachineTactic,
) -> Result<(MachineProofState, MachineProofDelta)> {
    run_machine_tactic_with_budget(state, tactic, TacticBudget::default())
}

pub fn run_machine_tactic_with_budget(
    state: &MachineProofState,
    tactic: MachineTactic,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal_id = machine_tactic_goal_id(&tactic);
    let tactic_kind = machine_tactic_kind(&tactic);
    let result = (|| -> Result<(MachineProofState, MachineProofDelta)> {
        validate_machine_proof_state(state)?;
        match tactic {
            MachineTactic::Exact { goal_id, term } => {
                run_exact_tactic_with_budget(state, goal_id, term, budget)
            }
            MachineTactic::Intro { goal_id, name } => {
                run_intro_tactic_with_budget(state, goal_id, name, budget)
            }
            MachineTactic::Apply {
                goal_id,
                head,
                universe_args,
                args,
            } => run_apply_tactic_with_budget(state, goal_id, head, universe_args, args, budget),
            MachineTactic::Rewrite {
                goal_id,
                rule,
                direction,
                site,
            } => run_rewrite_tactic_with_budget(state, goal_id, rule, direction, site, budget),
            MachineTactic::SimpLite { goal_id, rules } => {
                run_simp_lite_tactic_with_budget(state, goal_id, rules, budget)
            }
            MachineTactic::Smt { goal_id, lemmas } => {
                run_smt_tactic_with_budget(state, goal_id, lemmas, budget)
            }
            MachineTactic::InductionNat {
                goal_id,
                local_name,
            } => run_induction_nat_tactic_with_budget(state, goal_id, local_name, budget),
            MachineTactic::Constructor { goal_id, payload } => {
                run_constructor_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Cases { goal_id, payload } => {
                run_cases_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::GeneralInduction { goal_id, payload } => {
                run_general_induction_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Refine { goal_id, payload } => {
                run_refine_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Have { goal_id, payload } => {
                run_have_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Suffices { goal_id, payload } => {
                run_suffices_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Specialize { goal_id, payload } => {
                run_specialize_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Revert { goal_id, payload } => {
                run_revert_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Generalize { goal_id, payload } => {
                run_generalize_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Change { goal_id, payload } => {
                run_change_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Unfold { goal_id, payload } => {
                run_unfold_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Congr { goal_id, payload } => {
                run_congr_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Subst { goal_id, payload } => {
                run_subst_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::Contradiction { goal_id, payload } => {
                run_contradiction_tactic_with_budget(state, goal_id, payload, budget)
            }
            MachineTactic::FiniteDecide { goal_id } => {
                run_finite_decide_tactic_with_budget(state, goal_id, budget)
            }
            MachineTactic::Omega { goal_id } => {
                run_omega_tactic_with_budget(state, goal_id, budget)
            }
            MachineTactic::Ring { goal_id } => run_ring_tactic_with_budget(state, goal_id, budget),
            MachineTactic::Bitblast { .. } => Err(unsupported_machine_tactic(
                tactic_kind.expect("extended machine tactic has a kind"),
            )),
        }
    })();
    result.map_err(|diag| attach_tactic_context(diag, goal_id, tactic_kind))
}

fn unsupported_machine_tactic(kind: &'static str) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::UnsupportedMachineTactic,
        format!("machine tactic {kind:?} is not executable in this milestone"),
    )
}

pub fn run_machine_tactic_transactional(
    state: &MachineProofState,
    tactic: MachineTactic,
    budget: TacticBudget,
) -> MachineTacticResult {
    match run_machine_tactic_with_budget(state, tactic, budget) {
        Ok((state, delta)) => MachineTacticResult::Success { state, delta },
        Err(diagnostic) => MachineTacticResult::Error { diagnostic },
    }
}

pub fn run_machine_tactic_candidates_batch(
    state: &MachineProofState,
    goal_id: GoalId,
    candidates: Vec<MachineTacticBatchCandidate>,
    budget: TacticBudget,
    policy: MachineTacticBatchPolicy,
) -> Result<MachineTacticBatchResult> {
    validate_machine_tactic_batch_request(&candidates, policy)?;
    validate_machine_proof_state(state)?;
    state.goal(goal_id)?;

    let mut results = Vec::new();
    let mut successes = 0usize;
    let mut failures = 0usize;
    let max_evaluated = policy.max_evaluated_candidates as usize;
    let stop_after_successes = policy.stop_after_successes as usize;
    let stop_after_failures = policy.stop_after_failures as usize;

    for (evaluated, item) in candidates.into_iter().enumerate() {
        if evaluated >= max_evaluated
            || successes >= stop_after_successes
            || failures >= stop_after_failures
        {
            break;
        }

        let candidate_id = item.candidate_id;
        let tactic = match validate_machine_tactic_candidate(goal_id, item.candidate) {
            Ok(tactic) => tactic,
            Err(diagnostic) => {
                failures += 1;
                results.push(MachineTacticBatchItemResult::Error {
                    candidate_id,
                    candidate_hash: None,
                    phase: MachineTacticBatchErrorPhase::CandidateValidation,
                    diagnostic,
                    retryable: false,
                });
                continue;
            }
        };
        let candidate_hash = machine_tactic_hash(&tactic);
        if let Err(diagnostic) = validate_machine_tactic_for_state(
            state,
            &tactic,
            MachineTacticValidationBudget::from(budget),
            MachineTacticProfileVersion::PuaM04V2,
            &[],
        ) {
            failures += 1;
            results.push(MachineTacticBatchItemResult::Error {
                candidate_id,
                candidate_hash: Some(candidate_hash),
                phase: MachineTacticBatchErrorPhase::CandidateValidation,
                diagnostic,
                retryable: false,
            });
            continue;
        }

        match run_machine_tactic_transactional(state, tactic, budget) {
            MachineTacticResult::Success { state, delta } => {
                successes += 1;
                results.push(MachineTacticBatchItemResult::Success {
                    candidate_id,
                    candidate_hash,
                    state,
                    delta,
                });
            }
            MachineTacticResult::Error { diagnostic } => {
                failures += 1;
                results.push(MachineTacticBatchItemResult::Error {
                    candidate_id,
                    candidate_hash: Some(candidate_hash),
                    phase: MachineTacticBatchErrorPhase::TacticExecution,
                    diagnostic,
                    retryable: false,
                });
            }
        }
    }

    Ok(MachineTacticBatchResult {
        previous_state_fingerprint: state.fingerprint,
        deterministic_budget_hash: tactic_budget_hash(budget),
        results,
    })
}

fn validate_machine_tactic_batch_request(
    candidates: &[MachineTacticBatchCandidate],
    policy: MachineTacticBatchPolicy,
) -> Result<()> {
    const MAX_BATCH_CANDIDATES: usize = 256;
    if candidates.is_empty() {
        return Err(invalid_batch_policy("batch candidates must be non-empty"));
    }
    if candidates.len() > MAX_BATCH_CANDIDATES {
        return Err(invalid_batch_policy(
            "batch candidates must not exceed 256 entries",
        ));
    }

    let mut ids = BTreeSet::new();
    for item in candidates {
        if !is_machine_candidate_id(&item.candidate_id) {
            return Err(invalid_batch_policy(format!(
                "candidate_id {:?} does not match the machine batch grammar",
                item.candidate_id
            )));
        }
        if !ids.insert(item.candidate_id.as_str()) {
            return Err(invalid_batch_policy(format!(
                "duplicate candidate_id {:?}",
                item.candidate_id
            )));
        }
    }

    validate_batch_policy_field("max_evaluated_candidates", policy.max_evaluated_candidates)?;
    validate_batch_policy_field("stop_after_successes", policy.stop_after_successes)?;
    validate_batch_policy_field("stop_after_failures", policy.stop_after_failures)?;
    Ok(())
}

fn validate_batch_policy_field(name: &str, value: u32) -> Result<()> {
    if !(1..=256).contains(&value) {
        return Err(invalid_batch_policy(format!(
            "{name} must be in the inclusive range 1..=256"
        )));
    }
    Ok(())
}

fn invalid_batch_policy(message: impl Into<String>) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::InvalidBatchPolicy, message)
}

fn run_exact_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    term: MachineTermSource,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_machine_term_source(&term)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    let context = machine_term_elab_context(state, &goal.context)?;
    let checked = npa_frontend::elaborate_machine_term_check(
        term.source(),
        &context,
        &goal.target,
        &npa_frontend::MachineCompileOptions::default(),
    )
    .map_err(machine_term_elaboration_diag)?;
    ensure_tactic_step_fuel(budget, 2, goal_id, goal.meta_id)?;
    let fuel = TacticRunFuel::new(budget);
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        ProofExpr::Core(checked.expr),
        Vec::new(),
        budget,
        0,
        &fuel,
    )
}

fn run_finite_decide_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    let family = state.env.eq_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "finite_decide proof generation requires a resolved Eq family",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id)
    })?;
    let fuel = TacticRunFuel::new(budget);
    let mut required_tactic_steps = 0;
    let proof = finite_decide_proof_for_target(
        state,
        &goal,
        &goal.context,
        &goal.target,
        family,
        budget,
        &fuel,
        &mut required_tactic_steps,
    )?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        proof,
        Vec::new(),
        budget,
        required_tactic_steps,
        &fuel,
    )
}

