#[allow(clippy::too_many_arguments)]
fn finite_decide_proof_for_target(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
    target: &Expr,
    family: &ResolvedEqFamily,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
    required_tactic_steps: &mut u64,
) -> Result<ProofExpr> {
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let target_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        target,
        fuel,
        goal.id,
        goal.meta_id,
    )?;

    if let Some(eq_target) = parse_eq_target_from_expr(family, &target_whnf) {
        *required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, *required_tactic_steps, goal.id, goal.meta_id)?;
        if kernel_is_defeq_with_budget(
            state.env.kernel_env(),
            &ctx,
            &state.root.universe_params,
            &eq_target.lhs,
            &eq_target.rhs,
            fuel,
            goal.id,
            goal.meta_id,
        )? {
            return Ok(ProofExpr::Core(mk_eq_refl_expr(
                family,
                &eq_target.levels,
                eq_target.ty,
                eq_target.lhs,
            )));
        }
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "finite_decide equality goal evaluated to false",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&eq_target.lhs),
            &core_expr_canonical_bytes(&eq_target.rhs),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }

    if let Expr::Pi { binder, ty, body } = target_whnf {
        let domain = Arc::unwrap_or_clone(ty);
        if !finite_decide_supported_carrier_domain(state, goal, context, &domain, fuel)? {
            return Err(finite_decide_unsupported_goal(goal, &domain));
        }
        *required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, *required_tactic_steps, goal.id, goal.meta_id)?;
        let mut body_context = context.to_vec();
        body_context.push(MachineLocalDecl::assumption(binder.clone(), domain.clone()));
        let body_proof = finite_decide_proof_for_target(
            state,
            goal,
            &body_context,
            &body,
            family,
            budget,
            fuel,
            required_tactic_steps,
        )?;
        return Ok(ProofExpr::lam(binder, domain, body_proof));
    }

    if let Some(proof) = finite_decide_bool_true_proof(
        state,
        goal,
        &ctx,
        &target_whnf,
        budget,
        fuel,
        required_tactic_steps,
    )? {
        return Ok(ProofExpr::Core(proof));
    }

    Err(finite_decide_unsupported_goal(goal, &target_whnf))
}

#[allow(clippy::too_many_arguments)]
fn omega_proof_for_target(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
    target: &Expr,
    family: &ResolvedEqFamily,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
    required_tactic_steps: &mut u64,
) -> Result<ProofExpr> {
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let target_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        target,
        fuel,
        goal.id,
        goal.meta_id,
    )?;

    let Some(eq_target) = parse_eq_target_from_expr(family, &target_whnf) else {
        return Err(omega_unsupported_goal(goal, &target_whnf));
    };
    *required_tactic_steps += 1;
    ensure_tactic_step_fuel(budget, *required_tactic_steps, goal.id, goal.meta_id)?;
    if kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &eq_target.lhs,
        &eq_target.rhs,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Ok(ProofExpr::Core(mk_eq_refl_expr(
            family,
            &eq_target.levels,
            eq_target.ty,
            eq_target.lhs,
        )));
    }

    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::TypeMismatch,
        "omega equality goal evaluated to false in the direct proof path",
    )
    .with_expected_actual_payloads(
        DiagnosticPayloadKind::Expr,
        &core_expr_canonical_bytes(&eq_target.lhs),
        &core_expr_canonical_bytes(&eq_target.rhs),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id))
}

#[allow(clippy::too_many_arguments)]
fn ring_proof_for_target(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
    target: &Expr,
    family: &ResolvedEqFamily,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
    required_tactic_steps: &mut u64,
) -> Result<ProofExpr> {
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let target_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        target,
        fuel,
        goal.id,
        goal.meta_id,
    )?;

    let Some(eq_target) = parse_eq_target_from_expr(family, &target_whnf) else {
        return Err(ring_unsupported_goal(goal, &target_whnf));
    };
    *required_tactic_steps += 1;
    ensure_tactic_step_fuel(budget, *required_tactic_steps, goal.id, goal.meta_id)?;
    if kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &eq_target.lhs,
        &eq_target.rhs,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Ok(ProofExpr::Core(mk_eq_refl_expr(
            family,
            &eq_target.levels,
            eq_target.ty,
            eq_target.lhs,
        )));
    }

    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::TypeMismatch,
        "ring_nf equality goal has matching-normal-form proof metadata only when a checked equality proof is reconstructed",
    )
    .with_expected_actual_payloads(
        DiagnosticPayloadKind::Expr,
        &core_expr_canonical_bytes(&eq_target.lhs),
        &core_expr_canonical_bytes(&eq_target.rhs),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id))
}

fn omega_unsupported_goal(goal: &MachineGoal, target: &Expr) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::UnsupportedMachineTactic,
        "omega direct proof path supports only Eq goals whose sides are kernel-definitional equal",
    )
    .with_expected_actual_payloads(
        DiagnosticPayloadKind::Expr,
        &core_expr_canonical_bytes(&goal.target),
        &core_expr_canonical_bytes(target),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id)
}

fn ring_unsupported_goal(goal: &MachineGoal, target: &Expr) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::UnsupportedMachineTactic,
        "ring_nf direct proof path supports only Eq goals with checked reconstruction evidence",
    )
    .with_expected_actual_payloads(
        DiagnosticPayloadKind::Expr,
        &core_expr_canonical_bytes(&goal.target),
        &core_expr_canonical_bytes(target),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id)
}

fn finite_decide_supported_carrier_domain(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
    domain: &Expr,
    fuel: &TacticRunFuel,
) -> Result<bool> {
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        domain,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    Ok(finite_decide_supported_carrier_whnf(&whnf))
}

fn finite_decide_supported_carrier_whnf(expr: &Expr) -> bool {
    let (head, args) = collect_apps(expr);
    let Expr::Const { name, .. } = head else {
        return false;
    };
    match finite_decide_type_basename(&name) {
        "Bool" | "Empty" | "Unit" => args.is_empty(),
        "Fin" => args.len() == 1,
        "Vector" => args.len() == 2 && finite_decide_is_bool_type(&args[0]),
        "BitString" => args.len() == 1,
        "Option" => args.len() == 1,
        "Prod" | "Product" | "Sum" => args.len() == 2,
        _ => false,
    }
}

fn finite_decide_bool_true_proof(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    target_whnf: &Expr,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
    required_tactic_steps: &mut u64,
) -> Result<Option<Expr>> {
    let (head, args) = collect_apps(target_whnf);
    let Expr::Const { name, .. } = head else {
        return Ok(None);
    };
    if finite_decide_type_basename(&name) != "Bool" || !args.is_empty() {
        return Ok(None);
    }
    let candidates = [
        format!("{name}.true"),
        "Bool.true".to_owned(),
        "Bool.True".to_owned(),
    ];
    for candidate in candidates {
        if state.env.kernel_env().decl(&candidate).is_none() {
            continue;
        }
        let proof = Expr::konst(candidate, Vec::new());
        if kernel_check_with_budget(
            state.env.kernel_env(),
            ctx,
            &state.root.universe_params,
            &proof,
            target_whnf,
            fuel,
            goal.id,
            goal.meta_id,
        )
        .is_ok()
        {
            *required_tactic_steps += 1;
            ensure_tactic_step_fuel(budget, *required_tactic_steps, goal.id, goal.meta_id)?;
            return Ok(Some(proof));
        }
    }
    Ok(None)
}

fn finite_decide_is_bool_type(expr: &Expr) -> bool {
    let (head, args) = collect_apps(expr);
    let Expr::Const { name, .. } = head else {
        return false;
    };
    finite_decide_type_basename(&name) == "Bool" && args.is_empty()
}

fn finite_decide_type_basename(name: &str) -> &str {
    name.rsplit('.').next().unwrap_or(name)
}

fn finite_decide_unsupported_goal(goal: &MachineGoal, actual: &Expr) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::UnsupportedMachineTactic,
        "finite_decide supports only checked equality, finite universal equality, and Bool true-constructor goals in this milestone",
    )
    .with_expected_actual_payloads(
        DiagnosticPayloadKind::Expr,
        &core_expr_canonical_bytes(&Expr::konst("finite_decide.supported", Vec::new())),
        &core_expr_canonical_bytes(actual),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id)
}

fn run_refine_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: RefinePayload<RefineTermSource>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_refine_term_source(&payload.term)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    let ast = parse_refine_term_source(payload.term.source())
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    ensure_count_budget(
        "refine hole",
        ast.hole_count,
        payload.max_holes.unwrap_or_default(),
        TacticFuelKind::MetaAllocation,
        &goal,
    )?;
    ensure_count_budget(
        "refine meta allocation",
        ast.hole_count,
        budget.max_meta_allocations,
        TacticFuelKind::MetaAllocation,
        &goal,
    )?;

    let fuel = TacticRunFuel::new(budget);
    let mut checker = RefineTermChecker {
        state,
        goal: &goal,
        source: payload.term.source(),
        fuel: &fuel,
        new_goal_specs: Vec::new(),
    };
    let checked = checker.check_against(&ast, &goal.context, &goal.target)?;
    let required_steps = 2_u64.saturating_add(ast.hole_count);
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        checked.proof,
        checker.new_goal_specs,
        budget,
        required_steps,
        &fuel,
    )
}

#[derive(Clone, Debug)]
struct RefineCheckedTerm {
    proof: ProofExpr,
    ty: Expr,
    core: Option<Expr>,
}

struct RefineTermChecker<'a, 'fuel> {
    state: &'a MachineProofState,
    goal: &'a MachineGoal,
    source: &'a str,
    fuel: &'fuel TacticRunFuel,
    new_goal_specs: Vec<MachineNewGoalSpec>,
}

impl RefineTermChecker<'_, '_> {
    fn check_against(
        &mut self,
        ast: &RefineTermAst,
        context: &[MachineLocalDecl],
        expected: &Expr,
    ) -> Result<RefineCheckedTerm> {
        if !ast.has_holes {
            let checked = self.elaborate_core_check(ast, context, expected)?;
            let expr = checked.expr;
            return Ok(RefineCheckedTerm {
                proof: ProofExpr::Core(expr.clone()),
                ty: checked.inferred_type,
                core: Some(expr),
            });
        }

        match &ast.kind {
            RefineTermAstKind::Hole { .. } => self.check_hole(context, expected),
            RefineTermAstKind::Lam { binders, body } => {
                self.check_lambda(binders, body, context, expected)
            }
            RefineTermAstKind::Annot { expr, ty } => {
                self.check_annotation(expr, ty, context, expected)
            }
            _ => {
                let checked = self.infer(ast, context)?;
                self.ensure_type_matches(context, &checked.ty, expected)?;
                Ok(checked)
            }
        }
    }

    fn infer(
        &mut self,
        ast: &RefineTermAst,
        context: &[MachineLocalDecl],
    ) -> Result<RefineCheckedTerm> {
        if !ast.has_holes {
            let (expr, ty) = self.elaborate_core_infer(ast, context)?;
            return Ok(RefineCheckedTerm {
                proof: ProofExpr::Core(expr.clone()),
                ty,
                core: Some(expr),
            });
        }

        match &ast.kind {
            RefineTermAstKind::Hole { .. } => Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                "refine hole requires an expected type",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id)),
            RefineTermAstKind::App { func, arg } => self.infer_application(func, arg, context),
            RefineTermAstKind::Annot { expr, ty } => self.infer_annotation(expr, ty, context),
            RefineTermAstKind::Lam { .. } => Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                "refine lambda with holes requires an expected Pi target",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id)),
            RefineTermAstKind::Pi { .. } => Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTermSource,
                "refine holes inside forall terms are not supported",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id)),
            RefineTermAstKind::Let {
                name,
                ty,
                value,
                body,
            } => self.infer_let(name, ty, value, body, context),
            RefineTermAstKind::Core => unreachable!("core refine AST nodes do not contain holes"),
        }
    }

    fn check_hole(
        &mut self,
        context: &[MachineLocalDecl],
        expected: &Expr,
    ) -> Result<RefineCheckedTerm> {
        ensure_no_unresolved_universe_metas_in_expr(expected)
            .map_err(|diag| attach_goal_meta(diag, self.goal.id, self.goal.meta_id))?;
        let spec = typed_subgoal_spec_with_budget(
            self.state,
            self.goal,
            context.to_vec(),
            expected.clone(),
            self.fuel,
        )?;
        let meta_id = MetaVarId(
            self.state
                .metas
                .next_id
                .saturating_add(self.new_goal_specs.len() as u64),
        );
        self.new_goal_specs.push(spec);
        Ok(RefineCheckedTerm {
            proof: ProofExpr::Meta(meta_id),
            ty: expected.clone(),
            core: None,
        })
    }

    fn check_lambda(
        &mut self,
        binders: &[RefineTermBinder],
        body: &RefineTermAst,
        context: &[MachineLocalDecl],
        expected: &Expr,
    ) -> Result<RefineCheckedTerm> {
        if binders.iter().any(|binder| binder.ty.has_holes) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTermSource,
                "refine lambda binder types cannot contain holes",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id));
        }
        let mut proof_binders = Vec::with_capacity(binders.len());
        let mut body_context = context.to_vec();
        let mut expected_cursor = expected.clone();
        for binder in binders {
            let binder_ty = self.elaborate_core_type(&binder.ty, &body_context)?;
            let ctx = self.ctx(&body_context)?;
            let expected_whnf = kernel_whnf_with_budget(
                self.state.env.kernel_env(),
                &ctx,
                &self.state.root.universe_params,
                &expected_cursor,
                self.fuel,
                self.goal.id,
                self.goal.meta_id,
            )?;
            let Expr::Pi {
                ty: expected_ty,
                body: expected_body,
                ..
            } = expected_whnf
            else {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TypeMismatch,
                    "refine lambda requires a Pi goal target",
                )
                .with_goal(self.goal.id)
                .with_meta(self.goal.meta_id));
            };
            if !kernel_is_defeq_with_budget(
                self.state.env.kernel_env(),
                &ctx,
                &self.state.root.universe_params,
                &binder_ty,
                &expected_ty,
                self.fuel,
                self.goal.id,
                self.goal.meta_id,
            )? {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TypeMismatch,
                    "refine lambda binder type does not match Pi domain",
                )
                .with_expected_actual_payloads(
                    DiagnosticPayloadKind::Expr,
                    &core_expr_canonical_bytes(&expected_ty),
                    &core_expr_canonical_bytes(&binder_ty),
                )
                .with_goal(self.goal.id)
                .with_meta(self.goal.meta_id));
            }
            let binder_ty = Arc::unwrap_or_clone(expected_ty);
            proof_binders.push((binder.name.clone(), binder_ty.clone()));
            body_context.push(MachineLocalDecl::assumption(binder.name.clone(), binder_ty));
            expected_cursor = Arc::unwrap_or_clone(expected_body);
        }
        let body_checked = self.check_against(body, &body_context, &expected_cursor)?;
        let mut proof = body_checked.proof;
        for (name, ty) in proof_binders.into_iter().rev() {
            proof = ProofExpr::lam(name, ty, proof);
        }
        Ok(RefineCheckedTerm {
            proof,
            ty: expected.clone(),
            core: None,
        })
    }

    fn infer_application(
        &mut self,
        func: &RefineTermAst,
        arg: &RefineTermAst,
        context: &[MachineLocalDecl],
    ) -> Result<RefineCheckedTerm> {
        let func_checked = self.infer(func, context)?;
        let ctx = self.ctx(context)?;
        let fun_ty_whnf = kernel_whnf_with_budget(
            self.state.env.kernel_env(),
            &ctx,
            &self.state.root.universe_params,
            &func_checked.ty,
            self.fuel,
            self.goal.id,
            self.goal.meta_id,
        )?;
        let Expr::Pi { ty, body, .. } = fun_ty_whnf else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TypeMismatch,
                "refine application head is not a function",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id));
        };
        let arg_checked = self.check_against(arg, context, &ty)?;
        let result_ty = if let Some(arg_core) = &arg_checked.core {
            instantiate(&body, arg_core).map_err(kernel_diag)?
        } else if !contains_bound_var(&body, 0) {
            instantiate(&body, &Expr::bvar(0)).map_err(kernel_diag)?
        } else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                "dependent refine application result type cannot be computed from an unresolved hole",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id));
        };
        let proof = ProofExpr::app(func_checked.proof, arg_checked.proof);
        let core = match (func_checked.core, arg_checked.core) {
            (Some(func_core), Some(arg_core)) => Some(Expr::app(func_core, arg_core)),
            _ => None,
        };
        Ok(RefineCheckedTerm {
            proof,
            ty: result_ty,
            core,
        })
    }

    fn check_annotation(
        &mut self,
        expr: &RefineTermAst,
        ty: &RefineTermAst,
        context: &[MachineLocalDecl],
        expected: &Expr,
    ) -> Result<RefineCheckedTerm> {
        let checked = self.infer_annotation(expr, ty, context)?;
        self.ensure_type_matches(context, &checked.ty, expected)?;
        Ok(checked)
    }

    fn infer_annotation(
        &mut self,
        expr: &RefineTermAst,
        ty: &RefineTermAst,
        context: &[MachineLocalDecl],
    ) -> Result<RefineCheckedTerm> {
        if ty.has_holes {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTermSource,
                "refine type annotations cannot contain holes",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id));
        }
        let expected = self.elaborate_core_type(ty, context)?;
        self.check_against(expr, context, &expected)
    }

    fn infer_let(
        &mut self,
        name: &str,
        ty: &RefineTermAst,
        value: &RefineTermAst,
        body: &RefineTermAst,
        context: &[MachineLocalDecl],
    ) -> Result<RefineCheckedTerm> {
        if ty.has_holes || value.has_holes {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTermSource,
                "refine let types and values cannot contain holes",
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id));
        }
        let ty_expr = self.elaborate_core_type(ty, context)?;
        let value_checked = self.elaborate_core_check(value, context, &ty_expr)?;
        let mut body_context = context.to_vec();
        body_context.push(MachineLocalDecl::definition(
            name.to_owned(),
            ty_expr.clone(),
            value_checked.expr.clone(),
        ));
        let body_checked = self.infer(body, &body_context)?;
        let result_ty = instantiate(&body_checked.ty, &value_checked.expr).map_err(kernel_diag)?;
        Ok(RefineCheckedTerm {
            proof: ProofExpr::let_in(
                name.to_owned(),
                ty_expr,
                ProofExpr::Core(value_checked.expr.clone()),
                body_checked.proof,
            ),
            ty: result_ty,
            core: None,
        })
    }

    fn elaborate_core_check(
        &self,
        ast: &RefineTermAst,
        context: &[MachineLocalDecl],
        expected: &Expr,
    ) -> Result<npa_frontend::MachineTermCheckResult> {
        let elab_context = machine_term_elab_context(self.state, context)?;
        npa_frontend::elaborate_machine_term_check(
            refine_ast_source(self.source, ast),
            &elab_context,
            expected,
            &npa_frontend::MachineCompileOptions::default(),
        )
        .map_err(machine_term_elaboration_diag)
    }

    fn elaborate_core_infer(
        &self,
        ast: &RefineTermAst,
        context: &[MachineLocalDecl],
    ) -> Result<(Expr, Expr)> {
        let elab_context = machine_term_elab_context(self.state, context)?;
        let term = MachineTermSource::new_checked(refine_ast_source(self.source, ast))?;
        elaborate_apply_term_infer(&term, &elab_context)
    }

    fn elaborate_core_type(
        &self,
        ast: &RefineTermAst,
        context: &[MachineLocalDecl],
    ) -> Result<Expr> {
        let (expr, _) = self.elaborate_core_infer(ast, context)?;
        let ctx = self.ctx(context)?;
        kernel_expect_sort_with_budget(
            self.state.env.kernel_env(),
            &ctx,
            &self.state.root.universe_params,
            &expr,
            self.fuel,
            self.goal.id,
            self.goal.meta_id,
        )?;
        Ok(expr)
    }

    fn ensure_type_matches(
        &self,
        context: &[MachineLocalDecl],
        actual: &Expr,
        expected: &Expr,
    ) -> Result<()> {
        let ctx = self.ctx(context)?;
        if kernel_is_defeq_with_budget(
            self.state.env.kernel_env(),
            &ctx,
            &self.state.root.universe_params,
            actual,
            expected,
            self.fuel,
            self.goal.id,
            self.goal.meta_id,
        )? {
            Ok(())
        } else {
            Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TypeMismatch,
                "refine proof expression type does not match goal target",
            )
            .with_expected_actual_payloads(
                DiagnosticPayloadKind::Expr,
                &core_expr_canonical_bytes(expected),
                &core_expr_canonical_bytes(actual),
            )
            .with_goal(self.goal.id)
            .with_meta(self.goal.meta_id))
        }
    }

    fn ctx(&self, context: &[MachineLocalDecl]) -> Result<Ctx> {
        local_context_to_ctx_with_budget(
            self.state.env.kernel_env(),
            context,
            &self.state.root.universe_params,
            self.fuel,
            self.goal.id,
            self.goal.meta_id,
        )
    }
}

fn run_have_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: HavePayload<MachineTermSource>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_local_lemma_name_available(state, &goal, &payload.name)?;
    let fuel = TacticRunFuel::new(budget);
    let lemma_ty = elaborate_local_lemma_type_with_budget(state, &goal, &payload.ty, &fuel)?;
    let HavePayload {
        name,
        proof,
        insertion: _,
        ..
    } = payload;
    let first_new_meta = state.metas.next_id;
    let mut new_goal_specs = Vec::new();
    let lemma_proof = match proof {
        LocalLemmaProof::ChildGoal => {
            let lemma_meta = MetaVarId(first_new_meta);
            new_goal_specs.push(MachineNewGoalSpec::new(
                goal.context.clone(),
                lemma_ty.clone(),
            ));
            ProofExpr::Meta(lemma_meta)
        }
        LocalLemmaProof::Term(term) => {
            checked_local_lemma_term_proof(state, &goal, &term, &lemma_ty)?
        }
    };
    let continuation_meta = MetaVarId(first_new_meta.saturating_add(new_goal_specs.len() as u64));
    let continuation_context = extend_machine_local_context_assumption_with_budget(
        state,
        &goal,
        &goal.context,
        name.clone(),
        lemma_ty.clone(),
        &fuel,
    )?;
    let continuation_target = shifted_goal_target_for_local_lemma(&goal)?;
    new_goal_specs.push(MachineNewGoalSpec::new(
        continuation_context,
        continuation_target,
    ));
    let proof = local_lemma_parent_skeleton(name, lemma_ty, lemma_proof, continuation_meta);
    let required_steps = 3_u64.saturating_add(new_goal_specs.len() as u64);
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        proof,
        new_goal_specs,
        budget,
        required_steps,
        &fuel,
    )
}

fn run_suffices_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: SufficesPayload<MachineTermSource>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    let fuel = TacticRunFuel::new(budget);
    let lemma_ty = elaborate_local_lemma_type_with_budget(state, &goal, &payload.target, &fuel)?;
    let local_name = deterministic_available_local_name_for_state(
        state,
        &goal.context,
        MachineGeneratedNameKind::SufficesLocal,
        None,
    );
    let continuation_context = extend_machine_local_context_assumption_with_budget(
        state,
        &goal,
        &goal.context,
        local_name.clone(),
        lemma_ty.clone(),
        &fuel,
    )?;
    let continuation_target = shifted_goal_target_for_local_lemma(&goal)?;
    let first_new_meta = state.metas.next_id;
    let mut new_goal_specs = Vec::new();
    let (lemma_proof, continuation_meta) = match payload.proof {
        LocalLemmaProof::ChildGoal => match payload.continuation {
            SufficesContinuationPolicy::ProveIntermediateFirst => {
                let lemma_meta = MetaVarId(first_new_meta);
                let continuation_meta = MetaVarId(first_new_meta.saturating_add(1));
                new_goal_specs.push(MachineNewGoalSpec::new(
                    goal.context.clone(),
                    lemma_ty.clone(),
                ));
                new_goal_specs.push(MachineNewGoalSpec::new(
                    continuation_context,
                    continuation_target,
                ));
                (ProofExpr::Meta(lemma_meta), continuation_meta)
            }
            SufficesContinuationPolicy::ProveContinuationFirst => {
                let continuation_meta = MetaVarId(first_new_meta);
                let lemma_meta = MetaVarId(first_new_meta.saturating_add(1));
                new_goal_specs.push(MachineNewGoalSpec::new(
                    continuation_context,
                    continuation_target,
                ));
                new_goal_specs.push(MachineNewGoalSpec::new(
                    goal.context.clone(),
                    lemma_ty.clone(),
                ));
                (ProofExpr::Meta(lemma_meta), continuation_meta)
            }
        },
        LocalLemmaProof::Term(term) => {
            let continuation_meta = MetaVarId(first_new_meta);
            new_goal_specs.push(MachineNewGoalSpec::new(
                continuation_context,
                continuation_target,
            ));
            (
                checked_local_lemma_term_proof(state, &goal, &term, &lemma_ty)?,
                continuation_meta,
            )
        }
    };
    let proof = local_lemma_parent_skeleton(local_name, lemma_ty, lemma_proof, continuation_meta);
    let required_steps = 3_u64.saturating_add(new_goal_specs.len() as u64);
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        proof,
        new_goal_specs,
        budget,
        required_steps,
        &fuel,
    )
}

fn validate_local_lemma_name_available(
    state: &MachineProofState,
    goal: &MachineGoal,
    name: &str,
) -> Result<()> {
    validate_intro_name_shape(name)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    validate_intro_name_available(state, &goal.context, name)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    if state
        .reserved_local_names
        .iter()
        .any(|reserved| reserved == name)
    {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            format!("local lemma name {name:?} is already reserved by the proof skeleton"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn deterministic_available_local_name_for_state(
    state: &MachineProofState,
    context: &[MachineLocalDecl],
    kind: MachineGeneratedNameKind,
    hint: Option<&str>,
) -> String {
    let mut used = context
        .iter()
        .map(|local| local.name.clone())
        .collect::<Vec<_>>();
    used.extend(state.reserved_local_names.iter().cloned());
    used.extend(machine_global_roots(state));
    let used = used.iter().map(String::as_str).collect::<BTreeSet<_>>();
    if let Some(hint) = hint {
        if is_available_generated_name(&used, hint) {
            return hint.to_owned();
        }
        let prefix = sanitize_generated_name_stem(hint);
        return deterministic_generated_name_with_prefix(&used, &prefix);
    }
    deterministic_generated_name_with_prefix(&used, kind.stem())
}

fn elaborate_local_lemma_type_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    term: &MachineTermSource,
    fuel: &TacticRunFuel,
) -> Result<Expr> {
    validate_machine_term_source(term)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    let elab_context = machine_term_elab_context(state, &goal.context)?;
    let (ty, _) = elaborate_apply_term_infer(term, &elab_context)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    kernel_expect_sort_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    Ok(ty)
}

fn checked_local_lemma_term_proof(
    state: &MachineProofState,
    goal: &MachineGoal,
    term: &MachineTermSource,
    expected: &Expr,
) -> Result<ProofExpr> {
    validate_machine_term_source(term)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    let context = machine_term_elab_context(state, &goal.context)?;
    let checked = npa_frontend::elaborate_machine_term_check(
        term.source(),
        &context,
        expected,
        &npa_frontend::MachineCompileOptions::default(),
    )
    .map_err(|diag| attach_goal_meta(machine_term_elaboration_diag(diag), goal.id, goal.meta_id))?;
    Ok(ProofExpr::Core(checked.expr))
}

fn shifted_goal_target_for_local_lemma(goal: &MachineGoal) -> Result<Expr> {
    shift(&goal.target, 1, 0)
        .map_err(|err| attach_goal_meta(kernel_diag(err), goal.id, goal.meta_id))
}

fn local_lemma_parent_skeleton(
    name: String,
    lemma_ty: Expr,
    lemma_proof: ProofExpr,
    continuation_meta: MetaVarId,
) -> ProofExpr {
    ProofExpr::app(
        ProofExpr::lam(name, lemma_ty, ProofExpr::Meta(continuation_meta)),
        lemma_proof,
    )
}

fn run_specialize_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: SpecializePayload<ApplyArg>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_intro_name_shape(&payload.local_name)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    for level in &payload.universe_args {
        ensure_level_wf(&state.root.universe_params, level).map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("specialize universe argument is not well formed: {err:?}"),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
    }
    for arg in &payload.args {
        validate_apply_arg(arg).map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    }
    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal.id,
        goal.meta_id,
    )?;
    let local_index =
        resolve_local_apply_head_index(&goal, &payload.local_name, &payload.universe_args)?;
    let local = &goal.context[local_index];
    if local.value.is_some() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidLocalHead,
            format!(
                "specialize local {:?} resolves to a let declaration",
                payload.local_name
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let proof = ProofExpr::Core(local_bvar(goal.context.len(), local_index));
    let ty = kernel_infer_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &local_bvar(goal.context.len(), local_index),
        &fuel,
        goal.id,
        goal.meta_id,
    )?;
    let elab_context = machine_term_elab_context(state, &goal.context)?;
    let specialized = specialize_local_with_args(
        state,
        &goal,
        &ctx,
        &elab_context,
        proof,
        ty,
        &payload.args,
        budget,
        &fuel,
    )?;
    match payload.result_policy {
        SpecializeResultPolicy::AddLocal => {
            let result_name = match payload.result_name {
                Some(name) => {
                    validate_local_lemma_name_available(state, &goal, &name)?;
                    name
                }
                None => {
                    let hint = format!("{}_spec", payload.local_name);
                    deterministic_available_local_name_for_state(
                        state,
                        &goal.context,
                        MachineGeneratedNameKind::HaveLocal,
                        Some(&hint),
                    )
                }
            };
            let continuation_meta = MetaVarId(state.metas.next_id);
            let continuation_context = extend_machine_local_context_assumption_with_budget(
                state,
                &goal,
                &goal.context,
                result_name.clone(),
                specialized.ty.clone(),
                &fuel,
            )?;
            let continuation_target = shifted_goal_target_for_local_lemma(&goal)?;
            let proof = local_lemma_parent_skeleton(
                result_name,
                specialized.ty,
                specialized.proof,
                continuation_meta,
            );
            let required_steps = specialized.required_tactic_steps.saturating_add(2);
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(
                    continuation_context,
                    continuation_target,
                )],
                budget,
                required_steps,
                &fuel,
            )
        }
        SpecializeResultPolicy::ReplaceOriginal => run_specialize_replace_original_with_budget(
            state,
            &goal,
            local_index,
            payload.local_name,
            payload.result_name,
            specialized,
            budget,
            &fuel,
        ),
    }
}

#[derive(Clone, Debug)]
struct SpecializedLocal {
    proof: ProofExpr,
    ty: Expr,
    required_tactic_steps: u64,
}

#[allow(clippy::too_many_arguments)]
fn specialize_local_with_args(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    elab_context: &npa_frontend::MachineTermElabContext,
    mut proof: ProofExpr,
    mut ty: Expr,
    args: &[ApplyArg],
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<SpecializedLocal> {
    let mut required_tactic_steps = 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
    for arg in args {
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        let ty_whnf = kernel_whnf_with_budget(
            state.env.kernel_env(),
            ctx,
            &state.root.universe_params,
            &ty,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let Expr::Pi {
            ty: domain, body, ..
        } = ty_whnf
        else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TooManyApplyArguments,
                "specialize arguments remain after the local type stopped being a Pi",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        };
        let domain = Arc::unwrap_or_clone(domain);
        match arg {
            ApplyArg::Term(term) => {
                let checked = npa_frontend::elaborate_machine_term_check(
                    term.source(),
                    elab_context,
                    &domain,
                    &npa_frontend::MachineCompileOptions::default(),
                )
                .map_err(|err| {
                    attach_goal_meta(machine_term_elaboration_diag(err), goal.id, goal.meta_id)
                })?;
                ty = instantiate(&body, &checked.expr).map_err(kernel_diag)?;
                proof = ProofExpr::app(proof, ProofExpr::Core(checked.expr));
            }
            ApplyArg::InferFromTarget => {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::MissingExplicitArgument,
                    "specialize requires explicit term arguments in this milestone",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            ApplyArg::Subgoal { .. } => {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnsupportedTacticOption,
                    "specialize does not create subgoal arguments",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
        }
    }
    kernel_expect_sort_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    Ok(SpecializedLocal {
        proof,
        ty,
        required_tactic_steps,
    })
}

#[allow(clippy::too_many_arguments)]
fn run_specialize_replace_original_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    local_index: usize,
    original_name: String,
    result_name: Option<String>,
    specialized: SpecializedLocal,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<(MachineProofState, MachineProofDelta)> {
    ensure_specialize_replacement_suffix_independent(goal, local_index)?;
    let replacement_name = result_name.unwrap_or(original_name);
    validate_specialize_replacement_name(goal, local_index, &replacement_name)?;
    let replacement_ty = project_expr_to_prefix_context(
        goal,
        &specialized.ty,
        goal.context.len(),
        local_index,
        "specialize replacement result type",
    )?;
    let continuation_meta = MetaVarId(state.metas.next_id);
    let suffix = goal.context[local_index + 1..].to_vec();
    let continuation_target = specialize_replace_original_target(
        replacement_name,
        replacement_ty,
        &suffix,
        goal.target.clone(),
    );
    let proof = specialize_replace_original_parent_skeleton(
        goal,
        local_index,
        specialized.proof,
        continuation_meta,
    );
    let required_steps = specialized
        .required_tactic_steps
        .saturating_add(2)
        .saturating_add(suffix.len() as u64);
    assign_goal_with_budget_and_steps(
        state,
        goal.id,
        proof,
        vec![MachineNewGoalSpec::new(
            goal.context[..local_index].to_vec(),
            continuation_target,
        )],
        budget,
        required_steps,
        fuel,
    )
}

fn validate_specialize_replacement_name(
    goal: &MachineGoal,
    local_index: usize,
    name: &str,
) -> Result<()> {
    validate_intro_name_shape(name)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    if let Some((_, existing)) = goal
        .context
        .iter()
        .enumerate()
        .find(|(index, local)| *index != local_index && local.name == name)
    {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            format!(
                "specialize replacement name {name:?} would collide with existing local {:?}",
                existing.name
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn ensure_specialize_replacement_suffix_independent(
    goal: &MachineGoal,
    local_index: usize,
) -> Result<()> {
    for (index, local) in goal.context.iter().enumerate().skip(local_index + 1) {
        if expr_mentions_context_abs(&local.ty, index, index, local_index)
            || local
                .value
                .as_ref()
                .is_some_and(|value| expr_mentions_context_abs(value, index, index, local_index))
        {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                format!(
                    "specialize replace-original cannot keep later local {:?} because it depends on {:?}",
                    local.name, goal.context[local_index].name
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
    }
    if expr_mentions_context_abs(
        &goal.target,
        goal.context.len(),
        goal.context.len(),
        local_index,
    ) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            format!(
                "specialize replace-original cannot keep the target because it depends on {:?}",
                goal.context[local_index].name
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn specialize_replace_original_target(
    replacement_name: String,
    replacement_ty: Expr,
    suffix: &[MachineLocalDecl],
    body: Expr,
) -> Expr {
    let mut target = body;
    for local in suffix.iter().rev() {
        target = Expr::pi(local.name.clone(), local.ty.clone(), target);
    }
    Expr::pi(replacement_name, replacement_ty, target)
}

fn specialize_replace_original_parent_skeleton(
    goal: &MachineGoal,
    local_index: usize,
    specialized_proof: ProofExpr,
    meta_id: MetaVarId,
) -> ProofExpr {
    let mut proof = ProofExpr::app(ProofExpr::Meta(meta_id), specialized_proof);
    for index in local_index + 1..goal.context.len() {
        proof = ProofExpr::app(
            proof,
            ProofExpr::Core(local_bvar(goal.context.len(), index)),
        );
    }
    proof
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ContextProjectionError {
    DroppedLocal(usize),
    OutOfScope(u32),
}

fn project_expr_to_prefix_context(
    goal: &MachineGoal,
    expr: &Expr,
    source_ctx_len: usize,
    prefix_len: usize,
    label: &'static str,
) -> Result<Expr> {
    project_expr_to_prefix_context_at(expr, source_ctx_len, prefix_len, source_ctx_len, prefix_len)
        .map_err(|err| {
            let message = match err {
                ContextProjectionError::DroppedLocal(abs) => format!(
                    "{label} depends on local {:?}, which would be outside the replacement prefix",
                    goal.context
                        .get(abs)
                        .map(|local| local.name.as_str())
                        .unwrap_or("<unknown>")
                ),
                ContextProjectionError::OutOfScope(index) => {
                    format!("{label} contains out-of-scope de Bruijn index {index}")
                }
            };
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                message,
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })
}

fn project_expr_to_prefix_context_at(
    expr: &Expr,
    source_base_len: usize,
    keep_prefix_len: usize,
    source_ctx_len: usize,
    target_ctx_len: usize,
) -> std::result::Result<Expr, ContextProjectionError> {
    match expr {
        Expr::Sort(level) => Ok(Expr::Sort(level.clone())),
        Expr::BVar(index) => {
            let index = *index as usize;
            if index >= source_ctx_len {
                return Err(ContextProjectionError::OutOfScope(index as u32));
            }
            let source_abs = source_ctx_len - 1 - index;
            let target_abs = if source_abs < source_base_len {
                if source_abs < keep_prefix_len {
                    source_abs
                } else {
                    return Err(ContextProjectionError::DroppedLocal(source_abs));
                }
            } else {
                keep_prefix_len + (source_abs - source_base_len)
            };
            let target_index = target_ctx_len
                .checked_sub(1 + target_abs)
                .ok_or(ContextProjectionError::OutOfScope(index as u32))?;
            Ok(Expr::bvar(target_index as u32))
        }
        Expr::Const { name, levels } => Ok(Expr::konst(name.clone(), levels.clone())),
        Expr::App(fun, arg) => Ok(Expr::app(
            project_expr_to_prefix_context_at(
                fun,
                source_base_len,
                keep_prefix_len,
                source_ctx_len,
                target_ctx_len,
            )?,
            project_expr_to_prefix_context_at(
                arg,
                source_base_len,
                keep_prefix_len,
                source_ctx_len,
                target_ctx_len,
            )?,
        )),
        Expr::Lam { binder, ty, body } => Ok(Expr::lam(
            binder.clone(),
            project_expr_to_prefix_context_at(
                ty,
                source_base_len,
                keep_prefix_len,
                source_ctx_len,
                target_ctx_len,
            )?,
            project_expr_to_prefix_context_at(
                body,
                source_base_len,
                keep_prefix_len,
                source_ctx_len + 1,
                target_ctx_len + 1,
            )?,
        )),
        Expr::Pi { binder, ty, body } => Ok(Expr::pi(
            binder.clone(),
            project_expr_to_prefix_context_at(
                ty,
                source_base_len,
                keep_prefix_len,
                source_ctx_len,
                target_ctx_len,
            )?,
            project_expr_to_prefix_context_at(
                body,
                source_base_len,
                keep_prefix_len,
                source_ctx_len + 1,
                target_ctx_len + 1,
            )?,
        )),
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => Ok(Expr::let_in(
            binder.clone(),
            project_expr_to_prefix_context_at(
                ty,
                source_base_len,
                keep_prefix_len,
                source_ctx_len,
                target_ctx_len,
            )?,
            project_expr_to_prefix_context_at(
                value,
                source_base_len,
                keep_prefix_len,
                source_ctx_len,
                target_ctx_len,
            )?,
            project_expr_to_prefix_context_at(
                body,
                source_base_len,
                keep_prefix_len,
                source_ctx_len + 1,
                target_ctx_len + 1,
            )?,
        )),
    }
}

fn expr_mentions_context_abs(
    expr: &Expr,
    source_base_len: usize,
    source_ctx_len: usize,
    target_abs: usize,
) -> bool {
    match expr {
        Expr::Sort(_) | Expr::Const { .. } => false,
        Expr::BVar(index) => {
            let index = *index as usize;
            if index >= source_ctx_len {
                return false;
            }
            let source_abs = source_ctx_len - 1 - index;
            source_abs < source_base_len && source_abs == target_abs
        }
        Expr::App(fun, arg) => {
            expr_mentions_context_abs(fun, source_base_len, source_ctx_len, target_abs)
                || expr_mentions_context_abs(arg, source_base_len, source_ctx_len, target_abs)
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            expr_mentions_context_abs(ty, source_base_len, source_ctx_len, target_abs)
                || expr_mentions_context_abs(body, source_base_len, source_ctx_len + 1, target_abs)
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            expr_mentions_context_abs(ty, source_base_len, source_ctx_len, target_abs)
                || expr_mentions_context_abs(value, source_base_len, source_ctx_len, target_abs)
                || expr_mentions_context_abs(body, source_base_len, source_ctx_len + 1, target_abs)
        }
    }
}

fn run_revert_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: RevertPayload,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_revert_payload(&payload)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    let requested = resolve_revert_local_indices(&goal, &payload.locals)?;
    let earliest = *requested
        .iter()
        .min()
        .expect("revert payload validation rejected empty local list");
    let revert_indices = match payload.dependency_policy {
        RevertDependencyPolicy::Exact => exact_revert_suffix_indices(&goal, &requested)?,
        RevertDependencyPolicy::Closure => (earliest..goal.context.len()).collect::<Vec<_>>(),
    };
    ensure_revert_suffix_supported(&goal, &revert_indices)?;
    let new_context = goal.context[..earliest].to_vec();
    let suffix = goal.context[earliest..].to_vec();
    let target = revert_target_for_suffix(&suffix, goal.target.clone());
    let proof = revert_parent_skeleton(&goal, earliest, MetaVarId(state.metas.next_id));
    let fuel = TacticRunFuel::new(budget);
    let required_steps = 2_u64.saturating_add(suffix.len() as u64);
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        proof,
        vec![MachineNewGoalSpec::new(new_context, target)],
        budget,
        required_steps,
        &fuel,
    )
}

fn resolve_revert_local_indices(goal: &MachineGoal, locals: &[String]) -> Result<Vec<usize>> {
    let mut indices = Vec::new();
    for name in locals {
        let matches = goal
            .context
            .iter()
            .enumerate()
            .filter(|(_, local)| &local.name == name)
            .collect::<Vec<_>>();
        let [(index, _)] = matches.as_slice() else {
            return Err(if matches.is_empty() {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnknownLocalName,
                    format!("revert local {name:?} is not in the goal context"),
                )
            } else {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::AmbiguousLocalName,
                    format!("revert local {name:?} resolves to multiple locals"),
                )
            }
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        };
        indices.push(*index);
    }
    Ok(indices)
}

fn exact_revert_suffix_indices(goal: &MachineGoal, requested: &[usize]) -> Result<Vec<usize>> {
    let earliest = *requested
        .iter()
        .min()
        .expect("revert payload validation rejected empty local list");
    let expected = (earliest..goal.context.len()).collect::<Vec<_>>();
    let requested_set = requested.iter().copied().collect::<BTreeSet<_>>();
    let expected_set = expected.iter().copied().collect::<BTreeSet<_>>();
    if requested_set == expected_set {
        return Ok(expected);
    }
    let omitted = expected
        .iter()
        .copied()
        .filter(|index| !requested_set.contains(index))
        .collect::<Vec<_>>();
    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::InvalidMetaDependency,
        format!(
            "revert exact policy requires a suffix; later locals would remain after {:?}",
            omitted
                .iter()
                .map(|index| goal.context[*index].name.clone())
                .collect::<Vec<_>>()
        ),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id))
}

fn ensure_revert_suffix_supported(goal: &MachineGoal, indices: &[usize]) -> Result<()> {
    let Some(first) = indices.first().copied() else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            "revert requires at least one local",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    let expected = (first..goal.context.len()).collect::<Vec<_>>();
    if indices != expected {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            "revert implementation requires a deterministic suffix closure",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    for index in indices {
        if goal.context[*index].value.is_some() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnsupportedTacticOption,
                format!(
                    "revert does not support local definitions such as {:?}",
                    goal.context[*index].name
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
    }
    Ok(())
}

fn revert_target_for_suffix(suffix: &[MachineLocalDecl], mut body: Expr) -> Expr {
    for local in suffix.iter().rev() {
        body = Expr::pi(local.name.clone(), local.ty.clone(), body);
    }
    body
}

fn revert_parent_skeleton(goal: &MachineGoal, earliest: usize, meta_id: MetaVarId) -> ProofExpr {
    let mut proof = ProofExpr::Meta(meta_id);
    for index in earliest..goal.context.len() {
        proof = ProofExpr::app(
            proof,
            ProofExpr::Core(local_bvar(goal.context.len(), index)),
        );
    }
    proof
}

fn local_bvar(context_len: usize, index: usize) -> Expr {
    Expr::bvar((context_len - 1 - index) as u32)
}

fn occurrence_path_count(paths: &[OccurrencePath]) -> u64 {
    if paths.is_empty() {
        1
    } else {
        paths.len() as u64
    }
}

fn normalized_occurrence_paths(paths: &[OccurrencePath]) -> Result<Vec<OccurrencePath>> {
    let normalized = if paths.is_empty() {
        vec![OccurrencePath {
            indices: Vec::new(),
        }]
    } else {
        paths.to_vec()
    };
    let mut seen = BTreeSet::new();
    for path in &normalized {
        if !seen.insert(path.indices.clone()) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("duplicate occurrence path {:?}", path.indices),
            ));
        }
    }
    Ok(normalized)
}

fn run_generalize_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: GeneralizePayload<MachineTermSource>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    let paths = normalized_occurrence_paths(&payload.occurrences)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    ensure_rewrite_fuel(budget, paths.len() as u64, goal.id, goal.meta_id)?;
    let fuel = TacticRunFuel::new(budget);
    match payload.target {
        TacticTarget::Goal => {
            let elab_context = machine_term_elab_context(state, &goal.context)?;
            let (term, term_ty) = elaborate_apply_term_infer(&payload.term, &elab_context)
                .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
            let ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &goal.context,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            kernel_expect_sort_with_budget(
                state.env.kernel_env(),
                &ctx,
                &state.root.universe_params,
                &term_ty,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            let name = generalize_local_name(state, &goal.context, payload.name_hint);
            let shifted_target = shift(&goal.target, 1, 0).map_err(kernel_diag)?;
            let generalized_target =
                replace_occurrences_with_outer_local(&shifted_target, &paths, 0, &goal)?;
            ensure_expr_node_fuel(
                budget,
                core_expr_node_count(&generalized_target),
                goal.id,
                goal.meta_id,
            )?;
            let new_context = extend_machine_local_context_assumption_with_budget(
                state,
                &goal,
                &goal.context,
                name.clone(),
                term_ty.clone(),
                &fuel,
            )?;
            let proof = ProofExpr::app(
                ProofExpr::lam(
                    name,
                    term_ty,
                    ProofExpr::Meta(MetaVarId(state.metas.next_id)),
                ),
                ProofExpr::Core(term),
            );
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(new_context, generalized_target)],
                budget,
                3_u64.saturating_add(paths.len() as u64),
                &fuel,
            )
        }
        TacticTarget::Local { name } => {
            let local_index = resolve_unique_local_index(&goal, &name, "generalize target local")?;
            let prefix = goal.context[..local_index].to_vec();
            let local = goal.context[local_index].clone();
            let elab_context = machine_term_elab_context(state, &prefix)?;
            let (term, term_ty) = elaborate_apply_term_infer(&payload.term, &elab_context)
                .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
            let prefix_ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &prefix,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            kernel_expect_sort_with_budget(
                state.env.kernel_env(),
                &prefix_ctx,
                &state.root.universe_params,
                &term_ty,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            let generalized_name = generalize_local_name(state, &goal.context, payload.name_hint);
            ensure_generalize_local_transport_supported(&goal, local_index)?;
            let rebased_local_ty =
                insert_context_local_at(&local.ty, local_index, local_index, &goal)?;
            let generalized_local_ty =
                replace_occurrences_with_outer_local(&rebased_local_ty, &paths, 0, &goal)?;
            ensure_expr_node_fuel(
                budget,
                core_expr_node_count(&generalized_local_ty),
                goal.id,
                goal.meta_id,
            )?;
            let new_target = rebind_target_with_extra_prefix_local(
                &goal,
                local_index,
                generalized_name.clone(),
                term_ty.clone(),
                local.name.clone(),
                generalized_local_ty,
            )?;
            let proof_term =
                shift(&term, (goal.context.len() - prefix.len()) as i32, 0).map_err(kernel_diag)?;
            let proof = local_rebind_parent_skeleton(
                &goal,
                local_index,
                ProofExpr::Core(proof_term),
                MetaVarId(state.metas.next_id),
            );
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(prefix, new_target)],
                budget,
                3_u64
                    .saturating_add(paths.len() as u64)
                    .saturating_add((goal.context.len() - local_index) as u64),
                &fuel,
            )
        }
    }
}

fn run_change_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: ChangePayload<MachineTermSource>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    let paths = normalized_occurrence_paths(&payload.occurrences)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    ensure_rewrite_fuel(budget, paths.len() as u64, goal.id, goal.meta_id)?;
    let fuel = TacticRunFuel::new(budget);
    match payload.target {
        TacticTarget::Goal => {
            let elab_context = machine_term_elab_context(state, &goal.context)?;
            let (replacement, _) = elaborate_apply_term_infer(&payload.replacement, &elab_context)
                .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
            let changed_target =
                replace_occurrences_with_expr(&goal.target, &paths, &replacement, 0, &goal)?;
            let ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &goal.context,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            ensure_change_defeq(state, &goal, &ctx, &goal.target, &changed_target, &fuel)?;
            let proof = ProofExpr::Meta(MetaVarId(state.metas.next_id));
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(
                    goal.context.clone(),
                    changed_target,
                )],
                budget,
                2_u64.saturating_add(paths.len() as u64),
                &fuel,
            )
        }
        TacticTarget::Local { name } => {
            let local_index = resolve_unique_local_index(&goal, &name, "change target local")?;
            let prefix = goal.context[..local_index].to_vec();
            let local = goal.context[local_index].clone();
            let elab_context = machine_term_elab_context(state, &prefix)?;
            let (replacement, _) = elaborate_apply_term_infer(&payload.replacement, &elab_context)
                .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
            let changed_local_ty =
                replace_occurrences_with_expr(&local.ty, &paths, &replacement, 0, &goal)?;
            let prefix_ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &prefix,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            ensure_change_defeq(
                state,
                &goal,
                &prefix_ctx,
                &local.ty,
                &changed_local_ty,
                &fuel,
            )?;
            let new_target = rebind_target_without_extra_local(
                local.name.clone(),
                changed_local_ty,
                &goal.context[local_index + 1..],
                goal.target.clone(),
            );
            let proof = local_rebind_parent_skeleton_no_extra(
                &goal,
                local_index,
                MetaVarId(state.metas.next_id),
            );
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(prefix, new_target)],
                budget,
                2_u64
                    .saturating_add(paths.len() as u64)
                    .saturating_add((goal.context.len() - local_index) as u64),
                &fuel,
            )
        }
    }
}

fn run_unfold_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: UnfoldPayload,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    let paths = normalized_occurrence_paths(&payload.occurrences)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    let requested_delta = payload.max_delta_steps.unwrap_or(paths.len() as u64);
    ensure_rewrite_fuel(budget, requested_delta, goal.id, goal.meta_id)?;
    if requested_delta < paths.len() as u64 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::Rewrite,
            },
            format!(
                "unfold max_delta_steps {requested_delta} is smaller than selected occurrence count {}",
                paths.len()
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let fuel = TacticRunFuel::new(budget);
    let def = resolve_unfold_definition(state, &goal, &payload.constant)?;
    match payload.target {
        TacticTarget::Goal => {
            let unfolded_target = unfold_occurrences(&goal.target, &paths, &def, &goal)?;
            let ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &goal.context,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            ensure_change_defeq(state, &goal, &ctx, &goal.target, &unfolded_target, &fuel)?;
            let proof = ProofExpr::Meta(MetaVarId(state.metas.next_id));
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(
                    goal.context.clone(),
                    unfolded_target,
                )],
                budget,
                2_u64.saturating_add(paths.len() as u64),
                &fuel,
            )
        }
        TacticTarget::Local { name } => {
            let local_index = resolve_unique_local_index(&goal, &name, "unfold target local")?;
            let prefix = goal.context[..local_index].to_vec();
            let local = goal.context[local_index].clone();
            let unfolded_local_ty = unfold_occurrences(&local.ty, &paths, &def, &goal)?;
            let prefix_ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &prefix,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            ensure_change_defeq(
                state,
                &goal,
                &prefix_ctx,
                &local.ty,
                &unfolded_local_ty,
                &fuel,
            )?;
            let new_target = rebind_target_without_extra_local(
                local.name.clone(),
                unfolded_local_ty,
                &goal.context[local_index + 1..],
                goal.target.clone(),
            );
            let proof = local_rebind_parent_skeleton_no_extra(
                &goal,
                local_index,
                MetaVarId(state.metas.next_id),
            );
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(prefix, new_target)],
                budget,
                2_u64
                    .saturating_add(paths.len() as u64)
                    .saturating_add((goal.context.len() - local_index) as u64),
                &fuel,
            )
        }
    }
}

fn generalize_local_name(
    state: &MachineProofState,
    context: &[MachineLocalDecl],
    hint: Option<String>,
) -> String {
    if let Some(hint) = hint {
        deterministic_available_local_name_for_state(
            state,
            context,
            MachineGeneratedNameKind::GeneralizedLocal,
            Some(&hint),
        )
    } else {
        deterministic_available_local_name_for_state(
            state,
            context,
            MachineGeneratedNameKind::GeneralizedLocal,
            Some("x"),
        )
    }
}

fn ensure_change_defeq(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    old: &Expr,
    new: &Expr,
    fuel: &TacticRunFuel,
) -> Result<()> {
    kernel_expect_sort_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        new,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    if !kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        old,
        new,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "changed target is not definitionally equal to the original",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(old),
            &core_expr_canonical_bytes(new),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn ensure_generalize_local_transport_supported(
    goal: &MachineGoal,
    local_index: usize,
) -> Result<()> {
    for (index, local) in goal.context.iter().enumerate().skip(local_index + 1) {
        if expr_mentions_context_abs(&local.ty, index, index, local_index)
            || local
                .value
                .as_ref()
                .is_some_and(|value| expr_mentions_context_abs(value, index, index, local_index))
        {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                format!(
                    "generalize cannot keep later local {:?} because it depends on {:?}; dependent transport is not supported",
                    local.name, goal.context[local_index].name
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
    }
    if expr_mentions_context_abs(
        &goal.target,
        goal.context.len(),
        goal.context.len(),
        local_index,
    ) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            format!(
                "generalize cannot keep the target because it depends on {:?}; dependent transport is not supported",
                goal.context[local_index].name
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn rebind_target_with_extra_prefix_local(
    goal: &MachineGoal,
    local_index: usize,
    extra_name: String,
    extra_ty: Expr,
    local_name: String,
    local_ty: Expr,
) -> Result<Expr> {
    let source_len = goal.context.len();
    let mut target = insert_context_local_at(&goal.target, source_len, local_index, goal)?;
    for (index, local) in goal.context.iter().enumerate().skip(local_index + 1).rev() {
        let ty = insert_context_local_at(&local.ty, index, local_index, goal)?;
        target = Expr::pi(local.name.clone(), ty, target);
    }
    target = Expr::pi(local_name, local_ty, target);
    Ok(Expr::pi(extra_name, extra_ty, target))
}

fn insert_context_local_at(
    expr: &Expr,
    source_base_len: usize,
    insert_abs: usize,
    goal: &MachineGoal,
) -> Result<Expr> {
    if insert_abs > source_base_len {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            format!(
                "cannot insert generalized local at context position {insert_abs} in expression with base context length {source_base_len}"
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    insert_context_local_at_rec(
        expr,
        source_base_len,
        insert_abs,
        source_base_len,
        source_base_len + 1,
    )
    .map_err(|index| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ProofExprScopeError,
            format!("expression contains out-of-scope de Bruijn index {index}"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
    })
}

fn insert_context_local_at_rec(
    expr: &Expr,
    source_base_len: usize,
    insert_abs: usize,
    source_ctx_len: usize,
    target_ctx_len: usize,
) -> std::result::Result<Expr, u32> {
    match expr {
        Expr::Sort(level) => Ok(Expr::Sort(level.clone())),
        Expr::BVar(index) => {
            let index_usize = *index as usize;
            if index_usize >= source_ctx_len {
                return Err(*index);
            }
            let source_abs = source_ctx_len - 1 - index_usize;
            let target_abs = if source_abs < source_base_len {
                if source_abs < insert_abs {
                    source_abs
                } else {
                    source_abs + 1
                }
            } else {
                source_abs + 1
            };
            let target_index = target_ctx_len.checked_sub(1 + target_abs).ok_or(*index)?;
            Ok(Expr::bvar(target_index as u32))
        }
        Expr::Const { name, levels } => Ok(Expr::konst(name.clone(), levels.clone())),
        Expr::App(fun, arg) => Ok(Expr::app(
            insert_context_local_at_rec(
                fun,
                source_base_len,
                insert_abs,
                source_ctx_len,
                target_ctx_len,
            )?,
            insert_context_local_at_rec(
                arg,
                source_base_len,
                insert_abs,
                source_ctx_len,
                target_ctx_len,
            )?,
        )),
        Expr::Lam { binder, ty, body } => Ok(Expr::lam(
            binder.clone(),
            insert_context_local_at_rec(
                ty,
                source_base_len,
                insert_abs,
                source_ctx_len,
                target_ctx_len,
            )?,
            insert_context_local_at_rec(
                body,
                source_base_len,
                insert_abs,
                source_ctx_len + 1,
                target_ctx_len + 1,
            )?,
        )),
        Expr::Pi { binder, ty, body } => Ok(Expr::pi(
            binder.clone(),
            insert_context_local_at_rec(
                ty,
                source_base_len,
                insert_abs,
                source_ctx_len,
                target_ctx_len,
            )?,
            insert_context_local_at_rec(
                body,
                source_base_len,
                insert_abs,
                source_ctx_len + 1,
                target_ctx_len + 1,
            )?,
        )),
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => Ok(Expr::let_in(
            binder.clone(),
            insert_context_local_at_rec(
                ty,
                source_base_len,
                insert_abs,
                source_ctx_len,
                target_ctx_len,
            )?,
            insert_context_local_at_rec(
                value,
                source_base_len,
                insert_abs,
                source_ctx_len,
                target_ctx_len,
            )?,
            insert_context_local_at_rec(
                body,
                source_base_len,
                insert_abs,
                source_ctx_len + 1,
                target_ctx_len + 1,
            )?,
        )),
    }
}

fn rebind_target_without_extra_local(
    local_name: String,
    local_ty: Expr,
    suffix: &[MachineLocalDecl],
    body: Expr,
) -> Expr {
    let mut target = body;
    for local in suffix.iter().rev() {
        target = Expr::pi(local.name.clone(), local.ty.clone(), target);
    }
    Expr::pi(local_name, local_ty, target)
}

fn local_rebind_parent_skeleton(
    goal: &MachineGoal,
    local_index: usize,
    extra_arg: ProofExpr,
    meta_id: MetaVarId,
) -> ProofExpr {
    let mut proof = ProofExpr::app(ProofExpr::Meta(meta_id), extra_arg);
    for index in local_index..goal.context.len() {
        proof = ProofExpr::app(
            proof,
            ProofExpr::Core(local_bvar(goal.context.len(), index)),
        );
    }
    proof
}

fn local_rebind_parent_skeleton_no_extra(
    goal: &MachineGoal,
    local_index: usize,
    meta_id: MetaVarId,
) -> ProofExpr {
    let mut proof = ProofExpr::Meta(meta_id);
    for index in local_index..goal.context.len() {
        proof = ProofExpr::app(
            proof,
            ProofExpr::Core(local_bvar(goal.context.len(), index)),
        );
    }
    proof
}

fn resolve_unique_local_index(
    goal: &MachineGoal,
    name: &str,
    label: &'static str,
) -> Result<usize> {
    let matches = goal
        .context
        .iter()
        .enumerate()
        .filter(|(_, local)| local.name == name)
        .collect::<Vec<_>>();
    let [(index, _)] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownLocalName,
                format!("{label} {name:?} is not in the goal context"),
            )
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousLocalName,
                format!("{label} {name:?} resolves to multiple locals"),
            )
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    Ok(*index)
}

#[derive(Clone, Debug)]
struct UnfoldDefinition {
    name: String,
    universe_params: Vec<String>,
    value: Expr,
}

fn resolve_unfold_definition(
    state: &MachineProofState,
    goal: &MachineGoal,
    head: &TacticHead,
) -> Result<UnfoldDefinition> {
    match head {
        TacticHead::Local { name } => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            format!("unfold target {name:?} is a local term, not a checked definition"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
        TacticHead::Imported {
            name,
            decl_interface_hash,
        } => {
            let signature =
                resolve_imported_tactic_head_reference(state, goal, name, decl_interface_hash)?;
            if signature.kind != ExportKind::Def {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidTacticOption,
                    format!(
                        "unfold target {} is not an exported definition",
                        name.as_dotted()
                    ),
                )
                .with_primary_name(name.clone())
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            unfold_definition_from_kernel_decl(state, goal, name)
        }
        TacticHead::CurrentModule {
            name,
            decl_interface_hash,
        } => {
            let signature =
                resolve_current_tactic_head_reference(state, goal, name, decl_interface_hash)?;
            let checked = state
                .env
                .checked_current_decls
                .iter()
                .find(|decl| decl.signature().decl_interface_hash() == signature.decl_interface_hash())
                .ok_or_else(|| {
                    MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::UnknownTacticHead,
                        format!(
                            "current-module unfold target {} with the requested interface hash is unknown",
                            name.as_dotted()
                        ),
                    )
                    .with_primary_name(name.clone())
                    .with_goal(goal.id)
                    .with_meta(goal.meta_id)
                })?;
            unfold_definition_from_decl(goal, name, checked.core_decl())
        }
    }
}

fn unfold_definition_from_kernel_decl(
    state: &MachineProofState,
    goal: &MachineGoal,
    name: &Name,
) -> Result<UnfoldDefinition> {
    let decl = state
        .env
        .kernel_env()
        .decl(&name.as_dotted())
        .ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "unfold target {} is not present in the kernel environment",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
    unfold_definition_from_decl(goal, name, decl)
}

fn unfold_definition_from_decl(
    goal: &MachineGoal,
    name: &Name,
    decl: &Decl,
) -> Result<UnfoldDefinition> {
    match decl {
        Decl::Def {
            name: decl_name,
            universe_params,
            value,
            reducibility: npa_kernel::Reducibility::Reducible,
            ..
        }
        | Decl::DefConstrained {
            name: decl_name,
            universe_params,
            value,
            reducibility: npa_kernel::Reducibility::Reducible,
            ..
        } => Ok(UnfoldDefinition {
            name: decl_name.clone(),
            universe_params: universe_params.clone(),
            value: value.clone(),
        }),
        Decl::Def {
            reducibility: npa_kernel::Reducibility::Opaque,
            ..
        }
        | Decl::DefConstrained {
            reducibility: npa_kernel::Reducibility::Opaque,
            ..
        } => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidTacticOption,
            format!("unfold target {} is opaque", name.as_dotted()),
        )
        .with_primary_name(name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
        _ => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidTacticOption,
            format!("unfold target {} is not a definition", name.as_dotted()),
        )
        .with_primary_name(name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
    }
}

fn unfold_occurrences(
    expr: &Expr,
    paths: &[OccurrencePath],
    def: &UnfoldDefinition,
    goal: &MachineGoal,
) -> Result<Expr> {
    replace_occurrences(expr, paths, goal, &mut |selected, depth| {
        let Expr::Const { name, levels } = selected else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidTacticOption,
                format!(
                    "unfold occurrence for {} does not point to a constant",
                    def.name
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        };
        if name != &def.name {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidTacticOption,
                format!("unfold occurrence points to {name}, not {}", def.name),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
        if levels.len() != def.universe_params.len() {
            return Err(universe_argument_mismatch_diag(
                &def.universe_params,
                levels,
                goal.id,
                goal.meta_id,
            ));
        }
        let unfolded = subst_levels_expr(&def.value, &def.universe_params, levels);
        shift(&unfolded, depth as i32, 0).map_err(kernel_diag)
    })
}

fn replace_occurrences_with_outer_local(
    expr: &Expr,
    paths: &[OccurrencePath],
    depth_offset: u32,
    goal: &MachineGoal,
) -> Result<Expr> {
    replace_occurrences(expr, paths, goal, &mut |_selected, depth| {
        Ok(Expr::bvar(depth_offset + depth))
    })
}

fn replace_occurrences_with_expr(
    expr: &Expr,
    paths: &[OccurrencePath],
    replacement: &Expr,
    depth_offset: u32,
    goal: &MachineGoal,
) -> Result<Expr> {
    replace_occurrences(expr, paths, goal, &mut |_selected, depth| {
        shift(replacement, (depth_offset + depth) as i32, 0).map_err(kernel_diag)
    })
}

fn replace_occurrences<F>(
    expr: &Expr,
    paths: &[OccurrencePath],
    goal: &MachineGoal,
    make_replacement: &mut F,
) -> Result<Expr>
where
    F: FnMut(&Expr, u32) -> Result<Expr>,
{
    let path_slices = paths
        .iter()
        .map(|path| path.indices.as_slice())
        .collect::<Vec<_>>();
    replace_occurrences_at(expr, &path_slices, 0, make_replacement).map_err(|diag| {
        if diag.goal_id.is_none() && diag.meta_id.is_none() {
            attach_goal_meta(diag, goal.id, goal.meta_id)
        } else {
            diag
        }
    })
}

fn replace_occurrences_at<F>(
    expr: &Expr,
    paths: &[&[u64]],
    depth: u32,
    make_replacement: &mut F,
) -> Result<Expr>
where
    F: FnMut(&Expr, u32) -> Result<Expr>,
{
    let mut here = false;
    let mut child_paths = Vec::new();
    for path in paths.iter() {
        if path.is_empty() {
            here = true;
        } else {
            child_paths.push(*path);
        }
    }
    if here {
        if !child_paths.is_empty() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                "occurrence paths cannot select both an expression and one of its children",
            ));
        }
        return make_replacement(expr, depth);
    }

    match expr {
        Expr::Sort(_) | Expr::BVar(_) | Expr::Const { .. } => {
            if child_paths.is_empty() {
                Ok(expr.clone())
            } else {
                Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMachineTactic,
                    "occurrence path points outside a leaf expression",
                ))
            }
        }
        Expr::App(fun, arg) => {
            let fun_paths = occurrence_child_paths(&child_paths, 0)?;
            let arg_paths = occurrence_child_paths(&child_paths, 1)?;
            ensure_no_unknown_occurrence_child(&child_paths, 2)?;
            Ok(Expr::app(
                replace_occurrences_at(fun, fun_paths.as_slice(), depth, make_replacement)?,
                replace_occurrences_at(arg, arg_paths.as_slice(), depth, make_replacement)?,
            ))
        }
        Expr::Lam { binder, ty, body } => {
            let ty_paths = occurrence_child_paths(&child_paths, 0)?;
            let body_paths = occurrence_child_paths(&child_paths, 1)?;
            ensure_no_unknown_occurrence_child(&child_paths, 2)?;
            Ok(Expr::lam(
                binder.clone(),
                replace_occurrences_at(ty, ty_paths.as_slice(), depth, make_replacement)?,
                replace_occurrences_at(body, body_paths.as_slice(), depth + 1, make_replacement)?,
            ))
        }
        Expr::Pi { binder, ty, body } => {
            let ty_paths = occurrence_child_paths(&child_paths, 0)?;
            let body_paths = occurrence_child_paths(&child_paths, 1)?;
            ensure_no_unknown_occurrence_child(&child_paths, 2)?;
            Ok(Expr::pi(
                binder.clone(),
                replace_occurrences_at(ty, ty_paths.as_slice(), depth, make_replacement)?,
                replace_occurrences_at(body, body_paths.as_slice(), depth + 1, make_replacement)?,
            ))
        }
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => {
            let ty_paths = occurrence_child_paths(&child_paths, 0)?;
            let value_paths = occurrence_child_paths(&child_paths, 1)?;
            let body_paths = occurrence_child_paths(&child_paths, 2)?;
            ensure_no_unknown_occurrence_child(&child_paths, 3)?;
            Ok(Expr::let_in(
                binder.clone(),
                replace_occurrences_at(ty, ty_paths.as_slice(), depth, make_replacement)?,
                replace_occurrences_at(value, value_paths.as_slice(), depth, make_replacement)?,
                replace_occurrences_at(body, body_paths.as_slice(), depth + 1, make_replacement)?,
            ))
        }
    }
}

fn occurrence_child_paths<'a>(paths: &[&'a [u64]], child: u64) -> Result<Vec<&'a [u64]>> {
    Ok(paths
        .iter()
        .filter_map(|path| path.strip_prefix(&[child]))
        .collect())
}

fn ensure_no_unknown_occurrence_child(paths: &[&[u64]], child_count: u64) -> Result<()> {
    if let Some(path) = paths.iter().find(|path| path[0] >= child_count) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            format!("occurrence path child index {} is out of bounds", path[0]),
        ));
    }
    Ok(())
}

fn run_intro_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    name: String,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_intro_name_shape(&name)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    validate_intro_name_available(state, &goal.context, &name)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let target_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &goal.target,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let Expr::Pi { ty, body, .. } = target_whnf else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "intro requires the goal target to reduce to a Pi",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&goal.target),
            &core_expr_canonical_bytes(&target_whnf),
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id));
    };
    ensure_tactic_step_fuel(budget, 3, goal_id, goal.meta_id)?;
    let body_target = Arc::unwrap_or_clone(body);
    let binder_ty = Arc::unwrap_or_clone(ty);
    let new_meta_id = MetaVarId(state.metas.next_id);
    let body_context = extend_machine_local_context_assumption_with_budget(
        state,
        &goal,
        &goal.context,
        name.clone(),
        binder_ty.clone(),
        &fuel,
    )?;
    let proof = ProofExpr::lam(name, binder_ty, ProofExpr::Meta(new_meta_id));
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        proof,
        vec![MachineNewGoalSpec::new(body_context, body_target)],
        budget,
        0,
        &fuel,
    )
}

fn attach_goal_meta(
    mut diag: MachineTacticDiagnostic,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> MachineTacticDiagnostic {
    if diag.goal_id.is_none() {
        diag.goal_id = Some(goal_id);
    }
    if diag.meta_id.is_none() {
        diag.meta_id = Some(meta_id);
    }
    diag
}

fn attach_tactic_context(
    mut diag: MachineTacticDiagnostic,
    goal_id: GoalId,
    tactic_kind: Option<&'static str>,
) -> MachineTacticDiagnostic {
    if diag.goal_id.is_none() {
        diag.goal_id = Some(goal_id);
    }
    if diag.tactic_kind.is_none() {
        if let Some(tactic_kind) = tactic_kind {
            diag.tactic_kind = Some(tactic_kind.to_owned());
        }
    }
    diag
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord)]
struct PatternMetaId(u64);

#[derive(Clone, Debug)]
struct ResolvedApplyHead {
    proof: ProofExpr,
    ty: Expr,
}

#[derive(Clone, Debug)]
enum PendingApplyArg {
    Term {
        term: MachineTermSource,
        domain_pattern: Expr,
    },
    Subgoal {
        domain_pattern: Expr,
    },
    InferFromTarget {
        id: PatternMetaId,
        domain_pattern: Expr,
    },
}

#[derive(Clone, Debug)]
enum CheckedApplyArg {
    Core(Expr),
    Subgoal(Expr),
}

#[derive(Clone, Debug)]
struct ApplyAssembly {
    proof: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
}

#[derive(Clone, Debug, PartialEq, Eq)]
enum ConstructorCandidateOrigin {
    Imported { decl_interface_hash: Hash },
    CurrentModule { decl_interface_hash: Hash },
}

#[derive(Clone, Debug)]
struct ConstructorCandidate {
    name: Name,
    inductive: String,
    universe_params: Vec<String>,
    ty: Expr,
    param_count: usize,
    origin: ConstructorCandidateOrigin,
}

#[derive(Clone, Debug)]
struct ConstructorTarget {
    inductive: String,
    levels: Vec<Level>,
}

#[derive(Clone, Debug)]
struct ConstructorAssembly {
    proof: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    required_tactic_steps: u64,
}

#[derive(Clone, Debug)]
enum PendingConstructorArg {
    InferFromTarget {
        id: PatternMetaId,
        domain_pattern: Expr,
    },
    ChildGoal {
        domain_pattern: Expr,
    },
}

#[derive(Clone, Debug)]
struct EqTarget {
    levels: Vec<Level>,
    ty: Expr,
    lhs: Expr,
    rhs: Expr,
    expr: Expr,
}

#[derive(Clone, Debug)]
struct RewriteAssembly {
    proof: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    required_tactic_steps: u64,
}

#[derive(Clone, Debug)]
struct RewriteRuleInstance {
    proof: ProofExpr,
    eq_target: EqTarget,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    required_tactic_steps: u64,
}

#[derive(Clone, Debug)]
struct RewriteStep {
    old_eq_target: EqTarget,
    rule_eq_target: EqTarget,
    rule_proof: ProofExpr,
    direction: RewriteDirection,
    site: RewriteSite,
}

fn run_constructor_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: ConstructorPayload,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_constructor_payload(&payload)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;

    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let target = resolve_constructor_target(state, &goal, &ctx, &fuel)?;
    let selected = match &payload.selection {
        ConstructorSelection::Explicit { constructor } => {
            let candidate = resolve_explicit_constructor_candidate(state, &goal, constructor)?;
            if candidate.inductive != target.inductive {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TypeMismatch,
                    format!(
                        "constructor {} belongs to inductive {}, but target is {}",
                        candidate.name.as_dotted(),
                        candidate.inductive,
                        target.inductive
                    ),
                )
                .with_primary_name(candidate.name)
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            let assembly = assemble_constructor_candidate(
                state,
                &goal,
                &ctx,
                &target,
                &candidate,
                payload.max_new_goals,
                budget,
                &fuel,
            )?;
            (candidate, assembly)
        }
        ConstructorSelection::Auto => {
            let candidates = constructor_candidates_for_inductive(state, &target.inductive)?;
            let mut applicable = Vec::new();
            let mut skipped = Vec::new();
            for candidate in candidates {
                match assemble_constructor_candidate(
                    state,
                    &goal,
                    &ctx,
                    &target,
                    &candidate,
                    payload.max_new_goals,
                    budget,
                    &fuel,
                ) {
                    Ok(assembly) => applicable.push((candidate, assembly)),
                    Err(err) if constructor_candidate_not_applicable(&err.kind) => {
                        skipped.push(constructor_candidate_summary(&candidate));
                    }
                    Err(err) => return Err(err),
                }
            }
            match applicable.len() {
                1 => applicable.remove(0),
                0 => {
                    let summary = if skipped.is_empty() {
                        "none".to_owned()
                    } else {
                        skipped.join(",")
                    };
                    return Err(MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::TypeMismatch,
                        format!(
                            "no constructor applies to target inductive {}; candidates={summary}",
                            target.inductive
                        ),
                    )
                    .with_goal(goal.id)
                    .with_meta(goal.meta_id));
                }
                _ => {
                    let summary = applicable
                        .iter()
                        .map(|(candidate, _)| constructor_candidate_summary(candidate))
                        .collect::<Vec<_>>()
                        .join(",");
                    return Err(MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::AmbiguousTacticHead,
                        format!(
                            "auto constructor is ambiguous for target inductive {}; candidates={summary}",
                            target.inductive
                        ),
                    )
                    .with_goal(goal.id)
                    .with_meta(goal.meta_id));
                }
            }
        }
    };

    let (_, assembly) = selected;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        assembly.proof,
        assembly.new_goal_specs,
        budget,
        assembly.required_tactic_steps,
        &fuel,
    )
}

fn resolve_constructor_target(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    fuel: &TacticRunFuel,
) -> Result<ConstructorTarget> {
    let target_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &goal.target,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let (head, _) = collect_apps(&target_whnf);
    let Expr::Const { name, levels } = head else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "constructor target does not reduce to an inductive family application",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    match state.env.kernel_env().decl(&name) {
        Some(Decl::Inductive { .. }) => Ok(ConstructorTarget {
            inductive: name,
            levels,
        }),
        _ => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            format!("constructor target head {name} is not an inductive declaration"),
        )
        .with_primary_name(Name::from_dotted(&name))
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
    }
}

fn constructor_candidate_not_applicable(kind: &MachineTacticDiagnosticKind) -> bool {
    matches!(
        kind,
        MachineTacticDiagnosticKind::TypeMismatch
            | MachineTacticDiagnosticKind::MissingExplicitArgument
            | MachineTacticDiagnosticKind::AmbiguousApplyArgument
            | MachineTacticDiagnosticKind::TooFewApplyArguments
            | MachineTacticDiagnosticKind::InvalidMetaDependency
    )
}

fn deterministic_constructor_candidates(
    state: &MachineProofState,
) -> Result<Vec<ConstructorCandidate>> {
    let mut candidates = Vec::new();
    for import in &state.env.imports {
        for export in import
            .exports()
            .iter()
            .filter(|export| export.kind == ExportKind::Constructor)
        {
            candidates.push(imported_constructor_candidate(state, export)?);
        }
    }
    for checked in &state.env.checked_current_decls {
        let Decl::Inductive { data, .. } = checked.core_decl() else {
            continue;
        };
        for constructor in &data.constructors {
            candidates.push(current_constructor_candidate(
                state,
                checked,
                data,
                constructor,
            )?);
        }
    }
    candidates.sort_by(|lhs, rhs| {
        constructor_candidate_identity_bytes(lhs).cmp(&constructor_candidate_identity_bytes(rhs))
    });
    Ok(candidates)
}

fn constructor_candidates_for_inductive(
    state: &MachineProofState,
    inductive: &str,
) -> Result<Vec<ConstructorCandidate>> {
    Ok(deterministic_constructor_candidates(state)?
        .into_iter()
        .filter(|candidate| candidate.inductive == inductive)
        .collect())
}

fn resolve_explicit_constructor_candidate(
    state: &MachineProofState,
    goal: &MachineGoal,
    head: &TacticHead,
) -> Result<ConstructorCandidate> {
    validate_tactic_head_shape(head)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    if matches!(head, TacticHead::Local { .. }) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            "constructor selection must reference an imported or current-module constructor",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let matches = deterministic_constructor_candidates(state)?
        .into_iter()
        .filter(|candidate| constructor_candidate_matches_head(candidate, head))
        .collect::<Vec<_>>();
    let [candidate] = matches.as_slice() else {
        let (kind, message, primary_name) = if matches.is_empty() {
            (
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "explicit constructor {} with the requested interface hash is unknown",
                    tactic_head_name_for_message(head)
                ),
                tactic_head_primary_name(head),
            )
        } else {
            (
                MachineTacticDiagnosticKind::AmbiguousTacticHead,
                format!(
                    "explicit constructor {} with the requested interface hash is ambiguous",
                    tactic_head_name_for_message(head)
                ),
                tactic_head_primary_name(head),
            )
        };
        let mut diag = MachineTacticDiagnostic::new(kind, message)
            .with_goal(goal.id)
            .with_meta(goal.meta_id);
        if let Some(name) = primary_name {
            diag = diag.with_primary_name(name);
        }
        return Err(diag);
    };
    Ok(candidate.clone())
}

fn tactic_head_name_for_message(head: &TacticHead) -> String {
    match head {
        TacticHead::Imported { name, .. } | TacticHead::CurrentModule { name, .. } => {
            name.as_dotted()
        }
        TacticHead::Local { name } => name.clone(),
    }
}

fn tactic_head_primary_name(head: &TacticHead) -> Option<Name> {
    match head {
        TacticHead::Imported { name, .. } | TacticHead::CurrentModule { name, .. } => {
            Some(name.clone())
        }
        TacticHead::Local { .. } => None,
    }
}

fn constructor_candidate_matches_head(candidate: &ConstructorCandidate, head: &TacticHead) -> bool {
    match (head, &candidate.origin) {
        (
            TacticHead::Imported {
                name,
                decl_interface_hash,
            },
            ConstructorCandidateOrigin::Imported {
                decl_interface_hash: candidate_hash,
            },
        ) => candidate.name == *name && candidate_hash == decl_interface_hash,
        (
            TacticHead::CurrentModule {
                name,
                decl_interface_hash,
            },
            ConstructorCandidateOrigin::CurrentModule {
                decl_interface_hash: candidate_hash,
            },
        ) => candidate.name == *name && candidate_hash == decl_interface_hash,
        _ => false,
    }
}

fn imported_constructor_candidate(
    state: &MachineProofState,
    export: &VerifiedExportSignature,
) -> Result<ConstructorCandidate> {
    let name = export.name.as_dotted();
    let decl = state.env.kernel_env().decl(&name).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidVerifiedImport,
            format!("imported constructor {name} is missing from the kernel environment"),
        )
        .with_primary_name(export.name.clone())
    })?;
    let Decl::Constructor {
        universe_params,
        ty,
        inductive,
        ..
    } = decl
    else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidVerifiedImport,
            format!("imported constructor export {name} is not a kernel constructor"),
        )
        .with_primary_name(export.name.clone()));
    };
    let param_count = constructor_param_count(state, inductive)?;
    Ok(ConstructorCandidate {
        name: export.name.clone(),
        inductive: inductive.clone(),
        universe_params: universe_params.to_vec(),
        ty: ty.clone(),
        param_count,
        origin: ConstructorCandidateOrigin::Imported {
            decl_interface_hash: export.decl_interface_hash,
        },
    })
}

fn current_constructor_candidate(
    state: &MachineProofState,
    checked: &CheckedCurrentDecl,
    data: &npa_kernel::InductiveDecl,
    constructor: &npa_kernel::ConstructorDecl,
) -> Result<ConstructorCandidate> {
    let name = Name::from_dotted(&constructor.name);
    let decl = state
        .env
        .kernel_env()
        .decl(&constructor.name)
        .ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofSpec,
                format!(
                    "current constructor {} is missing from the kernel environment",
                    constructor.name
                ),
            )
            .with_primary_name(name.clone())
        })?;
    let Decl::Constructor {
        universe_params,
        ty,
        inductive,
        ..
    } = decl
    else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofSpec,
            format!(
                "current generated declaration {} is not a kernel constructor",
                constructor.name
            ),
        )
        .with_primary_name(name));
    };
    Ok(ConstructorCandidate {
        name: Name::from_dotted(&constructor.name),
        inductive: inductive.clone(),
        universe_params: universe_params.to_vec(),
        ty: ty.clone(),
        param_count: data.params.len(),
        origin: ConstructorCandidateOrigin::CurrentModule {
            decl_interface_hash: checked.signature().decl_interface_hash(),
        },
    })
}

fn constructor_param_count(state: &MachineProofState, inductive: &str) -> Result<usize> {
    let Some(Decl::Inductive { data, .. }) = state.env.kernel_env().decl(inductive) else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidVerifiedImport,
            format!(
                "constructor parent inductive {inductive} is missing from the kernel environment"
            ),
        )
        .with_primary_name(Name::from_dotted(inductive)));
    };
    Ok(data.params.len())
}

#[allow(clippy::too_many_arguments)]
fn assemble_constructor_candidate(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    target: &ConstructorTarget,
    candidate: &ConstructorCandidate,
    max_new_goals: Option<u64>,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<ConstructorAssembly> {
    if candidate.universe_params.len() != target.levels.len() {
        return Err(universe_argument_mismatch_diag(
            &candidate.universe_params,
            &target.levels,
            goal.id,
            goal.meta_id,
        ));
    }
    let env = state.env.kernel_env();
    let delta = &state.root.universe_params;
    let mut result_pattern =
        subst_levels_expr(&candidate.ty, &candidate.universe_params, &target.levels);
    let mut pending = Vec::new();
    let mut next_pattern_meta = 0;
    let mut required_tactic_steps = 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;

    loop {
        let result_whnf = kernel_whnf_with_budget(
            env,
            ctx,
            delta,
            &result_pattern,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        if !contains_pattern_meta(&result_whnf)
            && kernel_is_defeq_with_budget(
                env,
                ctx,
                delta,
                &result_whnf,
                &goal.target,
                fuel,
                goal.id,
                goal.meta_id,
            )?
        {
            result_pattern = result_whnf;
            break;
        }
        let Expr::Pi { ty, body, .. } = result_whnf else {
            result_pattern = result_whnf;
            break;
        };
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        let domain_pattern = Arc::unwrap_or_clone(ty);
        if pending.len() < candidate.param_count {
            let id = PatternMetaId(next_pattern_meta);
            next_pattern_meta += 1;
            result_pattern = instantiate(&body, &pattern_meta_expr(id)).map_err(kernel_diag)?;
            pending.push(PendingConstructorArg::InferFromTarget { id, domain_pattern });
        } else {
            if contains_bound_var(&body, 0) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaDependency,
                    "constructor generated child goals cannot occur in dependent result positions",
                )
                .with_primary_name(candidate.name.clone())
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            result_pattern = instantiate(&body, &Expr::bvar(0)).map_err(kernel_diag)?;
            pending.push(PendingConstructorArg::ChildGoal { domain_pattern });
        }
    }

    let infer_ids = pending
        .iter()
        .filter_map(|arg| match arg {
            PendingConstructorArg::InferFromTarget { id, .. } => Some(*id),
            PendingConstructorArg::ChildGoal { .. } => None,
        })
        .collect::<Vec<_>>();
    let solutions = if infer_ids.is_empty() {
        BTreeMap::new()
    } else {
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        infer_apply_args_from_target(state, ctx, goal, &result_pattern, &infer_ids, fuel)?
    };
    let result_after_solutions = replace_pattern_metas(&result_pattern, &solutions)?;
    if contains_pattern_meta(&result_after_solutions) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::AmbiguousApplyArgument,
            "constructor result still contains unresolved inferred parameters",
        )
        .with_primary_name(candidate.name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let result_whnf = kernel_whnf_with_budget(
        env,
        ctx,
        delta,
        &result_after_solutions,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    if !kernel_is_defeq_with_budget(
        env,
        ctx,
        delta,
        &result_whnf,
        &goal.target,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "constructor result type does not match the goal target",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&goal.target),
            &core_expr_canonical_bytes(&result_whnf),
        )
        .with_primary_name(candidate.name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }

    let mut proof = ProofExpr::Core(Expr::konst(
        candidate.name.as_dotted(),
        target.levels.clone(),
    ));
    let mut new_goal_specs = Vec::new();
    for arg in pending {
        match arg {
            PendingConstructorArg::InferFromTarget { id, domain_pattern } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions)?;
                let inferred = solutions.get(&id).ok_or_else(|| {
                    MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::MissingExplicitArgument,
                        "constructor inferred parameter was not solved by the target matcher",
                    )
                    .with_primary_name(candidate.name.clone())
                    .with_goal(goal.id)
                    .with_meta(goal.meta_id)
                })?;
                kernel_check_with_budget(
                    env,
                    ctx,
                    delta,
                    inferred,
                    &domain,
                    fuel,
                    goal.id,
                    goal.meta_id,
                )?;
                proof = ProofExpr::app(proof, ProofExpr::Core(inferred.clone()));
            }
            PendingConstructorArg::ChildGoal { domain_pattern } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions)?;
                let meta_id = MetaVarId(state.metas.next_id + new_goal_specs.len() as u64);
                let spec = typed_subgoal_spec_with_budget(
                    state,
                    goal,
                    goal.context.clone(),
                    domain,
                    fuel,
                )?;
                new_goal_specs.push(spec);
                proof = ProofExpr::app(proof, ProofExpr::Meta(meta_id));
            }
        }
    }
    ensure_count_budget(
        "constructor new goal",
        new_goal_specs.len() as u64,
        max_new_goals.unwrap_or(0),
        TacticFuelKind::MetaAllocation,
        goal,
    )?;
    required_tactic_steps += 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
    Ok(ConstructorAssembly {
        proof,
        new_goal_specs,
        required_tactic_steps,
    })
}

fn constructor_candidate_identity_bytes(candidate: &ConstructorCandidate) -> Vec<u8> {
    let mut out = tagged_bytes("npa.tactic.constructor-candidate.v1");
    match &candidate.origin {
        ConstructorCandidateOrigin::Imported {
            decl_interface_hash,
        } => {
            out.push(0);
            encode_hash_to(&mut out, decl_interface_hash);
        }
        ConstructorCandidateOrigin::CurrentModule {
            decl_interface_hash,
        } => {
            out.push(1);
            encode_hash_to(&mut out, decl_interface_hash);
        }
    }
    encode_string_to(&mut out, &candidate.name.as_dotted());
    encode_string_to(&mut out, &candidate.inductive);
    encode_hash_to(&mut out, &core_expr_hash(&candidate.ty));
    out
}

fn constructor_candidate_identity_hash(candidate: &ConstructorCandidate) -> Hash {
    hash_with_domain(
        "npa.tactic.constructor-candidate-id.v1",
        &constructor_candidate_identity_bytes(candidate),
    )
}

fn constructor_candidate_summary(candidate: &ConstructorCandidate) -> String {
    let hash = hex_hash(&constructor_candidate_identity_hash(candidate));
    format!("{}#{}", candidate.name.as_dotted(), &hash[..16])
}

fn run_apply_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    head: TacticHead,
    universe_args: Vec<Level>,
    args: Vec<ApplyArg>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_tactic_head_shape(&head)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    for arg in &args {
        validate_apply_arg(arg).map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    }
    for level in &universe_args {
        ensure_level_wf(&state.root.universe_params, level).map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("apply universe argument is not well formed: {err:?}"),
            )
            .with_goal(goal_id)
            .with_meta(goal.meta_id)
        })?;
    }
    validate_apply_head_static(state, &goal, &head, &universe_args)?;

    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let resolved = resolve_apply_head(state, &goal, &ctx, &head, &universe_args, &fuel)?;
    let elab_context = machine_term_elab_context(state, &goal.context)?;
    let assembly = assemble_apply(
        state,
        &goal,
        &ctx,
        &elab_context,
        resolved,
        &args,
        budget,
        &fuel,
    )?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        assembly.proof,
        assembly.new_goal_specs,
        budget,
        0,
        &fuel,
    )
}

fn resolve_apply_head(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    head: &TacticHead,
    universe_args: &[Level],
    fuel: &TacticRunFuel,
) -> Result<ResolvedApplyHead> {
    match head {
        TacticHead::Local { name } => {
            resolve_local_apply_head(state, goal, ctx, name, universe_args, fuel)
        }
        TacticHead::Imported {
            name,
            decl_interface_hash,
        } => {
            let signature =
                resolve_imported_apply_signature(state, goal, name, decl_interface_hash)?;
            resolve_global_apply_head(state, goal, ctx, signature, universe_args, fuel)
        }
        TacticHead::CurrentModule {
            name,
            decl_interface_hash,
        } => {
            let signature =
                resolve_current_apply_signature(state, goal, name, decl_interface_hash)?;
            resolve_global_apply_head(state, goal, ctx, signature, universe_args, fuel)
        }
    }
}

fn validate_apply_head_static(
    state: &MachineProofState,
    goal: &MachineGoal,
    head: &TacticHead,
    universe_args: &[Level],
) -> Result<()> {
    match head {
        TacticHead::Local { name } => {
            resolve_local_apply_head_index(goal, name, universe_args)?;
        }
        TacticHead::Imported {
            name,
            decl_interface_hash,
        } => {
            let signature =
                resolve_imported_apply_signature(state, goal, name, decl_interface_hash)?;
            validate_global_apply_signature(state, goal, signature, universe_args)?;
        }
        TacticHead::CurrentModule {
            name,
            decl_interface_hash,
        } => {
            let signature =
                resolve_current_apply_signature(state, goal, name, decl_interface_hash)?;
            validate_global_apply_signature(state, goal, signature, universe_args)?;
        }
    }
    Ok(())
}

fn resolve_local_apply_head(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    name: &str,
    universe_args: &[Level],
    fuel: &TacticRunFuel,
) -> Result<ResolvedApplyHead> {
    let index = resolve_local_apply_head_index(goal, name, universe_args)?;
    let bvar = Expr::bvar((goal.context.len() - 1 - index) as u32);
    let ty = kernel_infer_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &bvar,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    Ok(ResolvedApplyHead {
        proof: ProofExpr::Core(bvar),
        ty,
    })
}

fn resolve_local_apply_head_index(
    goal: &MachineGoal,
    name: &str,
    universe_args: &[Level],
) -> Result<usize> {
    if !universe_args.is_empty() {
        return Err(universe_argument_mismatch_diag(
            &[],
            universe_args,
            goal.id,
            goal.meta_id,
        ));
    }
    let matches = goal
        .context
        .iter()
        .enumerate()
        .filter(|(_, local)| local.name == name)
        .collect::<Vec<_>>();
    let [(index, local)] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownLocalName,
                format!("apply local head {name:?} is not in the goal context"),
            )
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousLocalName,
                format!("apply local head {name:?} resolves to multiple locals"),
            )
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    if local.value.is_some() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidLocalHead,
            format!("apply local head {name:?} resolves to a let declaration"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(*index)
}

fn resolve_imported_apply_signature<'a>(
    state: &'a MachineProofState,
    goal: &MachineGoal,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<&'a VerifiedExportSignature> {
    let matches = state
        .env
        .imports
        .iter()
        .flat_map(|import| import.exports.iter())
        .filter(|export| &export.name == name && &export.decl_interface_hash == decl_interface_hash)
        .collect::<Vec<_>>();
    let [signature] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "imported apply head {} with the requested interface hash is unknown",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousTacticHead,
                format!("imported apply head {} is ambiguous", name.as_dotted()),
            )
            .with_primary_name(name.clone())
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    Ok(signature)
}

fn resolve_current_apply_signature<'a>(
    state: &'a MachineProofState,
    goal: &MachineGoal,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<&'a CheckedDeclSignature> {
    let matches = state
        .env
        .checked_current_decls
        .iter()
        .map(|decl| decl.signature())
        .filter(|signature| {
            signature.name() == name && signature.decl_interface_hash() == *decl_interface_hash
        })
        .collect::<Vec<_>>();
    let [signature] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "current-module apply head {} with the requested interface hash is unknown",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousTacticHead,
                format!(
                    "current-module apply head {} is ambiguous",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    Ok(signature)
}

trait ApplySignature {
    fn name(&self) -> &Name;
    fn universe_params(&self) -> &[String];
}

impl ApplySignature for VerifiedExportSignature {
    fn name(&self) -> &Name {
        &self.name
    }

    fn universe_params(&self) -> &[String] {
        // Verified export signatures do not store universe params directly. The
        // canonical kernel declaration is authoritative for arity checks below.
        &[]
    }
}

impl ApplySignature for CheckedDeclSignature {
    fn name(&self) -> &Name {
        &self.name
    }

    fn universe_params(&self) -> &[String] {
        &self.universe_params
    }
}

fn resolve_global_apply_head<S: ApplySignature>(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    signature: &S,
    universe_args: &[Level],
    fuel: &TacticRunFuel,
) -> Result<ResolvedApplyHead> {
    validate_global_apply_signature(state, goal, signature, universe_args)?;
    let proof = Expr::konst(signature.name().as_dotted(), universe_args.to_vec());
    let ty = kernel_infer_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &proof,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    Ok(ResolvedApplyHead {
        proof: ProofExpr::Core(proof),
        ty,
    })
}

fn validate_global_apply_signature<S: ApplySignature>(
    state: &MachineProofState,
    goal: &MachineGoal,
    signature: &S,
    universe_args: &[Level],
) -> Result<()> {
    let decl = state
        .env
        .kernel_env()
        .decl(&signature.name().as_dotted())
        .ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "apply head {} is not present in the kernel environment",
                    signature.name().as_dotted()
                ),
            )
            .with_primary_name(signature.name().clone())
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
    let universe_params = if signature.universe_params().is_empty() {
        decl.universe_params()
    } else {
        signature.universe_params()
    };
    if universe_params.len() != universe_args.len() {
        return Err(universe_argument_mismatch_diag(
            universe_params,
            universe_args,
            goal.id,
            goal.meta_id,
        ));
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn assemble_apply(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    elab_context: &npa_frontend::MachineTermElabContext,
    resolved: ResolvedApplyHead,
    args: &[ApplyArg],
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<ApplyAssembly> {
    let env = state.env.kernel_env();
    let delta = &state.root.universe_params;
    let mut result_pattern = resolved.ty;
    let mut pending = Vec::new();
    let mut next_arg = 0;
    let mut next_pattern_meta = 0;
    let mut required_tactic_steps = 1;

    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;

    loop {
        let result_whnf = kernel_whnf_with_budget(
            env,
            ctx,
            delta,
            &result_pattern,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        if !contains_pattern_meta(&result_whnf)
            && kernel_is_defeq_with_budget(
                env,
                ctx,
                delta,
                &result_whnf,
                &goal.target,
                fuel,
                goal.id,
                goal.meta_id,
            )?
        {
            if next_arg < args.len() {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TooManyApplyArguments,
                    "apply arguments remain after the result already matches the goal target",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            break;
        }

        let Expr::Pi { ty, body, .. } = result_whnf else {
            if next_arg < args.len() {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TooManyApplyArguments,
                    "apply arguments remain after the head type stopped being a Pi",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            break;
        };
        let Some(arg) = args.get(next_arg) else {
            result_pattern = Expr::pi("_", Arc::unwrap_or_clone(ty), Arc::unwrap_or_clone(body));
            break;
        };
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        let domain_pattern = Arc::unwrap_or_clone(ty);
        result_pattern = match arg {
            ApplyArg::Term(term) => {
                let (expr, _) =
                    elaborate_apply_term_infer(term, elab_context).map_err(|mut diag| {
                        diag.goal_id = Some(goal.id);
                        diag.meta_id = Some(goal.meta_id);
                        diag
                    })?;
                let next = instantiate(&body, &expr).map_err(kernel_diag)?;
                pending.push(PendingApplyArg::Term {
                    term: term.clone(),
                    domain_pattern,
                });
                next
            }
            ApplyArg::Subgoal { .. } => {
                if !contains_pattern_meta(&domain_pattern) {
                    ensure_subgoal_domain_is_prop(
                        state,
                        ctx,
                        goal,
                        &domain_pattern,
                        Some((fuel, goal.id, goal.meta_id)),
                    )?;
                }
                if contains_bound_var(&body, 0) {
                    return Err(MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::InvalidMetaDependency,
                        "apply subgoal arguments cannot occur in dependent result positions",
                    )
                    .with_goal(goal.id)
                    .with_meta(goal.meta_id));
                }
                let next = instantiate(&body, &Expr::bvar(0)).map_err(kernel_diag)?;
                pending.push(PendingApplyArg::Subgoal { domain_pattern });
                next
            }
            ApplyArg::InferFromTarget => {
                let id = PatternMetaId(next_pattern_meta);
                next_pattern_meta += 1;
                let next = instantiate(&body, &pattern_meta_expr(id)).map_err(kernel_diag)?;
                pending.push(PendingApplyArg::InferFromTarget { id, domain_pattern });
                next
            }
        };
        next_arg += 1;
    }

    let infer_ids = pending
        .iter()
        .filter_map(|arg| match arg {
            PendingApplyArg::InferFromTarget { id, .. } => Some(*id),
            PendingApplyArg::Term { .. } | PendingApplyArg::Subgoal { .. } => None,
        })
        .collect::<Vec<_>>();
    let ran_infer_matcher = !infer_ids.is_empty();
    let solutions = if ran_infer_matcher {
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        infer_apply_args_from_target(state, ctx, goal, &result_pattern, &infer_ids, fuel)?
    } else {
        BTreeMap::new()
    };
    let result_after_solutions = replace_pattern_metas(&result_pattern, &solutions)?;
    if contains_pattern_meta(&result_after_solutions) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::AmbiguousApplyArgument,
            "apply result still contains unresolved inferred arguments",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }

    let result_whnf = kernel_whnf_with_budget(
        env,
        ctx,
        delta,
        &result_after_solutions,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    if !kernel_is_defeq_with_budget(
        env,
        ctx,
        delta,
        &result_whnf,
        &goal.target,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return if matches!(result_whnf, Expr::Pi { .. }) {
            Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TooFewApplyArguments,
                "apply arguments were exhausted before the result reached the goal target",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id))
        } else {
            Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TypeMismatch,
                "apply result type does not match the goal target",
            )
            .with_expected_actual_payloads(
                DiagnosticPayloadKind::Expr,
                &core_expr_canonical_bytes(&goal.target),
                &core_expr_canonical_bytes(&result_whnf),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id))
        };
    }

    let mut checked_args = Vec::new();
    for pending_arg in pending {
        let checked_arg = match pending_arg {
            PendingApplyArg::Term {
                term,
                domain_pattern,
            } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions)?;
                let checked = npa_frontend::elaborate_machine_term_check(
                    term.source(),
                    elab_context,
                    &domain,
                    &npa_frontend::MachineCompileOptions::default(),
                )
                .map_err(|err| {
                    let mut diag = machine_term_elaboration_diag(err);
                    diag.goal_id = Some(goal.id);
                    diag.meta_id = Some(goal.meta_id);
                    diag
                })?;
                CheckedApplyArg::Core(checked.expr)
            }
            PendingApplyArg::Subgoal { domain_pattern } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions)?;
                ensure_subgoal_domain_is_prop(
                    state,
                    ctx,
                    goal,
                    &domain,
                    Some((fuel, goal.id, goal.meta_id)),
                )?;
                CheckedApplyArg::Subgoal(domain)
            }
            PendingApplyArg::InferFromTarget { id, domain_pattern } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions)?;
                let inferred = solutions.get(&id).ok_or_else(|| {
                    MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::MissingExplicitArgument,
                        "apply inferred argument was not solved by the target matcher",
                    )
                    .with_goal(goal.id)
                    .with_meta(goal.meta_id)
                })?;
                kernel_check_with_budget(
                    state.env.kernel_env(),
                    ctx,
                    delta,
                    inferred,
                    &domain,
                    fuel,
                    goal.id,
                    goal.meta_id,
                )?;
                CheckedApplyArg::Core(inferred.clone())
            }
        };
        checked_args.push(checked_arg);
    }

    required_tactic_steps += 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
    let mut proof = resolved.proof;
    let mut new_goal_specs = Vec::new();
    for checked_arg in checked_args {
        let proof_arg = match checked_arg {
            CheckedApplyArg::Core(expr) => ProofExpr::Core(expr),
            CheckedApplyArg::Subgoal(domain) => {
                let meta_id = MetaVarId(state.metas.next_id + new_goal_specs.len() as u64);
                new_goal_specs.push(MachineNewGoalSpec::new(goal.context.clone(), domain));
                ProofExpr::Meta(meta_id)
            }
        };
        proof = ProofExpr::app(proof, proof_arg);
    }

    Ok(ApplyAssembly {
        proof,
        new_goal_specs,
    })
}

fn run_rewrite_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    rule: RewriteRuleRef,
    direction: RewriteDirection,
    site: RewriteSite,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_rewrite_rule_ref(&rule)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    for level in &rule.universe_args {
        ensure_level_wf(&state.root.universe_params, level).map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("rw universe argument is not well formed: {err:?}"),
            )
            .with_goal(goal_id)
            .with_meta(goal.meta_id)
        })?;
    }
    validate_apply_head_static(state, &goal, &rule.head, &rule.universe_args)?;
    let family = state.env.eq_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "rw requires a resolved Eq family",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id)
    })?;

    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let resolved = resolve_apply_head(state, &goal, &ctx, &rule.head, &rule.universe_args, &fuel)?;
    let old_eq_target = whnf_eq_target(state, &goal, &ctx, family, &fuel)?;
    let elab_context = machine_term_elab_context(state, &goal.context)?;
    let assembly = assemble_rewrite(
        state,
        &goal,
        &ctx,
        &elab_context,
        family,
        old_eq_target,
        resolved,
        &rule.args,
        direction,
        site,
        budget,
        &fuel,
    )?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        assembly.proof,
        assembly.new_goal_specs,
        budget,
        assembly.required_tactic_steps,
        &fuel,
    )
}

#[allow(clippy::too_many_arguments)]
fn assemble_rewrite(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    elab_context: &npa_frontend::MachineTermElabContext,
    family: &ResolvedEqFamily,
    old_eq_target: EqTarget,
    resolved: ResolvedApplyHead,
    args: &[ApplyArg],
    direction: RewriteDirection,
    site: RewriteSite,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<RewriteAssembly> {
    let instance = instantiate_rewrite_rule(
        state,
        goal,
        ctx,
        elab_context,
        family,
        resolved,
        args,
        &old_eq_target,
        direction,
        site,
        budget,
        fuel,
        0,
    )?;
    let mut required_tactic_steps = instance.required_tactic_steps;

    required_tactic_steps += 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
    let new_target =
        rewrite_eq_target_expr(family, &old_eq_target, &instance.eq_target, direction, site);
    let rewritten_meta_id = MetaVarId(state.metas.next_id + instance.new_goal_specs.len() as u64);
    let rewritten_goal = MachineNewGoalSpec::new(goal.context.clone(), new_target.clone());
    let mut new_goal_specs = instance.new_goal_specs;
    new_goal_specs.push(rewritten_goal);
    ensure_rewrite_fuel(budget, 1, goal.id, goal.meta_id)?;
    required_tactic_steps += 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
    let proof = mk_rewrite_transport(
        family,
        &old_eq_target,
        &instance.eq_target,
        instance.proof,
        direction,
        site,
        ProofExpr::Meta(rewritten_meta_id),
    )?;
    Ok(RewriteAssembly {
        proof,
        new_goal_specs,
        required_tactic_steps,
    })
}

#[allow(clippy::too_many_arguments)]
fn instantiate_rewrite_rule(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    elab_context: &npa_frontend::MachineTermElabContext,
    family: &ResolvedEqFamily,
    resolved: ResolvedApplyHead,
    args: &[ApplyArg],
    old_eq_target: &EqTarget,
    direction: RewriteDirection,
    site: RewriteSite,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
    initial_tactic_steps: u64,
) -> Result<RewriteRuleInstance> {
    let env = state.env.kernel_env();
    let delta = &state.root.universe_params;
    let selected_side = match site {
        RewriteSite::EqTargetLeft => &old_eq_target.lhs,
        RewriteSite::EqTargetRight => &old_eq_target.rhs,
    };
    let mut result_pattern = resolved.ty;
    let mut pending = Vec::new();
    let mut next_arg = 0;
    let mut next_pattern_meta = 0;
    let mut required_tactic_steps = initial_tactic_steps + 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;

    loop {
        let result_whnf = kernel_whnf_with_budget(
            env,
            ctx,
            delta,
            &result_pattern,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        if parse_eq_target_from_expr(family, &result_whnf).is_some() {
            if next_arg < args.len() {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TooManyApplyArguments,
                    "rewrite arguments remain after the rule conclusion reached Eq",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            result_pattern = result_whnf;
            break;
        }
        let Expr::Pi { ty, body, .. } = result_whnf else {
            return Err(ambiguous_rewrite_rule_diag(
                "rewrite rule type does not reduce to an Eq theorem",
                goal,
            ));
        };
        let Some(arg) = args.get(next_arg) else {
            return Err(ambiguous_rewrite_rule_diag(
                "rewrite rule has unsolved binders before its Eq conclusion",
                goal,
            ));
        };
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        let domain_pattern = Arc::unwrap_or_clone(ty);
        result_pattern = match arg {
            ApplyArg::Term(term) => {
                let (expr, _) =
                    elaborate_apply_term_infer(term, elab_context).map_err(|mut diag| {
                        diag.goal_id = Some(goal.id);
                        diag.meta_id = Some(goal.meta_id);
                        diag
                    })?;
                pending.push(PendingApplyArg::Term {
                    term: term.clone(),
                    domain_pattern,
                });
                instantiate(&body, &expr).map_err(kernel_diag)?
            }
            ApplyArg::Subgoal { .. } => {
                if !contains_pattern_meta(&domain_pattern) {
                    ensure_subgoal_domain_is_prop(
                        state,
                        ctx,
                        goal,
                        &domain_pattern,
                        Some((fuel, goal.id, goal.meta_id)),
                    )?;
                }
                if contains_bound_var(&body, 0) {
                    return Err(MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::InvalidMetaDependency,
                        "rw subgoal arguments cannot occur in dependent result positions",
                    )
                    .with_goal(goal.id)
                    .with_meta(goal.meta_id));
                }
                pending.push(PendingApplyArg::Subgoal { domain_pattern });
                instantiate(&body, &Expr::bvar(0)).map_err(kernel_diag)?
            }
            ApplyArg::InferFromTarget => {
                let id = PatternMetaId(next_pattern_meta);
                next_pattern_meta += 1;
                pending.push(PendingApplyArg::InferFromTarget { id, domain_pattern });
                instantiate(&body, &pattern_meta_expr(id)).map_err(kernel_diag)?
            }
        };
        next_arg += 1;
    }

    let infer_ids = pending
        .iter()
        .filter_map(|arg| match arg {
            PendingApplyArg::InferFromTarget { id, .. } => Some(*id),
            PendingApplyArg::Term { .. } | PendingApplyArg::Subgoal { .. } => None,
        })
        .collect::<Vec<_>>();
    let mut solutions = BTreeMap::new();
    let pattern_eq = parse_eq_target_from_expr(family, &result_pattern).ok_or_else(|| {
        ambiguous_rewrite_rule_diag("rewrite rule conclusion is not an Eq theorem", goal)
    })?;
    match_apply_pattern(
        env,
        ctx,
        delta,
        &pattern_eq.ty,
        &old_eq_target.ty,
        true,
        &mut solutions,
        Some((fuel, goal.id, goal.meta_id)),
    )
    .map_err(|err| {
        rewrite_match_error_or_ambiguous(
            err,
            "rewrite rule Eq type does not match target Eq type",
            goal,
        )
    })?;
    let from_pattern = rewrite_rule_from_side(&pattern_eq, direction);
    match_apply_pattern(
        env,
        ctx,
        delta,
        from_pattern,
        selected_side,
        true,
        &mut solutions,
        Some((fuel, goal.id, goal.meta_id)),
    )
    .map_err(|err| {
        rewrite_match_error_or_ambiguous(
            err,
            "rewrite rule selected side does not match target",
            goal,
        )
    })?;
    for id in &infer_ids {
        if !solutions.contains_key(id) {
            return Err(ambiguous_rewrite_rule_diag(
                "rewrite inferred argument was not uniquely solved",
                goal,
            ));
        }
    }
    let result_after_solutions =
        replace_pattern_metas(&result_pattern, &solutions).map_err(|_| {
            ambiguous_rewrite_rule_diag(
                "rewrite rule still contains unresolved inferred arguments",
                goal,
            )
        })?;
    if contains_pattern_meta(&result_after_solutions) {
        return Err(ambiguous_rewrite_rule_diag(
            "rewrite rule still contains unresolved inferred arguments",
            goal,
        ));
    }
    let eq_target =
        parse_eq_target_from_expr(family, &result_after_solutions).ok_or_else(|| {
            ambiguous_rewrite_rule_diag("rewrite instantiated result is not an Eq theorem", goal)
        })?;
    let selected_from = rewrite_rule_from_side(&eq_target, direction);
    if !kernel_is_defeq_with_budget(
        env,
        ctx,
        delta,
        &eq_target.ty,
        &old_eq_target.ty,
        fuel,
        goal.id,
        goal.meta_id,
    )? || !kernel_is_defeq_with_budget(
        env,
        ctx,
        delta,
        selected_from,
        selected_side,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Err(ambiguous_rewrite_rule_diag(
            "rewrite instantiated Eq theorem is not applicable to the selected side",
            goal,
        ));
    }

    let mut checked_args = Vec::new();
    for pending_arg in pending {
        let checked_arg = match pending_arg {
            PendingApplyArg::Term {
                term,
                domain_pattern,
            } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions).map_err(|_| {
                    ambiguous_rewrite_rule_diag("rewrite term argument domain is unresolved", goal)
                })?;
                let checked = npa_frontend::elaborate_machine_term_check(
                    term.source(),
                    elab_context,
                    &domain,
                    &npa_frontend::MachineCompileOptions::default(),
                )
                .map_err(|err| {
                    let mut diag = machine_term_elaboration_diag(err);
                    diag.goal_id = Some(goal.id);
                    diag.meta_id = Some(goal.meta_id);
                    diag
                })?;
                CheckedApplyArg::Core(checked.expr)
            }
            PendingApplyArg::Subgoal { domain_pattern } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions).map_err(|_| {
                    ambiguous_rewrite_rule_diag("rewrite subgoal domain is unresolved", goal)
                })?;
                ensure_subgoal_domain_is_prop(
                    state,
                    ctx,
                    goal,
                    &domain,
                    Some((fuel, goal.id, goal.meta_id)),
                )?;
                CheckedApplyArg::Subgoal(domain)
            }
            PendingApplyArg::InferFromTarget { id, domain_pattern } => {
                let domain = replace_pattern_metas(&domain_pattern, &solutions).map_err(|_| {
                    ambiguous_rewrite_rule_diag(
                        "rewrite inferred argument domain is unresolved",
                        goal,
                    )
                })?;
                let inferred = solutions.get(&id).ok_or_else(|| {
                    ambiguous_rewrite_rule_diag("rewrite inferred argument is missing", goal)
                })?;
                kernel_check_with_budget(
                    env,
                    ctx,
                    delta,
                    inferred,
                    &domain,
                    fuel,
                    goal.id,
                    goal.meta_id,
                )?;
                CheckedApplyArg::Core(inferred.clone())
            }
        };
        checked_args.push(checked_arg);
    }

    let mut proof = resolved.proof;
    let mut new_goal_specs = Vec::new();
    for checked_arg in checked_args {
        let proof_arg = match checked_arg {
            CheckedApplyArg::Core(expr) => ProofExpr::Core(expr),
            CheckedApplyArg::Subgoal(domain) => {
                let meta_id = MetaVarId(state.metas.next_id + new_goal_specs.len() as u64);
                new_goal_specs.push(MachineNewGoalSpec::new(goal.context.clone(), domain));
                ProofExpr::Meta(meta_id)
            }
        };
        proof = ProofExpr::app(proof, proof_arg);
    }

    Ok(RewriteRuleInstance {
        proof,
        eq_target,
        new_goal_specs,
        required_tactic_steps,
    })
}

fn ambiguous_rewrite_rule_diag(message: &str, goal: &MachineGoal) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::AmbiguousRewriteRule, message)
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
}

fn rewrite_match_error_or_ambiguous(
    err: MachineTacticDiagnostic,
    message: &str,
    goal: &MachineGoal,
) -> MachineTacticDiagnostic {
    if err.kind == MachineTacticDiagnosticKind::AmbiguousApplyArgument {
        ambiguous_rewrite_rule_diag(message, goal)
    } else {
        attach_goal_meta(err, goal.id, goal.meta_id)
    }
}

fn whnf_eq_target(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedEqFamily,
    fuel: &TacticRunFuel,
) -> Result<EqTarget> {
    let target_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &goal.target,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    parse_eq_target_from_expr(family, &target_whnf).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ExpectedEqTarget,
            "rw/simp-lite requires the goal target to reduce to the resolved Eq family",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&goal.target),
            &core_expr_canonical_bytes(&target_whnf),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
    })
}

fn parse_eq_target_from_expr(family: &ResolvedEqFamily, expr: &Expr) -> Option<EqTarget> {
    let (head, args) = collect_apps(expr);
    let Expr::Const { name, levels } = head else {
        return None;
    };
    if name != family.eq_name.as_dotted() || levels.len() != 1 || args.len() != 3 {
        return None;
    }
    Some(EqTarget {
        levels,
        ty: args[0].clone(),
        lhs: args[1].clone(),
        rhs: args[2].clone(),
        expr: expr.clone(),
    })
}

fn mk_eq_expr(family: &ResolvedEqFamily, levels: &[Level], ty: Expr, lhs: Expr, rhs: Expr) -> Expr {
    Expr::apps(
        Expr::konst(family.eq_name.as_dotted(), levels.to_vec()),
        vec![ty, lhs, rhs],
    )
}

fn mk_eq_refl_expr(family: &ResolvedEqFamily, levels: &[Level], ty: Expr, value: Expr) -> Expr {
    Expr::apps(
        Expr::konst(family.refl_name.as_dotted(), levels.to_vec()),
        vec![ty, value],
    )
}

fn rewrite_rule_from_side(eq_target: &EqTarget, direction: RewriteDirection) -> &Expr {
    match direction {
        RewriteDirection::Forward => &eq_target.lhs,
        RewriteDirection::Backward => &eq_target.rhs,
    }
}

fn rewrite_rule_to_side(eq_target: &EqTarget, direction: RewriteDirection) -> &Expr {
    match direction {
        RewriteDirection::Forward => &eq_target.rhs,
        RewriteDirection::Backward => &eq_target.lhs,
    }
}

fn rewrite_eq_target_expr(
    family: &ResolvedEqFamily,
    old_eq_target: &EqTarget,
    rule_eq_target: &EqTarget,
    direction: RewriteDirection,
    site: RewriteSite,
) -> Expr {
    let replacement = rewrite_rule_to_side(rule_eq_target, direction).clone();
    let (lhs, rhs) = match site {
        RewriteSite::EqTargetLeft => (replacement, old_eq_target.rhs.clone()),
        RewriteSite::EqTargetRight => (old_eq_target.lhs.clone(), replacement),
    };
    mk_eq_expr(
        family,
        &old_eq_target.levels,
        old_eq_target.ty.clone(),
        lhs,
        rhs,
    )
}

fn mk_rewrite_transport(
    family: &ResolvedEqFamily,
    old_eq_target: &EqTarget,
    rule_eq_target: &EqTarget,
    rule_proof: ProofExpr,
    direction: RewriteDirection,
    site: RewriteSite,
    p_new: ProofExpr,
) -> Result<ProofExpr> {
    let from = rewrite_rule_from_side(rule_eq_target, direction).clone();
    let to = rewrite_rule_to_side(rule_eq_target, direction).clone();
    let h_to_from = match direction {
        RewriteDirection::Forward => mk_eq_symm(family, rule_eq_target, rule_proof)?,
        RewriteDirection::Backward => rule_proof,
    };
    let motive = rewrite_motive_expr(family, old_eq_target, &to, site)?;
    let mut proof = ProofExpr::Core(Expr::konst(
        family.rec_name.as_dotted(),
        vec![old_eq_target.levels[0].clone(), Level::zero()],
    ));
    for arg in [
        ProofExpr::Core(old_eq_target.ty.clone()),
        ProofExpr::Core(to),
        ProofExpr::Core(motive),
        p_new,
        ProofExpr::Core(from),
        h_to_from,
    ] {
        proof = ProofExpr::app(proof, arg);
    }
    Ok(proof)
}

fn mk_eq_symm(
    family: &ResolvedEqFamily,
    eq_target: &EqTarget,
    proof: ProofExpr,
) -> Result<ProofExpr> {
    let level = eq_target.levels[0].clone();
    let ty_shift_1 = shift(&eq_target.ty, 1, 0).map_err(kernel_diag)?;
    let lhs_shift_1 = shift(&eq_target.lhs, 1, 0).map_err(kernel_diag)?;
    let ty_shift_2 = shift(&eq_target.ty, 2, 0).map_err(kernel_diag)?;
    let lhs_shift_2 = shift(&eq_target.lhs, 2, 0).map_err(kernel_diag)?;
    let motive = Expr::lam(
        "b",
        eq_target.ty.clone(),
        Expr::lam(
            "_",
            mk_eq_expr(
                family,
                &eq_target.levels,
                ty_shift_1,
                lhs_shift_1,
                Expr::bvar(0),
            ),
            mk_eq_expr(
                family,
                &eq_target.levels,
                ty_shift_2,
                Expr::bvar(1),
                lhs_shift_2,
            ),
        ),
    );
    let minor = mk_eq_refl_expr(
        family,
        &eq_target.levels,
        eq_target.ty.clone(),
        eq_target.lhs.clone(),
    );
    let mut symm = ProofExpr::Core(Expr::konst(
        family.rec_name.as_dotted(),
        vec![level, Level::zero()],
    ));
    for arg in [
        ProofExpr::Core(eq_target.ty.clone()),
        ProofExpr::Core(eq_target.lhs.clone()),
        ProofExpr::Core(motive),
        ProofExpr::Core(minor),
        ProofExpr::Core(eq_target.rhs.clone()),
        proof,
    ] {
        symm = ProofExpr::app(symm, arg);
    }
    Ok(symm)
}

fn rewrite_motive_expr(
    family: &ResolvedEqFamily,
    old_eq_target: &EqTarget,
    to: &Expr,
    site: RewriteSite,
) -> Result<Expr> {
    let ty_shift_1 = shift(&old_eq_target.ty, 1, 0).map_err(kernel_diag)?;
    let to_shift_1 = shift(to, 1, 0).map_err(kernel_diag)?;
    let ty_shift_2 = shift(&old_eq_target.ty, 2, 0).map_err(kernel_diag)?;
    let lhs_shift_2 = shift(&old_eq_target.lhs, 2, 0).map_err(kernel_diag)?;
    let rhs_shift_2 = shift(&old_eq_target.rhs, 2, 0).map_err(kernel_diag)?;
    let body = match site {
        RewriteSite::EqTargetLeft => mk_eq_expr(
            family,
            &old_eq_target.levels,
            ty_shift_2,
            Expr::bvar(1),
            rhs_shift_2,
        ),
        RewriteSite::EqTargetRight => mk_eq_expr(
            family,
            &old_eq_target.levels,
            ty_shift_2,
            lhs_shift_2,
            Expr::bvar(1),
        ),
    };
    Ok(Expr::lam(
        "x",
        old_eq_target.ty.clone(),
        Expr::lam(
            "_",
            mk_eq_expr(
                family,
                &old_eq_target.levels,
                ty_shift_1,
                to_shift_1,
                Expr::bvar(0),
            ),
            body,
        ),
    ))
}

fn run_subst_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: SubstPayload,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    let family = state.env.eq_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "subst requires a resolved Eq family",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id)
    })?;
    let paths = normalized_occurrence_paths(&payload.occurrences)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    ensure_rewrite_fuel(budget, paths.len() as u64, goal.id, goal.meta_id)?;

    let equality_index =
        resolve_unique_local_index(&goal, &payload.equality_local, "subst equality local")?;
    let fuel = TacticRunFuel::new(budget);
    match payload.target {
        TacticTarget::Goal => {
            let ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &goal.context,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            let rule = local_eq_target_with_proof(
                state,
                &goal,
                &ctx,
                goal.context.len(),
                equality_index,
                family,
                &fuel,
                "subst equality local",
            )?;
            let old_eq_target = whnf_eq_target(state, &goal, &ctx, family, &fuel)?;
            let sites = subst_sites_for_paths(
                state,
                &goal,
                &ctx,
                family,
                &old_eq_target,
                &rule.eq_target,
                payload.direction,
                &paths,
                &fuel,
            )?;
            let (new_eq_target, steps) = build_subst_rewrite_steps(
                state,
                &goal,
                &ctx,
                family,
                old_eq_target,
                &rule,
                payload.direction,
                &sites,
                &fuel,
            )?;
            let final_meta = MetaVarId(state.metas.next_id);
            let proof = mk_nested_rewrite_proof_from_meta(family, final_meta, steps)?;
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(
                    goal.context.clone(),
                    new_eq_target.expr,
                )],
                budget,
                2_u64.saturating_add(paths.len() as u64),
                &fuel,
            )
        }
        TacticTarget::Local { name } => {
            let target_index = resolve_unique_local_index(&goal, &name, "subst target local")?;
            if target_index == equality_index {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaDependency,
                    "subst equality local cannot also be the local whose type is rewritten",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            if equality_index > target_index {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaDependency,
                    "subst equality local must be available in the target local prefix context",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            ensure_generalize_local_transport_supported(&goal, target_index)?;

            let prefix = goal.context[..target_index].to_vec();
            let prefix_ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &prefix,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            let target_local = goal.context[target_index].clone();
            let old_prefix_eq = eq_target_from_type_with_ctx(
                state,
                &goal,
                &prefix_ctx,
                family,
                &target_local.ty,
                &fuel,
                "subst target local type",
            )?;
            let prefix_rule = local_eq_target_with_proof(
                state,
                &goal,
                &prefix_ctx,
                prefix.len(),
                equality_index,
                family,
                &fuel,
                "subst equality local",
            )?;
            let sites = subst_sites_for_paths(
                state,
                &goal,
                &prefix_ctx,
                family,
                &old_prefix_eq,
                &prefix_rule.eq_target,
                payload.direction,
                &paths,
                &fuel,
            )?;
            let (new_prefix_eq, _) = build_subst_rewrite_steps(
                state,
                &goal,
                &prefix_ctx,
                family,
                old_prefix_eq,
                &prefix_rule,
                payload.direction,
                &sites,
                &fuel,
            )?;

            let full_ctx = local_context_to_ctx_with_budget(
                state.env.kernel_env(),
                &goal.context,
                &state.root.universe_params,
                &fuel,
                goal.id,
                goal.meta_id,
            )?;
            let old_full_eq = local_type_eq_target_with_ctx(
                state,
                &goal,
                &full_ctx,
                goal.context.len(),
                target_index,
                family,
                &fuel,
                "subst target local type",
            )?;
            let full_rule = local_eq_target_with_proof(
                state,
                &goal,
                &full_ctx,
                goal.context.len(),
                equality_index,
                family,
                &fuel,
                "subst equality local",
            )?;
            let (_, full_steps) = build_subst_rewrite_steps(
                state,
                &goal,
                &full_ctx,
                family,
                old_full_eq,
                &full_rule,
                payload.direction,
                &sites,
                &fuel,
            )?;
            let transformed_local = mk_forward_rewrite_transport_from_core(
                family,
                ProofExpr::Core(local_bvar(goal.context.len(), target_index)),
                full_steps,
            )?;
            let proof = local_rebind_parent_skeleton_with_replacement(
                &goal,
                target_index,
                transformed_local,
                MetaVarId(state.metas.next_id),
            );
            let new_target = rebind_target_without_extra_local(
                target_local.name,
                new_prefix_eq.expr,
                &goal.context[target_index + 1..],
                goal.target.clone(),
            );
            assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                vec![MachineNewGoalSpec::new(prefix, new_target)],
                budget,
                3_u64
                    .saturating_add(paths.len() as u64)
                    .saturating_add((goal.context.len() - target_index) as u64),
                &fuel,
            )
        }
    }
}

#[derive(Clone, Debug)]
struct LocalEqRule {
    eq_target: EqTarget,
    proof: ProofExpr,
}

#[allow(clippy::too_many_arguments)]
fn local_eq_target_with_proof(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    context_len: usize,
    local_index: usize,
    family: &ResolvedEqFamily,
    fuel: &TacticRunFuel,
    label: &'static str,
) -> Result<LocalEqRule> {
    let proof_expr = local_bvar(context_len, local_index);
    let ty = kernel_infer_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &proof_expr,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let eq_target = eq_target_from_type_with_ctx(state, goal, ctx, family, &ty, fuel, label)?;
    Ok(LocalEqRule {
        eq_target,
        proof: ProofExpr::Core(proof_expr),
    })
}

#[allow(clippy::too_many_arguments)]
fn local_type_eq_target_with_ctx(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    context_len: usize,
    local_index: usize,
    family: &ResolvedEqFamily,
    fuel: &TacticRunFuel,
    label: &'static str,
) -> Result<EqTarget> {
    let local_expr = local_bvar(context_len, local_index);
    let local_ty = kernel_infer_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &local_expr,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    eq_target_from_type_with_ctx(state, goal, ctx, family, &local_ty, fuel, label)
}

fn eq_target_from_type_with_ctx(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedEqFamily,
    ty: &Expr,
    fuel: &TacticRunFuel,
    label: &'static str,
) -> Result<EqTarget> {
    let whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    parse_eq_target_from_expr(family, &whnf).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ExpectedEqTarget,
            format!("{label} must reduce to the resolved Eq family"),
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(ty),
            &core_expr_canonical_bytes(&whnf),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
    })
}

#[allow(clippy::too_many_arguments)]
fn subst_sites_for_paths(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedEqFamily,
    old_eq_target: &EqTarget,
    rule_eq_target: &EqTarget,
    direction: RewriteDirection,
    paths: &[OccurrencePath],
    fuel: &TacticRunFuel,
) -> Result<Vec<RewriteSite>> {
    let mut current = old_eq_target.clone();
    let mut sites = Vec::with_capacity(paths.len());
    for path in paths {
        let site = subst_site_for_path(
            state,
            goal,
            ctx,
            &current,
            rule_eq_target,
            direction,
            path,
            fuel,
        )?;
        ensure_subst_selected_side_matches(
            state,
            goal,
            ctx,
            &current,
            rule_eq_target,
            direction,
            site,
            fuel,
        )?;
        let new_expr = rewrite_eq_target_expr(family, &current, rule_eq_target, direction, site);
        current = parse_eq_target_from_expr(family, &new_expr).ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidEqFamily,
                "subst produced a target that no longer parses as the resolved Eq family",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
        sites.push(site);
    }
    Ok(sites)
}

#[allow(clippy::too_many_arguments)]
fn subst_site_for_path(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    old_eq_target: &EqTarget,
    rule_eq_target: &EqTarget,
    direction: RewriteDirection,
    path: &OccurrencePath,
    fuel: &TacticRunFuel,
) -> Result<RewriteSite> {
    match path.indices.as_slice() {
        [0] => Ok(RewriteSite::EqTargetLeft),
        [1] => Ok(RewriteSite::EqTargetRight),
        [] => {
            let from = rewrite_rule_from_side(rule_eq_target, direction);
            if kernel_is_defeq_with_budget(
                state.env.kernel_env(),
                ctx,
                &state.root.universe_params,
                &old_eq_target.lhs,
                from,
                fuel,
                goal.id,
                goal.meta_id,
            )? {
                return Ok(RewriteSite::EqTargetLeft);
            }
            if kernel_is_defeq_with_budget(
                state.env.kernel_env(),
                ctx,
                &state.root.universe_params,
                &old_eq_target.rhs,
                from,
                fuel,
                goal.id,
                goal.meta_id,
            )? {
                return Ok(RewriteSite::EqTargetRight);
            }
            Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TypeMismatch,
                "subst could not find the selected equality side for the requested orientation",
            )
            .with_expected_actual_payloads(
                DiagnosticPayloadKind::Expr,
                &core_expr_canonical_bytes(from),
                &core_expr_canonical_bytes(&old_eq_target.expr),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id))
        }
        other => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            format!(
                "subst occurrence paths are Eq-side paths: [] for first matching side, [0] for lhs, or [1] for rhs; got {other:?}"
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
    }
}

#[allow(clippy::too_many_arguments)]
fn build_subst_rewrite_steps(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedEqFamily,
    old_eq_target: EqTarget,
    rule: &LocalEqRule,
    direction: RewriteDirection,
    sites: &[RewriteSite],
    fuel: &TacticRunFuel,
) -> Result<(EqTarget, Vec<RewriteStep>)> {
    let mut current = old_eq_target;
    let mut steps = Vec::with_capacity(sites.len());
    for site in sites {
        ensure_subst_selected_side_matches(
            state,
            goal,
            ctx,
            &current,
            &rule.eq_target,
            direction,
            *site,
            fuel,
        )?;
        let new_expr = rewrite_eq_target_expr(family, &current, &rule.eq_target, direction, *site);
        let new_eq = parse_eq_target_from_expr(family, &new_expr).ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidEqFamily,
                "subst produced a target that no longer parses as the resolved Eq family",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
        steps.push(RewriteStep {
            old_eq_target: current,
            rule_eq_target: rule.eq_target.clone(),
            rule_proof: rule.proof.clone(),
            direction,
            site: *site,
        });
        current = new_eq;
    }
    Ok((current, steps))
}

#[allow(clippy::too_many_arguments)]
fn ensure_subst_selected_side_matches(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    old_eq_target: &EqTarget,
    rule_eq_target: &EqTarget,
    direction: RewriteDirection,
    site: RewriteSite,
    fuel: &TacticRunFuel,
) -> Result<()> {
    let selected = match site {
        RewriteSite::EqTargetLeft => &old_eq_target.lhs,
        RewriteSite::EqTargetRight => &old_eq_target.rhs,
    };
    let from = rewrite_rule_from_side(rule_eq_target, direction);
    if kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        selected,
        from,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Ok(());
    }
    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::TypeMismatch,
        "subst equality orientation does not match the selected target side",
    )
    .with_expected_actual_payloads(
        DiagnosticPayloadKind::Expr,
        &core_expr_canonical_bytes(from),
        &core_expr_canonical_bytes(selected),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id))
}

fn reverse_rewrite_direction(direction: RewriteDirection) -> RewriteDirection {
    match direction {
        RewriteDirection::Forward => RewriteDirection::Backward,
        RewriteDirection::Backward => RewriteDirection::Forward,
    }
}

fn mk_forward_rewrite_transport_from_core(
    family: &ResolvedEqFamily,
    mut proof: ProofExpr,
    steps: Vec<RewriteStep>,
) -> Result<ProofExpr> {
    for step in steps {
        let new_eq_target = parse_eq_target_from_expr(
            family,
            &rewrite_eq_target_expr(
                family,
                &step.old_eq_target,
                &step.rule_eq_target,
                step.direction,
                step.site,
            ),
        )
        .ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidEqFamily,
                "subst transport produced a target that no longer parses as Eq",
            )
        })?;
        proof = mk_rewrite_transport(
            family,
            &new_eq_target,
            &step.rule_eq_target,
            step.rule_proof,
            reverse_rewrite_direction(step.direction),
            step.site,
            proof,
        )?;
    }
    Ok(proof)
}

fn local_rebind_parent_skeleton_with_replacement(
    goal: &MachineGoal,
    local_index: usize,
    replacement_arg: ProofExpr,
    meta_id: MetaVarId,
) -> ProofExpr {
    let mut proof = ProofExpr::app(ProofExpr::Meta(meta_id), replacement_arg);
    for index in (local_index + 1)..goal.context.len() {
        proof = ProofExpr::app(
            proof,
            ProofExpr::Core(local_bvar(goal.context.len(), index)),
        );
    }
    proof
}

fn run_congr_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: CongrPayload,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    if !matches!(payload.target, TacticTarget::Goal) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            "congr currently supports goal equality targets; local congruence requires dependent context transport",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let max_depth = payload.max_depth.unwrap_or(1);
    if max_depth == 0 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::TacticStep,
            },
            "congr max_depth is zero before the application target is decomposed",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    ensure_count_budget(
        "congr new goal",
        1,
        payload.max_new_goals.unwrap_or_default(),
        TacticFuelKind::MetaAllocation,
        &goal,
    )?;
    let family = state.env.eq_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "congr requires a resolved Eq family",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id)
    })?;
    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal.id,
        goal.meta_id,
    )?;
    let eq_target = whnf_eq_target(state, &goal, &ctx, family, &fuel)?;
    let assembly = assemble_congr_tactic(state, &goal, &ctx, family, eq_target, &fuel)?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        assembly.proof,
        assembly.new_goal_specs,
        budget,
        3,
        &fuel,
    )
}

fn assemble_congr_tactic(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedEqFamily,
    eq_target: EqTarget,
    fuel: &TacticRunFuel,
) -> Result<ConstructorAssembly> {
    let (lhs_fun, lhs_arg) = decompose_congr_application(&eq_target.lhs, goal)?;
    let (rhs_fun, rhs_arg) = decompose_congr_application(&eq_target.rhs, goal)?;
    if !kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &lhs_fun,
        &rhs_fun,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "congr requires both sides to apply definitionally equal functions",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&lhs_fun),
            &core_expr_canonical_bytes(&rhs_fun),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let fun_ty = kernel_infer_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &lhs_fun,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let fun_ty_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &fun_ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let Expr::Pi {
        ty: arg_ty,
        body: result_body,
        ..
    } = fun_ty_whnf
    else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ExpectedFunctionType,
            "congr target head does not reduce to a function type",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    let arg_ty = Arc::unwrap_or_clone(arg_ty);
    let result_body = Arc::unwrap_or_clone(result_body);
    if contains_bound_var(&result_body, 0) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            "congr rejects dependent function targets until dependent transport is available",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    kernel_check_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &lhs_arg,
        &arg_ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    kernel_check_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &rhs_arg,
        &arg_ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let result_ty = instantiate(&result_body, &lhs_arg).map_err(kernel_diag)?;
    if !kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &eq_target.ty,
        &result_ty,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "congr result type does not match the goal Eq type",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&eq_target.ty),
            &core_expr_canonical_bytes(&result_ty),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let lhs_rebuilt = Expr::app(lhs_fun.clone(), lhs_arg.clone());
    let rhs_rebuilt = Expr::app(lhs_fun.clone(), rhs_arg.clone());
    if !kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &eq_target.lhs,
        &lhs_rebuilt,
        fuel,
        goal.id,
        goal.meta_id,
    )? || !kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &eq_target.rhs,
        &rhs_rebuilt,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "congr could not rebuild the goal equality from the decomposed application",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let arg_level = sort_level_of_type_with_budget(state, goal, ctx, &arg_ty, fuel)?;
    let arg_eq_target = mk_eq_expr(
        family,
        std::slice::from_ref(&arg_level),
        arg_ty.clone(),
        lhs_arg.clone(),
        rhs_arg.clone(),
    );
    let child_meta = MetaVarId(state.metas.next_id);
    let shifted_target = shift_eq_target(&eq_target, 1)?;
    let proof_body = mk_congr_arg_proof(
        family,
        &shifted_target,
        arg_level.clone(),
        shift(&arg_ty, 1, 0).map_err(kernel_diag)?,
        shift(&lhs_fun, 1, 0).map_err(kernel_diag)?,
        shift(&lhs_arg, 1, 0).map_err(kernel_diag)?,
        shift(&rhs_arg, 1, 0).map_err(kernel_diag)?,
        ProofExpr::Core(Expr::bvar(0)),
    )?;
    let proof = ProofExpr::app(
        ProofExpr::lam("h_congr", arg_eq_target.clone(), proof_body),
        ProofExpr::Meta(child_meta),
    );
    Ok(ConstructorAssembly {
        proof,
        new_goal_specs: vec![MachineNewGoalSpec::new(goal.context.clone(), arg_eq_target)],
        required_tactic_steps: 3,
    })
}

fn shift_eq_target(eq_target: &EqTarget, amount: i32) -> Result<EqTarget> {
    Ok(EqTarget {
        levels: eq_target.levels.clone(),
        ty: shift(&eq_target.ty, amount, 0).map_err(kernel_diag)?,
        lhs: shift(&eq_target.lhs, amount, 0).map_err(kernel_diag)?,
        rhs: shift(&eq_target.rhs, amount, 0).map_err(kernel_diag)?,
        expr: shift(&eq_target.expr, amount, 0).map_err(kernel_diag)?,
    })
}

fn decompose_congr_application(expr: &Expr, goal: &MachineGoal) -> Result<(Expr, Expr)> {
    match expr {
        Expr::App(fun, arg) => Ok((
            Arc::unwrap_or_clone(fun.clone()),
            Arc::unwrap_or_clone(arg.clone()),
        )),
        _ => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ExpectedFunctionType,
            "congr requires both equality sides to be applications",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
    }
}

fn sort_level_of_type_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    ty: &Expr,
    fuel: &TacticRunFuel,
) -> Result<Level> {
    let sort = kernel_infer_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let sort_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &sort,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    match sort_whnf {
        Expr::Sort(level) => Ok(level),
        actual => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "congr argument type must itself have a sort type",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&Expr::sort(Level::zero())),
            &core_expr_canonical_bytes(&actual),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
    }
}

#[allow(clippy::too_many_arguments)]
fn mk_congr_arg_proof(
    family: &ResolvedEqFamily,
    target: &EqTarget,
    arg_level: Level,
    arg_ty: Expr,
    fun: Expr,
    lhs_arg: Expr,
    rhs_arg: Expr,
    child_proof: ProofExpr,
) -> Result<ProofExpr> {
    let arg_ty_shift_1 = shift(&arg_ty, 1, 0).map_err(kernel_diag)?;
    let lhs_arg_shift_1 = shift(&lhs_arg, 1, 0).map_err(kernel_diag)?;
    let target_ty_shift_2 = shift(&target.ty, 2, 0).map_err(kernel_diag)?;
    let target_lhs_shift_2 = shift(&target.lhs, 2, 0).map_err(kernel_diag)?;
    let fun_shift_2 = shift(&fun, 2, 0).map_err(kernel_diag)?;
    let motive = Expr::lam(
        "b",
        arg_ty.clone(),
        Expr::lam(
            "_",
            mk_eq_expr(
                family,
                std::slice::from_ref(&arg_level),
                arg_ty_shift_1,
                lhs_arg_shift_1,
                Expr::bvar(0),
            ),
            mk_eq_expr(
                family,
                &target.levels,
                target_ty_shift_2,
                target_lhs_shift_2,
                Expr::app(fun_shift_2, Expr::bvar(1)),
            ),
        ),
    );
    let minor = mk_eq_refl_expr(
        family,
        &target.levels,
        target.ty.clone(),
        target.lhs.clone(),
    );
    let mut proof = ProofExpr::Core(Expr::konst(
        family.rec_name.as_dotted(),
        vec![arg_level, Level::zero()],
    ));
    for arg in [
        ProofExpr::Core(arg_ty),
        ProofExpr::Core(lhs_arg),
        ProofExpr::Core(motive),
        ProofExpr::Core(minor),
        ProofExpr::Core(rhs_arg),
        child_proof,
    ] {
        proof = ProofExpr::app(proof, arg);
    }
    Ok(proof)
}

fn run_contradiction_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: ContradictionPayload,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    match payload.mode {
        ContradictionMode::Local { major_local } => {
            let result = run_cases_tactic_with_budget(
                state,
                goal_id,
                contradiction_cases_payload(&major_local),
                budget,
            );
            result.map_err(|diag| {
                if contradiction_candidate_rejection(&diag) {
                    no_supported_contradiction_diag(&goal, Some(&major_local))
                } else {
                    diag
                }
            })
        }
        ContradictionMode::Auto => {
            for local in &goal.context {
                if local.value.is_some() {
                    continue;
                }
                match run_cases_tactic_with_budget(
                    state,
                    goal_id,
                    contradiction_cases_payload(&local.name),
                    budget,
                ) {
                    Ok(success) => return Ok(success),
                    Err(diag) if contradiction_candidate_rejection(&diag) => continue,
                    Err(diag) => return Err(diag),
                }
            }
            Err(no_supported_contradiction_diag(&goal, None))
        }
    }
}

fn contradiction_cases_payload(major_local: &str) -> CasesPayload<MachineTermSource> {
    CasesPayload {
        major_local: major_local.to_owned(),
        motive: None,
        branch_names: Vec::new(),
        max_new_goals: Some(0),
    }
}

fn contradiction_candidate_rejection(diag: &MachineTacticDiagnostic) -> bool {
    matches!(
        diag.kind,
        MachineTacticDiagnosticKind::TypeMismatch
            | MachineTacticDiagnosticKind::InvalidLocalHead
            | MachineTacticDiagnosticKind::TacticPrimitiveUnavailable
            | MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::MetaAllocation
            }
    )
}

fn no_supported_contradiction_diag(
    goal: &MachineGoal,
    major_local: Option<&str>,
) -> MachineTacticDiagnostic {
    let message = match major_local {
        Some(name) => {
            format!("contradiction local {name:?} is not supported checked impossible evidence")
        }
        None => "contradiction found no supported checked impossible evidence in the local context"
            .to_owned(),
    };
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
        message,
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id)
}

fn ensure_rewrite_fuel(
    budget: TacticBudget,
    needed: u64,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<()> {
    if budget.max_rewrite_steps < needed {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::Rewrite,
            },
            format!(
                "tactic requires {needed} rewrite fuel, remaining rewrite fuel is {}",
                budget.max_rewrite_steps
            ),
        )
        .with_goal(goal_id)
        .with_meta(meta_id));
    }
    Ok(())
}

fn kernel_whnf_with_budget(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    term: &Expr,
    fuel: &TacticRunFuel,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<Expr> {
    let mut remaining = fuel.whnf_steps.get();
    let result = env.whnf_with_fuel_metered(ctx, delta, term, &mut remaining);
    fuel.whnf_steps.set(remaining);
    result.map_err(|err| match err {
        npa_kernel::Error::ResourceLimit { .. } => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::Whnf,
            },
            format!(
                "tactic exhausted WHNF fuel; remaining WHNF fuel is {}",
                fuel.whnf_steps.get()
            ),
        )
        .with_goal(goal_id)
        .with_meta(meta_id),
        err => kernel_diag(err),
    })
}

#[allow(clippy::too_many_arguments)]
fn kernel_is_defeq_with_budget(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    lhs: &Expr,
    rhs: &Expr,
    fuel: &TacticRunFuel,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<bool> {
    let mut remaining = fuel.conversion_steps.get();
    let result = env.is_defeq_with_fuel_metered(ctx, delta, lhs, rhs, &mut remaining);
    fuel.conversion_steps.set(remaining);
    result.map_err(|err| match err {
        npa_kernel::Error::ResourceLimit { .. } => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::Conversion,
            },
            format!(
                "tactic exhausted conversion fuel; remaining conversion fuel is {}",
                fuel.conversion_steps.get()
            ),
        )
        .with_goal(goal_id)
        .with_meta(meta_id),
        err => kernel_diag(err),
    })
}

#[allow(clippy::too_many_arguments)]
fn kernel_infer_with_budget(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    term: &Expr,
    fuel: &TacticRunFuel,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<Expr> {
    let mut whnf_remaining = fuel.whnf_steps.get();
    let mut conversion_remaining = fuel.conversion_steps.get();
    let result = env.infer_with_fuel_metered(
        ctx,
        delta,
        term,
        &mut whnf_remaining,
        &mut conversion_remaining,
    );
    fuel.whnf_steps.set(whnf_remaining);
    fuel.conversion_steps.set(conversion_remaining);
    result.map_err(|err| match err {
        npa_kernel::Error::ResourceLimit { kind } => {
            kernel_resource_limit_diag(kind, fuel, goal_id, meta_id)
        }
        err => kernel_diag(err),
    })
}

#[allow(clippy::too_many_arguments)]
fn kernel_check_with_budget(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    term: &Expr,
    expected: &Expr,
    fuel: &TacticRunFuel,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<()> {
    let mut whnf_remaining = fuel.whnf_steps.get();
    let mut conversion_remaining = fuel.conversion_steps.get();
    let result = env.check_with_fuel_metered(
        ctx,
        delta,
        term,
        expected,
        &mut whnf_remaining,
        &mut conversion_remaining,
    );
    fuel.whnf_steps.set(whnf_remaining);
    fuel.conversion_steps.set(conversion_remaining);
    result.map_err(|err| match err {
        npa_kernel::Error::ResourceLimit { kind } => {
            kernel_resource_limit_diag(kind, fuel, goal_id, meta_id)
        }
        err => kernel_diag(err),
    })
}

#[allow(clippy::too_many_arguments)]
fn kernel_expect_sort_with_budget(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    term: &Expr,
    fuel: &TacticRunFuel,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<()> {
    let ty = kernel_infer_with_budget(env, ctx, delta, term, fuel, goal_id, meta_id)?;
    match kernel_whnf_with_budget(env, ctx, delta, &ty, fuel, goal_id, meta_id)? {
        Expr::Sort(_) => Ok(()),
        actual => Err(kernel_diag(npa_kernel::Error::ExpectedSort { actual })),
    }
}

fn kernel_resource_limit_diag(
    kind: ResourceLimitKind,
    fuel: &TacticRunFuel,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> MachineTacticDiagnostic {
    let (kind, label, remaining) = match kind {
        ResourceLimitKind::Whnf => (TacticFuelKind::Whnf, "WHNF", fuel.whnf_steps.get()),
        ResourceLimitKind::Conversion => (
            TacticFuelKind::Conversion,
            "conversion",
            fuel.conversion_steps.get(),
        ),
        ResourceLimitKind::UniverseConstraints => {
            return kernel_diag(npa_kernel::Error::ResourceLimit { kind });
        }
    };
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::TacticFuelExhausted { kind },
        format!("tactic exhausted {label} fuel; remaining {label} fuel is {remaining}"),
    )
    .with_goal(goal_id)
    .with_meta(meta_id)
}

fn kernel_is_defeq_with_optional_budget(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    lhs: &Expr,
    rhs: &Expr,
    budget_context: Option<KernelFuelContext<'_>>,
) -> Result<bool> {
    match budget_context {
        Some((fuel, goal_id, meta_id)) => {
            kernel_is_defeq_with_budget(env, ctx, delta, lhs, rhs, fuel, goal_id, meta_id)
        }
        None => env.is_defeq(ctx, delta, lhs, rhs).map_err(kernel_diag),
    }
}

fn fuel_to_usize(value: u64) -> usize {
    usize::try_from(value).unwrap_or(usize::MAX)
}

fn run_simp_lite_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    rules: Vec<SimpRuleRef>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_simp_rule_refs(&rules)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    let selected_rules = resolve_simp_lite_allowlist(state, &goal, rules)?;
    let family = state.env.eq_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "simp-lite requires a resolved Eq family",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id)
    })?;
    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let initial_eq_target = whnf_eq_target(state, &goal, &ctx, family, &fuel)?;
    let simp = assemble_simp_lite(
        state,
        &goal,
        &ctx,
        family,
        initial_eq_target,
        &selected_rules,
        budget,
        &fuel,
    )?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        simp.proof,
        simp.new_goal_specs,
        budget,
        simp.required_tactic_steps,
        &fuel,
    )
}

fn run_smt_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    lemmas: Vec<SmtLemmaRef>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_smt_lemma_refs(&lemmas)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    for lemma in &lemmas {
        for level in &lemma.universe_args {
            ensure_level_wf(&state.root.universe_params, level).map_err(|err| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMachineTactic,
                    format!("smt lemma universe argument is not well formed: {err:?}"),
                )
                .with_goal(goal_id)
                .with_meta(goal.meta_id)
            })?;
        }
    }
    let fuel = TacticRunFuel::new(budget);
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;

    if lemmas.is_empty() {
        if let Some(proof) = resolve_smt_local_exact(state, &goal, &ctx, &fuel)? {
            ensure_tactic_step_fuel(budget, 1, goal_id, goal.meta_id)?;
            return assign_goal_with_budget_and_steps(
                state,
                goal_id,
                proof,
                Vec::new(),
                budget,
                0,
                &fuel,
            );
        }
    } else {
        for lemma in &lemmas {
            validate_apply_head_static(state, &goal, &lemma.head, &lemma.universe_args)?;
            let resolved =
                resolve_apply_head(state, &goal, &ctx, &lemma.head, &lemma.universe_args, &fuel)?;
            if kernel_is_defeq_with_budget(
                state.env.kernel_env(),
                &ctx,
                &state.root.universe_params,
                &resolved.ty,
                &goal.target,
                &fuel,
                goal_id,
                goal.meta_id,
            )? {
                ensure_tactic_step_fuel(budget, 1, goal_id, goal.meta_id)?;
                return assign_goal_with_budget_and_steps(
                    state,
                    goal_id,
                    resolved.proof,
                    Vec::new(),
                    budget,
                    0,
                    &fuel,
                );
            }
        }
    }

    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::TypeMismatch,
        "smt could not close the goal from local hypotheses or explicit lemmas",
    )
    .with_goal(goal_id)
    .with_meta(goal.meta_id))
}

fn resolve_smt_local_exact(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    fuel: &TacticRunFuel,
) -> Result<Option<ProofExpr>> {
    for (index, local) in goal.context.iter().enumerate().rev() {
        if local.value.is_some() {
            continue;
        }
        let proof = Expr::bvar((goal.context.len() - 1 - index) as u32);
        let local_ty = kernel_infer_with_budget(
            state.env.kernel_env(),
            ctx,
            &state.root.universe_params,
            &proof,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        if kernel_is_defeq_with_budget(
            state.env.kernel_env(),
            ctx,
            &state.root.universe_params,
            &local_ty,
            &goal.target,
            fuel,
            goal.id,
            goal.meta_id,
        )? {
            return Ok(Some(ProofExpr::Core(proof)));
        }
    }
    Ok(None)
}

fn resolve_simp_lite_allowlist<'a>(
    state: &'a MachineProofState,
    goal: &MachineGoal,
    rules: Vec<SimpRuleRef>,
) -> Result<Vec<&'a ResolvedSimpRule>> {
    let allowlist = canonicalize_simp_rule_refs(rules)?;
    if allowlist.is_empty() {
        return Ok(state.env.simp_registry.rules.iter().collect());
    }
    let mut selected = Vec::new();
    for rule in &allowlist {
        let matches = state
            .env
            .simp_registry
            .rules
            .iter()
            .filter(|candidate| candidate.key == *rule)
            .collect::<Vec<_>>();
        let [resolved] = matches.as_slice() else {
            return Err(if matches.is_empty() {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnknownSimpRule,
                    format!(
                        "simp-lite rule {} with the requested interface hash is not registered",
                        rule.name.as_dotted()
                    ),
                )
                .with_primary_name(rule.name.clone())
            } else {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::AmbiguousSimpRule,
                    format!("simp-lite rule {} is ambiguous", rule.name.as_dotted()),
                )
                .with_primary_name(rule.name.clone())
            }
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        };
        selected.push(*resolved);
    }
    Ok(selected)
}

#[allow(clippy::too_many_arguments)]
fn assemble_simp_lite(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedEqFamily,
    initial_eq_target: EqTarget,
    rules: &[&ResolvedSimpRule],
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<RewriteAssembly> {
    let env = state.env.kernel_env();
    let delta = &state.root.universe_params;
    let mut current_eq = initial_eq_target;
    let mut rewrite_count = 0_u64;
    let mut steps = Vec::new();
    let mut required_tactic_steps = 0_u64;

    loop {
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;

        if kernel_is_defeq_with_budget(
            env,
            ctx,
            delta,
            &current_eq.lhs,
            &current_eq.rhs,
            fuel,
            goal.id,
            goal.meta_id,
        )? {
            let proof = mk_nested_rewrite_proof_from_refl(family, &current_eq, steps)?;
            return Ok(RewriteAssembly {
                proof,
                new_goal_specs: Vec::new(),
                required_tactic_steps,
            });
        }
        if rewrite_count >= state.env.options.max_simp_rewrite_steps {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::SimpStepLimitExceeded,
                "simp-lite reached max_simp_rewrite_steps before reaching a fixed point",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }

        let current_hash = core_expr_hash(&current_eq.expr);
        let mut progress = None;
        'scan: for rule in rules {
            for site in [RewriteSite::EqTargetLeft, RewriteSite::EqTargetRight] {
                let Some(universe_args) = solve_simp_universe_args(rule, &current_eq, site) else {
                    continue;
                };
                let instance = match instantiate_simp_rule(
                    state,
                    goal,
                    ctx,
                    family,
                    rule,
                    &universe_args,
                    &current_eq,
                    rule.key.direction,
                    site,
                    budget,
                    fuel,
                    required_tactic_steps,
                ) {
                    Ok(instance) => instance,
                    Err(err) if simp_candidate_not_applicable(&err) => continue,
                    Err(err) => return Err(err),
                };
                required_tactic_steps = instance.required_tactic_steps;
                if !instance.new_goal_specs.is_empty() {
                    continue;
                }
                let new_target = rewrite_eq_target_expr(
                    family,
                    &current_eq,
                    &instance.eq_target,
                    rule.key.direction,
                    site,
                );
                let new_whnf = kernel_whnf_with_budget(
                    env,
                    ctx,
                    delta,
                    &new_target,
                    fuel,
                    goal.id,
                    goal.meta_id,
                )?;
                let Some(new_eq) = parse_eq_target_from_expr(family, &new_whnf) else {
                    continue;
                };
                if core_expr_hash(&new_eq.expr) == current_hash {
                    continue;
                }
                progress = Some((rule.key.direction, site, instance, new_eq));
                break 'scan;
            }
        }

        let Some((direction, site, instance, new_eq)) = progress else {
            if rewrite_count == 0 {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::SimpNoProgress,
                    "simp-lite could not close by Eq.refl and no registered rule made progress",
                )
                .with_goal(goal.id)
                .with_meta(goal.meta_id));
            }
            required_tactic_steps += 1;
            ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
            let final_meta = MetaVarId(state.metas.next_id);
            let proof = mk_nested_rewrite_proof_from_meta(family, final_meta, steps)?;
            return Ok(RewriteAssembly {
                proof,
                new_goal_specs: vec![MachineNewGoalSpec::new(
                    goal.context.clone(),
                    current_eq.expr,
                )],
                required_tactic_steps,
            });
        };

        ensure_rewrite_fuel(budget, rewrite_count + 1, goal.id, goal.meta_id)?;
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        steps.push(RewriteStep {
            old_eq_target: current_eq,
            rule_eq_target: instance.eq_target,
            rule_proof: instance.proof,
            direction,
            site,
        });
        rewrite_count += 1;
        current_eq = new_eq;
    }
}

fn simp_candidate_not_applicable(err: &MachineTacticDiagnostic) -> bool {
    matches!(
        err.kind,
        MachineTacticDiagnosticKind::AmbiguousRewriteRule
            | MachineTacticDiagnosticKind::AmbiguousApplyArgument
            | MachineTacticDiagnosticKind::TypeMismatch
    )
}

#[derive(Clone, Debug)]
struct InductionNatAssembly {
    proof: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    required_tactic_steps: u64,
}

#[derive(Clone, Debug)]
struct GeneralInductionAssembly {
    proof: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    required_tactic_steps: u64,
}

#[derive(Clone, Debug)]
struct GeneralizedInductionLocal {
    index: usize,
    local: MachineLocalDecl,
}

#[derive(Clone, Debug)]
struct CasesTarget {
    index: usize,
    local: MachineLocalDecl,
    inductive: String,
    levels: Vec<Level>,
    params: Vec<Expr>,
    indices: Vec<Expr>,
    data: npa_kernel::InductiveDecl,
}

#[derive(Clone, Debug)]
struct CasesRecursor {
    name: Name,
    universe_params: Vec<String>,
    ty: Expr,
}

#[derive(Clone, Debug)]
struct CasesAssembly {
    proof: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    required_tactic_steps: u64,
}

#[derive(Clone, Debug)]
struct CasesIndexEq {
    name: String,
    ty: Expr,
    refl: Expr,
}

fn run_induction_nat_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    local_name: String,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_intro_name_shape(&local_name)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    let target = resolve_induction_nat_target(&goal, &local_name)?;
    let family = state.env.nat_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "induction-nat requires a resolved Nat family",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id)
    })?;
    ensure_resolved_nat_family_heads(state, &goal, family)?;

    let fuel = TacticRunFuel::new(budget);
    let prefix_ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context[..target.index],
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let nat_expr = nat_family_type_expr(family);
    if !kernel_is_defeq_with_budget(
        state.env.kernel_env(),
        &prefix_ctx,
        &state.root.universe_params,
        &target.local.ty,
        &nat_expr,
        &fuel,
        goal_id,
        goal.meta_id,
    )? {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidInductionTarget,
            "induction-nat target local type is not definitionally equal to the resolved Nat family",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&nat_expr),
            &core_expr_canonical_bytes(&target.local.ty),
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id));
    }
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let assembly = assemble_induction_nat(state, &goal, &ctx, family, target.index, budget, &fuel)?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        assembly.proof,
        assembly.new_goal_specs,
        budget,
        assembly.required_tactic_steps,
        &fuel,
    )
}

fn run_cases_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: CasesPayload<MachineTermSource>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_intro_name_shape(&payload.major_local)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    validate_branch_names(&payload.branch_names)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    if payload.motive.is_some() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            "cases motive hints are reserved for a later deterministic motive elaborator",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id));
    }

    let fuel = TacticRunFuel::new(budget);
    let target = resolve_cases_major_target(state, &goal, &payload.major_local, &fuel)?;
    let recursor = resolve_checked_cases_recursor(state, &goal, &target)?;
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let assembly = assemble_cases_tactic(
        state,
        &goal,
        &ctx,
        &target,
        &recursor,
        &payload.branch_names,
        payload.max_new_goals,
        budget,
        &fuel,
    )?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        assembly.proof,
        assembly.new_goal_specs,
        budget,
        assembly.required_tactic_steps,
        &fuel,
    )
}

fn run_general_induction_tactic_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    payload: GeneralInductionPayload<MachineTermSource>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let goal = state.goal(goal_id)?;
    validate_intro_name_shape(&payload.major_local)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    validate_tactic_head_shape(&payload.recursor)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    validate_branch_names(&payload.branch_names)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    validate_local_name_list("generalized locals", &payload.generalized_locals)
        .map_err(|diag| attach_goal_meta(diag, goal_id, goal.meta_id))?;
    if payload.motive.is_some() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            "general-induction motive hints are reserved for a later deterministic motive elaborator",
        )
        .with_goal(goal_id)
        .with_meta(goal.meta_id));
    }

    let fuel = TacticRunFuel::new(budget);
    let target = resolve_cases_major_target(state, &goal, &payload.major_local, &fuel)?;
    let generalized =
        resolve_generalized_induction_locals(&goal, target.index, &payload.generalized_locals)?;
    if !target.indices.is_empty() && !generalized.is_empty() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            "general-induction does not combine indexed families with generalized locals without an explicit motive profile",
        )
        .with_primary_name(Name::from_dotted(&target.inductive))
        .with_goal(goal_id)
        .with_meta(goal.meta_id));
    }
    let recursor =
        resolve_checked_general_induction_recursor(state, &goal, &target, &payload.recursor)?;
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        &fuel,
        goal_id,
        goal.meta_id,
    )?;
    let assembly = assemble_general_induction_tactic(
        state,
        &goal,
        &ctx,
        &target,
        &recursor,
        &generalized,
        &payload.branch_names,
        payload.max_new_goals,
        budget,
        &fuel,
    )?;
    assign_goal_with_budget_and_steps(
        state,
        goal_id,
        assembly.proof,
        assembly.new_goal_specs,
        budget,
        assembly.required_tactic_steps,
        &fuel,
    )
}

fn resolve_generalized_induction_locals(
    goal: &MachineGoal,
    major_index: usize,
    local_names: &[String],
) -> Result<Vec<GeneralizedInductionLocal>> {
    let mut seen = BTreeSet::new();
    let mut resolved = Vec::new();
    for name in local_names {
        if !seen.insert(name.as_str()) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidInductionTarget,
                format!("general-induction generalized local {name:?} is duplicated"),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
        if name == &goal.context[major_index].name {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidInductionTarget,
                "general-induction major local cannot also be generalized",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
        let matches = goal
            .context
            .iter()
            .enumerate()
            .filter(|(_, local)| local.name == *name)
            .collect::<Vec<_>>();
        let [(index, local)] = matches.as_slice() else {
            return Err(if matches.is_empty() {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnknownLocalName,
                    format!(
                        "general-induction generalized local {name:?} is not in the goal context"
                    ),
                )
            } else {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::AmbiguousLocalName,
                    format!(
                        "general-induction generalized local {name:?} resolves to multiple locals"
                    ),
                )
            }
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        };
        if local.value.is_some() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidInductionTarget,
                format!(
                    "general-induction generalized local {name:?} resolves to a let declaration"
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
        if *index <= major_index {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidInductionTarget,
                "general-induction generalized locals must be later than the major local",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
        resolved.push(GeneralizedInductionLocal {
            index: *index,
            local: (*local).clone(),
        });
    }

    let expected_suffix = (major_index + 1)..goal.context.len();
    let expected = expected_suffix.collect::<Vec<_>>();
    let actual = resolved.iter().map(|local| local.index).collect::<Vec<_>>();
    if actual != expected {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidInductionTarget,
            "general-induction requires the deterministic suffix dependency closure after the major local",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(resolved)
}

fn resolve_checked_general_induction_recursor(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    head: &TacticHead,
) -> Result<CasesRecursor> {
    match head {
        TacticHead::Local { name } => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            format!(
                "general-induction recursor {name:?} is a local term; only certificate-derived recursor references are allowed"
            ),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
        TacticHead::Imported {
            name,
            decl_interface_hash,
        } => resolve_checked_imported_general_induction_recursor(
            state,
            goal,
            target,
            name,
            decl_interface_hash,
        ),
        TacticHead::CurrentModule {
            name,
            decl_interface_hash,
        } => resolve_checked_current_general_induction_recursor(
            state,
            goal,
            target,
            name,
            decl_interface_hash,
        ),
    }
}

fn kernel_recursor_for_target(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    name: &Name,
) -> Result<CasesRecursor> {
    let recursor_decl = state
        .env
        .kernel_env()
        .decl(&name.as_dotted())
        .ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownTacticHead,
                format!(
                    "general-induction recursor {} is missing from the kernel environment",
                    name.as_dotted()
                ),
            )
            .with_primary_name(name.clone())
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
    let Decl::Recursor {
        universe_params,
        ty,
        inductive,
        ..
    } = recursor_decl
    else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            format!(
                "general-induction declaration {} is not a kernel recursor",
                name.as_dotted()
            ),
        )
        .with_primary_name(name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    if inductive != &target.inductive {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            format!(
                "general-induction recursor {} belongs to inductive {inductive}, but target is {}",
                name.as_dotted(),
                target.inductive
            ),
        )
        .with_primary_name(name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(CasesRecursor {
        name: name.clone(),
        universe_params: universe_params.to_vec(),
        ty: ty.clone(),
    })
}

fn resolve_checked_imported_general_induction_recursor(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<CasesRecursor> {
    let recursor = kernel_recursor_for_target(state, goal, target, name)?;
    let checked = state.env.imports.iter().any(|import| {
        import.exports().iter().any(|export| {
            export.kind == ExportKind::Recursor
                && &export.name == name
                && &export.decl_interface_hash == decl_interface_hash
        }) && import.certified_env_decls().iter().any(|decl| {
            matches!(
                decl,
                Decl::Inductive { name, data, .. }
                    if name == &target.inductive
                        && data
                            .recursor
                            .as_ref()
                            .is_some_and(|generated| general_induction_recursor_metadata_matches(
                                state,
                                generated,
                                &recursor,
                            ))
            )
        })
    });
    if !checked {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            format!(
                "general-induction recursor {} is not directly exported by a verified import for {}",
                name.as_dotted(),
                target.inductive
            ),
        )
        .with_primary_name(name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(recursor)
}

fn resolve_checked_current_general_induction_recursor(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<CasesRecursor> {
    let recursor = kernel_recursor_for_target(state, goal, target, name)?;
    let checked = state.env.checked_current_decls.iter().any(|checked| {
        checked.signature().decl_interface_hash() == *decl_interface_hash
            && matches!(
                checked.core_decl(),
                Decl::Inductive { name: parent, data, .. }
                    if parent == &target.inductive
                        && data
                            .recursor
                            .as_ref()
                            .is_some_and(|generated| general_induction_recursor_metadata_matches(
                                state,
                                generated,
                                &recursor,
                            ))
            )
    });
    if !checked {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            format!(
                "general-induction recursor {} is not generated by a checked current declaration for {}",
                name.as_dotted(),
                target.inductive
            ),
        )
        .with_primary_name(name.clone())
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(recursor)
}

fn general_induction_recursor_metadata_matches(
    state: &MachineProofState,
    generated: &npa_kernel::RecursorDecl,
    recursor: &CasesRecursor,
) -> bool {
    generated.name == recursor.name.as_dotted()
        && generated.universe_params.len() == recursor.universe_params.len()
        && state
            .env
            .kernel_env()
            .is_defeq(
                &Ctx::new(),
                &recursor.universe_params,
                &generated.ty,
                &recursor.ty,
            )
            .unwrap_or(false)
}

fn resolve_cases_major_target(
    state: &MachineProofState,
    goal: &MachineGoal,
    local_name: &str,
    fuel: &TacticRunFuel,
) -> Result<CasesTarget> {
    let matches = goal
        .context
        .iter()
        .enumerate()
        .filter(|(_, local)| local.name == local_name)
        .collect::<Vec<_>>();
    let [(index, local)] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownLocalName,
                format!("cases major premise {local_name:?} is not in the goal context"),
            )
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousLocalName,
                format!("cases major premise {local_name:?} resolves to multiple locals"),
            )
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    if local.value.is_some() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidLocalHead,
            format!("cases major premise {local_name:?} resolves to a let declaration"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let prefix_ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context[..*index],
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let local_ty_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        &prefix_ctx,
        &state.root.universe_params,
        &local.ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let (head, args) = collect_apps(&local_ty_whnf);
    let Expr::Const { name, levels } = head else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "cases major premise type does not reduce to an inductive family application",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    let Some(Decl::Inductive { data, .. }) = state.env.kernel_env().decl(&name) else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            format!("cases major premise head {name} is not an inductive declaration"),
        )
        .with_primary_name(Name::from_dotted(&name))
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    let expected_arg_count = data.params.len() + data.indices.len();
    if args.len() != expected_arg_count {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            format!(
                "cases major premise inductive expects {expected_arg_count} parameters/indices, got {}",
                args.len()
            ),
        )
        .with_primary_name(Name::from_dotted(&name))
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(CasesTarget {
        index: *index,
        local: (*local).clone(),
        inductive: name,
        levels,
        params: args[..data.params.len()].to_vec(),
        indices: args[data.params.len()..].to_vec(),
        data: data.as_ref().clone(),
    })
}

fn resolve_checked_cases_recursor(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
) -> Result<CasesRecursor> {
    let recursor_name = target
        .data
        .recursor
        .as_ref()
        .map(|recursor| recursor.name.clone())
        .ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
                format!(
                    "cases target {} has no certificate-derived recursor",
                    target.inductive
                ),
            )
            .with_primary_name(Name::from_dotted(&target.inductive))
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
    let recursor_decl = state.env.kernel_env().decl(&recursor_name).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofState,
            format!("cases recursor {recursor_name} is missing from the kernel environment"),
        )
        .with_primary_name(Name::from_dotted(&recursor_name))
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
    })?;
    let Decl::Recursor {
        universe_params,
        ty,
        inductive,
        ..
    } = recursor_decl
    else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            format!("cases declaration {recursor_name} is not a kernel recursor"),
        )
        .with_primary_name(Name::from_dotted(&recursor_name))
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    if inductive != &target.inductive {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            format!(
                "cases recursor {recursor_name} belongs to inductive {inductive}, but target is {}",
                target.inductive
            ),
        )
        .with_primary_name(Name::from_dotted(&recursor_name))
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }

    let recursor = CasesRecursor {
        name: Name::from_dotted(&recursor_name),
        universe_params: universe_params.to_vec(),
        ty: ty.clone(),
    };
    let imported = state.env.imports.iter().any(|import| {
        import
            .exports()
            .iter()
            .any(|export| export.kind == ExportKind::Recursor && export.name == recursor.name)
            && import.certified_env_decls().iter().any(|decl| {
                matches!(
                    decl,
                    Decl::Inductive {
                        name,
                        data,
                        ..
                    } if name == &target.inductive
                        && data
                            .recursor
                            .as_ref()
                            .is_some_and(|imported| imported.name == recursor_name
                                && imported.ty == recursor.ty)
                )
            })
    });
    let current = state.env.checked_current_decls.iter().any(|checked| {
        checked.core_decl().name() == target.inductive
            && matches!(
                checked.core_decl(),
                Decl::Inductive { data, .. }
                    if data
                        .recursor
                        .as_ref()
                        .is_some_and(|recursor| recursor.name == recursor_name)
            )
    });
    if !imported && !current {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            format!(
                "cases recursor {recursor_name} is present in the kernel environment but is not checked-current or directly exported by a verified import"
            ),
        )
        .with_primary_name(recursor.name)
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(recursor)
}

#[allow(clippy::too_many_arguments)]
fn assemble_cases_tactic(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    target: &CasesTarget,
    recursor: &CasesRecursor,
    branch_names: &[String],
    max_new_goals: Option<u64>,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<CasesAssembly> {
    ensure_tactic_step_fuel(budget, 1, goal.id, goal.meta_id)?;
    let sort_level = target_sort_level_with_budget(state, goal, ctx, fuel)?;
    let recursor_levels = cases_recursor_levels(recursor, target, sort_level, goal)?;
    let mut recursor_ty =
        subst_levels_expr(&recursor.ty, &recursor.universe_params, &recursor_levels);
    let mut proof = ProofExpr::Core(Expr::konst(
        recursor.name.as_dotted(),
        recursor_levels.clone(),
    ));

    let full_context_shift = (goal.context.len() - target.index) as i32;
    let major_bvar = (goal.context.len() - 1 - target.index) as u32;
    let param_args = target
        .params
        .iter()
        .map(|param| shift(param, full_context_shift, 0).map_err(kernel_diag))
        .collect::<Result<Vec<_>>>()?;
    let index_args = target
        .indices
        .iter()
        .map(|index| shift(index, full_context_shift, 0).map_err(kernel_diag))
        .collect::<Result<Vec<_>>>()?;

    for param in &param_args {
        let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        recursor_ty = instantiate(&body, param).map_err(kernel_diag)?;
        proof = ProofExpr::app(proof, ProofExpr::Core(param.clone()));
    }

    let (motive_domain, after_motive) =
        peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
    let motive_domains = peel_cases_motive_domains(state, goal, ctx, &motive_domain, target, fuel)?;
    let (motive, index_eqs) =
        build_cases_motive(state, goal, target, &motive_domains, &index_args, fuel)?;
    recursor_ty = instantiate(&after_motive, &motive).map_err(kernel_diag)?;
    proof = ProofExpr::app(proof, ProofExpr::Core(motive));

    let mut new_goal_specs = Vec::new();
    let mut required_tactic_steps = 2;
    for (constructor_index, constructor) in target.data.constructors.iter().enumerate() {
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        let (minor_domain, body) =
            peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        let meta_id = MetaVarId(state.metas.next_id + new_goal_specs.len() as u64);
        let hint = branch_names.get(constructor_index).map(String::as_str);
        let (branch_proof, branch_spec) = build_cases_branch_proof(
            state,
            goal,
            &minor_domain,
            &constructor.name,
            hint,
            meta_id,
            fuel,
        )?;
        proof = ProofExpr::app(proof, branch_proof);
        new_goal_specs.push(branch_spec);
        if contains_bound_var(&body, 0) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                "cases recursor type unexpectedly depends on an earlier branch proof",
            )
            .with_primary_name(recursor.name.clone())
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
        recursor_ty = instantiate(&body, &Expr::bvar(0)).map_err(kernel_diag)?;
    }

    for index in &index_args {
        let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        recursor_ty = instantiate(&body, index).map_err(kernel_diag)?;
        proof = ProofExpr::app(proof, ProofExpr::Core(index.clone()));
    }

    let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
    let major = Expr::bvar(major_bvar);
    recursor_ty = instantiate(&body, &major).map_err(kernel_diag)?;
    proof = ProofExpr::app(proof, ProofExpr::Core(major));
    for index_eq in &index_eqs {
        let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        recursor_ty = instantiate(&body, &index_eq.refl).map_err(kernel_diag)?;
        proof = ProofExpr::app(proof, ProofExpr::Core(index_eq.refl.clone()));
    }

    ensure_count_budget(
        "cases new goal",
        new_goal_specs.len() as u64,
        max_new_goals.unwrap_or(branch_names.len() as u64),
        TacticFuelKind::MetaAllocation,
        goal,
    )?;
    Ok(CasesAssembly {
        proof,
        new_goal_specs,
        required_tactic_steps,
    })
}

#[allow(clippy::too_many_arguments)]
fn assemble_general_induction_tactic(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    target: &CasesTarget,
    recursor: &CasesRecursor,
    generalized: &[GeneralizedInductionLocal],
    branch_names: &[String],
    max_new_goals: u64,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<GeneralInductionAssembly> {
    ensure_tactic_step_fuel(budget, 1, goal.id, goal.meta_id)?;
    let sort_level = target_sort_level_with_budget(state, goal, ctx, fuel)?;
    let recursor_levels = cases_recursor_levels(recursor, target, sort_level, goal)?;
    let mut recursor_ty =
        subst_levels_expr(&recursor.ty, &recursor.universe_params, &recursor_levels);
    let mut proof = ProofExpr::Core(Expr::konst(
        recursor.name.as_dotted(),
        recursor_levels.clone(),
    ));

    let full_context_shift = (goal.context.len() - target.index) as i32;
    let major_bvar = (goal.context.len() - 1 - target.index) as u32;
    let param_args = target
        .params
        .iter()
        .map(|param| shift(param, full_context_shift, 0).map_err(kernel_diag))
        .collect::<Result<Vec<_>>>()?;
    let index_args = target
        .indices
        .iter()
        .map(|index| shift(index, full_context_shift, 0).map_err(kernel_diag))
        .collect::<Result<Vec<_>>>()?;

    for param in &param_args {
        let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        recursor_ty = instantiate(&body, param).map_err(kernel_diag)?;
        proof = ProofExpr::app(proof, ProofExpr::Core(param.clone()));
    }

    let (motive_domain, after_motive) =
        peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
    let motive_domains = peel_cases_motive_domains(state, goal, ctx, &motive_domain, target, fuel)?;
    let (motive, index_eqs) = build_general_induction_motive(
        state,
        goal,
        target,
        generalized,
        &motive_domains,
        &index_args,
        fuel,
    )?;
    recursor_ty = instantiate(&after_motive, &motive).map_err(kernel_diag)?;
    proof = ProofExpr::app(proof, ProofExpr::Core(motive));

    let mut new_goal_specs = Vec::new();
    let mut required_tactic_steps = 2;
    for (constructor_index, constructor) in target.data.constructors.iter().enumerate() {
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
        let (minor_domain, body) =
            peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        let meta_id = MetaVarId(state.metas.next_id + new_goal_specs.len() as u64);
        let hint = branch_names.get(constructor_index).map(String::as_str);
        let (branch_proof, branch_spec) = build_general_induction_branch_proof(
            state,
            goal,
            target,
            &minor_domain,
            &constructor.name,
            hint,
            generalized,
            meta_id,
            fuel,
        )?;
        proof = ProofExpr::app(proof, branch_proof);
        new_goal_specs.push(branch_spec);
        if contains_bound_var(&body, 0) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaDependency,
                "general-induction recursor type unexpectedly depends on an earlier branch proof",
            )
            .with_primary_name(recursor.name.clone())
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
        recursor_ty = instantiate(&body, &Expr::bvar(0)).map_err(kernel_diag)?;
    }

    for index in &index_args {
        let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        recursor_ty = instantiate(&body, index).map_err(kernel_diag)?;
        proof = ProofExpr::app(proof, ProofExpr::Core(index.clone()));
    }

    let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
    let major = Expr::bvar(major_bvar);
    recursor_ty = instantiate(&body, &major).map_err(kernel_diag)?;
    proof = ProofExpr::app(proof, ProofExpr::Core(major));
    for index_eq in &index_eqs {
        let (_, body) = peel_pi_domain_with_budget(state, goal, ctx, &recursor_ty, fuel)?;
        recursor_ty = instantiate(&body, &index_eq.refl).map_err(kernel_diag)?;
        proof = ProofExpr::app(proof, ProofExpr::Core(index_eq.refl.clone()));
    }
    for generalized_local in generalized {
        let generalized_bvar = (goal.context.len() - 1 - generalized_local.index) as u32;
        proof = ProofExpr::app(proof, ProofExpr::Core(Expr::bvar(generalized_bvar)));
    }

    ensure_count_budget(
        "general-induction new goal",
        new_goal_specs.len() as u64,
        max_new_goals,
        TacticFuelKind::MetaAllocation,
        goal,
    )?;
    Ok(GeneralInductionAssembly {
        proof,
        new_goal_specs,
        required_tactic_steps,
    })
}

fn cases_recursor_levels(
    recursor: &CasesRecursor,
    target: &CasesTarget,
    sort_level: Level,
    goal: &MachineGoal,
) -> Result<Vec<Level>> {
    if recursor.universe_params.len() == target.levels.len() + 1 {
        let mut levels = target.levels.clone();
        levels.push(sort_level);
        return Ok(levels);
    }
    if recursor.universe_params.len() == target.levels.len() {
        return Ok(target.levels.clone());
    }
    Err(universe_argument_mismatch_diag(
        &recursor.universe_params,
        &target.levels,
        goal.id,
        goal.meta_id,
    ))
}

fn peel_pi_domain_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    ty: &Expr,
    fuel: &TacticRunFuel,
) -> Result<(Expr, Expr)> {
    let whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let Expr::Pi { ty, body, .. } = whnf else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ExpectedFunctionType,
            "cases recursor type stopped before all required arguments were consumed",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(ty),
            &core_expr_canonical_bytes(&whnf),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    Ok((Arc::unwrap_or_clone(ty), Arc::unwrap_or_clone(body)))
}

fn peel_cases_motive_domains(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    motive_domain: &Expr,
    target: &CasesTarget,
    fuel: &TacticRunFuel,
) -> Result<Vec<Expr>> {
    let mut domains = Vec::new();
    let mut current = motive_domain.clone();
    for _ in 0..=target.indices.len() {
        let (domain, body) = peel_pi_domain_with_budget(state, goal, ctx, &current, fuel)?;
        domains.push(domain);
        current = body;
    }
    let current_whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &current,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    if !matches!(current_whnf, Expr::Sort(_)) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "cases recursor motive domain does not return a Sort",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(domains)
}

fn build_cases_motive(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    motive_domains: &[Expr],
    index_args: &[Expr],
    fuel: &TacticRunFuel,
) -> Result<(Expr, Vec<CasesIndexEq>)> {
    let added_binders = (target.indices.len() + 1) as u32;
    let major_bvar = (goal.context.len() - 1 - target.index) as u32;
    let mut body = replace_cases_major_keep(&goal.target, major_bvar, Expr::bvar(0), added_binders)
        .map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("cases could not structurally build a motive: {err:?}"),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
    let index_eqs = if target.indices.is_empty() {
        Vec::new()
    } else {
        build_cases_index_equalities(state, goal, target, motive_domains, index_args, fuel)?
    };
    for index_eq in index_eqs.iter().rev() {
        body = Expr::pi(
            index_eq.name.clone(),
            index_eq.ty.clone(),
            shift(&body, 1, 0).map_err(kernel_diag)?,
        );
    }
    let motive_names = cases_motive_binder_names(&goal.context, target, motive_domains.len());
    let mut motive = body;
    for (binder_index, domain) in motive_domains.iter().enumerate().rev() {
        motive = Expr::lam(motive_names[binder_index].clone(), domain.clone(), motive);
    }
    Ok((motive, index_eqs))
}

fn build_general_induction_motive(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    generalized: &[GeneralizedInductionLocal],
    motive_domains: &[Expr],
    index_args: &[Expr],
    fuel: &TacticRunFuel,
) -> Result<(Expr, Vec<CasesIndexEq>)> {
    if generalized.is_empty() {
        return build_cases_motive(state, goal, target, motive_domains, index_args, fuel);
    }
    if !target.indices.is_empty() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnsupportedTacticOption,
            "generalized induction over indexed families requires an explicit motive profile",
        )
        .with_primary_name(Name::from_dotted(&target.inductive))
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    if motive_domains.len() != 1 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "general-induction generalized motive expects a single major-premise motive binder",
        )
        .with_primary_name(Name::from_dotted(&target.inductive))
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }

    let added_total = 1 + generalized.len();
    let full_replacements =
        general_induction_replacements(goal.context.len(), target.index, generalized, added_total);
    let mut body = replace_context_bvars_keep(&goal.target, &full_replacements, added_total as u32)
        .map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("general-induction could not structurally build a motive: {err:?}"),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;

    for (generalized_index, generalized_local) in generalized.iter().enumerate().rev() {
        let added_before = 1 + generalized_index;
        let replacements = general_induction_replacements(
            generalized_local.index,
            target.index,
            &generalized[..generalized_index],
            added_before,
        );
        let domain = replace_context_bvars_keep(
            &generalized_local.local.ty,
            &replacements,
            added_before as u32,
        )
        .map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!(
                    "general-induction could not generalize local {:?}: {err:?}",
                    generalized_local.local.name
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id)
        })?;
        body = Expr::pi(
            generalized_motive_binder_name(goal, generalized, generalized_index),
            domain,
            body,
        );
    }

    let motive_name = deterministic_generated_local_name(
        &goal.context,
        MachineGeneratedNameKind::InductionMajor,
        Some(&target.local.name),
    );
    Ok((
        Expr::lam(motive_name, motive_domains[0].clone(), body),
        Vec::new(),
    ))
}

fn generalized_motive_binder_name(
    goal: &MachineGoal,
    generalized: &[GeneralizedInductionLocal],
    generalized_index: usize,
) -> String {
    let mut synthetic_context = goal.context.clone();
    for prior in generalized.iter().take(generalized_index) {
        synthetic_context.push(MachineLocalDecl::assumption(
            prior.local.name.clone(),
            prior.local.ty.clone(),
        ));
    }
    deterministic_generated_local_name(
        &synthetic_context,
        MachineGeneratedNameKind::GeneralizedLocal,
        Some(&generalized[generalized_index].local.name),
    )
}

fn general_induction_replacements(
    context_len: usize,
    major_index: usize,
    generalized: &[GeneralizedInductionLocal],
    added_count: usize,
) -> BTreeMap<u32, Expr> {
    let mut replacements = BTreeMap::new();
    if major_index < context_len {
        replacements.insert(
            (context_len - 1 - major_index) as u32,
            Expr::bvar((added_count - 1) as u32),
        );
    }
    for (generalized_index, generalized_local) in generalized.iter().enumerate() {
        if generalized_local.index < context_len {
            replacements.insert(
                (context_len - 1 - generalized_local.index) as u32,
                Expr::bvar((added_count - 2 - generalized_index) as u32),
            );
        }
    }
    replacements
}

fn replace_context_bvars_keep(
    expr: &Expr,
    replacements: &BTreeMap<u32, Expr>,
    added_after_original_context: u32,
) -> npa_kernel::Result<Expr> {
    replace_context_bvars_keep_at_depth(expr, replacements, added_after_original_context, 0)
}

fn replace_context_bvars_keep_at_depth(
    expr: &Expr,
    replacements: &BTreeMap<u32, Expr>,
    added_after_original_context: u32,
    depth: u32,
) -> npa_kernel::Result<Expr> {
    match expr {
        Expr::Sort(level) => Ok(Expr::sort(level.clone())),
        Expr::BVar(index) if *index < depth => Ok(Expr::bvar(*index)),
        Expr::BVar(index) => {
            let original = index - depth;
            if let Some(replacement) = replacements.get(&original) {
                shift(replacement, depth as i32, 0)
            } else {
                Ok(Expr::bvar(index + added_after_original_context))
            }
        }
        Expr::Const { name, levels } => Ok(Expr::konst(name.clone(), levels.clone())),
        Expr::App(fun, arg) => Ok(Expr::app(
            replace_context_bvars_keep_at_depth(
                fun,
                replacements,
                added_after_original_context,
                depth,
            )?,
            replace_context_bvars_keep_at_depth(
                arg,
                replacements,
                added_after_original_context,
                depth,
            )?,
        )),
        Expr::Lam { binder, ty, body } => Ok(Expr::lam(
            binder.clone(),
            replace_context_bvars_keep_at_depth(
                ty,
                replacements,
                added_after_original_context,
                depth,
            )?,
            replace_context_bvars_keep_at_depth(
                body,
                replacements,
                added_after_original_context,
                depth + 1,
            )?,
        )),
        Expr::Pi { binder, ty, body } => Ok(Expr::pi(
            binder.clone(),
            replace_context_bvars_keep_at_depth(
                ty,
                replacements,
                added_after_original_context,
                depth,
            )?,
            replace_context_bvars_keep_at_depth(
                body,
                replacements,
                added_after_original_context,
                depth + 1,
            )?,
        )),
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => Ok(Expr::let_in(
            binder.clone(),
            replace_context_bvars_keep_at_depth(
                ty,
                replacements,
                added_after_original_context,
                depth,
            )?,
            replace_context_bvars_keep_at_depth(
                value,
                replacements,
                added_after_original_context,
                depth,
            )?,
            replace_context_bvars_keep_at_depth(
                body,
                replacements,
                added_after_original_context,
                depth + 1,
            )?,
        )),
    }
}

fn replace_cases_major_keep(
    expr: &Expr,
    major_bvar: u32,
    replacement: Expr,
    added_after_original_context: u32,
) -> npa_kernel::Result<Expr> {
    replace_cases_major_keep_at_depth(
        expr,
        major_bvar,
        &replacement,
        added_after_original_context,
        0,
    )
}

fn replace_cases_major_keep_at_depth(
    expr: &Expr,
    major_bvar: u32,
    replacement: &Expr,
    added_after_original_context: u32,
    depth: u32,
) -> npa_kernel::Result<Expr> {
    match expr {
        Expr::Sort(level) => Ok(Expr::sort(level.clone())),
        Expr::BVar(index) if *index < depth => Ok(Expr::bvar(*index)),
        Expr::BVar(index) if *index == depth + major_bvar => shift(replacement, depth as i32, 0),
        Expr::BVar(index) => Ok(Expr::bvar(index + added_after_original_context)),
        Expr::Const { name, levels } => Ok(Expr::konst(name.clone(), levels.clone())),
        Expr::App(fun, arg) => Ok(Expr::app(
            replace_cases_major_keep_at_depth(
                fun,
                major_bvar,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_cases_major_keep_at_depth(
                arg,
                major_bvar,
                replacement,
                added_after_original_context,
                depth,
            )?,
        )),
        Expr::Lam { binder, ty, body } => Ok(Expr::lam(
            binder.clone(),
            replace_cases_major_keep_at_depth(
                ty,
                major_bvar,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_cases_major_keep_at_depth(
                body,
                major_bvar,
                replacement,
                added_after_original_context,
                depth + 1,
            )?,
        )),
        Expr::Pi { binder, ty, body } => Ok(Expr::pi(
            binder.clone(),
            replace_cases_major_keep_at_depth(
                ty,
                major_bvar,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_cases_major_keep_at_depth(
                body,
                major_bvar,
                replacement,
                added_after_original_context,
                depth + 1,
            )?,
        )),
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => Ok(Expr::let_in(
            binder.clone(),
            replace_cases_major_keep_at_depth(
                ty,
                major_bvar,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_cases_major_keep_at_depth(
                value,
                major_bvar,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_cases_major_keep_at_depth(
                body,
                major_bvar,
                replacement,
                added_after_original_context,
                depth + 1,
            )?,
        )),
    }
}

fn cases_motive_binder_names(
    context: &[MachineLocalDecl],
    target: &CasesTarget,
    len: usize,
) -> Vec<String> {
    let mut synthetic_context = context.to_vec();
    let mut names = Vec::new();
    for index in 0..len {
        let hint = if index + 1 == len {
            Some(format!("{}_major", target.local.name))
        } else {
            Some(format!("idx{index}"))
        };
        let name = deterministic_generated_local_name(
            &synthetic_context,
            MachineGeneratedNameKind::BranchHypothesis,
            hint.as_deref(),
        );
        synthetic_context.push(MachineLocalDecl::assumption(
            name.clone(),
            Expr::sort(Level::zero()),
        ));
        names.push(name);
    }
    names
}

fn build_cases_index_equalities(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    motive_domains: &[Expr],
    index_args: &[Expr],
    fuel: &TacticRunFuel,
) -> Result<Vec<CasesIndexEq>> {
    let family = state.env.eq_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "cases on an indexed family requires a resolved Eq family for branch index equations",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)
    })?;
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &goal.context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let mut motive_context = goal.context.clone();
    let motive_names = cases_motive_binder_names(&goal.context, target, motive_domains.len());
    for (index, domain) in motive_domains.iter().enumerate() {
        motive_context.push(MachineLocalDecl::assumption(
            motive_names[index].clone(),
            domain.clone(),
        ));
    }
    let motive_ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &motive_context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let mut out = Vec::new();
    let motive_binder_count = target.indices.len() + 1;
    for (index, original) in index_args.iter().enumerate() {
        let original_in_motive =
            shift(original, motive_binder_count as i32, 0).map_err(kernel_diag)?;
        let current_index = Expr::bvar((target.indices.len() - index) as u32);
        let index_ty = shift(
            &motive_domains[index],
            (target.indices.len() - index + 1) as i32,
            0,
        )
        .map_err(kernel_diag)?;
        let sort = kernel_infer_with_budget(
            state.env.kernel_env(),
            &motive_ctx,
            &state.root.universe_params,
            &index_ty,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let Expr::Sort(level) = kernel_whnf_with_budget(
            state.env.kernel_env(),
            &motive_ctx,
            &state.root.universe_params,
            &sort,
            fuel,
            goal.id,
            goal.meta_id,
        )?
        else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TypeMismatch,
                "cases index type does not infer to a sort",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        };
        let index_ty_full = kernel_infer_with_budget(
            state.env.kernel_env(),
            &ctx,
            &state.root.universe_params,
            original,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let refl_sort = kernel_infer_with_budget(
            state.env.kernel_env(),
            &ctx,
            &state.root.universe_params,
            &index_ty_full,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let Expr::Sort(refl_level) = kernel_whnf_with_budget(
            state.env.kernel_env(),
            &ctx,
            &state.root.universe_params,
            &refl_sort,
            fuel,
            goal.id,
            goal.meta_id,
        )?
        else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TypeMismatch,
                "cases index type for reflexivity does not infer to a sort",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        };
        let ty = mk_eq_expr(
            family,
            &[level],
            index_ty,
            original_in_motive,
            current_index,
        );
        let refl = mk_eq_refl_expr(family, &[refl_level], index_ty_full, original.clone());
        out.push(CasesIndexEq {
            name: format!("idx_eq{index}"),
            ty,
            refl,
        });
    }
    Ok(out)
}

#[derive(Clone, Debug)]
struct GeneralInductionRawBranchBinder {
    domain: Expr,
    recursive_argument: bool,
}

#[allow(clippy::too_many_arguments)]
fn build_general_induction_branch_proof(
    state: &MachineProofState,
    goal: &MachineGoal,
    target: &CasesTarget,
    minor_domain: &Expr,
    constructor_name: &str,
    _branch_hint: Option<&str>,
    generalized: &[GeneralizedInductionLocal],
    meta_id: MetaVarId,
    fuel: &TacticRunFuel,
) -> Result<(ProofExpr, MachineNewGoalSpec)> {
    let mut temp_context = goal.context.clone();
    let mut raw_binders = Vec::new();
    let mut current = minor_domain.clone();
    loop {
        let ctx = local_context_to_ctx_with_budget(
            state.env.kernel_env(),
            &temp_context,
            &state.root.universe_params,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let whnf = kernel_whnf_with_budget(
            state.env.kernel_env(),
            &ctx,
            &state.root.universe_params,
            &current,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let Expr::Pi { ty, body, .. } = whnf else {
            current = whnf;
            break;
        };
        let domain = Arc::unwrap_or_clone(ty);
        let recursive_argument =
            domain_is_target_inductive_app(state, goal, &temp_context, target, &domain, fuel)?;
        temp_context.push(MachineLocalDecl::assumption(
            format!("__induction_branch{}", raw_binders.len()),
            domain.clone(),
        ));
        raw_binders.push(GeneralInductionRawBranchBinder {
            domain,
            recursive_argument,
        });
        current = Arc::unwrap_or_clone(body);
    }

    if generalized.len() > raw_binders.len() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "general-induction branch did not expose all generalized locals in the motive result",
        )
        .with_primary_name(Name::from_dotted(constructor_name))
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    let generalized_start = raw_binders.len() - generalized.len();
    let mut context = goal.context.clone();
    let mut binders = Vec::new();
    let mut next_binder_is_ih = false;
    for (binder_index, raw) in raw_binders.into_iter().enumerate() {
        let (kind, hint) = if binder_index >= generalized_start {
            let generalized_index = binder_index - generalized_start;
            (
                MachineGeneratedNameKind::GeneralizedLocal,
                Some(generalized[generalized_index].local.name.as_str()),
            )
        } else if next_binder_is_ih {
            next_binder_is_ih = false;
            (MachineGeneratedNameKind::InductionHypothesis, Some("ih0"))
        } else if raw.recursive_argument {
            next_binder_is_ih = true;
            (MachineGeneratedNameKind::InductionMajor, None)
        } else {
            (MachineGeneratedNameKind::ConstructorArgument, None)
        };
        let name = deterministic_generated_local_name(&context, kind, hint);
        context.push(MachineLocalDecl::assumption(
            name.clone(),
            raw.domain.clone(),
        ));
        binders.push((name, raw.domain));
    }

    let spec = typed_subgoal_spec_with_budget(state, goal, context, current, fuel)?;
    let mut proof = ProofExpr::Meta(meta_id);
    for (name, domain) in binders.into_iter().rev() {
        proof = ProofExpr::lam(name, domain, proof);
    }
    Ok((proof, spec))
}

fn domain_is_target_inductive_app(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
    target: &CasesTarget,
    domain: &Expr,
    fuel: &TacticRunFuel,
) -> Result<bool> {
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let whnf = kernel_whnf_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        domain,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let (head, args) = collect_apps(&whnf);
    Ok(matches!(
        head,
        Expr::Const { name, .. }
            if name == target.inductive && args.len() == target.params.len() + target.indices.len()
    ))
}

fn build_cases_branch_proof(
    state: &MachineProofState,
    goal: &MachineGoal,
    minor_domain: &Expr,
    constructor_name: &str,
    branch_hint: Option<&str>,
    meta_id: MetaVarId,
    fuel: &TacticRunFuel,
) -> Result<(ProofExpr, MachineNewGoalSpec)> {
    let mut context = goal.context.clone();
    let mut binders = Vec::new();
    let mut current = minor_domain.clone();
    loop {
        let ctx = local_context_to_ctx_with_budget(
            state.env.kernel_env(),
            &context,
            &state.root.universe_params,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let whnf = kernel_whnf_with_budget(
            state.env.kernel_env(),
            &ctx,
            &state.root.universe_params,
            &current,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        let Expr::Pi { ty, body, .. } = whnf else {
            current = whnf;
            break;
        };
        let domain = Arc::unwrap_or_clone(ty);
        let hint = if binders.is_empty() {
            branch_hint
        } else {
            None
        };
        let kind = if state
            .env
            .eq_family
            .as_ref()
            .and_then(|family| parse_eq_target_from_expr(family, &domain))
            .is_some()
        {
            MachineGeneratedNameKind::BranchHypothesis
        } else {
            MachineGeneratedNameKind::ConstructorArgument
        };
        let fallback = constructor_name
            .rsplit('.')
            .next()
            .filter(|component| !component.is_empty());
        let name = deterministic_generated_local_name(&context, kind, hint.or(fallback));
        context.push(MachineLocalDecl::assumption(name.clone(), domain.clone()));
        binders.push((name, domain));
        current = Arc::unwrap_or_clone(body);
    }
    let spec = typed_subgoal_spec_with_budget(state, goal, context, current, fuel)?;
    let mut proof = ProofExpr::Meta(meta_id);
    for (name, domain) in binders.into_iter().rev() {
        proof = ProofExpr::lam(name, domain, proof);
    }
    Ok((proof, spec))
}

#[derive(Clone, Debug)]
struct InductionNatTarget {
    index: usize,
    local: MachineLocalDecl,
}

fn resolve_induction_nat_target(
    goal: &MachineGoal,
    local_name: &str,
) -> Result<InductionNatTarget> {
    let matches = goal
        .context
        .iter()
        .enumerate()
        .filter(|(_, local)| local.name == local_name)
        .collect::<Vec<_>>();
    let [(index, local)] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownLocalName,
                format!("induction-nat target {local_name:?} is not in the goal context"),
            )
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousLocalName,
                format!("induction-nat target {local_name:?} resolves to multiple locals"),
            )
        }
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    };
    if local.value.is_some() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidInductionTarget,
            format!("induction-nat target {local_name:?} resolves to a let declaration"),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    if *index + 1 != goal.context.len() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidInductionTarget,
            "induction-nat MVP requires the target local to be the last local declaration",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(InductionNatTarget {
        index: *index,
        local: (*local).clone(),
    })
}

fn ensure_resolved_nat_family_heads(
    state: &MachineProofState,
    goal: &MachineGoal,
    family: &ResolvedNatFamily,
) -> Result<()> {
    for name in [
        &family.nat_name,
        &family.zero_name,
        &family.succ_name,
        &family.rec_name,
    ] {
        if state.env.kernel_env().decl(&name.as_dotted()).is_none() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!(
                    "resolved Nat family head {} is missing from the kernel environment",
                    name.as_dotted()
                ),
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
    }
    Ok(())
}

fn assemble_induction_nat(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedNatFamily,
    target_index: usize,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
) -> Result<InductionNatAssembly> {
    ensure_tactic_step_fuel(budget, 1, goal.id, goal.meta_id)?;
    let sort_level = target_sort_level_with_budget(state, goal, ctx, fuel)?;
    let nat_expr = nat_family_type_expr(family);
    let zero_expr = nat_family_zero_expr(family);
    let (step_n_name, step_ih_name) = deterministic_induction_local_names(&goal.context);

    let motive_body = replace_induction_target_keep(&goal.target, Expr::bvar(0), 1)
        .map_err(|err| invalid_induction_target_kernel_err(goal, err))?;
    let motive = Expr::lam(step_n_name.clone(), nat_expr.clone(), motive_body);

    ensure_tactic_step_fuel(budget, 2, goal.id, goal.meta_id)?;
    let base_motive = Expr::lam(step_n_name.clone(), nat_expr.clone(), goal.target.clone());
    let base_target = Expr::app(base_motive, zero_expr);
    let ih_ty = Expr::app(
        shift(&motive, 1, 0).map_err(|err| invalid_induction_target_kernel_err(goal, err))?,
        Expr::bvar(0),
    );
    let step_target = Expr::app(
        shift(&motive, 2, 0).map_err(|err| invalid_induction_target_kernel_err(goal, err))?,
        nat_family_succ_expr(family, Expr::bvar(1)),
    );

    let base_context = goal.context[..target_index].to_vec();
    let mut step_context = goal.context.clone();
    step_context.push(MachineLocalDecl::assumption(
        step_n_name.clone(),
        nat_expr.clone(),
    ));
    step_context.push(MachineLocalDecl::assumption(
        step_ih_name.clone(),
        ih_ty.clone(),
    ));

    ensure_tactic_step_fuel(budget, 3, goal.id, goal.meta_id)?;
    let base_meta = MetaVarId(state.metas.next_id);
    let step_meta = MetaVarId(state.metas.next_id + 1);
    let step_fun = ProofExpr::lam(
        step_n_name,
        nat_expr,
        ProofExpr::lam(step_ih_name, ih_ty, ProofExpr::Meta(step_meta)),
    );
    let mut proof = ProofExpr::Core(Expr::konst(family.rec_name.as_dotted(), vec![sort_level]));
    for arg in [
        ProofExpr::Core(motive),
        ProofExpr::Meta(base_meta),
        step_fun,
        ProofExpr::Core(Expr::bvar(0)),
    ] {
        proof = ProofExpr::app(proof, arg);
    }

    Ok(InductionNatAssembly {
        proof,
        new_goal_specs: vec![
            MachineNewGoalSpec::new(base_context, base_target),
            MachineNewGoalSpec::new(step_context, step_target),
        ],
        required_tactic_steps: 3,
    })
}

fn target_sort_level_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    fuel: &TacticRunFuel,
) -> Result<Level> {
    let ty = kernel_infer_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &goal.target,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    match kernel_whnf_with_budget(
        state.env.kernel_env(),
        ctx,
        &state.root.universe_params,
        &ty,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        Expr::Sort(level) => Ok(level),
        actual => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidInductionTarget,
            "induction-nat target motive result is not a sort",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&Expr::sort(npa_kernel::type0())),
            &core_expr_canonical_bytes(&actual),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
    }
}

fn invalid_induction_target_kernel_err(
    goal: &MachineGoal,
    err: npa_kernel::Error,
) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::InvalidInductionTarget,
        format!("induction-nat could not structurally extract a motive: {err:?}"),
    )
    .with_goal(goal.id)
    .with_meta(goal.meta_id)
}

fn nat_family_type_expr(family: &ResolvedNatFamily) -> Expr {
    Expr::konst(family.nat_name.as_dotted(), Vec::new())
}

fn nat_family_zero_expr(family: &ResolvedNatFamily) -> Expr {
    Expr::konst(family.zero_name.as_dotted(), Vec::new())
}

fn nat_family_succ_expr(family: &ResolvedNatFamily, arg: Expr) -> Expr {
    Expr::app(Expr::konst(family.succ_name.as_dotted(), Vec::new()), arg)
}

fn deterministic_induction_local_names(context: &[MachineLocalDecl]) -> (String, String) {
    let used = context
        .iter()
        .map(|local| local.name.as_str())
        .collect::<BTreeSet<_>>();
    for index in 0.. {
        let n = format!("n{index}");
        let ih = format!("ih{index}");
        if !used.contains(n.as_str()) && !used.contains(ih.as_str()) {
            return (n, ih);
        }
    }
    unreachable!("unbounded deterministic name search should always find a pair")
}

fn replace_induction_target_keep(
    expr: &Expr,
    replacement: Expr,
    added_after_original_context: u32,
) -> npa_kernel::Result<Expr> {
    replace_induction_target_keep_at_depth(expr, &replacement, added_after_original_context, 0)
}

fn replace_induction_target_keep_at_depth(
    expr: &Expr,
    replacement: &Expr,
    added_after_original_context: u32,
    depth: u32,
) -> npa_kernel::Result<Expr> {
    match expr {
        Expr::Sort(level) => Ok(Expr::sort(level.clone())),
        Expr::BVar(index) if *index < depth => Ok(Expr::bvar(*index)),
        Expr::BVar(index) if *index == depth => shift(replacement, depth as i32, 0),
        Expr::BVar(index) => Ok(Expr::bvar(index + added_after_original_context)),
        Expr::Const { name, levels } => Ok(Expr::konst(name.clone(), levels.clone())),
        Expr::App(fun, arg) => Ok(Expr::app(
            replace_induction_target_keep_at_depth(
                fun,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_induction_target_keep_at_depth(
                arg,
                replacement,
                added_after_original_context,
                depth,
            )?,
        )),
        Expr::Lam { binder, ty, body } => Ok(Expr::lam(
            binder.clone(),
            replace_induction_target_keep_at_depth(
                ty,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_induction_target_keep_at_depth(
                body,
                replacement,
                added_after_original_context,
                depth + 1,
            )?,
        )),
        Expr::Pi { binder, ty, body } => Ok(Expr::pi(
            binder.clone(),
            replace_induction_target_keep_at_depth(
                ty,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_induction_target_keep_at_depth(
                body,
                replacement,
                added_after_original_context,
                depth + 1,
            )?,
        )),
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => Ok(Expr::let_in(
            binder.clone(),
            replace_induction_target_keep_at_depth(
                ty,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_induction_target_keep_at_depth(
                value,
                replacement,
                added_after_original_context,
                depth,
            )?,
            replace_induction_target_keep_at_depth(
                body,
                replacement,
                added_after_original_context,
                depth + 1,
            )?,
        )),
    }
}

#[allow(clippy::too_many_arguments)]
fn instantiate_simp_rule(
    state: &MachineProofState,
    goal: &MachineGoal,
    ctx: &Ctx,
    family: &ResolvedEqFamily,
    rule: &ResolvedSimpRule,
    universe_args: &[Level],
    old_eq_target: &EqTarget,
    direction: RewriteDirection,
    site: RewriteSite,
    budget: TacticBudget,
    fuel: &TacticRunFuel,
    initial_tactic_steps: u64,
) -> Result<RewriteRuleInstance> {
    let env = state.env.kernel_env();
    let delta = &state.root.universe_params;
    let mut required_tactic_steps = initial_tactic_steps + 1;
    ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;

    let param_count = rule.rule_telescope.len();
    let eq_type_pattern = instantiate_simp_pattern(
        &rule.eq_type,
        param_count,
        &rule.universe_params,
        universe_args,
    )?;
    let from_pattern = instantiate_simp_pattern(
        &rule.from_pattern,
        param_count,
        &rule.universe_params,
        universe_args,
    )?;
    let mut solutions = BTreeMap::new();
    match_apply_pattern(
        env,
        ctx,
        delta,
        &eq_type_pattern,
        &old_eq_target.ty,
        true,
        &mut solutions,
        Some((fuel, goal.id, goal.meta_id)),
    )
    .map_err(|err| {
        rewrite_match_error_or_ambiguous(
            err,
            "simp rule Eq type does not match target Eq type",
            goal,
        )
    })?;
    let selected_side = match site {
        RewriteSite::EqTargetLeft => &old_eq_target.lhs,
        RewriteSite::EqTargetRight => &old_eq_target.rhs,
    };
    match_apply_pattern(
        env,
        ctx,
        delta,
        &from_pattern,
        selected_side,
        true,
        &mut solutions,
        Some((fuel, goal.id, goal.meta_id)),
    )
    .map_err(|err| {
        rewrite_match_error_or_ambiguous(err, "simp rule selected side does not match target", goal)
    })?;
    for id in 0..param_count {
        if !solutions.contains_key(&PatternMetaId(id as u64)) {
            return Err(ambiguous_rewrite_rule_diag(
                "simp rule inferred argument was not uniquely solved",
                goal,
            ));
        }
    }

    let mut proof = ProofExpr::Core(Expr::konst(
        rule.signature.name().as_dotted(),
        universe_args.to_vec(),
    ));
    for (index, param) in rule.rule_telescope.iter().enumerate() {
        let domain_pattern =
            instantiate_simp_param_domain(param, index, &rule.universe_params, universe_args)?;
        let domain = replace_pattern_metas(&domain_pattern, &solutions).map_err(|_| {
            ambiguous_rewrite_rule_diag("simp rule inferred argument domain is unresolved", goal)
        })?;
        let inferred = solutions.get(&PatternMetaId(index as u64)).ok_or_else(|| {
            ambiguous_rewrite_rule_diag("simp rule inferred argument is missing", goal)
        })?;
        kernel_check_with_budget(
            env,
            ctx,
            delta,
            inferred,
            &domain,
            fuel,
            goal.id,
            goal.meta_id,
        )?;
        proof = ProofExpr::app(proof, ProofExpr::Core(inferred.clone()));
        required_tactic_steps += 1;
        ensure_tactic_step_fuel(budget, required_tactic_steps, goal.id, goal.meta_id)?;
    }

    let levels = rule
        .eq_levels
        .iter()
        .map(|level| subst_simp_level(level, &rule.universe_params, universe_args))
        .collect::<Vec<_>>();
    let eq_type = replace_pattern_metas(&eq_type_pattern, &solutions).map_err(|_| {
        ambiguous_rewrite_rule_diag("simp rule Eq type is unresolved after matching", goal)
    })?;
    let lhs_pattern = instantiate_simp_pattern(
        &rule.theorem_lhs,
        param_count,
        &rule.universe_params,
        universe_args,
    )?;
    let rhs_pattern = instantiate_simp_pattern(
        &rule.theorem_rhs,
        param_count,
        &rule.universe_params,
        universe_args,
    )?;
    let lhs = replace_pattern_metas(&lhs_pattern, &solutions).map_err(|_| {
        ambiguous_rewrite_rule_diag("simp rule lhs is unresolved after matching", goal)
    })?;
    let rhs = replace_pattern_metas(&rhs_pattern, &solutions).map_err(|_| {
        ambiguous_rewrite_rule_diag("simp rule rhs is unresolved after matching", goal)
    })?;
    let expr = mk_eq_expr(family, &levels, eq_type.clone(), lhs.clone(), rhs.clone());
    let eq_target = EqTarget {
        levels: levels.clone(),
        ty: eq_type.clone(),
        lhs,
        rhs,
        expr,
    };
    let selected_from = rewrite_rule_from_side(&eq_target, direction);
    if !kernel_is_defeq_with_budget(
        env,
        ctx,
        delta,
        &eq_target.ty,
        &old_eq_target.ty,
        fuel,
        goal.id,
        goal.meta_id,
    )? || !kernel_is_defeq_with_budget(
        env,
        ctx,
        delta,
        selected_from,
        selected_side,
        fuel,
        goal.id,
        goal.meta_id,
    )? {
        return Err(ambiguous_rewrite_rule_diag(
            "simp instantiated Eq theorem is not applicable to the selected side",
            goal,
        ));
    }

    Ok(RewriteRuleInstance {
        proof,
        eq_target,
        new_goal_specs: Vec::new(),
        required_tactic_steps,
    })
}

fn instantiate_simp_pattern(
    expr: &Expr,
    param_count: usize,
    universe_params: &[String],
    universe_args: &[Level],
) -> Result<Expr> {
    Ok(subst_levels_expr(
        &replace_simp_param_bvars(expr, param_count, 0),
        universe_params,
        universe_args,
    ))
}

fn instantiate_simp_param_domain(
    param: &ResolvedRuleParam,
    prior_param_count: usize,
    universe_params: &[String],
    universe_args: &[Level],
) -> Result<Expr> {
    Ok(subst_levels_expr(
        &replace_simp_param_bvars(&param.ty, prior_param_count, 0),
        universe_params,
        universe_args,
    ))
}

fn replace_simp_param_bvars(expr: &Expr, param_count: usize, depth: u32) -> Expr {
    match expr {
        Expr::Sort(level) => Expr::sort(level.clone()),
        Expr::BVar(index) if *index < depth => Expr::bvar(*index),
        Expr::BVar(index) => {
            let relative = *index - depth;
            if relative < param_count as u32 {
                let id = param_count as u32 - 1 - relative;
                pattern_meta_expr(PatternMetaId(id as u64))
            } else {
                Expr::bvar(index - param_count as u32)
            }
        }
        Expr::Const { name, levels } => Expr::konst(name.clone(), levels.clone()),
        Expr::App(fun, arg) => Expr::app(
            replace_simp_param_bvars(fun, param_count, depth),
            replace_simp_param_bvars(arg, param_count, depth),
        ),
        Expr::Lam { binder, ty, body } => Expr::lam(
            binder.clone(),
            replace_simp_param_bvars(ty, param_count, depth),
            replace_simp_param_bvars(body, param_count, depth + 1),
        ),
        Expr::Pi { binder, ty, body } => Expr::pi(
            binder.clone(),
            replace_simp_param_bvars(ty, param_count, depth),
            replace_simp_param_bvars(body, param_count, depth + 1),
        ),
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => Expr::let_in(
            binder.clone(),
            replace_simp_param_bvars(ty, param_count, depth),
            replace_simp_param_bvars(value, param_count, depth),
            replace_simp_param_bvars(body, param_count, depth + 1),
        ),
    }
}

fn subst_simp_level(level: &Level, params: &[String], args: &[Level]) -> Level {
    match level {
        Level::Zero => Level::Zero,
        Level::Succ(level) => Level::succ(subst_simp_level(level, params, args)),
        Level::Max(lhs, rhs) => Level::max(
            subst_simp_level(lhs, params, args),
            subst_simp_level(rhs, params, args),
        ),
        Level::IMax(lhs, rhs) => Level::imax(
            subst_simp_level(lhs, params, args),
            subst_simp_level(rhs, params, args),
        ),
        Level::Param(name) => params
            .iter()
            .position(|param| param == name)
            .and_then(|index| args.get(index))
            .cloned()
            .unwrap_or_else(|| Level::param(name.clone())),
    }
}

fn solve_simp_universe_args(
    rule: &ResolvedSimpRule,
    current_eq: &EqTarget,
    site: RewriteSite,
) -> Option<Vec<Level>> {
    let mut solutions = BTreeMap::new();
    if !match_simp_universe_levels(
        &rule.universe_params,
        &rule.eq_levels,
        &current_eq.levels,
        &mut solutions,
    ) {
        return None;
    }
    if !match_simp_universe_expr(
        &rule.universe_params,
        &rule.eq_type,
        &current_eq.ty,
        &mut solutions,
    ) {
        return None;
    }
    let selected_side = match site {
        RewriteSite::EqTargetLeft => &current_eq.lhs,
        RewriteSite::EqTargetRight => &current_eq.rhs,
    };
    if !match_simp_universe_expr(
        &rule.universe_params,
        &rule.from_pattern,
        selected_side,
        &mut solutions,
    ) {
        return None;
    }
    rule.universe_params
        .iter()
        .map(|param| solutions.get(param).cloned())
        .collect()
}

fn match_simp_universe_expr(
    params: &[String],
    pattern: &Expr,
    target: &Expr,
    solutions: &mut BTreeMap<String, Level>,
) -> bool {
    match (pattern, target) {
        (Expr::Sort(pattern), Expr::Sort(target)) => {
            match_simp_universe_level(params, pattern, target, solutions)
        }
        (Expr::BVar(_), _) => true,
        (
            Expr::Const {
                name: pattern_name,
                levels: pattern_levels,
            },
            Expr::Const {
                name: target_name,
                levels: target_levels,
            },
        ) if pattern_name == target_name => {
            match_simp_universe_levels(params, pattern_levels, target_levels, solutions)
        }
        (Expr::App(pattern_fun, pattern_arg), Expr::App(target_fun, target_arg)) => {
            match_simp_universe_expr(params, pattern_fun, target_fun, solutions)
                && match_simp_universe_expr(params, pattern_arg, target_arg, solutions)
        }
        (
            Expr::Lam {
                ty: pattern_ty,
                body: pattern_body,
                ..
            }
            | Expr::Pi {
                ty: pattern_ty,
                body: pattern_body,
                ..
            },
            Expr::Lam {
                ty: target_ty,
                body: target_body,
                ..
            }
            | Expr::Pi {
                ty: target_ty,
                body: target_body,
                ..
            },
        ) => {
            match_simp_universe_expr(params, pattern_ty, target_ty, solutions)
                && match_simp_universe_expr(params, pattern_body, target_body, solutions)
        }
        (
            Expr::Let {
                ty: pattern_ty,
                value: pattern_value,
                body: pattern_body,
                ..
            },
            Expr::Let {
                ty: target_ty,
                value: target_value,
                body: target_body,
                ..
            },
        ) => {
            match_simp_universe_expr(params, pattern_ty, target_ty, solutions)
                && match_simp_universe_expr(params, pattern_value, target_value, solutions)
                && match_simp_universe_expr(params, pattern_body, target_body, solutions)
        }
        _ => !contains_rule_universe_param_expr(params, pattern),
    }
}

fn match_simp_universe_levels(
    params: &[String],
    pattern: &[Level],
    target: &[Level],
    solutions: &mut BTreeMap<String, Level>,
) -> bool {
    pattern.len() == target.len()
        && pattern
            .iter()
            .zip(target)
            .all(|(pattern, target)| match_simp_universe_level(params, pattern, target, solutions))
}

fn match_simp_universe_level(
    params: &[String],
    pattern: &Level,
    target: &Level,
    solutions: &mut BTreeMap<String, Level>,
) -> bool {
    match pattern {
        Level::Param(name) if params.iter().any(|param| param == name) => {
            match solutions.get(name) {
                Some(existing) => {
                    normalize_level(existing.clone()) == normalize_level(target.clone())
                }
                None => {
                    solutions.insert(name.clone(), target.clone());
                    true
                }
            }
        }
        Level::Zero => matches!(target, Level::Zero),
        Level::Succ(pattern) => {
            matches!(target, Level::Succ(target) if match_simp_universe_level(params, pattern, target, solutions))
        }
        Level::Max(pattern_lhs, pattern_rhs) => {
            matches!(target, Level::Max(target_lhs, target_rhs)
                if match_simp_universe_level(params, pattern_lhs, target_lhs, solutions)
                    && match_simp_universe_level(params, pattern_rhs, target_rhs, solutions))
        }
        Level::IMax(pattern_lhs, pattern_rhs) => {
            matches!(target, Level::IMax(target_lhs, target_rhs)
                if match_simp_universe_level(params, pattern_lhs, target_lhs, solutions)
                    && match_simp_universe_level(params, pattern_rhs, target_rhs, solutions))
        }
        Level::Param(name) => matches!(target, Level::Param(target) if target == name),
    }
}

fn contains_rule_universe_param_expr(params: &[String], expr: &Expr) -> bool {
    match expr {
        Expr::Sort(level) => contains_rule_universe_param_level(params, level),
        Expr::BVar(_) => false,
        Expr::Const { levels, .. } => levels
            .iter()
            .any(|level| contains_rule_universe_param_level(params, level)),
        Expr::App(fun, arg) => {
            contains_rule_universe_param_expr(params, fun)
                || contains_rule_universe_param_expr(params, arg)
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            contains_rule_universe_param_expr(params, ty)
                || contains_rule_universe_param_expr(params, body)
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            contains_rule_universe_param_expr(params, ty)
                || contains_rule_universe_param_expr(params, value)
                || contains_rule_universe_param_expr(params, body)
        }
    }
}

fn contains_rule_universe_param_level(params: &[String], level: &Level) -> bool {
    match level {
        Level::Zero => false,
        Level::Succ(level) => contains_rule_universe_param_level(params, level),
        Level::Max(lhs, rhs) | Level::IMax(lhs, rhs) => {
            contains_rule_universe_param_level(params, lhs)
                || contains_rule_universe_param_level(params, rhs)
        }
        Level::Param(name) => params.iter().any(|param| param == name),
    }
}

fn mk_nested_rewrite_proof_from_refl(
    family: &ResolvedEqFamily,
    final_eq: &EqTarget,
    steps: Vec<RewriteStep>,
) -> Result<ProofExpr> {
    let mut proof = ProofExpr::Core(mk_eq_refl_expr(
        family,
        &final_eq.levels,
        final_eq.ty.clone(),
        final_eq.lhs.clone(),
    ));
    for step in steps.into_iter().rev() {
        proof = mk_rewrite_transport(
            family,
            &step.old_eq_target,
            &step.rule_eq_target,
            step.rule_proof,
            step.direction,
            step.site,
            proof,
        )?;
    }
    Ok(proof)
}

fn mk_nested_rewrite_proof_from_meta(
    family: &ResolvedEqFamily,
    final_meta: MetaVarId,
    steps: Vec<RewriteStep>,
) -> Result<ProofExpr> {
    let mut proof = ProofExpr::Meta(final_meta);
    for step in steps.into_iter().rev() {
        proof = mk_rewrite_transport(
            family,
            &step.old_eq_target,
            &step.rule_eq_target,
            step.rule_proof,
            step.direction,
            step.site,
            proof,
        )?;
    }
    Ok(proof)
}

fn extend_machine_local_context_assumption_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
    name: String,
    ty: Expr,
    fuel: &TacticRunFuel,
) -> Result<Vec<MachineLocalDecl>> {
    validate_local_context_extension_base(goal, context)?;
    validate_intro_name_available(state, context, &name)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    kernel_expect_sort_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let mut out = context.to_vec();
    out.push(MachineLocalDecl::assumption(name, ty));
    Ok(out)
}

#[allow(dead_code)]
fn extend_machine_local_context_definition_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
    name: String,
    ty: Expr,
    value: Expr,
    fuel: &TacticRunFuel,
) -> Result<Vec<MachineLocalDecl>> {
    validate_local_context_extension_base(goal, context)?;
    validate_intro_name_available(state, context, &name)
        .map_err(|diag| attach_goal_meta(diag, goal.id, goal.meta_id))?;
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    kernel_expect_sort_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    kernel_check_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &value,
        &ty,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    let mut out = context.to_vec();
    out.push(MachineLocalDecl::definition(name, ty, value));
    Ok(out)
}

fn validate_local_context_extension_base(
    goal: &MachineGoal,
    context: &[MachineLocalDecl],
) -> Result<()> {
    if !machine_local_context_is_prefix(context, &goal.context)
        && !machine_local_context_is_prefix(&goal.context, context)
    {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaContext,
            "local context extension must be comparable with the target goal context",
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id));
    }
    Ok(())
}

fn typed_subgoal_spec_with_budget(
    state: &MachineProofState,
    goal: &MachineGoal,
    context: Vec<MachineLocalDecl>,
    target: Expr,
    fuel: &TacticRunFuel,
) -> Result<MachineNewGoalSpec> {
    validate_local_context_extension_base(goal, &context)?;
    let ctx = local_context_to_ctx_with_budget(
        state.env.kernel_env(),
        &context,
        &state.root.universe_params,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    kernel_expect_sort_with_budget(
        state.env.kernel_env(),
        &ctx,
        &state.root.universe_params,
        &target,
        fuel,
        goal.id,
        goal.meta_id,
    )?;
    Ok(MachineNewGoalSpec::new(context, target))
}

struct MachineProofDeltaBuilder<'a, 'fuel> {
    state: &'a MachineProofState,
    goal_id: GoalId,
    proof_expr: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    budget: TacticBudget,
    required_tactic_steps: u64,
    fuel: &'fuel TacticRunFuel,
}

impl<'a, 'fuel> MachineProofDeltaBuilder<'a, 'fuel> {
    fn new(
        state: &'a MachineProofState,
        goal_id: GoalId,
        proof_expr: ProofExpr,
        budget: TacticBudget,
        required_tactic_steps: u64,
        fuel: &'fuel TacticRunFuel,
    ) -> Self {
        Self {
            state,
            goal_id,
            proof_expr,
            new_goal_specs: Vec::new(),
            budget,
            required_tactic_steps,
            fuel,
        }
    }

    fn with_new_goal_specs(mut self, new_goal_specs: Vec<MachineNewGoalSpec>) -> Self {
        self.new_goal_specs = new_goal_specs;
        self
    }

    fn build(self) -> Result<(MachineProofState, MachineProofDelta)> {
        validate_machine_proof_state(self.state)?;
        let goal_index = self
            .state
            .open_goals
            .iter()
            .position(|open_goal| *open_goal == self.goal_id)
            .ok_or_else(|| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnknownGoal,
                    format!("goal {} is not open", self.goal_id.0),
                )
                .with_goal(self.goal_id)
            })?;
        let assigned_meta_id = MetaVarId::from(self.goal_id);
        let assigned_meta = self.state.metas.get(assigned_meta_id).ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownGoal,
                format!(
                    "goal {} does not have a backing metavariable",
                    self.goal_id.0
                ),
            )
            .with_goal(self.goal_id)
            .with_meta(assigned_meta_id)
        })?;
        if assigned_meta.assignment.is_some() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::GoalAlreadyAssigned,
                format!("goal {} is already assigned", self.goal_id.0),
            )
            .with_goal(self.goal_id)
            .with_meta(assigned_meta_id));
        }
        if self.new_goal_specs.len() as u64 > self.budget.max_meta_allocations {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TacticFuelExhausted {
                    kind: TacticFuelKind::MetaAllocation,
                },
                format!(
                    "assign_goal requested {} new metas, remaining meta allocation fuel is {}",
                    self.new_goal_specs.len(),
                    self.budget.max_meta_allocations
                ),
            )
            .with_goal(self.goal_id)
            .with_meta(assigned_meta_id));
        }
        let resulting_open_goals = self.state.open_goals.len() - 1 + self.new_goal_specs.len();
        if resulting_open_goals > self.state.env.options.max_open_goals {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::GoalLimitExceeded,
                format!(
                    "assign_goal would leave {} open goals, limit is {}",
                    resulting_open_goals, self.state.env.options.max_open_goals
                ),
            )
            .with_goal(self.goal_id)
            .with_meta(assigned_meta_id));
        }
        if self.state.metas.len() + self.new_goal_specs.len() > self.state.env.options.max_metas {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::MetaLimitExceeded,
                format!(
                    "assign_goal would create {} metas total, limit is {}",
                    self.state.metas.len() + self.new_goal_specs.len(),
                    self.state.env.options.max_metas
                ),
            )
            .with_goal(self.goal_id)
            .with_meta(assigned_meta_id));
        }

        let goal = MachineGoal {
            id: self.goal_id,
            meta_id: assigned_meta_id,
            context: assigned_meta.context.clone(),
            context_hash: machine_local_context_hash(&assigned_meta.context),
            target: assigned_meta.target.clone(),
            target_hash: core_expr_hash(&assigned_meta.target),
        };
        let mut new_goal_expr_nodes = 0;
        for spec in &self.new_goal_specs {
            typed_subgoal_spec_with_budget(
                self.state,
                &goal,
                spec.context.clone(),
                spec.target.clone(),
                self.fuel,
            )?;
            new_goal_expr_nodes += core_expr_node_count(&spec.target);
        }

        ensure_tactic_step_fuel(
            self.budget,
            self.required_tactic_steps,
            self.goal_id,
            assigned_meta_id,
        )?;

        let mut candidate = self.state.clone();
        let mut new_meta_ids = BTreeSet::new();
        let mut added_goals = Vec::new();
        let mut new_metas_delta = Vec::new();
        for spec in self.new_goal_specs {
            let meta_id = MetaVarId(candidate.metas.next_id);
            let new_goal_id = GoalId::from(meta_id);
            candidate.metas.next_id += 1;
            new_meta_ids.insert(meta_id);
            candidate.metas.metas.insert(
                meta_id,
                MachineMetaVar {
                    id: meta_id,
                    goal_id: new_goal_id,
                    context: spec.context.clone(),
                    target: spec.target.clone(),
                    assignment: None,
                    creation_index: meta_id.0,
                },
            );
            added_goals.push(new_goal_id);
            new_metas_delta.push(MachineNewMetaDelta {
                meta_id,
                goal_id: new_goal_id,
                context_hash: machine_local_context_hash(&spec.context),
                target_hash: core_expr_hash(&spec.target),
            });
        }

        ensure_expr_node_fuel(
            self.budget,
            proof_expr_node_count(&self.proof_expr) + new_goal_expr_nodes,
            self.goal_id,
            assigned_meta_id,
        )?;

        check_proof_expr(
            candidate.env.kernel_env(),
            &candidate.metas,
            &assigned_meta.context,
            &candidate.root.universe_params,
            &self.proof_expr,
            &assigned_meta.target,
            &new_meta_ids,
            assigned_meta_id,
            self.fuel,
        )?;

        candidate
            .metas
            .get_mut(assigned_meta_id)
            .expect("assigned meta was looked up before cloning")
            .assignment = Some(self.proof_expr.clone());
        candidate
            .open_goals
            .splice(goal_index..goal_index + 1, added_goals.iter().copied());
        refresh_state_identity(&mut candidate);
        validate_machine_proof_state(&candidate)?;

        let proof_expr_hash = proof_expr_hash(&self.proof_expr);
        let mut delta = MachineProofDelta {
            from_state_fingerprint: self.state.fingerprint,
            to_state_fingerprint: candidate.fingerprint,
            assigned_goal: self.goal_id,
            assigned_meta: assigned_meta_id,
            proof_expr_hash,
            added_goals,
            new_metas: new_metas_delta,
            delta_hash: ZERO_HASH,
        };
        delta.delta_hash = machine_proof_delta_hash(&delta);
        Ok((candidate, delta))
    }
}

pub fn assign_goal(
    state: &MachineProofState,
    goal_id: GoalId,
    proof_expr: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
) -> Result<(MachineProofState, MachineProofDelta)> {
    assign_goal_with_budget(
        state,
        goal_id,
        proof_expr,
        new_goal_specs,
        TacticBudget::default(),
    )
}

pub fn assign_goal_with_budget(
    state: &MachineProofState,
    goal_id: GoalId,
    proof_expr: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    budget: TacticBudget,
) -> Result<(MachineProofState, MachineProofDelta)> {
    let fuel = TacticRunFuel::new(budget);
    assign_goal_with_budget_and_steps(state, goal_id, proof_expr, new_goal_specs, budget, 1, &fuel)
}

fn assign_goal_with_budget_and_steps(
    state: &MachineProofState,
    goal_id: GoalId,
    proof_expr: ProofExpr,
    new_goal_specs: Vec<MachineNewGoalSpec>,
    budget: TacticBudget,
    required_tactic_steps: u64,
    fuel: &TacticRunFuel,
) -> Result<(MachineProofState, MachineProofDelta)> {
    MachineProofDeltaBuilder::new(
        state,
        goal_id,
        proof_expr,
        budget,
        required_tactic_steps,
        fuel,
    )
    .with_new_goal_specs(new_goal_specs)
    .build()
}

pub fn extract_closed_machine_proof(state: &MachineProofState) -> Result<Expr> {
    validate_machine_proof_state(state)?;
    if !state.open_goals.is_empty() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UnresolvedGoal,
            format!("proof has {} open goals", state.open_goals.len()),
        ));
    }
    let proof = expand_proof_expr(state, &state.root.body, &[], &mut BTreeSet::new())?;
    state
        .env
        .kernel_env()
        .check(
            &Ctx::new(),
            &state.root.universe_params,
            &proof,
            &state.root.theorem_type,
        )
        .map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::KernelRejected,
                format!("kernel rejected extracted proof: {err:?}"),
            )
        })?;
    Ok(proof)
}

pub fn extract_closed_machine_theorem_decl(state: &MachineProofState) -> Result<Decl> {
    let proof = extract_closed_machine_proof(state)?;
    Ok(Decl::Theorem {
        name: state.root.theorem_name.as_dotted(),
        universe_params: state.root.universe_params.clone(),
        ty: state.root.theorem_type.clone(),
        proof,
    })
}

/// Verified certificate handoff for a closed machine proof.
///
/// Machine tactic, machine API, and AI search produce tactic candidates and proof states, not trusted certificate
/// producer tokens. This handoff keeps the boundary at the final `CoreModule`,
/// canonical `.npcert` bytes, and the `VerifiedModule` returned by
/// `npa_cert::verify_module_cert`.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct MachineProofCertificate {
    pub core_module: CoreModule,
    pub certificate: npa_cert::ModuleCert,
    pub certificate_bytes: Vec<u8>,
    pub verified_module: VerifiedModule,
}

pub fn extract_closed_machine_core_module(state: &MachineProofState) -> Result<CoreModule> {
    let theorem = extract_closed_machine_theorem_decl(state)?;
    let mut declarations = state
        .env
        .checked_current_decls
        .iter()
        .map(|decl| decl.core_decl().clone())
        .collect::<Vec<_>>();
    declarations.push(theorem);
    Ok(CoreModule {
        name: state.root.module.clone(),
        declarations,
    })
}

/// Build, encode, and verify the final `.npcert` for a closed machine proof.
pub fn extract_closed_machine_certificate(
    state: &MachineProofState,
) -> Result<MachineProofCertificate> {
    let core_module = extract_closed_machine_core_module(state)?;
    let certificate_imports =
        certificate_imports_for_current_decl_hashes(&state.env.imports, &core_module.declarations)?;
    let import_closure = state
        .env
        .imports
        .iter()
        .map(|import| import.verified_module.as_ref().clone())
        .collect::<Vec<_>>();
    let certificate = npa_cert::build_module_cert(core_module.clone(), &certificate_imports)
        .map_err(|err| certificate_handoff_diag("build_module_cert", err))?;
    let certificate_bytes = npa_cert::encode_module_cert(&certificate)
        .map_err(|err| certificate_handoff_diag("encode_module_cert", err))?;
    let mut session = npa_cert::VerifierSession::new();
    for import in import_closure {
        session.register_verified_module(import);
    }
    let verified_module = npa_cert::verify_module_cert(
        &certificate_bytes,
        &mut session,
        &npa_cert::AxiomPolicy::normal(),
    )
    .map_err(|err| certificate_handoff_diag("verify_module_cert", err))?;
    Ok(MachineProofCertificate {
        core_module,
        certificate,
        certificate_bytes,
        verified_module,
    })
}

fn certificate_handoff_diag(stage: &str, err: npa_cert::CertError) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::KernelRejected,
        format!("certificate handoff {stage} failed: {err:?}"),
    )
}

pub fn validate_machine_proof_state(state: &MachineProofState) -> Result<()> {
    validate_options(&state.env.options)?;
    if state.env.options_fingerprint != machine_tactic_options_hash(&state.env.options) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofState,
            "machine tactic options fingerprint is stale",
        ));
    }
    if state.env.env_fingerprint != machine_tactic_env_hash(&state.env) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofState,
            "machine tactic env fingerprint is stale",
        ));
    }
    let expected_reserved = recompute_reserved_local_names(state);
    if state.reserved_local_names != expected_reserved {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofState,
            "reserved local names are stale",
        ));
    }
    let expected_fingerprint = machine_proof_state_hash(state);
    if state.fingerprint != expected_fingerprint {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofState,
            "machine proof state fingerprint is stale",
        ));
    }
    let expected_state_id = hex_hash(&expected_fingerprint);
    if state.state_id != expected_state_id {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofState,
            "machine proof state_id is stale",
        ));
    }
    for (meta_id, meta) in &state.metas.metas {
        if *meta_id != meta.id || meta.goal_id != GoalId::from(*meta_id) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!("metavariable {} has inconsistent id fields", meta_id.0),
            )
            .with_meta(*meta_id));
        }
        if meta.id.0 >= state.metas.next_id {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!(
                    "metavariable {} is outside the allocated next_id {}",
                    meta.id.0, state.metas.next_id
                ),
            )
            .with_meta(*meta_id));
        }
    }
    let mut seen_open_goals = BTreeSet::new();
    for goal_id in &state.open_goals {
        if !seen_open_goals.insert(*goal_id) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!("goal {} appears more than once", goal_id.0),
            )
            .with_goal(*goal_id));
        }
        let meta_id = MetaVarId::from(*goal_id);
        let meta = state.metas.get(meta_id).ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!("open goal {} has no metavariable", goal_id.0),
            )
            .with_goal(*goal_id)
            .with_meta(meta_id)
        })?;
        if meta.assignment.is_some() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!("open goal {} is already assigned", goal_id.0),
            )
            .with_goal(*goal_id)
            .with_meta(meta_id));
        }
    }
    for meta in state.metas.metas.values() {
        let is_open = seen_open_goals.contains(&meta.goal_id);
        if meta.assignment.is_none() && !is_open {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!("unassigned meta {} is missing from open goals", meta.id.0),
            )
            .with_goal(meta.goal_id)
            .with_meta(meta.id));
        }
        if meta.assignment.is_some() && is_open {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofState,
                format!("assigned meta {} is still listed as open", meta.id.0),
            )
            .with_goal(meta.goal_id)
            .with_meta(meta.id));
        }
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn check_proof_expr(
    env: &Env,
    metas: &MetaVarStore,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    expr: &ProofExpr,
    expected: &Expr,
    allowed_new_metas: &BTreeSet<MetaVarId>,
    assigning_meta: MetaVarId,
    fuel: &TacticRunFuel,
) -> Result<CheckedProofExpr> {
    match expr {
        ProofExpr::Lam { binder, ty, body } => check_lam_proof_expr(
            env,
            metas,
            context,
            universe_params,
            binder,
            ty,
            body,
            expected,
            allowed_new_metas,
            assigning_meta,
            fuel,
        ),
        ProofExpr::Let {
            binder,
            ty,
            value,
            body,
        } => check_let_proof_expr(
            env,
            metas,
            context,
            universe_params,
            binder,
            ty,
            value,
            body,
            expected,
            allowed_new_metas,
            assigning_meta,
            fuel,
        ),
        _ => {
            let checked = infer_proof_expr(
                env,
                metas,
                context,
                universe_params,
                expr,
                allowed_new_metas,
                assigning_meta,
                fuel,
                &mut BTreeSet::new(),
            )?;
            let ctx = local_context_to_ctx_with_budget(
                env,
                context,
                universe_params,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            if kernel_is_defeq_with_budget(
                env,
                &ctx,
                universe_params,
                &checked.ty,
                expected,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )? {
                Ok(checked)
            } else {
                Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TypeMismatch,
                    "proof expression type does not match goal target",
                )
                .with_expected_actual_payloads(
                    DiagnosticPayloadKind::Expr,
                    &core_expr_canonical_bytes(expected),
                    &core_expr_canonical_bytes(&checked.ty),
                ))
            }
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn check_lam_proof_expr(
    env: &Env,
    metas: &MetaVarStore,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    binder: &str,
    ty: &Expr,
    body: &ProofExpr,
    expected: &Expr,
    allowed_new_metas: &BTreeSet<MetaVarId>,
    assigning_meta: MetaVarId,
    fuel: &TacticRunFuel,
) -> Result<CheckedProofExpr> {
    let ctx = local_context_to_ctx_with_budget(
        env,
        context,
        universe_params,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )?;
    kernel_expect_sort_with_budget(
        env,
        &ctx,
        universe_params,
        ty,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )?;
    let expected_whnf = kernel_whnf_with_budget(
        env,
        &ctx,
        universe_params,
        expected,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )?;
    let Expr::Pi {
        ty: expected_ty,
        body: expected_body,
        ..
    } = expected_whnf
    else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "lambda proof expression requires a Pi goal target",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(expected),
            &core_expr_canonical_bytes(&expected_whnf),
        ));
    };
    if !kernel_is_defeq_with_budget(
        env,
        &ctx,
        universe_params,
        ty,
        &expected_ty,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )? {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            "lambda binder type does not match Pi domain",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&expected_ty),
            &core_expr_canonical_bytes(ty),
        ));
    }
    let mut body_context = context.to_vec();
    body_context.push(MachineLocalDecl::assumption(
        binder.to_owned(),
        Arc::unwrap_or_clone(expected_ty),
    ));
    let body_checked = check_proof_expr(
        env,
        metas,
        &body_context,
        universe_params,
        body,
        &expected_body,
        allowed_new_metas,
        assigning_meta,
        fuel,
    )?;
    Ok(CheckedProofExpr {
        expr: body_checked
            .expr
            .map(|body_expr| Expr::lam(binder.to_owned(), ty.clone(), body_expr)),
        ty: expected.clone(),
    })
}

#[allow(clippy::too_many_arguments)]
fn check_let_proof_expr(
    env: &Env,
    metas: &MetaVarStore,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    binder: &str,
    ty: &Expr,
    value: &ProofExpr,
    body: &ProofExpr,
    expected: &Expr,
    allowed_new_metas: &BTreeSet<MetaVarId>,
    assigning_meta: MetaVarId,
    fuel: &TacticRunFuel,
) -> Result<CheckedProofExpr> {
    let ctx = local_context_to_ctx_with_budget(
        env,
        context,
        universe_params,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )?;
    kernel_expect_sort_with_budget(
        env,
        &ctx,
        universe_params,
        ty,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )?;
    let value_checked = check_proof_expr(
        env,
        metas,
        context,
        universe_params,
        value,
        ty,
        allowed_new_metas,
        assigning_meta,
        fuel,
    )?;
    let Some(value_expr) = value_checked.expr else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            "let value must be a closed skeleton expression before it can extend a local context",
        ));
    };
    let mut body_context = context.to_vec();
    body_context.push(MachineLocalDecl::definition(
        binder.to_owned(),
        ty.clone(),
        value_expr.clone(),
    ));
    let body_expected = shift(expected, 1, 0).map_err(kernel_diag)?;
    let body_checked = check_proof_expr(
        env,
        metas,
        &body_context,
        universe_params,
        body,
        &body_expected,
        allowed_new_metas,
        assigning_meta,
        fuel,
    )?;
    Ok(CheckedProofExpr {
        expr: body_checked
            .expr
            .map(|body_expr| Expr::let_in(binder.to_owned(), ty.clone(), value_expr, body_expr)),
        ty: expected.clone(),
    })
}

#[derive(Clone, Debug)]
struct CheckedProofExpr {
    expr: Option<Expr>,
    ty: Expr,
}

#[allow(clippy::too_many_arguments)]
fn infer_proof_expr(
    env: &Env,
    metas: &MetaVarStore,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    expr: &ProofExpr,
    allowed_new_metas: &BTreeSet<MetaVarId>,
    assigning_meta: MetaVarId,
    fuel: &TacticRunFuel,
    visiting: &mut BTreeSet<MetaVarId>,
) -> Result<CheckedProofExpr> {
    match expr {
        ProofExpr::Core(core) => {
            let ctx = local_context_to_ctx_with_budget(
                env,
                context,
                universe_params,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            let ty = kernel_infer_with_budget(
                env,
                &ctx,
                universe_params,
                core,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            Ok(CheckedProofExpr {
                expr: Some(core.clone()),
                ty,
            })
        }
        ProofExpr::Meta(meta_id) => infer_meta_ref(
            env,
            metas,
            context,
            universe_params,
            *meta_id,
            allowed_new_metas,
            assigning_meta,
            visiting,
        ),
        ProofExpr::App(fun, arg) => {
            let fun_checked = infer_proof_expr(
                env,
                metas,
                context,
                universe_params,
                fun,
                allowed_new_metas,
                assigning_meta,
                fuel,
                visiting,
            )?;
            let ctx = local_context_to_ctx_with_budget(
                env,
                context,
                universe_params,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            let fun_ty_whnf = kernel_whnf_with_budget(
                env,
                &ctx,
                universe_params,
                &fun_checked.ty,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            let Expr::Pi { ty, body, .. } = fun_ty_whnf else {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::TypeMismatch,
                    "application head is not a function",
                )
                .with_expected_actual_payloads(
                    DiagnosticPayloadKind::Expr,
                    &core_expr_canonical_bytes(&fun_checked.ty),
                    &core_expr_canonical_bytes(&fun_ty_whnf),
                ));
            };
            let arg_checked = check_proof_expr(
                env,
                metas,
                context,
                universe_params,
                arg,
                &ty,
                allowed_new_metas,
                assigning_meta,
                fuel,
            )?;
            let result_ty = if let Some(arg_expr) = &arg_checked.expr {
                instantiate(&body, arg_expr).map_err(kernel_diag)?
            } else if !contains_bound_var(&body, 0) {
                instantiate(&body, &Expr::bvar(0)).map_err(kernel_diag)?
            } else {
                result_type_for_unresolved_dependent_arg(
                    env,
                    context,
                    universe_params,
                    &ty,
                    &body,
                    assigning_meta,
                    fuel,
                )?
            };
            let expr = match (fun_checked.expr, arg_checked.expr) {
                (Some(fun_expr), Some(arg_expr)) => Some(Expr::app(fun_expr, arg_expr)),
                _ => None,
            };
            Ok(CheckedProofExpr {
                expr,
                ty: result_ty,
            })
        }
        ProofExpr::Lam { binder, ty, body } => {
            let ctx = local_context_to_ctx_with_budget(
                env,
                context,
                universe_params,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            kernel_expect_sort_with_budget(
                env,
                &ctx,
                universe_params,
                ty,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            let mut body_context = context.to_vec();
            body_context.push(MachineLocalDecl::assumption(binder.clone(), ty.clone()));
            let body_checked = infer_proof_expr(
                env,
                metas,
                &body_context,
                universe_params,
                body,
                allowed_new_metas,
                assigning_meta,
                fuel,
                visiting,
            )?;
            Ok(CheckedProofExpr {
                expr: body_checked
                    .expr
                    .map(|body_expr| Expr::lam(binder.clone(), ty.clone(), body_expr)),
                ty: Expr::pi(binder.clone(), ty.clone(), body_checked.ty),
            })
        }
        ProofExpr::Let {
            binder,
            ty,
            value,
            body,
        } => {
            let ctx = local_context_to_ctx_with_budget(
                env,
                context,
                universe_params,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            kernel_expect_sort_with_budget(
                env,
                &ctx,
                universe_params,
                ty,
                fuel,
                GoalId::from(assigning_meta),
                assigning_meta,
            )?;
            let value_checked = check_proof_expr(
                env,
                metas,
                context,
                universe_params,
                value,
                ty,
                allowed_new_metas,
                assigning_meta,
                fuel,
            )?;
            let Some(value_expr) = value_checked.expr else {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaDependency,
                    "let value must be a closed skeleton expression before it can extend a local context",
                ));
            };
            let mut body_context = context.to_vec();
            body_context.push(MachineLocalDecl::definition(
                binder.clone(),
                ty.clone(),
                value_expr.clone(),
            ));
            let body_checked = infer_proof_expr(
                env,
                metas,
                &body_context,
                universe_params,
                body,
                allowed_new_metas,
                assigning_meta,
                fuel,
                visiting,
            )?;
            let result_ty = instantiate(&body_checked.ty, &value_expr).map_err(kernel_diag)?;
            Ok(CheckedProofExpr {
                expr: body_checked.expr.map(|body_expr| {
                    Expr::let_in(binder.clone(), ty.clone(), value_expr, body_expr)
                }),
                ty: result_ty,
            })
        }
    }
}

fn result_type_for_unresolved_dependent_arg(
    env: &Env,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    arg_ty: &Expr,
    body: &Expr,
    assigning_meta: MetaVarId,
    fuel: &TacticRunFuel,
) -> Result<Expr> {
    let mut extended_context = context.to_vec();
    extended_context.push(MachineLocalDecl::assumption(
        "__arg".to_owned(),
        arg_ty.clone(),
    ));
    let body_in_extended_context = shift(body, 1, 1).map_err(kernel_diag)?;
    let hypothetical =
        instantiate(&body_in_extended_context, &Expr::bvar(0)).map_err(kernel_diag)?;
    let extended_ctx = local_context_to_ctx_with_budget(
        env,
        &extended_context,
        universe_params,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )?;
    let normalized = kernel_whnf_with_budget(
        env,
        &extended_ctx,
        universe_params,
        &hypothetical,
        fuel,
        GoalId::from(assigning_meta),
        assigning_meta,
    )?;
    project_expr_to_prefix_context_at(
        &normalized,
        extended_context.len(),
        context.len(),
        extended_context.len(),
        context.len(),
    )
    .map_err(|err| {
        let message = match err {
            ContextProjectionError::DroppedLocal(_) => {
                "dependent application result type still depends on an unresolved meta argument"
                    .to_owned()
            }
            ContextProjectionError::OutOfScope(index) => {
                format!("dependent application result type contains out-of-scope de Bruijn index {index}")
            }
        };
        MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::InvalidMetaDependency, message)
            .with_goal(GoalId::from(assigning_meta))
            .with_meta(assigning_meta)
    })
}

#[allow(clippy::too_many_arguments)]
fn infer_meta_ref(
    env: &Env,
    metas: &MetaVarStore,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    meta_id: MetaVarId,
    allowed_new_metas: &BTreeSet<MetaVarId>,
    assigning_meta: MetaVarId,
    visiting: &mut BTreeSet<MetaVarId>,
) -> Result<CheckedProofExpr> {
    if meta_id == assigning_meta {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            "proof expression cannot directly reference the metavariable being assigned",
        )
        .with_meta(meta_id));
    }
    let meta = metas.get(meta_id).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            format!("proof expression references unknown meta {}", meta_id.0),
        )
        .with_meta(meta_id)
    })?;
    if !machine_local_context_is_prefix(&meta.context, context) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaContext,
            format!(
                "meta {} context is not a prefix of the current proof expression context",
                meta_id.0
            ),
        )
        .with_meta(meta_id));
    }
    let weakening = context.len() - meta.context.len();
    let target = shift(&meta.target, weakening as i32, 0).map_err(kernel_diag)?;
    match &meta.assignment {
        None if allowed_new_metas.contains(&meta_id) => Ok(CheckedProofExpr {
            expr: None,
            ty: target,
        }),
        None => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMetaDependency,
            format!(
                "proof expression references old unresolved meta {}",
                meta_id.0
            ),
        )
        .with_meta(meta_id)),
        Some(assignment) => {
            if !visiting.insert(meta_id) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaDependency,
                    format!("metavariable dependency cycle at meta {}", meta_id.0),
                )
                .with_meta(meta_id));
            }
            let expr = expand_proof_expr_maybe(
                env,
                metas,
                assignment,
                &meta.context,
                universe_params,
                allowed_new_metas,
                assigning_meta,
                visiting,
            )?
            .map(|expanded| shift(&expanded, weakening as i32, 0))
            .transpose()
            .map_err(kernel_diag)?;
            visiting.remove(&meta_id);
            Ok(CheckedProofExpr { expr, ty: target })
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn expand_proof_expr_maybe(
    env: &Env,
    metas: &MetaVarStore,
    expr: &ProofExpr,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    allowed_new_metas: &BTreeSet<MetaVarId>,
    assigning_meta: MetaVarId,
    visiting: &mut BTreeSet<MetaVarId>,
) -> Result<Option<Expr>> {
    Ok(match expr {
        ProofExpr::Core(core) => Some(core.clone()),
        ProofExpr::Meta(meta_id) => {
            let checked = infer_meta_ref(
                env,
                metas,
                context,
                universe_params,
                *meta_id,
                allowed_new_metas,
                assigning_meta,
                visiting,
            )?;
            checked.expr
        }
        ProofExpr::App(fun, arg) => {
            match (
                expand_proof_expr_maybe(
                    env,
                    metas,
                    fun,
                    context,
                    universe_params,
                    allowed_new_metas,
                    assigning_meta,
                    visiting,
                )?,
                expand_proof_expr_maybe(
                    env,
                    metas,
                    arg,
                    context,
                    universe_params,
                    allowed_new_metas,
                    assigning_meta,
                    visiting,
                )?,
            ) {
                (Some(fun), Some(arg)) => Some(Expr::app(fun, arg)),
                _ => None,
            }
        }
        ProofExpr::Lam { binder, ty, body } => {
            let mut body_context = context.to_vec();
            body_context.push(MachineLocalDecl::assumption(binder.clone(), ty.clone()));
            expand_proof_expr_maybe(
                env,
                metas,
                body,
                &body_context,
                universe_params,
                allowed_new_metas,
                assigning_meta,
                visiting,
            )?
            .map(|body| Expr::lam(binder.clone(), ty.clone(), body))
        }
        ProofExpr::Let {
            binder,
            ty,
            value,
            body,
        } => {
            let value = expand_proof_expr_maybe(
                env,
                metas,
                value,
                context,
                universe_params,
                allowed_new_metas,
                assigning_meta,
                visiting,
            )?;
            let Some(value) = value else {
                return Ok(None);
            };
            let mut body_context = context.to_vec();
            body_context.push(MachineLocalDecl::definition(
                binder.clone(),
                ty.clone(),
                value.clone(),
            ));
            expand_proof_expr_maybe(
                env,
                metas,
                body,
                &body_context,
                universe_params,
                allowed_new_metas,
                assigning_meta,
                visiting,
            )?
            .map(|body| Expr::let_in(binder.clone(), ty.clone(), value, body))
        }
    })
}

fn expand_proof_expr(
    state: &MachineProofState,
    expr: &ProofExpr,
    context: &[MachineLocalDecl],
    visiting: &mut BTreeSet<MetaVarId>,
) -> Result<Expr> {
    match expr {
        ProofExpr::Core(core) => Ok(core.clone()),
        ProofExpr::Meta(meta_id) => {
            let meta = state.metas.get(*meta_id).ok_or_else(|| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaDependency,
                    format!("proof references unknown meta {}", meta_id.0),
                )
                .with_meta(*meta_id)
            })?;
            if !machine_local_context_is_prefix(&meta.context, context) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaContext,
                    format!("meta {} context is not a prefix at extraction", meta_id.0),
                )
                .with_meta(*meta_id));
            }
            let assignment = meta.assignment.as_ref().ok_or_else(|| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnresolvedGoal,
                    format!("meta {} is unresolved", meta_id.0),
                )
                .with_goal(meta.goal_id)
                .with_meta(*meta_id)
            })?;
            if !visiting.insert(*meta_id) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMetaDependency,
                    format!("metavariable dependency cycle at meta {}", meta_id.0),
                )
                .with_meta(*meta_id));
            }
            let expanded = expand_proof_expr(state, assignment, &meta.context, visiting)?;
            visiting.remove(meta_id);
            let weakening = context.len() - meta.context.len();
            shift(&expanded, weakening as i32, 0).map_err(kernel_diag)
        }
        ProofExpr::App(fun, arg) => Ok(Expr::app(
            expand_proof_expr(state, fun, context, visiting)?,
            expand_proof_expr(state, arg, context, visiting)?,
        )),
        ProofExpr::Lam { binder, ty, body } => {
            let mut body_context = context.to_vec();
            body_context.push(MachineLocalDecl::assumption(binder.clone(), ty.clone()));
            Ok(Expr::lam(
                binder.clone(),
                ty.clone(),
                expand_proof_expr(state, body, &body_context, visiting)?,
            ))
        }
        ProofExpr::Let {
            binder,
            ty,
            value,
            body,
        } => {
            let value_expr = expand_proof_expr(state, value, context, visiting)?;
            let mut body_context = context.to_vec();
            body_context.push(MachineLocalDecl::definition(
                binder.clone(),
                ty.clone(),
                value_expr.clone(),
            ));
            Ok(Expr::let_in(
                binder.clone(),
                ty.clone(),
                value_expr,
                expand_proof_expr(state, body, &body_context, visiting)?,
            ))
        }
    }
}

fn refresh_state_identity(state: &mut MachineProofState) {
    state.reserved_local_names = recompute_reserved_local_names(state);
    state.fingerprint = machine_proof_state_hash(state);
    state.state_id = hex_hash(&state.fingerprint);
}

fn recompute_reserved_local_names(state: &MachineProofState) -> Vec<String> {
    let mut names = BTreeSet::new();
    collect_proof_expr_binders(&state.root.body, &mut names);
    for meta in state.metas.metas.values() {
        for local in &meta.context {
            names.insert(local.name.clone());
        }
        if let Some(assignment) = &meta.assignment {
            collect_proof_expr_binders(assignment, &mut names);
        }
    }
    names.into_iter().collect()
}

fn collect_proof_expr_binders(expr: &ProofExpr, names: &mut BTreeSet<String>) {
    match expr {
        ProofExpr::Core(core) => collect_core_binders(core, names),
        ProofExpr::Meta(_) => {}
        ProofExpr::App(fun, arg) => {
            collect_proof_expr_binders(fun, names);
            collect_proof_expr_binders(arg, names);
        }
        ProofExpr::Lam { binder, ty, body } => {
            names.insert(binder.clone());
            collect_core_binders(ty, names);
            collect_proof_expr_binders(body, names);
        }
        ProofExpr::Let {
            binder,
            ty,
            value,
            body,
        } => {
            names.insert(binder.clone());
            collect_core_binders(ty, names);
            collect_proof_expr_binders(value, names);
            collect_proof_expr_binders(body, names);
        }
    }
}

fn collect_core_binders(expr: &Expr, names: &mut BTreeSet<String>) {
    match expr {
        Expr::Sort(_) | Expr::BVar(_) | Expr::Const { .. } => {}
        Expr::App(fun, arg) => {
            collect_core_binders(fun, names);
            collect_core_binders(arg, names);
        }
        Expr::Lam { binder, ty, body } | Expr::Pi { binder, ty, body } => {
            names.insert(binder.clone());
            collect_core_binders(ty, names);
            collect_core_binders(body, names);
        }
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => {
            names.insert(binder.clone());
            collect_core_binders(ty, names);
            collect_core_binders(value, names);
            collect_core_binders(body, names);
        }
    }
}

fn validate_options(options: &MachineTacticOptions) -> Result<()> {
    validate_simp_rule_refs(&options.simp_rules)?;
    if options.max_simp_rewrite_steps == 0 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidTacticOption,
            "max_simp_rewrite_steps must be nonzero",
        ));
    }
    if options.max_open_goals == 0 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidTacticOption,
            "max_open_goals must be nonzero",
        ));
    }
    if options.max_metas == 0 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidTacticOption,
            "max_metas must be nonzero",
        ));
    }
    Ok(())
}

fn canonicalize_options(mut options: MachineTacticOptions) -> Result<MachineTacticOptions> {
    validate_options(&options)?;
    options.simp_rules = canonicalize_simp_rule_refs(options.simp_rules)?;
    Ok(options)
}

fn validate_simp_rule_refs(rules: &[SimpRuleRef]) -> Result<()> {
    for rule in rules {
        if !rule.name.is_canonical() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                format!("simp rule name {} is not canonical", rule.name.as_dotted()),
            ));
        }
    }
    Ok(())
}

fn validate_smt_lemma_refs(lemmas: &[SmtLemmaRef]) -> Result<()> {
    for lemma in lemmas {
        validate_tactic_head_shape(&lemma.head)?;
    }
    Ok(())
}

fn canonicalize_simp_rule_refs(rules: Vec<SimpRuleRef>) -> Result<Vec<SimpRuleRef>> {
    validate_simp_rule_refs(&rules)?;
    let mut keyed = BTreeMap::new();
    for rule in rules {
        keyed
            .entry(simp_rule_ref_canonical_bytes(&rule))
            .or_insert(rule);
    }
    Ok(keyed.into_values().collect())
}

fn validate_candidate_rewrite_rule(rule: CandidateRewriteRuleRef) -> Result<RewriteRuleRef> {
    validate_tactic_head_shape(&rule.head)?;
    let args = rule
        .args
        .into_iter()
        .map(validate_candidate_apply_arg)
        .collect::<Result<Vec<_>>>()?;
    Ok(RewriteRuleRef {
        head: rule.head,
        universe_args: rule.universe_args,
        args,
    })
}

fn validate_rewrite_rule_ref(rule: &RewriteRuleRef) -> Result<()> {
    validate_tactic_head_shape(&rule.head)?;
    for arg in &rule.args {
        validate_apply_arg(arg)?;
    }
    Ok(())
}

fn resolve_eq_family(
    kernel_env: &Env,
    imports: &[VerifiedImportRef],
    current: &[CheckedCurrentDecl],
    family_ref: Option<&EqFamilyRef>,
) -> Result<Option<ResolvedEqFamily>> {
    match family_ref {
        None => {
            if kernel_env.decl("Eq").is_some()
                && kernel_env.decl("Eq.refl").is_some()
                && kernel_env.decl("Eq.rec").is_some()
            {
                let mut out = tagged_bytes("npa.machine-tactic.resolved-eq-family.builtin.v1");
                encode_string_to(&mut out, "builtin-nat-eq-rec-v0.1");
                Ok(Some(ResolvedEqFamily {
                    eq_name: Name::from_dotted("Eq"),
                    refl_name: Name::from_dotted("Eq.refl"),
                    rec_name: Name::from_dotted("Eq.rec"),
                    fingerprint: hash_with_domain("npa.machine-tactic.resolved-eq-family.v1", &out),
                }))
            } else {
                Ok(None)
            }
        }
        Some(reference) => {
            let eq = resolve_family_signature(
                kernel_env,
                imports,
                current,
                &reference.eq_name,
                &reference.eq_interface_hash,
            )?;
            let refl = resolve_family_signature(
                kernel_env,
                imports,
                current,
                &reference.refl_name,
                &reference.refl_interface_hash,
            )?;
            let rec = resolve_family_signature(
                kernel_env,
                imports,
                current,
                &reference.rec_name,
                &reference.rec_interface_hash,
            )?;
            check_eq_family_interfaces(kernel_env, &eq, &refl, &rec)?;
            if eq.origin != refl.origin || eq.origin != rec.origin {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidEqFamily,
                    "Eq family heads must resolve to the same verified import or checked current declaration",
                ));
            }
            let mut out = tagged_bytes("npa.machine-tactic.resolved-eq-family.decl.v1");
            encode_family_origin_to(&mut out, &eq.origin);
            encode_checked_decl_signature_to(&mut out, &eq.signature);
            encode_checked_decl_signature_to(&mut out, &refl.signature);
            encode_checked_decl_signature_to(&mut out, &rec.signature);
            Ok(Some(ResolvedEqFamily {
                eq_name: reference.eq_name.clone(),
                refl_name: reference.refl_name.clone(),
                rec_name: reference.rec_name.clone(),
                fingerprint: hash_with_domain("npa.machine-tactic.resolved-eq-family.v1", &out),
            }))
        }
    }
}

#[derive(Clone, Debug)]
struct ResolvedFamilySignature {
    signature: CheckedDeclSignature,
    origin: FamilyOrigin,
}

#[derive(Clone, Debug, PartialEq, Eq)]
enum FamilyOrigin {
    Imported {
        module: ModuleName,
        export_hash: Hash,
        certificate_hash: Hash,
    },
    CurrentSourceDecl {
        module: ModuleName,
        source_index: u64,
        core_decl_hash: Hash,
    },
}

fn resolve_family_signature(
    kernel_env: &Env,
    imports: &[VerifiedImportRef],
    current: &[CheckedCurrentDecl],
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<ResolvedFamilySignature> {
    let mut matches = Vec::new();
    for import in imports {
        for export in import.exports().iter().filter(|export| {
            &export.name == name && &export.decl_interface_hash == decl_interface_hash
        }) {
            let decl = kernel_env.decl(&export.name.as_dotted()).ok_or_else(|| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidEqFamily,
                    format!(
                        "Eq family head {} is exported but missing from kernel env",
                        export.name.as_dotted()
                    ),
                )
                .with_primary_name(export.name.clone())
            })?;
            matches.push(ResolvedFamilySignature {
                signature: CheckedDeclSignature::from_core_decl(decl, export.decl_interface_hash),
                origin: FamilyOrigin::Imported {
                    module: import.module.clone(),
                    export_hash: import.export_hash,
                    certificate_hash: import.certificate_hash,
                },
            });
        }
    }
    for decl in current {
        if let Some(signature) =
            resolve_current_family_signature(kernel_env, decl, name, decl_interface_hash)?
        {
            matches.push(signature);
        }
    }
    let [resolved] = matches.as_slice() else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidEqFamily,
            if matches.is_empty() {
                format!(
                    "Eq family head {} with the requested interface hash is unknown",
                    name.as_dotted()
                )
            } else {
                format!("Eq family head {} is ambiguous", name.as_dotted())
            },
        )
        .with_primary_name(name.clone()));
    };
    Ok(resolved.clone())
}

fn resolve_current_family_signature(
    kernel_env: &Env,
    decl: &CheckedCurrentDecl,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<Option<ResolvedFamilySignature>> {
    let parent_signature = decl.signature();
    if parent_signature.name() == name
        && parent_signature.decl_interface_hash() == *decl_interface_hash
    {
        return Ok(Some(ResolvedFamilySignature {
            signature: parent_signature.clone(),
            origin: FamilyOrigin::CurrentSourceDecl {
                module: current_decl_module_name(parent_signature.name()),
                source_index: decl.source_index(),
                core_decl_hash: decl.core_decl_hash(),
            },
        }));
    }

    if parent_signature.decl_interface_hash() != *decl_interface_hash {
        return Ok(None);
    }
    let Decl::Inductive { data, .. } = decl.core_decl() else {
        return Ok(None);
    };
    let generated_by_parent = data
        .constructors
        .iter()
        .any(|constructor| Name::from_dotted(&constructor.name) == *name)
        || data
            .recursor
            .as_ref()
            .map(|recursor| Name::from_dotted(&recursor.name) == *name)
            .unwrap_or(false);
    if !generated_by_parent {
        return Ok(None);
    }

    let generated = kernel_env.decl(&name.as_dotted()).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidEqFamily,
            format!(
                "current generated Eq family head {} is missing from kernel env",
                name.as_dotted()
            ),
        )
        .with_primary_name(name.clone())
    })?;
    match generated {
        Decl::Constructor { inductive, .. } | Decl::Recursor { inductive, .. }
            if inductive == decl.core_decl().name() => {}
        _ => {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidEqFamily,
                format!(
                    "current generated Eq family head {} is not generated by {}",
                    name.as_dotted(),
                    decl.core_decl().name()
                ),
            )
            .with_primary_name(name.clone()));
        }
    }

    Ok(Some(ResolvedFamilySignature {
        signature: CheckedDeclSignature::from_core_decl(generated, *decl_interface_hash),
        origin: FamilyOrigin::CurrentSourceDecl {
            module: current_decl_module_name(parent_signature.name()),
            source_index: decl.source_index(),
            core_decl_hash: decl.core_decl_hash(),
        },
    }))
}

fn current_decl_module_name(name: &Name) -> ModuleName {
    Name(vec![name
        .0
        .first()
        .cloned()
        .unwrap_or_else(|| name.as_dotted())])
}

fn encode_family_origin_to(out: &mut Vec<u8>, origin: &FamilyOrigin) {
    match origin {
        FamilyOrigin::Imported {
            module,
            export_hash,
            certificate_hash,
        } => {
            out.push(0x00);
            encode_name_to(out, module);
            encode_hash_to(out, export_hash);
            encode_hash_to(out, certificate_hash);
        }
        FamilyOrigin::CurrentSourceDecl {
            module,
            source_index,
            core_decl_hash,
        } => {
            out.push(0x01);
            encode_name_to(out, module);
            encode_u64_to(out, *source_index);
            encode_hash_to(out, core_decl_hash);
        }
    }
}

fn check_eq_family_interfaces(
    kernel_env: &Env,
    eq: &ResolvedFamilySignature,
    refl: &ResolvedFamilySignature,
    rec: &ResolvedFamilySignature,
) -> Result<()> {
    let eq_params = eq.signature.universe_params();
    let refl_params = refl.signature.universe_params();
    let rec_params = rec.signature.universe_params();
    if eq_params.len() != 1 || refl_params.len() != 1 || rec_params.len() != 2 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidEqFamily,
            "Eq family universe arity does not match Eq/Eq.refl/Eq.rec",
        ));
    }
    let eq_level = Level::param(eq_params[0].clone());
    let refl_level = Level::param(refl_params[0].clone());
    let rec_value_level = Level::param(rec_params[0].clone());
    let rec_motive_level = Level::param(rec_params[1].clone());
    let expected_eq = expected_eq_type(&eq.signature.name().as_dotted(), eq_level.clone());
    let expected_refl = expected_eq_refl_type(
        &eq.signature.name().as_dotted(),
        &refl.signature.name().as_dotted(),
        refl_level,
    );
    let expected_rec = expected_eq_rec_type(
        &eq.signature.name().as_dotted(),
        &refl.signature.name().as_dotted(),
        rec_value_level,
        rec_motive_level,
    );
    for (actual, expected, label) in [
        (eq.signature.ty(), &expected_eq, "Eq"),
        (refl.signature.ty(), &expected_refl, "Eq.refl"),
        (rec.signature.ty(), &expected_rec, "Eq.rec"),
    ] {
        if !kernel_env
            .is_defeq(
                &Ctx::new(),
                actual_universe_params_for_signature(label, eq, refl, rec),
                actual,
                expected,
            )
            .map_err(kernel_diag)?
        {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidEqFamily,
                format!("{label} family interface does not match the required M4 shape"),
            )
            .with_expected_actual_payloads(
                DiagnosticPayloadKind::Expr,
                &core_expr_canonical_bytes(expected),
                &core_expr_canonical_bytes(actual),
            ));
        }
    }
    Ok(())
}

fn actual_universe_params_for_signature<'a>(
    label: &str,
    eq: &'a ResolvedFamilySignature,
    refl: &'a ResolvedFamilySignature,
    rec: &'a ResolvedFamilySignature,
) -> &'a [String] {
    match label {
        "Eq" => eq.signature.universe_params(),
        "Eq.refl" => refl.signature.universe_params(),
        "Eq.rec" => rec.signature.universe_params(),
        _ => &[],
    }
}

fn expected_eq_type(eq_name: &str, level: Level) -> Expr {
    let _ = eq_name;
    npa_kernel::eq_type(level)
}

fn expected_eq_refl_type(eq_name: &str, refl_name: &str, level: Level) -> Expr {
    let _ = refl_name;
    Expr::pi(
        "A",
        Expr::sort(level.clone()),
        Expr::pi(
            "x",
            Expr::bvar(0),
            Expr::apps(
                Expr::konst(eq_name, vec![level]),
                vec![Expr::bvar(1), Expr::bvar(0), Expr::bvar(0)],
            ),
        ),
    )
}

fn expected_eq_rec_type(
    eq_name: &str,
    refl_name: &str,
    value_level: Level,
    motive_level: Level,
) -> Expr {
    let a_sort_level = value_level.clone();
    let motive_ty = Expr::pi(
        "b",
        Expr::bvar(1),
        Expr::pi(
            "h",
            Expr::apps(
                Expr::konst(eq_name, vec![value_level.clone()]),
                vec![Expr::bvar(2), Expr::bvar(1), Expr::bvar(0)],
            ),
            Expr::sort(motive_level),
        ),
    );
    let refl_proof = Expr::apps(
        Expr::konst(refl_name, vec![value_level.clone()]),
        vec![Expr::bvar(2), Expr::bvar(1)],
    );
    let minor_ty = Expr::apps(Expr::bvar(0), vec![Expr::bvar(1), refl_proof]);
    let major_ty = Expr::apps(
        Expr::konst(eq_name, vec![value_level]),
        vec![Expr::bvar(4), Expr::bvar(3), Expr::bvar(0)],
    );
    let result_ty = Expr::apps(Expr::bvar(3), vec![Expr::bvar(1), Expr::bvar(0)]);
    Expr::pi(
        "A",
        Expr::sort(a_sort_level),
        Expr::pi(
            "a",
            Expr::bvar(0),
            Expr::pi(
                "motive",
                motive_ty,
                Expr::pi(
                    "minor",
                    minor_ty,
                    Expr::pi("b", Expr::bvar(3), Expr::pi("h", major_ty, result_ty)),
                ),
            ),
        ),
    )
}

fn resolve_nat_family(
    kernel_env: &Env,
    imports: &[VerifiedImportRef],
    current: &[CheckedCurrentDecl],
    family_ref: Option<&NatFamilyRef>,
) -> Result<Option<ResolvedNatFamily>> {
    let Some(reference) = family_ref else {
        return Ok(None);
    };
    let nat = resolve_nat_family_signature(
        kernel_env,
        imports,
        current,
        &reference.nat_name,
        &reference.nat_interface_hash,
    )?;
    let zero = resolve_nat_family_signature(
        kernel_env,
        imports,
        current,
        &reference.zero_name,
        &reference.zero_interface_hash,
    )?;
    let succ = resolve_nat_family_signature(
        kernel_env,
        imports,
        current,
        &reference.succ_name,
        &reference.succ_interface_hash,
    )?;
    let rec = resolve_nat_family_signature(
        kernel_env,
        imports,
        current,
        &reference.rec_name,
        &reference.rec_interface_hash,
    )?;
    check_nat_family_interfaces(kernel_env, &nat, &zero, &succ, &rec)?;
    if nat.origin != zero.origin || nat.origin != succ.origin || nat.origin != rec.origin {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            "Nat family heads must resolve to the same verified import or checked current declaration",
        ));
    }
    let mut out = tagged_bytes("npa.machine-tactic.resolved-nat-family.decl.v1");
    encode_family_origin_to(&mut out, &nat.origin);
    encode_checked_decl_signature_to(&mut out, &nat.signature);
    encode_checked_decl_signature_to(&mut out, &zero.signature);
    encode_checked_decl_signature_to(&mut out, &succ.signature);
    encode_checked_decl_signature_to(&mut out, &rec.signature);
    Ok(Some(ResolvedNatFamily {
        nat_name: reference.nat_name.clone(),
        zero_name: reference.zero_name.clone(),
        succ_name: reference.succ_name.clone(),
        rec_name: reference.rec_name.clone(),
        fingerprint: hash_with_domain("npa.machine-tactic.resolved-nat-family.v1", &out),
    }))
}

fn resolve_nat_family_signature(
    kernel_env: &Env,
    imports: &[VerifiedImportRef],
    current: &[CheckedCurrentDecl],
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<ResolvedFamilySignature> {
    let mut matches = Vec::new();
    for import in imports {
        for export in import.exports().iter().filter(|export| {
            &export.name == name && &export.decl_interface_hash == decl_interface_hash
        }) {
            let decl = kernel_env.decl(&export.name.as_dotted()).ok_or_else(|| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidNatFamily,
                    format!(
                        "Nat family head {} is exported but missing from kernel env",
                        export.name.as_dotted()
                    ),
                )
                .with_primary_name(export.name.clone())
            })?;
            matches.push(ResolvedFamilySignature {
                signature: CheckedDeclSignature::from_core_decl(decl, export.decl_interface_hash),
                origin: FamilyOrigin::Imported {
                    module: import.module.clone(),
                    export_hash: import.export_hash,
                    certificate_hash: import.certificate_hash,
                },
            });
        }
    }
    for decl in current {
        if let Some(signature) =
            resolve_current_nat_family_signature(kernel_env, decl, name, decl_interface_hash)?
        {
            matches.push(signature);
        }
    }
    let [resolved] = matches.as_slice() else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            if matches.is_empty() {
                format!(
                    "Nat family head {} with the requested interface hash is unknown",
                    name.as_dotted()
                )
            } else {
                format!("Nat family head {} is ambiguous", name.as_dotted())
            },
        )
        .with_primary_name(name.clone()));
    };
    Ok(resolved.clone())
}

fn resolve_current_nat_family_signature(
    kernel_env: &Env,
    decl: &CheckedCurrentDecl,
    name: &Name,
    decl_interface_hash: &Hash,
) -> Result<Option<ResolvedFamilySignature>> {
    let parent_signature = decl.signature();
    if parent_signature.name() == name
        && parent_signature.decl_interface_hash() == *decl_interface_hash
    {
        return Ok(Some(ResolvedFamilySignature {
            signature: parent_signature.clone(),
            origin: FamilyOrigin::CurrentSourceDecl {
                module: current_decl_module_name(parent_signature.name()),
                source_index: decl.source_index(),
                core_decl_hash: decl.core_decl_hash(),
            },
        }));
    }

    if parent_signature.decl_interface_hash() != *decl_interface_hash {
        return Ok(None);
    }
    let Decl::Inductive { data, .. } = decl.core_decl() else {
        return Ok(None);
    };
    let generated_by_parent = data
        .constructors
        .iter()
        .any(|constructor| Name::from_dotted(&constructor.name) == *name)
        || data
            .recursor
            .as_ref()
            .map(|recursor| Name::from_dotted(&recursor.name) == *name)
            .unwrap_or(false);
    if !generated_by_parent {
        return Ok(None);
    }

    let generated = kernel_env.decl(&name.as_dotted()).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            format!(
                "current generated Nat family head {} is missing from kernel env",
                name.as_dotted()
            ),
        )
        .with_primary_name(name.clone())
    })?;
    match generated {
        Decl::Constructor { inductive, .. } | Decl::Recursor { inductive, .. }
            if inductive == decl.core_decl().name() => {}
        _ => {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidNatFamily,
                format!(
                    "current generated Nat family head {} is not generated by {}",
                    name.as_dotted(),
                    decl.core_decl().name()
                ),
            )
            .with_primary_name(name.clone()));
        }
    }

    Ok(Some(ResolvedFamilySignature {
        signature: CheckedDeclSignature::from_core_decl(generated, *decl_interface_hash),
        origin: FamilyOrigin::CurrentSourceDecl {
            module: current_decl_module_name(parent_signature.name()),
            source_index: decl.source_index(),
            core_decl_hash: decl.core_decl_hash(),
        },
    }))
}

fn check_nat_family_interfaces(
    kernel_env: &Env,
    nat: &ResolvedFamilySignature,
    zero: &ResolvedFamilySignature,
    succ: &ResolvedFamilySignature,
    rec: &ResolvedFamilySignature,
) -> Result<()> {
    check_nat_family_decl_kinds(kernel_env, nat, zero, succ, rec)?;
    if !nat.signature.universe_params().is_empty()
        || !zero.signature.universe_params().is_empty()
        || !succ.signature.universe_params().is_empty()
        || rec.signature.universe_params().len() != 1
    {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            "Nat family universe arity does not match Nat/Nat.zero/Nat.succ/Nat.rec",
        ));
    }
    let nat_expr = Expr::konst(nat.signature.name().as_dotted(), Vec::new());
    let expected_succ = Expr::pi("_", nat_expr.clone(), nat_expr.clone());
    let rec_level = Level::param(rec.signature.universe_params()[0].clone());
    let expected_rec = expected_nat_rec_type(
        &nat.signature.name().as_dotted(),
        &zero.signature.name().as_dotted(),
        &succ.signature.name().as_dotted(),
        rec_level,
    );
    for (actual, expected, delta, label) in [
        (
            zero.signature.ty(),
            &nat_expr,
            zero.signature.universe_params(),
            "Nat.zero",
        ),
        (
            succ.signature.ty(),
            &expected_succ,
            succ.signature.universe_params(),
            "Nat.succ",
        ),
        (
            rec.signature.ty(),
            &expected_rec,
            rec.signature.universe_params(),
            "Nat.rec",
        ),
    ] {
        if !kernel_env
            .is_defeq(&Ctx::new(), delta, actual, expected)
            .map_err(kernel_diag)?
        {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidNatFamily,
                format!("{label} family interface does not match the required M5 shape"),
            )
            .with_expected_actual_payloads(
                DiagnosticPayloadKind::Expr,
                &core_expr_canonical_bytes(expected),
                &core_expr_canonical_bytes(actual),
            ));
        }
    }
    match nat.signature.ty() {
        Expr::Sort(_) => Ok(()),
        actual => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            "Nat family head must have a sort type",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&Expr::sort(npa_kernel::type0())),
            &core_expr_canonical_bytes(actual),
        )),
    }
}

fn check_nat_family_decl_kinds(
    kernel_env: &Env,
    nat: &ResolvedFamilySignature,
    zero: &ResolvedFamilySignature,
    succ: &ResolvedFamilySignature,
    rec: &ResolvedFamilySignature,
) -> Result<()> {
    let nat_name = nat.signature.name().as_dotted();
    let nat_decl = kernel_env.decl(&nat_name).ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            format!("Nat family head {nat_name} is missing from kernel env"),
        )
    })?;
    if !matches!(nat_decl, Decl::Inductive { .. }) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            format!("Nat family head {nat_name} must be an inductive declaration"),
        ));
    }
    for (signature, label) in [(zero, "Nat.zero"), (succ, "Nat.succ")] {
        let name = signature.signature.name().as_dotted();
        match kernel_env.decl(&name) {
            Some(Decl::Constructor { inductive, .. }) if inductive == &nat_name => {}
            _ => {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidNatFamily,
                    format!(
                        "{label} family head {name} must be a constructor generated by {nat_name}"
                    ),
                ));
            }
        }
    }
    let rec_name = rec.signature.name().as_dotted();
    match kernel_env.decl(&rec_name) {
        Some(Decl::Recursor { inductive, .. }) if inductive == &nat_name => Ok(()),
        _ => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidNatFamily,
            format!("Nat.rec family head {rec_name} must be a recursor generated by {nat_name}"),
        )),
    }
}

fn expected_nat_rec_type(nat_name: &str, zero_name: &str, succ_name: &str, level: Level) -> Expr {
    let nat = Expr::konst(nat_name, Vec::new());
    let zero = Expr::konst(zero_name, Vec::new());
    let succ = |arg| Expr::app(Expr::konst(succ_name, Vec::new()), arg);
    let motive_ty = Expr::pi("_", nat.clone(), Expr::sort(level.clone()));
    let z_ty = Expr::app(Expr::bvar(0), zero);
    let s_ty = Expr::pi(
        "n",
        nat.clone(),
        Expr::pi(
            "ih",
            Expr::app(Expr::bvar(2), Expr::bvar(0)),
            Expr::app(Expr::bvar(3), succ(Expr::bvar(1))),
        ),
    );
    Expr::pi(
        "motive",
        motive_ty,
        Expr::pi(
            "z",
            z_ty,
            Expr::pi(
                "s",
                s_ty,
                Expr::pi("n", nat, Expr::app(Expr::bvar(3), Expr::bvar(0))),
            ),
        ),
    )
}

fn resolve_simp_registry(
    kernel_env: &Env,
    imports: &[VerifiedImportRef],
    current: &[CheckedCurrentDecl],
    eq_family: &Option<ResolvedEqFamily>,
    rules: &[SimpRuleRef],
) -> Result<SimpRegistry> {
    let canonical = canonicalize_simp_rule_refs(rules.to_vec())?;
    let mut resolved_rules = Vec::new();
    for rule in canonical {
        resolved_rules.push(resolve_simp_rule(
            kernel_env, imports, current, eq_family, rule,
        )?);
    }
    resolved_rules.sort_by_key(|rule| simp_rule_ref_canonical_bytes(&rule.key));
    Ok(SimpRegistry {
        rules: resolved_rules,
    })
}

fn resolve_simp_rule(
    kernel_env: &Env,
    imports: &[VerifiedImportRef],
    current: &[CheckedCurrentDecl],
    eq_family: &Option<ResolvedEqFamily>,
    rule: SimpRuleRef,
) -> Result<ResolvedSimpRule> {
    let mut matches = Vec::new();
    for import in imports {
        for export in import.exports().iter().filter(|export| {
            export.name == rule.name && export.decl_interface_hash == rule.decl_interface_hash
        }) {
            let decl = kernel_env.decl(&export.name.as_dotted()).ok_or_else(|| {
                MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::UnknownSimpRule,
                    format!(
                        "simp rule {} is exported but missing from kernel env",
                        export.name.as_dotted()
                    ),
                )
                .with_primary_name(export.name.clone())
            })?;
            let core_hash = import
                .certified_env_decls()
                .iter()
                .zip(import.certified_env_decl_hashes())
                .find(|(decl, _)| decl.name() == export.name.as_dotted())
                .map(|(_, hash)| *hash)
                .unwrap_or(export.decl_interface_hash);
            matches.push((
                TacticHead::Imported {
                    name: export.name.clone(),
                    decl_interface_hash: export.decl_interface_hash,
                },
                CheckedDeclSignature::from_core_decl(decl, export.decl_interface_hash),
                core_hash,
                decl.clone(),
                SimpRuleOrigin::Imported { kind: export.kind },
            ));
        }
    }
    for decl in current {
        if decl.signature().name() == &rule.name
            && decl.signature().decl_interface_hash() == rule.decl_interface_hash
        {
            matches.push((
                TacticHead::CurrentModule {
                    name: rule.name.clone(),
                    decl_interface_hash: rule.decl_interface_hash,
                },
                decl.signature().clone(),
                decl.core_decl_hash(),
                decl.core_decl().clone(),
                SimpRuleOrigin::CurrentModule,
            ));
        }
    }
    let [(source, signature, core_decl_hash, core_decl, origin)] = matches.as_slice() else {
        return Err(if matches.is_empty() {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::UnknownSimpRule,
                format!(
                    "simp rule {} with the requested interface hash is unknown",
                    rule.name.as_dotted()
                ),
            )
            .with_primary_name(rule.name.clone())
        } else {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousSimpRule,
                format!("simp rule {} is ambiguous", rule.name.as_dotted()),
            )
            .with_primary_name(rule.name.clone())
        });
    };
    ensure_simp_rule_decl_kind(core_decl, &rule.name, origin)?;
    let family = eq_family.as_ref().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "simp registry resolution requires a resolved Eq family",
        )
    })?;
    let (rule_telescope, eq_target, theorem_ty) = analyze_simp_rule_type(
        kernel_env,
        family,
        signature.ty(),
        signature.universe_params(),
    )?;
    let (from_pattern, to_pattern) = match rule.direction {
        RewriteDirection::Forward => (eq_target.lhs.clone(), eq_target.rhs.clone()),
        RewriteDirection::Backward => (eq_target.rhs.clone(), eq_target.lhs.clone()),
    };
    Ok(ResolvedSimpRule {
        key: rule,
        source: source.clone(),
        signature: signature.clone(),
        core_decl_hash: *core_decl_hash,
        theorem_ty,
        universe_params: signature.universe_params().to_vec(),
        rule_telescope,
        eq_levels: eq_target.levels,
        eq_type: eq_target.ty,
        theorem_lhs: eq_target.lhs,
        theorem_rhs: eq_target.rhs,
        from_pattern,
        to_pattern,
    })
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum SimpRuleOrigin {
    Imported { kind: ExportKind },
    CurrentModule,
}

fn ensure_simp_rule_decl_kind(decl: &Decl, name: &Name, origin: &SimpRuleOrigin) -> Result<()> {
    let valid = match origin {
        SimpRuleOrigin::Imported {
            kind: ExportKind::Theorem,
        } => true,
        SimpRuleOrigin::Imported {
            kind: ExportKind::Def,
        }
        | SimpRuleOrigin::CurrentModule => matches!(
            decl,
            Decl::Theorem { .. }
                | Decl::Def {
                    reducibility: npa_kernel::Reducibility::Reducible,
                    ..
                }
        ),
        SimpRuleOrigin::Imported { .. } => false,
    };
    if valid {
        Ok(())
    } else {
        Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidSimpRule,
            format!(
                "simp rule {} must resolve to a theorem or reducible proof definition",
                name.as_dotted()
            ),
        ))
    }
}

fn analyze_simp_rule_type(
    kernel_env: &Env,
    family: &ResolvedEqFamily,
    theorem_ty: &Expr,
    universe_params: &[String],
) -> Result<(Vec<ResolvedRuleParam>, EqTarget, Expr)> {
    let mut ctx = Ctx::new();
    let mut ty = theorem_ty.clone();
    let mut params = Vec::new();
    let mut theorem_ty_whnf = None;
    loop {
        let whnf = kernel_env
            .whnf(&ctx, universe_params, &ty)
            .map_err(kernel_diag)?;
        if theorem_ty_whnf.is_none() {
            theorem_ty_whnf = Some(whnf.clone());
        }
        if let Some(eq_target) = parse_eq_target_from_expr(family, &whnf) {
            ensure_simp_rule_params_inferable(&params, &eq_target)?;
            return Ok((
                params,
                eq_target,
                theorem_ty_whnf.expect("WHNF was stored before analysis returns"),
            ));
        }
        let Expr::Pi {
            binder,
            ty: domain,
            body,
        } = whnf
        else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidSimpRule,
                "simp rule type does not reduce to an Eq theorem",
            ));
        };
        let domain_ty = kernel_env
            .infer(&ctx, universe_params, &domain)
            .map_err(kernel_diag)?;
        let domain_ty_whnf = kernel_env
            .whnf(&ctx, universe_params, &domain_ty)
            .map_err(kernel_diag)?;
        if matches!(domain_ty_whnf, Expr::Sort(level) if normalize_level(level.clone()) == Level::zero())
        {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidSimpRule,
                "simp-lite MVP rejects simp rules with proof premises",
            ));
        }
        params.push(ResolvedRuleParam {
            name: binder.clone(),
            ty: (*domain).clone(),
        });
        ctx.push_assumption(binder, Arc::unwrap_or_clone(domain));
        ty = Arc::unwrap_or_clone(body);
    }
}

fn ensure_simp_rule_params_inferable(
    params: &[ResolvedRuleParam],
    eq_target: &EqTarget,
) -> Result<()> {
    for (index, param) in params.iter().enumerate() {
        let bvar = (params.len() - 1 - index) as u32;
        if !contains_bound_var(&eq_target.ty, bvar)
            && !contains_bound_var(&eq_target.lhs, bvar)
            && !contains_bound_var(&eq_target.rhs, bvar)
        {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidSimpRule,
                format!(
                    "simp-lite MVP rejects simp rule binder {} because it is not inferable from the Eq conclusion",
                    param.name
                ),
            ));
        }
    }
    Ok(())
}

fn validate_machine_term_source(term: &MachineTermSource) -> Result<()> {
    let canonical =
        npa_frontend::canonicalize_machine_term_source(&term.source).map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTermSource,
                format!(
                    "machine term source canonicalization failed: {}",
                    err.message
                ),
            )
        })?;
    let expected = machine_term_source_hash_from_frontend(&canonical.canonical_bytes);
    if term.canonical_hash != expected {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTermSource,
            "machine term source canonical hash is stale",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::MachineTermSource,
            &machine_term_source_canonical_bytes_from_frontend(&canonical.canonical_bytes),
            &term.canonical_hash,
        ));
    }
    Ok(())
}

fn validate_tactic_head_shape(head: &TacticHead) -> Result<()> {
    match head {
        TacticHead::Imported { name, .. } | TacticHead::CurrentModule { name, .. } => {
            if !name.is_canonical() {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMachineTactic,
                    format!("tactic head name {} is not canonical", name.as_dotted()),
                ));
            }
        }
        TacticHead::Local { name } => {
            if !is_machine_identifier(name) || is_reserved_spelling(name) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidMachineTactic,
                    format!("local tactic head {name:?} is not a valid machine local identifier"),
                ));
            }
        }
    }
    Ok(())
}

fn validate_candidate_apply_arg(arg: CandidateApplyArg) -> Result<ApplyArg> {
    match arg {
        CandidateApplyArg::Term(term) => {
            Ok(ApplyArg::Term(MachineTermSource::new_checked(term.source)?))
        }
        CandidateApplyArg::Subgoal { name_hint } => {
            if let Some(name_hint) = &name_hint {
                validate_intro_name_shape(name_hint)?;
            }
            Ok(ApplyArg::Subgoal { name_hint })
        }
        CandidateApplyArg::InferFromTarget => Ok(ApplyArg::InferFromTarget),
    }
}

fn validate_apply_arg(arg: &ApplyArg) -> Result<()> {
    match arg {
        ApplyArg::Term(term) => validate_machine_term_source(term),
        ApplyArg::Subgoal { .. } | ApplyArg::InferFromTarget => Ok(()),
    }
}

fn elaborate_apply_term_infer(
    term: &MachineTermSource,
    context: &npa_frontend::MachineTermElabContext,
) -> Result<(Expr, Expr)> {
    validate_machine_term_source(term)?;
    let canonical =
        npa_frontend::canonicalize_machine_term_source(term.source()).map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTermSource,
                format!(
                    "machine term source canonicalization failed: {}",
                    err.message
                ),
            )
        })?;
    let ast = npa_frontend::decode_machine_term_source_canonical(&canonical.canonical_bytes)
        .map_err(|err| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineTermSource,
                format!("machine term canonical decode failed: {}", err.message),
            )
        })?;
    npa_frontend::elaborate_machine_term_infer_from_ast(
        &ast,
        context,
        &npa_frontend::MachineCompileOptions::default(),
    )
    .map_err(machine_term_elaboration_diag)
}

fn universe_argument_mismatch_diag(
    expected_params: &[String],
    actual_levels: &[Level],
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> MachineTacticDiagnostic {
    MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::UniverseArgumentMismatch,
        format!(
            "tactic head expects {} universe arguments, got {}",
            expected_params.len(),
            actual_levels.len()
        ),
    )
    .with_expected_actual_payload_kinds(
        DiagnosticPayloadKind::UniverseParamList,
        &universe_param_list_canonical_bytes(expected_params),
        DiagnosticPayloadKind::LevelArgList,
        &level_arg_list_canonical_bytes(actual_levels),
    )
    .with_universe_diagnostic(universe_argument_diagnostic_payload(
        expected_params,
        actual_levels,
    ))
    .with_goal(goal_id)
    .with_meta(meta_id)
}

fn ensure_subgoal_domain_is_prop(
    state: &MachineProofState,
    ctx: &Ctx,
    goal: &MachineGoal,
    domain: &Expr,
    budget_context: Option<KernelFuelContext<'_>>,
) -> Result<()> {
    let env = state.env.kernel_env();
    let domain_ty = match budget_context {
        Some((fuel, goal_id, meta_id)) => kernel_infer_with_budget(
            env,
            ctx,
            &state.root.universe_params,
            domain,
            fuel,
            goal_id,
            meta_id,
        )?,
        None => env
            .infer(ctx, &state.root.universe_params, domain)
            .map_err(kernel_diag)?,
    };
    let domain_ty_whnf = match budget_context {
        Some((fuel, goal_id, meta_id)) => kernel_whnf_with_budget(
            env,
            ctx,
            &state.root.universe_params,
            &domain_ty,
            fuel,
            goal_id,
            meta_id,
        )?,
        None => env
            .whnf(ctx, &state.root.universe_params, &domain_ty)
            .map_err(kernel_diag)?,
    };
    match domain_ty_whnf {
        Expr::Sort(level) if normalize_level(level.clone()) == Level::Zero => Ok(()),
        actual => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::SubgoalDataArgument,
            "apply Subgoal is only allowed for proposition-valued binder domains",
        )
        .with_expected_actual_payloads(
            DiagnosticPayloadKind::Expr,
            &core_expr_canonical_bytes(&Expr::sort(Level::zero())),
            &core_expr_canonical_bytes(&actual),
        )
        .with_goal(goal.id)
        .with_meta(goal.meta_id)),
    }
}

fn infer_apply_args_from_target(
    state: &MachineProofState,
    ctx: &Ctx,
    goal: &MachineGoal,
    result_pattern: &Expr,
    infer_ids: &[PatternMetaId],
    fuel: &TacticRunFuel,
) -> Result<BTreeMap<PatternMetaId, Expr>> {
    let env = state.env.kernel_env();
    let delta = &state.root.universe_params;
    let pattern_whnf =
        kernel_whnf_with_budget(env, ctx, delta, result_pattern, fuel, goal.id, goal.meta_id)?;
    let target_whnf =
        kernel_whnf_with_budget(env, ctx, delta, &goal.target, fuel, goal.id, goal.meta_id)?;
    let mut present = BTreeSet::new();
    collect_pattern_meta_ids(&pattern_whnf, &mut present);
    for id in infer_ids {
        if !present.contains(id) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::MissingExplicitArgument,
                "InferFromTarget argument does not occur in the result pattern",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
    }
    let mut solutions = BTreeMap::new();
    match_apply_pattern(
        env,
        ctx,
        delta,
        &pattern_whnf,
        &target_whnf,
        false,
        &mut solutions,
        Some((fuel, goal.id, goal.meta_id)),
    )
    .map_err(|mut diag| {
        diag.goal_id = Some(goal.id);
        diag.meta_id = Some(goal.meta_id);
        diag
    })?;
    for id in infer_ids {
        if !solutions.contains_key(id) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousApplyArgument,
                "InferFromTarget argument was not uniquely solved",
            )
            .with_goal(goal.id)
            .with_meta(goal.meta_id));
        }
    }
    Ok(solutions)
}

#[allow(clippy::too_many_arguments)]
fn match_apply_pattern(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    pattern: &Expr,
    target: &Expr,
    allow_pattern_meta: bool,
    solutions: &mut BTreeMap<PatternMetaId, Expr>,
    budget_context: Option<KernelFuelContext<'_>>,
) -> Result<()> {
    if let Some(id) = pattern_meta_id(pattern) {
        if !allow_pattern_meta {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousApplyArgument,
                "InferFromTarget cannot be solved from a non-rigid result position",
            ));
        }
        return assign_pattern_meta_solution(
            env,
            ctx,
            delta,
            id,
            target,
            solutions,
            budget_context,
        );
    }
    if !contains_pattern_meta(pattern) {
        if kernel_is_defeq_with_optional_budget(env, ctx, delta, pattern, target, budget_context)? {
            return Ok(());
        }
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::AmbiguousApplyArgument,
            "rigid apply result pattern does not match the goal target",
        ));
    }

    match pattern {
        Expr::App(_, _) => {
            let (pattern_head, pattern_args) = collect_core_apps(pattern);
            if contains_pattern_meta(&pattern_head) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::AmbiguousApplyArgument,
                    "InferFromTarget cannot occur in function-head position",
                ));
            }
            let (target_head, target_args) = collect_core_apps(target);
            if pattern_args.len() != target_args.len()
                || !rigid_heads_match(env, ctx, delta, &pattern_head, &target_head, budget_context)?
            {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::AmbiguousApplyArgument,
                    "apply result pattern and target have incompatible rigid heads",
                ));
            }
            for (pattern_arg, target_arg) in pattern_args.iter().zip(&target_args) {
                match_apply_pattern(
                    env,
                    ctx,
                    delta,
                    pattern_arg,
                    target_arg,
                    true,
                    solutions,
                    budget_context,
                )?;
            }
            Ok(())
        }
        Expr::Lam { .. } | Expr::Pi { .. } | Expr::Let { .. } => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::AmbiguousApplyArgument,
            "InferFromTarget under binders or let bodies is not supported",
        )),
        Expr::Sort(_) | Expr::BVar(_) | Expr::Const { .. } => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::AmbiguousApplyArgument,
            "unsupported InferFromTarget result pattern shape",
        )),
    }
}

fn assign_pattern_meta_solution(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    id: PatternMetaId,
    target: &Expr,
    solutions: &mut BTreeMap<PatternMetaId, Expr>,
    budget_context: Option<KernelFuelContext<'_>>,
) -> Result<()> {
    if contains_pattern_meta(target) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::AmbiguousApplyArgument,
            "InferFromTarget solution cannot contain another inferred argument",
        ));
    }
    match solutions.get(&id) {
        Some(existing)
            if kernel_is_defeq_with_optional_budget(
                env,
                ctx,
                delta,
                existing,
                target,
                budget_context,
            )? =>
        {
            Ok(())
        }
        Some(_) => Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::AmbiguousApplyArgument,
            "InferFromTarget has multiple non-convertible target matches",
        )),
        None => {
            solutions.insert(id, target.clone());
            Ok(())
        }
    }
}

fn rigid_heads_match(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    pattern_head: &Expr,
    target_head: &Expr,
    budget_context: Option<KernelFuelContext<'_>>,
) -> Result<bool> {
    match (pattern_head, target_head) {
        (
            Expr::Const {
                name: lhs_name,
                levels: lhs_levels,
            },
            Expr::Const {
                name: rhs_name,
                levels: rhs_levels,
            },
        ) => Ok(lhs_name == rhs_name && levels_eq(lhs_levels, rhs_levels)),
        (Expr::BVar(lhs), Expr::BVar(rhs)) => Ok(lhs == rhs),
        _ => kernel_is_defeq_with_optional_budget(
            env,
            ctx,
            delta,
            pattern_head,
            target_head,
            budget_context,
        ),
    }
}

fn collect_core_apps(expr: &Expr) -> (Expr, Vec<Expr>) {
    let mut args = Vec::new();
    let mut head = expr.clone();
    while let Expr::App(fun, arg) = head {
        args.push(Arc::unwrap_or_clone(arg));
        head = Arc::unwrap_or_clone(fun);
    }
    args.reverse();
    (head, args)
}

const PATTERN_META_PREFIX: &str = "\0npa.machine-tactic.pattern-meta.";

fn pattern_meta_expr(id: PatternMetaId) -> Expr {
    Expr::konst(format!("{PATTERN_META_PREFIX}{}", id.0), Vec::new())
}

fn pattern_meta_id(expr: &Expr) -> Option<PatternMetaId> {
    let Expr::Const { name, levels } = expr else {
        return None;
    };
    if !levels.is_empty() {
        return None;
    }
    let suffix = name.strip_prefix(PATTERN_META_PREFIX)?;
    suffix.parse::<u64>().ok().map(PatternMetaId)
}

fn contains_pattern_meta(expr: &Expr) -> bool {
    if pattern_meta_id(expr).is_some() {
        return true;
    }
    match expr {
        Expr::Sort(_) | Expr::BVar(_) | Expr::Const { .. } => false,
        Expr::App(fun, arg) => contains_pattern_meta(fun) || contains_pattern_meta(arg),
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            contains_pattern_meta(ty) || contains_pattern_meta(body)
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            contains_pattern_meta(ty) || contains_pattern_meta(value) || contains_pattern_meta(body)
        }
    }
}

fn collect_pattern_meta_ids(expr: &Expr, ids: &mut BTreeSet<PatternMetaId>) {
    if let Some(id) = pattern_meta_id(expr) {
        ids.insert(id);
        return;
    }
    match expr {
        Expr::Sort(_) | Expr::BVar(_) | Expr::Const { .. } => {}
        Expr::App(fun, arg) => {
            collect_pattern_meta_ids(fun, ids);
            collect_pattern_meta_ids(arg, ids);
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            collect_pattern_meta_ids(ty, ids);
            collect_pattern_meta_ids(body, ids);
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            collect_pattern_meta_ids(ty, ids);
            collect_pattern_meta_ids(value, ids);
            collect_pattern_meta_ids(body, ids);
        }
    }
}

fn replace_pattern_metas(expr: &Expr, solutions: &BTreeMap<PatternMetaId, Expr>) -> Result<Expr> {
    replace_pattern_metas_at_depth(expr, solutions, 0)
}

fn replace_pattern_metas_at_depth(
    expr: &Expr,
    solutions: &BTreeMap<PatternMetaId, Expr>,
    depth: u32,
) -> Result<Expr> {
    if let Some(id) = pattern_meta_id(expr) {
        let solution = solutions.get(&id).ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::AmbiguousApplyArgument,
                "unresolved InferFromTarget argument remains after matching",
            )
        })?;
        return shift(solution, depth as i32, 0).map_err(kernel_diag);
    }
    Ok(match expr {
        Expr::Sort(level) => Expr::sort(level.clone()),
        Expr::BVar(index) => Expr::bvar(*index),
        Expr::Const { name, levels } => Expr::konst(name.clone(), levels.clone()),
        Expr::App(fun, arg) => Expr::app(
            replace_pattern_metas_at_depth(fun, solutions, depth)?,
            replace_pattern_metas_at_depth(arg, solutions, depth)?,
        ),
        Expr::Lam { binder, ty, body } => Expr::lam(
            binder.clone(),
            replace_pattern_metas_at_depth(ty, solutions, depth)?,
            replace_pattern_metas_at_depth(body, solutions, depth + 1)?,
        ),
        Expr::Pi { binder, ty, body } => Expr::pi(
            binder.clone(),
            replace_pattern_metas_at_depth(ty, solutions, depth)?,
            replace_pattern_metas_at_depth(body, solutions, depth + 1)?,
        ),
        Expr::Let {
            binder,
            ty,
            value,
            body,
        } => Expr::let_in(
            binder.clone(),
            replace_pattern_metas_at_depth(ty, solutions, depth)?,
            replace_pattern_metas_at_depth(value, solutions, depth)?,
            replace_pattern_metas_at_depth(body, solutions, depth + 1)?,
        ),
    })
}

fn validate_intro_name_shape(name: &str) -> Result<()> {
    if !is_machine_identifier(name) || is_reserved_spelling(name) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            format!("intro name {name:?} is not a valid machine local identifier"),
        ));
    }
    Ok(())
}

fn validate_intro_name_available(
    state: &MachineProofState,
    context: &[MachineLocalDecl],
    name: &str,
) -> Result<()> {
    if context.iter().any(|local| local.name == name) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            format!("intro name {name} already exists in the local context"),
        ));
    }
    if machine_global_roots(state).contains(name) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTactic,
            format!("intro name {name} shadows a global namespace root"),
        ));
    }
    Ok(())
}

fn machine_global_roots(state: &MachineProofState) -> BTreeSet<String> {
    let mut roots = BTreeSet::new();
    insert_name_root(&mut roots, &state.root.theorem_name);
    for import in &state.env.imports {
        for export in &import.exports {
            insert_name_root(&mut roots, &export.name);
        }
    }
    for checked in &state.env.checked_current_decls {
        insert_name_root(&mut roots, checked.signature.name());
        if let Decl::Inductive { data, .. } = &checked.core_decl {
            for constructor in &data.constructors {
                insert_dotted_name_root(&mut roots, &constructor.name);
            }
            if let Some(recursor) = &data.recursor {
                insert_dotted_name_root(&mut roots, &recursor.name);
            }
        }
    }
    roots
}

fn insert_name_root(roots: &mut BTreeSet<String>, name: &Name) {
    if let Some(root) = name.0.first() {
        roots.insert(root.clone());
    }
}

fn insert_dotted_name_root(roots: &mut BTreeSet<String>, name: &str) {
    if let Some(root) = name.split('.').next() {
        if !root.is_empty() {
            roots.insert(root.to_owned());
        }
    }
}

fn is_machine_identifier(value: &str) -> bool {
    let mut chars = value.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    first.is_ascii_alphabetic()
        && chars.all(|ch| ch.is_ascii_alphanumeric() || ch == '_' || ch == '\'')
}

fn is_machine_candidate_id(value: &str) -> bool {
    (1..=64).contains(&value.len())
        && value
            .bytes()
            .all(|byte| byte.is_ascii_alphanumeric() || matches!(byte, b'.' | b'_' | b'-'))
}

fn is_reserved_spelling(value: &str) -> bool {
    matches!(
        value,
        "import"
            | "def"
            | "theorem"
            | "fun"
            | "forall"
            | "let"
            | "in"
            | "Prop"
            | "Type"
            | "Sort"
            | "open"
            | "namespace"
            | "match"
            | "with"
            | "notation"
            | "infix"
            | "infixl"
            | "infixr"
            | "axiom"
            | "inductive"
            | "succ"
            | "max"
            | "imax"
    )
}

fn ensure_tactic_step_fuel(
    budget: TacticBudget,
    needed: u64,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<()> {
    if budget.max_tactic_steps < needed {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::TacticStep,
            },
            format!(
                "tactic requires {needed} tactic step fuel, remaining tactic step fuel is {}",
                budget.max_tactic_steps
            ),
        )
        .with_goal(goal_id)
        .with_meta(meta_id));
    }
    Ok(())
}

fn ensure_expr_node_fuel(
    budget: TacticBudget,
    needed: u64,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<()> {
    if budget.max_expr_nodes < needed {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::ExprNode,
            },
            format!(
                "tactic requires {needed} expression node fuel, remaining expression node fuel is {}",
                budget.max_expr_nodes
            ),
        )
        .with_goal(goal_id)
        .with_meta(meta_id));
    }
    Ok(())
}

fn machine_term_elab_context(
    state: &MachineProofState,
    context: &[MachineLocalDecl],
) -> Result<npa_frontend::MachineTermElabContext> {
    let callable_interface_table = machine_surface_callable_interface_table(state)?;
    let direct_imports = state
        .env
        .imports
        .iter()
        .filter(|import| import.is_visible())
        .map(frontend_import_from_ref)
        .collect::<Vec<_>>();
    let available_imports = state
        .env
        .imports
        .iter()
        .map(|import| npa_frontend::VerifiedImport::from(import.verified_module.as_ref()))
        .collect::<Vec<_>>();
    let checked_current_decls = state
        .env
        .checked_current_decls
        .iter()
        .map(|decl| npa_frontend::MachineCheckedCurrentDecl {
            name: decl.signature.name().clone(),
            source_index: decl.source_index,
            decl_interface_hash: decl.signature.decl_interface_hash(),
            decl: decl.core_decl.clone(),
        })
        .collect::<Vec<_>>();
    let mut current_generated_decls = Vec::new();
    for decl in &state.env.checked_current_decls {
        if let Decl::Inductive { data, .. } = &decl.core_decl {
            for constructor in &data.constructors {
                current_generated_decls.push(npa_frontend::MachineCheckedCurrentGeneratedDecl {
                    name: Name::from_dotted(&constructor.name),
                    parent_source_index: decl.source_index,
                    decl_interface_hash: decl.signature.decl_interface_hash(),
                });
            }
            if let Some(recursor) = &data.recursor {
                current_generated_decls.push(npa_frontend::MachineCheckedCurrentGeneratedDecl {
                    name: Name::from_dotted(&recursor.name),
                    parent_source_index: decl.source_index,
                    decl_interface_hash: decl.signature.decl_interface_hash(),
                });
            }
        }
    }
    let local_context = context
        .iter()
        .map(|local| npa_frontend::MachineLocalDecl {
            name: local.name.clone(),
            ty: local.ty.clone(),
            value: local.value.clone(),
        })
        .collect();
    npa_frontend::MachineTermElabContext::from_verified_imports_and_current_decls_in_module(
        &direct_imports,
        &available_imports,
        state.root.module.clone(),
        &checked_current_decls,
        &current_generated_decls,
        local_context,
        state.root.universe_params.clone(),
    )
    .map(|context| context.with_callable_interface_table(callable_interface_table))
    .map_err(machine_term_elaboration_diag)
}

fn frontend_import_from_ref(import: &VerifiedImportRef) -> npa_frontend::VerifiedImport {
    let mut frontend = npa_frontend::VerifiedImport::from(import.verified_module.as_ref());
    let visible_exports = import
        .exports
        .iter()
        .map(|export| (export.name.clone(), export.decl_interface_hash))
        .collect::<BTreeSet<_>>();
    frontend.exports.retain(|export| {
        visible_exports.contains(&(export.name.clone(), export.decl_interface_hash))
    });
    frontend
}

fn machine_surface_callable_interface_table(
    state: &MachineProofState,
) -> Result<npa_frontend::MachineSurfaceCallableInterfaceTable> {
    let mut entries = Vec::new();
    for import in &state.env.imports {
        for export in &import.exports {
            ensure_imported_machine_surface_callable_name(import, &export.name)?;
            let ty = import_export_type(import, export)?;
            entries.push(
                npa_frontend::MachineSurfaceCallableInterfaceEntry::all_explicit(
                    npa_frontend::MachineSurfaceCallableRef::Imported {
                        module: import.module.clone(),
                        name: export.name.clone(),
                        export_hash: import.export_hash,
                        decl_interface_hash: export.decl_interface_hash,
                    },
                    expr_pi_telescope_len(&ty),
                ),
            );
        }
    }
    for checked in &state.env.checked_current_decls {
        ensure_current_machine_surface_callable_name(checked.signature.name())?;
        entries.push(
            npa_frontend::MachineSurfaceCallableInterfaceEntry::all_explicit(
                npa_frontend::MachineSurfaceCallableRef::CurrentModule {
                    module: state.root.module.clone(),
                    name: checked.signature.name.clone(),
                    source_index: checked.source_index,
                    decl_interface_hash: checked.signature.decl_interface_hash,
                },
                expr_pi_telescope_len(&checked.signature.ty),
            ),
        );
        if let Decl::Inductive { data, .. } = &checked.core_decl {
            for constructor in &data.constructors {
                let name = Name::from_dotted(&constructor.name);
                ensure_current_machine_surface_callable_name(&name)?;
                entries.push(
                    npa_frontend::MachineSurfaceCallableInterfaceEntry::all_explicit(
                        npa_frontend::MachineSurfaceCallableRef::CurrentGenerated {
                            module: state.root.module.clone(),
                            name,
                            parent_source_index: checked.source_index,
                            decl_interface_hash: checked.signature.decl_interface_hash,
                        },
                        expr_pi_telescope_len(&constructor.ty),
                    ),
                );
            }
            if let Some(recursor) = &data.recursor {
                let name = Name::from_dotted(&recursor.name);
                ensure_current_machine_surface_callable_name(&name)?;
                entries.push(
                    npa_frontend::MachineSurfaceCallableInterfaceEntry::all_explicit(
                        npa_frontend::MachineSurfaceCallableRef::CurrentGenerated {
                            module: state.root.module.clone(),
                            name,
                            parent_source_index: checked.source_index,
                            decl_interface_hash: checked.signature.decl_interface_hash,
                        },
                        expr_pi_telescope_len(&recursor.ty),
                    ),
                );
            }
        }
    }

    npa_frontend::MachineSurfaceCallableInterfaceTable::from_entries(entries).map_err(|err| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofSpec,
            format!("machine surface callable interface table is invalid: {err:?}"),
        )
    })
}

fn ensure_imported_machine_surface_callable_name(
    import: &VerifiedImportRef,
    name: &Name,
) -> Result<()> {
    if npa_frontend::is_machine_surface_renderable_name(name) {
        return Ok(());
    }

    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::InvalidVerifiedImport,
        format!(
            "verified import {} export {} is not Machine Surface renderable",
            import.module.as_dotted(),
            name.as_dotted()
        ),
    ))
}

fn ensure_current_machine_surface_callable_name(name: &Name) -> Result<()> {
    if npa_frontend::is_machine_surface_renderable_name(name) {
        return Ok(());
    }

    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::InvalidMachineProofSpec,
        format!(
            "current declaration {} is not Machine Surface renderable",
            name.as_dotted()
        ),
    ))
}

fn import_export_type(
    import: &VerifiedImportRef,
    export: &VerifiedExportSignature,
) -> Result<Expr> {
    match export.kind {
        ExportKind::Axiom | ExportKind::Def | ExportKind::Theorem | ExportKind::Inductive => {
            import_ordinary_export_type(import, export)
        }
        ExportKind::Constructor | ExportKind::Recursor => {
            import_generated_export_type(import, export)
        }
    }
}

fn import_ordinary_export_type(
    import: &VerifiedImportRef,
    export: &VerifiedExportSignature,
) -> Result<Expr> {
    let export_name = export.name.as_dotted();
    import
        .certified_env_decls
        .iter()
        .find(|decl| decl.name() == export_name)
        .map(|decl| decl.ty().clone())
        .ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidVerifiedImport,
                format!(
                    "verified import {} export {} is missing from the reconstructed kernel env",
                    import.module.as_dotted(),
                    export.name.as_dotted()
                ),
            )
        })
}

fn import_generated_export_type(
    import: &VerifiedImportRef,
    export: &VerifiedExportSignature,
) -> Result<Expr> {
    let export_name = export.name.as_dotted();
    if export.kind == ExportKind::Recursor && export_name == "Eq.rec" {
        return Ok(npa_kernel::eq_rec_type(
            Level::param("u"),
            Level::param("v"),
        ));
    }
    for decl in &import.certified_env_decls {
        let Decl::Inductive { data, .. } = decl else {
            continue;
        };
        match export.kind {
            ExportKind::Constructor => {
                if let Some(constructor) = data
                    .constructors
                    .iter()
                    .find(|constructor| constructor.name == export_name)
                {
                    return Ok(constructor.ty.clone());
                }
            }
            ExportKind::Recursor => {
                if let Some(recursor) = data
                    .recursor
                    .as_ref()
                    .filter(|recursor| recursor.name == export_name)
                {
                    return Ok(recursor.ty.clone());
                }
            }
            _ => unreachable!("caller dispatches only generated export kinds"),
        }
    }

    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::InvalidVerifiedImport,
        format!(
            "verified import {} generated export {} is missing from the reconstructed kernel env",
            import.module.as_dotted(),
            export.name.as_dotted()
        ),
    ))
}

fn expr_pi_telescope_len(expr: &Expr) -> usize {
    let mut len = 0;
    let mut current = expr;
    while let Expr::Pi { body, .. } = current {
        len += 1;
        current = body;
    }
    len
}

fn machine_term_elaboration_diag(err: npa_frontend::MachineDiagnostic) -> MachineTacticDiagnostic {
    match err.kind {
        npa_frontend::MachineDiagnosticKind::UnknownGlobalName
        | npa_frontend::MachineDiagnosticKind::ShortGlobalName
        | npa_frontend::MachineDiagnosticKind::AmbiguousGlobalName
        | npa_frontend::MachineDiagnosticKind::GlobalShadowedByLocal
        | npa_frontend::MachineDiagnosticKind::UnknownLocalName => {
            machine_term_frontend_diag_with_optional_name(
                MachineTacticDiagnosticKind::UnknownName,
                "machine term name resolution failed",
                &err,
            )
        }
        npa_frontend::MachineDiagnosticKind::ImplicitArgumentRequired
        | npa_frontend::MachineDiagnosticKind::MissingExplicitUniverse => {
            machine_term_frontend_diag_with_optional_name(
                MachineTacticDiagnosticKind::ImplicitArgumentRequired,
                "machine term requires explicit arguments",
                &err,
            )
        }
        npa_frontend::MachineDiagnosticKind::ExpectedFunctionType => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ExpectedFunctionType,
            format!("machine term expected a function type: {}", err.message),
        ),
        npa_frontend::MachineDiagnosticKind::TypeMismatch => {
            let mut diag = MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::TypeMismatch,
                format!("machine term type check failed: {}", err.message),
            );
            if let Some(payload) = err.payload {
                if let (Some(expected), Some(actual)) =
                    (payload.expected_hash.as_ref(), payload.actual_hash.as_ref())
                {
                    diag.expected_hash = Some(Box::new(*expected));
                    diag.actual_hash = Some(Box::new(*actual));
                    diag = diag.with_unification_conflict_kind(
                        UnificationDiagnosticKind::RigidRigidMismatch,
                    );
                }
            }
            diag
        }
        npa_frontend::MachineDiagnosticKind::ParseError
        | npa_frontend::MachineDiagnosticKind::UnsupportedSyntax
        | npa_frontend::MachineDiagnosticKind::HoleNotAllowed => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTermSource,
            format!("machine term source is invalid: {}", err.message),
        ),
        npa_frontend::MachineDiagnosticKind::KernelRejected => {
            machine_term_frontend_diag_with_optional_name(
                MachineTacticDiagnosticKind::MachineTermElaborationError,
                "machine term elaboration was rejected by the kernel",
                &err,
            )
        }
        _ => machine_term_frontend_diag_with_optional_name(
            MachineTacticDiagnosticKind::MachineTermElaborationError,
            "machine term elaboration failed",
            &err,
        ),
    }
}

fn machine_term_frontend_diag_with_optional_name(
    kind: MachineTacticDiagnosticKind,
    prefix: &str,
    err: &npa_frontend::MachineDiagnostic,
) -> MachineTacticDiagnostic {
    let mut diag = MachineTacticDiagnostic::new(kind, format!("{prefix}: {}", err.message));
    if let Some(payload) = err.payload.as_ref() {
        if let Some(head_symbol) = payload.head_symbol.as_ref() {
            let name = Name::from_dotted(head_symbol);
            if name.is_canonical() {
                diag = diag.with_primary_name(name);
            }
        }
    }
    diag
}

fn canonicalize_imports(mut imports: Vec<VerifiedImportRef>) -> Vec<VerifiedImportRef> {
    imports.sort_by(|lhs, rhs| {
        name_canonical_bytes(&lhs.module)
            .cmp(&name_canonical_bytes(&rhs.module))
            .then_with(|| lhs.export_hash.cmp(&rhs.export_hash))
            .then_with(|| lhs.certificate_hash.cmp(&rhs.certificate_hash))
    });
    imports
}

fn validate_imports(imports: &[VerifiedImportRef]) -> Result<()> {
    let mut import_keys = BTreeSet::new();
    let mut module_hashes = BTreeMap::new();
    let mut exported_names = BTreeSet::new();
    for import in imports {
        let key = (
            import.module.clone(),
            import.export_hash,
            import.certificate_hash,
        );
        if let Some((existing_export_hash, existing_certificate_hash)) =
            module_hashes.get(&import.module)
        {
            if *existing_export_hash != import.export_hash
                || *existing_certificate_hash != import.certificate_hash
            {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidVerifiedImport,
                    format!(
                        "verified imports contain multiple hashes for module {}",
                        import.module.as_dotted()
                    ),
                ));
            }
        } else {
            module_hashes.insert(
                import.module.clone(),
                (import.export_hash, import.certificate_hash),
            );
        }
        if !import_keys.insert(key) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidVerifiedImport,
                format!("duplicate verified import {}", import.module.as_dotted()),
            ));
        }
        let mut module_exported_names = BTreeSet::new();
        for export in &import.exports {
            if !module_exported_names.insert(export.name.clone()) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidVerifiedImport,
                    format!(
                        "verified import {} exports duplicate name {}",
                        import.module.as_dotted(),
                        export.name.as_dotted()
                    ),
                ));
            }
            if !exported_names.insert(export.name.clone()) {
                return Err(MachineTacticDiagnostic::new(
                    MachineTacticDiagnosticKind::InvalidVerifiedImport,
                    format!(
                        "verified imports export duplicate name {}",
                        export.name.as_dotted()
                    ),
                ));
            }
        }
    }
    Ok(())
}

fn validate_proof_spec(spec: &MachineProofSpec) -> Result<()> {
    if !spec.module.is_canonical() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofSpec,
            "proof module name is not canonical",
        ));
    }
    if !spec.theorem_name.is_canonical() {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofSpec,
            "theorem name is not canonical",
        ));
    }
    if !name_is_in_module(&spec.theorem_name, &spec.module) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineProofSpec,
            format!(
                "theorem name {} is not in proof module {}",
                spec.theorem_name.as_dotted(),
                spec.module.as_dotted()
            ),
        ));
    }
    validate_universe_params(&spec.universe_params)?;
    Ok(())
}

fn validate_checked_current_decls_for_module(
    module: &ModuleName,
    theorem_name: &Name,
    checked_current_decls: &[CheckedCurrentDecl],
) -> Result<()> {
    for checked in checked_current_decls {
        let core_name = Name::from_dotted(checked.core_decl.name());
        if !name_is_in_module(&core_name, module) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidCurrentDeclOrder,
                format!(
                    "checked current declaration {} is not in proof module {}",
                    core_name.as_dotted(),
                    module.as_dotted()
                ),
            ));
        }
        if &core_name == theorem_name || checked.signature.name() == theorem_name {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidCurrentDeclOrder,
                format!(
                    "checked current declaration {} duplicates theorem name {}",
                    core_name.as_dotted(),
                    theorem_name.as_dotted()
                ),
            ));
        }
    }
    Ok(())
}

fn name_is_in_module(name: &Name, module: &ModuleName) -> bool {
    name.0.len() > module.0.len() && name.0.starts_with(&module.0)
}

fn validate_universe_params(params: &[String]) -> Result<()> {
    let mut seen = BTreeSet::new();
    for param in params {
        if param.is_empty() {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofSpec,
                "universe parameter names must be nonempty",
            ));
        }
        if !seen.insert(param) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMachineProofSpec,
                format!("duplicate universe parameter {param}"),
            ));
        }
    }
    Ok(())
}

fn add_decl_to_kernel_env(env: &mut Env, decl: Decl) -> npa_kernel::Result<()> {
    match decl {
        Decl::Axiom {
            name,
            universe_params,
            ty,
        } => env.add_axiom(name, universe_params, ty),
        Decl::AxiomConstrained {
            name,
            universe_params,
            universe_constraints,
            ty,
        } => {
            env.add_axiom_with_universe_constraints(name, universe_params, universe_constraints, ty)
        }
        Decl::Def {
            name,
            universe_params,
            ty,
            value,
            reducibility,
        } => env.add_def(name, universe_params, ty, value, reducibility),
        Decl::DefConstrained {
            name,
            universe_params,
            universe_constraints,
            ty,
            value,
            reducibility,
        } => env.add_def_with_universe_constraints(
            name,
            universe_params,
            universe_constraints,
            ty,
            value,
            reducibility,
        ),
        Decl::Theorem {
            name,
            universe_params,
            ty,
            proof,
        } => env.add_theorem(name, universe_params, ty, proof),
        Decl::TheoremConstrained {
            name,
            universe_params,
            universe_constraints,
            ty,
            proof,
        } => env.add_theorem_with_universe_constraints(
            name,
            universe_params,
            universe_constraints,
            ty,
            proof,
        ),
        Decl::Inductive { data, .. } => env.add_inductive(*data),
        Decl::MutualInductiveBlock { data, .. } => env.add_mutual_inductive(*data),
        Decl::Constructor { .. } | Decl::Recursor { .. } => {
            Err(npa_kernel::Error::InvalidInductive(
                "generated declarations cannot be added directly".to_owned(),
            ))
        }
    }
}

fn verified_builtin_decl_matches_kernel_env(env: &Env, decl: &Decl) -> bool {
    match decl {
        Decl::Inductive { name, .. } if name == "Nat" || name == "Eq" => {
            let Ok(candidate) = kernel_env_from_single_decl(decl.clone()) else {
                return false;
            };
            let Some(mut names) = generated_decl_closure_names(decl) else {
                return false;
            };
            if name == "Eq" {
                names.retain(|name| name != "Eq.rec");
            }
            names.iter().all(|candidate_name| {
                let Some(existing) = env.decl(candidate_name) else {
                    return false;
                };
                let Some(candidate) = candidate.decl(candidate_name) else {
                    return false;
                };
                builtin_kernel_decl_interfaces_match(name, existing, candidate)
            })
        }
        Decl::Axiom {
            name,
            universe_params,
            ty,
        } if name == "Eq.rec" => {
            env.decl("Eq.rec").is_some()
                && universe_params.len() == 2
                && universe_params[0] == "u"
                && universe_params[1] == "v"
                && core_expr_hash(ty)
                    == core_expr_hash(&npa_kernel::eq_rec_type(
                        Level::param("u"),
                        Level::param("v"),
                    ))
        }
        _ => false,
    }
}

fn kernel_env_from_single_decl(decl: Decl) -> npa_kernel::Result<Env> {
    let mut env = Env::new();
    add_decl_to_kernel_env(&mut env, decl)?;
    Ok(env)
}

fn generated_decl_closure_names(decl: &Decl) -> Option<Vec<String>> {
    let Decl::Inductive { data, .. } = decl else {
        return None;
    };
    let mut names = Vec::new();
    names.push(data.name.clone());
    names.extend(
        data.constructors
            .iter()
            .map(|constructor| constructor.name.clone()),
    );
    if let Some(recursor) = &data.recursor {
        names.push(recursor.name.clone());
    }
    Some(names)
}

fn kernel_decl_interfaces_match(lhs: &Decl, rhs: &Decl) -> bool {
    match (lhs, rhs) {
        (
            Decl::Axiom {
                name: lhs_name,
                universe_params: lhs_params,
                ty: lhs_ty,
            },
            Decl::Axiom {
                name: rhs_name,
                universe_params: rhs_params,
                ty: rhs_ty,
            },
        ) => {
            lhs_name == rhs_name
                && lhs_params == rhs_params
                && core_expr_hash(lhs_ty) == core_expr_hash(rhs_ty)
        }
        (
            Decl::Inductive {
                name: lhs_name,
                universe_params: lhs_params,
                ty: lhs_ty,
                data: lhs_data,
            },
            Decl::Inductive {
                name: rhs_name,
                universe_params: rhs_params,
                ty: rhs_ty,
                data: rhs_data,
            },
        ) => {
            lhs_name == rhs_name
                && lhs_params == rhs_params
                && core_expr_hash(lhs_ty) == core_expr_hash(rhs_ty)
                && inductive_interfaces_match(lhs_data, rhs_data)
        }
        (
            Decl::Constructor {
                name: lhs_name,
                universe_params: lhs_params,
                ty: lhs_ty,
                inductive: lhs_inductive,
            },
            Decl::Constructor {
                name: rhs_name,
                universe_params: rhs_params,
                ty: rhs_ty,
                inductive: rhs_inductive,
            },
        ) => {
            lhs_name == rhs_name
                && lhs_params == rhs_params
                && lhs_inductive == rhs_inductive
                && core_expr_hash(lhs_ty) == core_expr_hash(rhs_ty)
        }
        (
            Decl::Recursor {
                name: lhs_name,
                universe_params: lhs_params,
                ty: lhs_ty,
                inductive: lhs_inductive,
                rules: lhs_rules,
            },
            Decl::Recursor {
                name: rhs_name,
                universe_params: rhs_params,
                ty: rhs_ty,
                inductive: rhs_inductive,
                rules: rhs_rules,
            },
        ) => {
            lhs_name == rhs_name
                && lhs_params == rhs_params
                && lhs_inductive == rhs_inductive
                && lhs_rules == rhs_rules
                && core_expr_hash(lhs_ty) == core_expr_hash(rhs_ty)
        }
        _ => false,
    }
}

fn builtin_kernel_decl_interfaces_match(builtin: &str, lhs: &Decl, rhs: &Decl) -> bool {
    if builtin == "Eq" {
        if let (
            Decl::Inductive {
                name: lhs_name,
                universe_params: lhs_params,
                ty: lhs_ty,
                data: lhs_data,
            },
            Decl::Inductive {
                name: rhs_name,
                universe_params: rhs_params,
                ty: rhs_ty,
                data: rhs_data,
            },
        ) = (lhs, rhs)
        {
            return lhs_name == rhs_name
                && lhs_params == rhs_params
                && core_expr_hash(lhs_ty) == core_expr_hash(rhs_ty)
                && lhs_data.name == rhs_data.name
                && lhs_data.universe_params == rhs_data.universe_params
                && lhs_data.sort == rhs_data.sort
                && binder_type_hashes(&lhs_data.params) == binder_type_hashes(&rhs_data.params)
                && binder_type_hashes(&lhs_data.indices) == binder_type_hashes(&rhs_data.indices)
                && constructor_interfaces_match(&lhs_data.constructors, &rhs_data.constructors);
        }
    }
    kernel_decl_interfaces_match(lhs, rhs)
}

fn inductive_interfaces_match(
    lhs: &npa_kernel::InductiveDecl,
    rhs: &npa_kernel::InductiveDecl,
) -> bool {
    lhs.name == rhs.name
        && lhs.universe_params == rhs.universe_params
        && lhs.sort == rhs.sort
        && binder_type_hashes(&lhs.params) == binder_type_hashes(&rhs.params)
        && binder_type_hashes(&lhs.indices) == binder_type_hashes(&rhs.indices)
        && constructor_interfaces_match(&lhs.constructors, &rhs.constructors)
        && recursor_interfaces_match(&lhs.recursor, &rhs.recursor, lhs)
}

fn binder_type_hashes(binders: &[npa_kernel::Binder]) -> Vec<Hash> {
    binders
        .iter()
        .map(|binder| core_expr_hash(&binder.ty))
        .collect()
}

fn constructor_interfaces_match(
    lhs: &[npa_kernel::ConstructorDecl],
    rhs: &[npa_kernel::ConstructorDecl],
) -> bool {
    lhs.len() == rhs.len()
        && lhs.iter().zip(rhs).all(|(lhs, rhs)| {
            lhs.name == rhs.name && core_expr_hash(&lhs.ty) == core_expr_hash(&rhs.ty)
        })
}

fn recursor_interfaces_match(
    lhs: &Option<npa_kernel::RecursorDecl>,
    rhs: &Option<npa_kernel::RecursorDecl>,
    data: &npa_kernel::InductiveDecl,
) -> bool {
    match (lhs, rhs) {
        (Some(lhs), Some(rhs)) => {
            lhs.name == rhs.name
                && lhs.universe_params == rhs.universe_params
                && core_expr_hash(&lhs.ty) == core_expr_hash(&rhs.ty)
                && effective_recursor_rules(lhs, data) == effective_recursor_rules(rhs, data)
        }
        (None, None) => true,
        _ => false,
    }
}

fn effective_recursor_rules(
    recursor: &npa_kernel::RecursorDecl,
    data: &npa_kernel::InductiveDecl,
) -> npa_kernel::RecursorRules {
    recursor.rules.clone().unwrap_or_else(|| {
        let minor_start = data.params.len() + 1;
        npa_kernel::RecursorRules::new(minor_start, minor_start + data.constructors.len())
    })
}

fn ensure_type_is_sort(
    env: &Env,
    ctx: &Ctx,
    delta: &[String],
    term: &Expr,
) -> npa_kernel::Result<()> {
    match env.whnf(ctx, delta, &env.infer(ctx, delta, term)?)? {
        Expr::Sort(_) => Ok(()),
        actual => Err(npa_kernel::Error::ExpectedSort { actual }),
    }
}

fn local_context_to_ctx_with_budget(
    env: &Env,
    context: &[MachineLocalDecl],
    universe_params: &[String],
    fuel: &TacticRunFuel,
    goal_id: GoalId,
    meta_id: MetaVarId,
) -> Result<Ctx> {
    let mut ctx = Ctx::new();
    let mut names = BTreeSet::new();
    for local in context {
        if local.name.is_empty() || !names.insert(local.name.clone()) {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidMetaContext,
                format!("invalid or duplicate local name {}", local.name),
            ));
        }
        kernel_expect_sort_with_budget(
            env,
            &ctx,
            universe_params,
            &local.ty,
            fuel,
            goal_id,
            meta_id,
        )?;
        match &local.value {
            Some(value) => {
                kernel_check_with_budget(
                    env,
                    &ctx,
                    universe_params,
                    value,
                    &local.ty,
                    fuel,
                    goal_id,
                    meta_id,
                )?;
                ctx.push_definition(local.name.clone(), local.ty.clone(), value.clone());
            }
            None => ctx.push_assumption(local.name.clone(), local.ty.clone()),
        }
    }
    Ok(ctx)
}

pub fn machine_local_context_is_prefix(
    prefix: &[MachineLocalDecl],
    full: &[MachineLocalDecl],
) -> bool {
    prefix.len() <= full.len() && prefix.iter().zip(full).all(|(lhs, rhs)| lhs == rhs)
}

fn kernel_diag(err: npa_kernel::Error) -> MachineTacticDiagnostic {
    match err {
        npa_kernel::Error::InvalidBVar(_) => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ProofExprScopeError,
            format!("kernel rejected proof expression scope: {err:?}"),
        ),
        npa_kernel::Error::TypeMismatch { expected, actual } => {
            let message = format!(
                "kernel rejected proof expression type: {:?}",
                npa_kernel::Error::TypeMismatch {
                    expected: expected.clone(),
                    actual: actual.clone()
                }
            );
            MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::TypeMismatch, message)
                .with_expected_actual_payloads(
                    DiagnosticPayloadKind::Expr,
                    &core_expr_canonical_bytes(&expected),
                    &core_expr_canonical_bytes(&actual),
                )
        }
        npa_kernel::Error::UnresolvedUniverseMeta(meta) => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::KernelRejected,
            format!("kernel rejected proof expression with unresolved universe meta {meta}"),
        )
        .with_universe_diagnostic(unresolved_universe_meta_diagnostic(vec![meta])),
        npa_kernel::Error::UniverseConstraintViolation { constraint, .. } => {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::KernelRejected,
                format!("kernel rejected proof expression universe constraint: {constraint:?}"),
            )
            .with_universe_diagnostic(universe_constraint_diagnostic(
                UniverseDiagnosticKind::UnsatisfiableConstraint,
                constraint,
                UniverseDiagnosticCoreKind::Unsat,
            ))
        }
        npa_kernel::Error::UnsupportedUniverseConstraint { constraint } => {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::KernelRejected,
                format!("kernel rejected unsupported universe constraint: {constraint:?}"),
            )
            .with_universe_diagnostic(universe_constraint_diagnostic(
                UniverseDiagnosticKind::InvalidInstantiation,
                constraint,
                UniverseDiagnosticCoreKind::Reduced,
            ))
        }
        _ => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::KernelRejected,
            format!("kernel rejected proof expression: {err:?}"),
        ),
    }
}

fn theorem_type_diag(err: npa_kernel::Error) -> MachineTacticDiagnostic {
    match err {
        npa_kernel::Error::ExpectedSort { actual } => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::TypeMismatch,
            format!("theorem type must have a sort type, got {actual:?}"),
        ),
        npa_kernel::Error::ExpectedPi { actual } => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ExpectedFunctionType,
            format!("theorem type contains an application whose function has type {actual:?}"),
        ),
        npa_kernel::Error::TypeMismatch { expected, actual } => {
            let message = format!(
                "kernel rejected theorem type: {:?}",
                npa_kernel::Error::TypeMismatch {
                    expected: expected.clone(),
                    actual: actual.clone()
                }
            );
            MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::TypeMismatch, message)
                .with_expected_actual_payloads(
                    DiagnosticPayloadKind::Expr,
                    &core_expr_canonical_bytes(&expected),
                    &core_expr_canonical_bytes(&actual),
                )
        }
        npa_kernel::Error::InvalidBVar(_) => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::ProofExprScopeError,
            format!("kernel rejected theorem type scope: {err:?}"),
        ),
        _ => MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::KernelRejected,
            format!("kernel rejected theorem type: {err:?}"),
        ),
    }
}

fn contains_bound_var(expr: &Expr, target: u32) -> bool {
    match expr {
        Expr::Sort(_) | Expr::Const { .. } => false,
        Expr::BVar(index) => *index == target,
        Expr::App(fun, arg) => contains_bound_var(fun, target) || contains_bound_var(arg, target),
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            contains_bound_var(ty, target) || contains_bound_var(body, target + 1)
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            contains_bound_var(ty, target)
                || contains_bound_var(value, target)
                || contains_bound_var(body, target + 1)
        }
    }
}

fn ensure_no_unresolved_universe_metas_in_expr(expr: &Expr) -> Result<()> {
    if expr_contains_unresolved_universe_meta(expr) {
        let mut metas = BTreeSet::new();
        collect_expr_unresolved_universe_metas(expr, &mut metas);
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidMachineTermSource,
            "refine hole expected type contains an unresolved universe meta",
        )
        .with_universe_diagnostic(unresolved_universe_meta_diagnostic(
            metas.into_iter().collect(),
        )));
    }
    Ok(())
}

fn expr_contains_unresolved_universe_meta(expr: &Expr) -> bool {
    match expr {
        Expr::Sort(level) => level_contains_unresolved_universe_meta(level),
        Expr::BVar(_) => false,
        Expr::Const { levels, .. } => levels.iter().any(level_contains_unresolved_universe_meta),
        Expr::App(fun, arg) => {
            expr_contains_unresolved_universe_meta(fun)
                || expr_contains_unresolved_universe_meta(arg)
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            expr_contains_unresolved_universe_meta(ty)
                || expr_contains_unresolved_universe_meta(body)
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            expr_contains_unresolved_universe_meta(ty)
                || expr_contains_unresolved_universe_meta(value)
                || expr_contains_unresolved_universe_meta(body)
        }
    }
}

fn level_contains_unresolved_universe_meta(level: &Level) -> bool {
    match level {
        Level::Zero => false,
        Level::Succ(inner) => level_contains_unresolved_universe_meta(inner),
        Level::Max(lhs, rhs) | Level::IMax(lhs, rhs) => {
            level_contains_unresolved_universe_meta(lhs)
                || level_contains_unresolved_universe_meta(rhs)
        }
        Level::Param(name) => name.starts_with('?'),
    }
}

fn collect_expr_unresolved_universe_metas(expr: &Expr, metas: &mut BTreeSet<String>) {
    match expr {
        Expr::Sort(level) => collect_level_universe_metas(level, metas),
        Expr::BVar(_) => {}
        Expr::Const { levels, .. } => {
            for level in levels {
                collect_level_universe_metas(level, metas);
            }
        }
        Expr::App(fun, arg) => {
            collect_expr_unresolved_universe_metas(fun, metas);
            collect_expr_unresolved_universe_metas(arg, metas);
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            collect_expr_unresolved_universe_metas(ty, metas);
            collect_expr_unresolved_universe_metas(body, metas);
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            collect_expr_unresolved_universe_metas(ty, metas);
            collect_expr_unresolved_universe_metas(value, metas);
            collect_expr_unresolved_universe_metas(body, metas);
        }
    }
}

fn core_expr_node_count(expr: &Expr) -> u64 {
    match expr {
        Expr::Sort(_) | Expr::BVar(_) | Expr::Const { .. } => 1,
        Expr::App(fun, arg) => 1 + core_expr_node_count(fun) + core_expr_node_count(arg),
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            1 + core_expr_node_count(ty) + core_expr_node_count(body)
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            1 + core_expr_node_count(ty) + core_expr_node_count(value) + core_expr_node_count(body)
        }
    }
}

fn proof_expr_node_count(expr: &ProofExpr) -> u64 {
    match expr {
        ProofExpr::Core(core) => 1 + core_expr_node_count(core),
        ProofExpr::Meta(_) => 1,
        ProofExpr::App(fun, arg) => 1 + proof_expr_node_count(fun) + proof_expr_node_count(arg),
        ProofExpr::Lam { ty, body, .. } => {
            1 + core_expr_node_count(ty) + proof_expr_node_count(body)
        }
        ProofExpr::Let {
            ty, value, body, ..
        } => {
            1 + core_expr_node_count(ty)
                + proof_expr_node_count(value)
                + proof_expr_node_count(body)
        }
    }
}

fn diagnostic_head_symbol(expr: &Expr) -> Option<String> {
    let mut head = expr;
    while let Expr::App(fun, _) = head {
        head = fun;
    }
    match head {
        Expr::Sort(_) => Some("Sort".to_owned()),
        Expr::BVar(index) => Some(format!("bvar:{index}")),
        Expr::Const { name, .. } => Some(name.clone()),
        Expr::App(_, _) => None,
        Expr::Lam { .. } => Some("Lam".to_owned()),
        Expr::Pi { .. } => Some("Pi".to_owned()),
        Expr::Let { .. } => Some("Let".to_owned()),
    }
}

fn diagnostic_binder_arity(expr: &Expr) -> u64 {
    let mut current = expr;
    let mut arity = 0;
    while let Expr::Lam { body, .. } | Expr::Pi { body, .. } = current {
        arity += 1;
        current = body;
    }
    arity
}

fn count_expr_nodes_bounded(expr: &Expr, max_nodes: u64) -> (u64, bool) {
    let mut count = 0;
    let truncated = count_expr_nodes_bounded_to(expr, max_nodes, &mut count);
    (count, truncated)
}

fn count_expr_nodes_bounded_to(expr: &Expr, max_nodes: u64, count: &mut u64) -> bool {
    if *count >= max_nodes {
        return true;
    }
    *count += 1;
    match expr {
        Expr::Sort(_) | Expr::BVar(_) | Expr::Const { .. } => false,
        Expr::App(fun, arg) => {
            count_expr_nodes_bounded_to(fun, max_nodes, count)
                || count_expr_nodes_bounded_to(arg, max_nodes, count)
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            count_expr_nodes_bounded_to(ty, max_nodes, count)
                || count_expr_nodes_bounded_to(body, max_nodes, count)
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            count_expr_nodes_bounded_to(ty, max_nodes, count)
                || count_expr_nodes_bounded_to(value, max_nodes, count)
                || count_expr_nodes_bounded_to(body, max_nodes, count)
        }
    }
}

fn diagnostic_universe_summary(
    expr: &Expr,
    max_universe_params: usize,
) -> DiagnosticUniverseSummary {
    let mut level_count = 0;
    let mut params = BTreeSet::new();
    collect_expr_universe_summary(expr, &mut level_count, &mut params);
    let truncated = params.len() > max_universe_params;
    DiagnosticUniverseSummary {
        level_count,
        params: params.into_iter().take(max_universe_params).collect(),
        truncated,
    }
}

fn collect_expr_universe_summary(
    expr: &Expr,
    level_count: &mut u64,
    params: &mut BTreeSet<String>,
) {
    match expr {
        Expr::Sort(level) => collect_level_universe_summary(level, level_count, params),
        Expr::BVar(_) => {}
        Expr::Const { levels, .. } => {
            for level in levels {
                collect_level_universe_summary(level, level_count, params);
            }
        }
        Expr::App(fun, arg) => {
            collect_expr_universe_summary(fun, level_count, params);
            collect_expr_universe_summary(arg, level_count, params);
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            collect_expr_universe_summary(ty, level_count, params);
            collect_expr_universe_summary(body, level_count, params);
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            collect_expr_universe_summary(ty, level_count, params);
            collect_expr_universe_summary(value, level_count, params);
            collect_expr_universe_summary(body, level_count, params);
        }
    }
}

fn collect_level_universe_summary(
    level: &Level,
    level_count: &mut u64,
    params: &mut BTreeSet<String>,
) {
    let normalized = normalize_level(level.clone());
    collect_normalized_level_universe_summary(&normalized, level_count, params);
}

fn collect_normalized_level_universe_summary(
    level: &Level,
    level_count: &mut u64,
    params: &mut BTreeSet<String>,
) {
    *level_count += 1;
    match level {
        Level::Zero => {}
        Level::Succ(inner) => {
            collect_normalized_level_universe_summary(inner, level_count, params);
        }
        Level::Max(lhs, rhs) | Level::IMax(lhs, rhs) => {
            collect_normalized_level_universe_summary(lhs, level_count, params);
            collect_normalized_level_universe_summary(rhs, level_count, params);
        }
        Level::Param(name) => {
            params.insert(name.clone());
        }
    }
}

fn collect_local_dependency_ids(local: &MachineLocalDecl, prior_local_count: usize) -> Vec<u32> {
    let mut ids = BTreeSet::new();
    collect_expr_local_dependency_ids(&local.ty, prior_local_count, 0, &mut ids);
    if let Some(value) = &local.value {
        collect_expr_local_dependency_ids(value, prior_local_count, 0, &mut ids);
    }
    ids.into_iter().collect()
}

fn collect_expr_local_dependency_ids(
    expr: &Expr,
    prior_local_count: usize,
    binder_depth: usize,
    ids: &mut BTreeSet<u32>,
) {
    match expr {
        Expr::Sort(_) | Expr::Const { .. } => {}
        Expr::BVar(index) => {
            let index = *index as usize;
            if index >= binder_depth {
                let local_offset = index - binder_depth;
                if local_offset < prior_local_count {
                    let local_index = prior_local_count - 1 - local_offset;
                    ids.insert(saturating_u32_from_usize(local_index));
                }
            }
        }
        Expr::App(fun, arg) => {
            collect_expr_local_dependency_ids(fun, prior_local_count, binder_depth, ids);
            collect_expr_local_dependency_ids(arg, prior_local_count, binder_depth, ids);
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            collect_expr_local_dependency_ids(ty, prior_local_count, binder_depth, ids);
            collect_expr_local_dependency_ids(body, prior_local_count, binder_depth + 1, ids);
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            collect_expr_local_dependency_ids(ty, prior_local_count, binder_depth, ids);
            collect_expr_local_dependency_ids(value, prior_local_count, binder_depth, ids);
            collect_expr_local_dependency_ids(body, prior_local_count, binder_depth + 1, ids);
        }
    }
}

fn saturating_u32_from_usize(value: usize) -> u32 {
    u32::try_from(value).unwrap_or(u32::MAX)
}

fn certificate_current_decl_hashes(
    imports: &[VerifiedImportRef],
    checked_prior_current_decls: &[CheckedCurrentDecl],
    decl: &Decl,
) -> Result<DeclHashes> {
    let module_name = infer_current_module_name(decl)?;
    let declarations = checked_prior_current_decls
        .iter()
        .map(|checked| checked.core_decl.clone())
        .chain(std::iter::once(decl.clone()))
        .collect::<Vec<_>>();
    let verified_imports = certificate_imports_for_current_decl_hashes(imports, &declarations)?;
    let cert = npa_cert::build_module_cert(
        CoreModule {
            name: module_name,
            declarations,
        },
        &verified_imports,
    )
    .map_err(|err| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UncheckedCurrentDecl,
            format!(
                "certificate rejected current declaration interface hash materialization for {}: {err:?}",
                decl.name()
            ),
        )
    })?;
    let target_name = Name::from_dotted(decl.name());
    for cert_decl in &cert.declarations {
        if decl_payload_name(&cert, &cert_decl.decl)? == target_name {
            return Ok(cert_decl.hashes.clone());
        }
    }
    Err(MachineTacticDiagnostic::new(
        MachineTacticDiagnosticKind::CurrentDeclSignatureMismatch,
        format!(
            "certificate materialization did not return current declaration {}",
            decl.name()
        ),
    ))
}

fn infer_current_module_name(decl: &Decl) -> Result<ModuleName> {
    let name = Name::from_dotted(decl.name());
    if !name.is_canonical() || name.0.len() < 2 {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UncheckedCurrentDecl,
            format!(
                "current declaration {} must be a canonical qualified module declaration",
                decl.name()
            ),
        ));
    }
    Ok(Name(name.0[..name.0.len() - 1].to_vec()))
}

fn decl_payload_name(cert: &npa_cert::ModuleCert, payload: &DeclPayload) -> Result<Name> {
    let name_id = match payload {
        DeclPayload::Axiom { name, .. }
        | DeclPayload::AxiomConstrained { name, .. }
        | DeclPayload::Def { name, .. }
        | DeclPayload::DefConstrained { name, .. }
        | DeclPayload::Theorem { name, .. }
        | DeclPayload::TheoremConstrained { name, .. }
        | DeclPayload::Inductive { name, .. }
        | DeclPayload::InductiveConstrained { name, .. }
        | DeclPayload::MutualInductiveBlock { name, .. } => *name,
    };
    cert.name_table.get(name_id).cloned().ok_or_else(|| {
        MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::CurrentDeclSignatureMismatch,
            "certificate materialization returned a declaration with an invalid name id",
        )
    })
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct CertificateImportKey {
    module: ModuleName,
    export_hash: Hash,
    certificate_hash: Hash,
}

impl PartialOrd for CertificateImportKey {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for CertificateImportKey {
    fn cmp(&self, other: &Self) -> Ordering {
        name_canonical_bytes(&self.module)
            .cmp(&name_canonical_bytes(&other.module))
            .then_with(|| self.export_hash.cmp(&other.export_hash))
            .then_with(|| self.certificate_hash.cmp(&other.certificate_hash))
    }
}

fn certificate_import_key_from_ref(import: &VerifiedImportRef) -> CertificateImportKey {
    CertificateImportKey {
        module: import.module.clone(),
        export_hash: import.export_hash,
        certificate_hash: import.certificate_hash,
    }
}

fn certificate_import_key_from_entry(
    entry: &npa_cert::ImportEntry,
) -> Result<CertificateImportKey> {
    let Some(certificate_hash) = entry.certificate_hash else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidVerifiedImport,
            format!(
                "verified import {} dependency is missing a certificate hash",
                entry.module.as_dotted()
            ),
        ));
    };
    Ok(CertificateImportKey {
        module: entry.module.clone(),
        export_hash: entry.export_hash,
        certificate_hash,
    })
}

fn certificate_imports_for_current_decl_hashes(
    imports: &[VerifiedImportRef],
    declarations: &[Decl],
) -> Result<Vec<VerifiedModule>> {
    let imports_by_key = imports
        .iter()
        .map(|import| (certificate_import_key_from_ref(import), import))
        .collect::<BTreeMap<_, _>>();
    let visible_imports = imports
        .iter()
        .filter(|import| import.is_visible())
        .collect::<Vec<_>>();
    let referenced_names = referenced_visible_import_export_names(declarations, &visible_imports);
    let mut selected_keys = BTreeSet::new();
    let mut pending_keys = Vec::new();

    for import in &visible_imports {
        select_certificate_import_key(
            &certificate_import_key_from_ref(import),
            &imports_by_key,
            &mut selected_keys,
            &mut pending_keys,
        )?;
    }
    for import in visible_imports {
        add_axiom_origin_imports_for_referenced_visible_exports(
            import,
            &imports_by_key,
            &referenced_names,
            &mut selected_keys,
            &mut pending_keys,
        )?;
    }
    while let Some(key) = pending_keys.pop() {
        let import = imports_by_key.get(&key).copied().ok_or_else(|| {
            MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidVerifiedImport,
                format!(
                    "current declaration certificate import {} is missing from verified imports",
                    key.module.as_dotted()
                ),
            )
        })?;
        add_export_interface_dependency_imports_for_current_decl(
            import,
            &imports_by_key,
            &mut selected_keys,
            &mut pending_keys,
        )?;
    }

    selected_keys
        .into_iter()
        .map(|key| {
            imports_by_key
                .get(&key)
                .map(|import| import.verified_module.as_ref().clone())
                .ok_or_else(|| {
                    MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::InvalidVerifiedImport,
                        format!(
                            "current declaration certificate import {} is missing from verified imports",
                            key.module.as_dotted()
                        ),
                    )
                })
        })
        .collect()
}

fn add_axiom_origin_imports_for_referenced_visible_exports(
    import: &VerifiedImportRef,
    imports_by_key: &BTreeMap<CertificateImportKey, &VerifiedImportRef>,
    referenced_names: &BTreeSet<Name>,
    selected_keys: &mut BTreeSet<CertificateImportKey>,
    pending_keys: &mut Vec<CertificateImportKey>,
) -> Result<()> {
    for export in import.verified_module.export_block() {
        let Some(export_name) = import.verified_module.name_table().get(export.name) else {
            return Err(MachineTacticDiagnostic::new(
                MachineTacticDiagnosticKind::InvalidVerifiedImport,
                "verified import export references an out-of-range name table entry",
            ));
        };
        if !referenced_names.contains(export_name) {
            continue;
        }
        for axiom in &export.axiom_dependencies {
            let GlobalRef::Imported { import_index, .. } = &axiom.global_ref else {
                continue;
            };
            let import_entry = import
                .verified_module
                .imports()
                .get(*import_index)
                .ok_or_else(|| {
                    MachineTacticDiagnostic::new(
                        MachineTacticDiagnosticKind::InvalidVerifiedImport,
                        "verified import axiom provenance references an out-of-range import table entry",
                    )
                })?;
            let key = certificate_import_key_from_entry(import_entry)?;
            select_certificate_import_key(&key, imports_by_key, selected_keys, pending_keys)?;
        }
    }
    Ok(())
}

fn add_export_interface_dependency_imports_for_current_decl(
    import: &VerifiedImportRef,
    imports_by_key: &BTreeMap<CertificateImportKey, &VerifiedImportRef>,
    selected_keys: &mut BTreeSet<CertificateImportKey>,
    pending_keys: &mut Vec<CertificateImportKey>,
) -> Result<()> {
    for export in import.verified_module.export_block() {
        add_certificate_term_dependency_imports(
            import,
            export.ty,
            imports_by_key,
            selected_keys,
            pending_keys,
        )?;
        if let Some(body) = export.body {
            add_certificate_term_dependency_imports(
                import,
                body,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
        }
    }
    Ok(())
}

fn add_certificate_term_dependency_imports(
    import: &VerifiedImportRef,
    term: TermId,
    imports_by_key: &BTreeMap<CertificateImportKey, &VerifiedImportRef>,
    selected_keys: &mut BTreeSet<CertificateImportKey>,
    pending_keys: &mut Vec<CertificateImportKey>,
) -> Result<()> {
    let Some(term) = import.verified_module.term_table().get(term) else {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidVerifiedImport,
            "verified import export references an out-of-range term table entry",
        ));
    };
    match term {
        TermNode::Sort(_) | TermNode::BVar(_) => {}
        TermNode::Const { global_ref, .. } => {
            if let GlobalRef::Imported { import_index, .. } = global_ref {
                let import_entry = import
                    .verified_module
                    .imports()
                    .get(*import_index)
                    .ok_or_else(|| {
                        MachineTacticDiagnostic::new(
                            MachineTacticDiagnosticKind::InvalidVerifiedImport,
                            "verified import export references an out-of-range import table entry",
                        )
                    })?;
                let key = certificate_import_key_from_entry(import_entry)?;
                select_certificate_import_key(&key, imports_by_key, selected_keys, pending_keys)?;
            }
        }
        TermNode::App(fun, arg) => {
            add_certificate_term_dependency_imports(
                import,
                *fun,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
            add_certificate_term_dependency_imports(
                import,
                *arg,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
        }
        TermNode::Lam { ty, body } | TermNode::Pi { ty, body } => {
            add_certificate_term_dependency_imports(
                import,
                *ty,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
            add_certificate_term_dependency_imports(
                import,
                *body,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
        }
        TermNode::Let { ty, value, body } => {
            add_certificate_term_dependency_imports(
                import,
                *ty,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
            add_certificate_term_dependency_imports(
                import,
                *value,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
            add_certificate_term_dependency_imports(
                import,
                *body,
                imports_by_key,
                selected_keys,
                pending_keys,
            )?;
        }
    }
    Ok(())
}

fn select_certificate_import_key(
    key: &CertificateImportKey,
    imports_by_key: &BTreeMap<CertificateImportKey, &VerifiedImportRef>,
    selected_keys: &mut BTreeSet<CertificateImportKey>,
    pending_keys: &mut Vec<CertificateImportKey>,
) -> Result<()> {
    if !imports_by_key.contains_key(key) {
        return Err(MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::InvalidVerifiedImport,
            format!(
                "current declaration certificate dependency module {} is missing from verified imports",
                key.module.as_dotted()
            ),
        ));
    }
    if selected_keys.insert(key.clone()) {
        pending_keys.push(key.clone());
    }
    Ok(())
}

fn referenced_visible_import_export_names(
    declarations: &[Decl],
    visible_imports: &[&VerifiedImportRef],
) -> BTreeSet<Name> {
    let mut referenced_names = referenced_const_names(declarations);
    let local_names = local_public_names(declarations);
    referenced_names.retain(|name| !local_names.contains(name));

    let mut visible_export_names = BTreeSet::new();
    for import in visible_imports {
        visible_export_names.extend(import.exports.iter().map(|export| export.name.clone()));
    }
    referenced_names.retain(|name| visible_export_names.contains(name));
    referenced_names
}

fn referenced_const_names(declarations: &[Decl]) -> BTreeSet<Name> {
    let mut names = BTreeSet::new();
    for decl in declarations {
        collect_const_names_from_decl(&mut names, decl);
    }
    names
}

fn local_public_names(declarations: &[Decl]) -> BTreeSet<Name> {
    let mut names = BTreeSet::new();
    for decl in declarations {
        names.insert(Name::from_dotted(decl.name()));
        match decl {
            Decl::Inductive { data, .. } => {
                for constructor in &data.constructors {
                    names.insert(Name::from_dotted(&constructor.name));
                }
                if let Some(recursor) = &data.recursor {
                    names.insert(Name::from_dotted(&recursor.name));
                }
            }
            Decl::MutualInductiveBlock { data, .. } => {
                for inductive in &data.inductives {
                    names.insert(Name::from_dotted(&inductive.name));
                    for constructor in &inductive.constructors {
                        names.insert(Name::from_dotted(&constructor.name));
                    }
                    if let Some(recursor) = &inductive.recursor {
                        names.insert(Name::from_dotted(&recursor.name));
                    }
                }
            }
            _ => {}
        }
    }
    names
}

fn collect_const_names_from_decl(names: &mut BTreeSet<Name>, decl: &Decl) {
    match decl {
        Decl::Axiom { ty, .. } | Decl::AxiomConstrained { ty, .. } => {
            collect_const_names_from_expr(names, ty)
        }
        Decl::Def { ty, value, .. } | Decl::DefConstrained { ty, value, .. } => {
            collect_const_names_from_expr(names, ty);
            collect_const_names_from_expr(names, value);
        }
        Decl::Theorem { ty, proof, .. } | Decl::TheoremConstrained { ty, proof, .. } => {
            collect_const_names_from_expr(names, ty);
            collect_const_names_from_expr(names, proof);
        }
        Decl::Inductive { ty, data, .. } => {
            collect_const_names_from_expr(names, ty);
            for param in &data.params {
                collect_const_names_from_expr(names, &param.ty);
            }
            for index in &data.indices {
                collect_const_names_from_expr(names, &index.ty);
            }
            for constructor in &data.constructors {
                collect_const_names_from_expr(names, &constructor.ty);
            }
            if let Some(recursor) = &data.recursor {
                collect_const_names_from_expr(names, &recursor.ty);
            }
        }
        Decl::MutualInductiveBlock { data, .. } => {
            for inductive in &data.inductives {
                for param in &inductive.params {
                    collect_const_names_from_expr(names, &param.ty);
                }
                for index in &inductive.indices {
                    collect_const_names_from_expr(names, &index.ty);
                }
                for constructor in &inductive.constructors {
                    collect_const_names_from_expr(names, &constructor.ty);
                }
                if let Some(recursor) = &inductive.recursor {
                    collect_const_names_from_expr(names, &recursor.ty);
                }
            }
        }
        Decl::Constructor { ty, .. } | Decl::Recursor { ty, .. } => {
            collect_const_names_from_expr(names, ty);
        }
    }
}

fn collect_const_names_from_expr(names: &mut BTreeSet<Name>, expr: &Expr) {
    match expr {
        Expr::Sort(_) | Expr::BVar(_) => {}
        Expr::Const { name, .. } => {
            names.insert(Name::from_dotted(name));
        }
        Expr::App(fun, arg) => {
            collect_const_names_from_expr(names, fun);
            collect_const_names_from_expr(names, arg);
        }
        Expr::Lam { ty, body, .. } | Expr::Pi { ty, body, .. } => {
            collect_const_names_from_expr(names, ty);
            collect_const_names_from_expr(names, body);
        }
        Expr::Let {
            ty, value, body, ..
        } => {
            collect_const_names_from_expr(names, ty);
            collect_const_names_from_expr(names, value);
            collect_const_names_from_expr(names, body);
        }
    }
}

fn verified_export_signature_hash(export: &VerifiedExportSignature) -> Hash {
    let mut out = Vec::new();
    encode_name_to(&mut out, &export.name);
    encode_export_kind_to(&mut out, export.kind);
    encode_hash_to(&mut out, &export.decl_interface_hash);
    encode_hash_to(&mut out, &export.type_hash);
    encode_option_hash_to(&mut out, export.body_hash.as_ref());
    hash_with_domain("npa.machine-tactic.verified-export-signature.v1", &out)
}

fn checked_current_chain_fingerprint(checked_current_decls: &[CheckedCurrentDecl]) -> Hash {
    let mut out = Vec::new();
    encode_list_len_to(&mut out, checked_current_decls.len());
    for decl in checked_current_decls {
        encode_u64_to(&mut out, decl.source_index);
        encode_hash_to(&mut out, &checked_decl_signature_hash(&decl.signature));
        encode_hash_to(&mut out, &decl.core_decl_hash);
        encode_hash_to(&mut out, &decl.prior_chain_fingerprint);
        encode_hash_to(&mut out, &decl.checked_env_fingerprint);
    }
    hash_with_domain("npa.machine-tactic.current.prior-chain.v1", &out)
}

fn checked_env_fingerprint_with_kernel_profile(
    kernel_profile: MachineKernelProfile,
    imports: &[VerifiedImportRef],
    checked_current_decls: &[CheckedCurrentDecl],
) -> Hash {
    let mut out = Vec::new();
    encode_list_len_to(&mut out, imports.len());
    for import in imports {
        encode_name_to(&mut out, &import.module);
        encode_hash_to(&mut out, &import.export_hash);
        encode_hash_to(&mut out, &import.certificate_hash);
        let mut export_signature_hashes = import
            .exports
            .iter()
            .map(verified_export_signature_hash)
            .collect::<Vec<_>>();
        export_signature_hashes.sort();
        encode_list_len_to(&mut out, export_signature_hashes.len());
        for hash in export_signature_hashes {
            encode_hash_to(&mut out, &hash);
        }
        encode_list_len_to(&mut out, import.certified_env_decl_hashes.len());
        for hash in &import.certified_env_decl_hashes {
            encode_hash_to(&mut out, hash);
        }
    }
    encode_hash_to(
        &mut out,
        &checked_current_chain_fingerprint(checked_current_decls),
    );
    encode_list_len_to(&mut out, checked_current_decls.len());
    for decl in checked_current_decls {
        encode_u64_to(&mut out, decl.source_index);
        encode_hash_to(&mut out, &checked_decl_signature_hash(&decl.signature));
        encode_hash_to(&mut out, &decl.core_decl_hash);
        encode_hash_to(&mut out, &decl.checked_env_fingerprint);
    }
    encode_hash_to(&mut out, &kernel_check_profile_hash(kernel_profile));
    hash_with_domain("npa.machine-tactic.current.checked-env.v1", &out)
}

