    #[test]
    fn universe_diagnostic_simple_mismatch_exposes_graph_and_repair_operator() {
        let expected_params = vec!["u".to_owned(), "v".to_owned()];
        let actual_levels = vec![Level::param("u")];
        let diagnostic = universe_argument_mismatch_diag(
            &expected_params,
            &actual_levels,
            GoalId(0),
            MetaVarId(0),
        );

        let universe =
            collect_universe_diagnostic(&diagnostic, universe_diagnostic_budget(8, 8, 8, 8))
                .expect("universe argument mismatch should carry universe diagnostics");

        assert_eq!(universe.constraints.len(), 2);
        assert_eq!(universe.constraints[0].id, UniverseDiagnosticId(0));
        assert_eq!(
            universe.constraints[0].kind,
            UniverseDiagnosticKind::UniverseMismatch
        );
        assert_eq!(
            universe.constraints[0].relation,
            UniverseConstraintRelation::Eq
        );
        assert_eq!(
            universe.constraints[0].path,
            vec!["AppFunction".to_owned(), "UniverseArg(0)".to_owned()]
        );
        assert!(universe
            .repair_operators
            .contains(&UniverseRepairOperator::InstantiateUniverse));
        assert_eq!(universe.candidate_instantiations.len(), 1);
        assert!(!universe.candidate_instantiations[0].valid);
        assert_eq!(
            universe.candidate_instantiations[0].rejection_kind,
            Some(UniverseDiagnosticKind::InvalidInstantiation)
        );
    }

    #[test]
    fn repair_generator_universe_diagnostic_hints_ignore_display_text() {
        let payload = UniverseDiagnostic {
            subset_kind: UnificationConflictSubsetKind::Minimal,
            core_kind: UniverseDiagnosticCoreKind::Reduced,
            constraints: vec![universe_diagnostic_constraint(
                0,
                Level::param("u"),
                Level::zero(),
            )],
            unresolved_metas: Vec::new(),
            candidate_instantiations: vec![UniverseInstantiationCandidate {
                param: "u".to_owned(),
                level: Level::zero(),
                source_path: vec!["AppFunction".to_owned(), "UniverseArg(0)".to_owned()],
                valid: true,
                rejection_kind: None,
            }],
            repair_operators: vec![UniverseRepairOperator::InstantiateUniverse],
            complete_graph: true,
            budget_report: DiagnosticBudget::default().report(DiagnosticBudgetUsage::default()),
        };
        let first = MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UniverseArgumentMismatch,
            "first display string",
        )
        .with_universe_diagnostic(payload.clone());
        let second = MachineTacticDiagnostic::new(
            MachineTacticDiagnosticKind::UniverseArgumentMismatch,
            "second display string",
        )
        .with_universe_diagnostic(payload);

        let first_universe =
            collect_universe_diagnostic(&first, universe_diagnostic_budget(4, 4, 4, 4)).unwrap();
        let second_universe =
            collect_universe_diagnostic(&second, universe_diagnostic_budget(4, 4, 4, 4)).unwrap();

        assert_eq!(
            first_universe.repair_operators,
            vec![UniverseRepairOperator::InstantiateUniverse]
        );
        assert_eq!(
            first_universe.candidate_instantiations,
            second_universe.candidate_instantiations
        );
        assert_eq!(
            first_universe.candidate_instantiations[0].source_path,
            vec!["AppFunction".to_owned(), "UniverseArg(0)".to_owned()]
        );
    }

