    fn rewrite_diagnostic_budget(
        nodes: u64,
        paths: u64,
        scans: u64,
        repairs: u64,
        steps: u64,
    ) -> DiagnosticBudget {
        DiagnosticBudget {
            max_graph_nodes: nodes,
            max_expression_paths: paths,
            max_rewrite_site_scans: scans,
            max_pretty_term_bytes: 0,
            max_repair_proposals: repairs,
            max_diagnostic_steps: steps,
        }
    }

    fn rewrite_diagnostic_site(
        id: u64,
        kind: RewriteDiagnosticKind,
        path: Vec<String>,
    ) -> RewriteDiagnosticSite {
        RewriteDiagnosticSite {
            id: RewriteDiagnosticId(id),
            kind,
            target_kind: RewriteDiagnosticTargetKind::Goal,
            local_name: None,
            path,
            direction: RewriteDirection::Forward,
            matched_side: RewriteSite::EqTargetLeft,
            replacement_side: RewriteSite::EqTargetRight,
            occurrence_index: Some(id),
            required_unfoldings: Vec::new(),
            congruence_depth: 0,
            expected_hash: Some(unification_diagnostic_hash(7)),
            actual_hash: Some(unification_diagnostic_hash(8)),
            repair_operators: default_rewrite_repair_operators(kind),
        }
    }

    fn rewrite_diagnostic_payload(sites: Vec<RewriteDiagnosticSite>) -> RewriteDiagnostic {
        RewriteDiagnostic {
            subset_kind: UnificationConflictSubsetKind::Reduced,
            sites,
            forward_valid: true,
            backward_valid: true,
            forward_matches_goal: true,
            backward_matches_goal: false,
            forward_matches_hypothesis: false,
            backward_matches_hypothesis: true,
            rejected_by_budget_or_progress: false,
            complete_scan: true,
            no_progress_reason: Some(RewriteNoProgressReason::NoRuleMatched),
            budget_report: DiagnosticBudget::default().report(DiagnosticBudgetUsage::default()),
        }
    }

    #[test]
    fn rewrite_diagnostic_categories_cover_required_design_cases() {
        let cases = [
            (
                MachineTacticDiagnosticKind::AmbiguousRewriteRule,
                Some("rw"),
                None,
                RewriteDiagnosticKind::NoMatch,
            ),
            (
                MachineTacticDiagnosticKind::UnknownSimpRule,
                Some("simp-lite"),
                None,
                RewriteDiagnosticKind::InvalidRule,
            ),
            (
                MachineTacticDiagnosticKind::InvalidMachineTactic,
                Some("rw"),
                Some(RewriteDiagnosticKind::AmbiguousOccurrence),
                RewriteDiagnosticKind::AmbiguousOccurrence,
            ),
            (
                MachineTacticDiagnosticKind::SimpNoProgress,
                Some("simp-lite"),
                None,
                RewriteDiagnosticKind::NoProgress,
            ),
            (
                MachineTacticDiagnosticKind::TacticFuelExhausted {
                    kind: TacticFuelKind::Rewrite,
                },
                Some("rw"),
                None,
                RewriteDiagnosticKind::BudgetRejected,
            ),
        ];

        for (diagnostic_kind, tactic_kind, override_kind, expected_kind) in cases {
            let mut diagnostic = MachineTacticDiagnostic::new(diagnostic_kind, "rewrite failure");
            diagnostic.tactic_kind = tactic_kind.map(str::to_owned);
            if let Some(override_kind) = override_kind {
                diagnostic = diagnostic.with_rewrite_diagnostic(rewrite_diagnostic_payload(vec![
                    rewrite_diagnostic_site(
                        0,
                        override_kind,
                        vec!["RewriteOccurrence(0)".to_owned()],
                    ),
                ]));
            }

            let rewrite =
                collect_rewrite_diagnostic(&diagnostic, rewrite_diagnostic_budget(4, 4, 4, 8, 4))
                    .expect("rewrite diagnostic should be collected");

            assert_eq!(rewrite.sites.len(), 1);
            assert_eq!(rewrite.sites[0].kind, expected_kind);
        }
    }

    #[test]
    fn rewrite_diagnostic_default_no_match_does_not_offer_reverse_without_policy() {
        let mut diagnostic =
            MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::AmbiguousRewriteRule, "rw");
        diagnostic.tactic_kind = Some("rw".to_owned());

        let rewrite =
            collect_rewrite_diagnostic(&diagnostic, rewrite_diagnostic_budget(4, 4, 4, 8, 4))
                .expect("rw no-match should carry rewrite diagnostics");

        assert_eq!(rewrite.sites[0].kind, RewriteDiagnosticKind::NoMatch);
        assert!(!rewrite.complete_scan);
        assert!(!rewrite.sites[0]
            .repair_operators
            .contains(&RewriteRepairOperator::ReverseRewrite));
        assert!(rewrite.sites[0]
            .repair_operators
            .contains(&RewriteRepairOperator::SelectRewriteOccurrence));
    }

    #[test]
    fn rewrite_diagnostic_orders_occurrence_paths_and_identifies_hypotheses() {
        let mut hypothesis_site = rewrite_diagnostic_site(
            1,
            RewriteDiagnosticKind::NoMatch,
            vec!["RewriteOccurrence(0)".to_owned()],
        );
        hypothesis_site.target_kind = RewriteDiagnosticTargetKind::LocalType;
        hypothesis_site.local_name = Some("h".to_owned());
        hypothesis_site.direction = RewriteDirection::Backward;
        hypothesis_site.matched_side = RewriteSite::EqTargetRight;
        hypothesis_site.replacement_side = RewriteSite::EqTargetLeft;
        let payload = rewrite_diagnostic_payload(vec![
            rewrite_diagnostic_site(
                2,
                RewriteDiagnosticKind::NoProgress,
                vec!["RewriteOccurrence(2)".to_owned()],
            ),
            hypothesis_site,
            rewrite_diagnostic_site(
                1,
                RewriteDiagnosticKind::AmbiguousOccurrence,
                vec!["RewriteOccurrence(1)".to_owned()],
            ),
        ]);
        let rewrite = reduce_rewrite_diagnostic(payload, rewrite_diagnostic_budget(8, 8, 8, 8, 8));

        assert_eq!(
            rewrite
                .sites
                .iter()
                .map(|site| (site.id.0, site.path.clone(), site.kind))
                .collect::<Vec<_>>(),
            vec![
                (
                    1,
                    vec!["RewriteOccurrence(0)".to_owned()],
                    RewriteDiagnosticKind::NoMatch
                ),
                (
                    1,
                    vec!["RewriteOccurrence(1)".to_owned()],
                    RewriteDiagnosticKind::AmbiguousOccurrence
                ),
                (
                    2,
                    vec!["RewriteOccurrence(2)".to_owned()],
                    RewriteDiagnosticKind::NoProgress
                ),
            ]
        );
        assert_eq!(
            rewrite.sites[0].target_kind,
            RewriteDiagnosticTargetKind::LocalType
        );
        assert_eq!(rewrite.sites[0].local_name.as_deref(), Some("h"));
        assert!(rewrite.backward_matches_hypothesis);
    }

