    #[test]
    fn rewrite_diagnostic_classifies_actual_simp_no_progress_failure() {
        let state = start_machine_proof(
            MachineProofSpec {
                theorem_type: eq_nat(nat_zero(), nat_succ(nat_zero())),
                ..trivial_spec()
            },
            Vec::new(),
            Vec::new(),
            MachineTacticOptions::default(),
        )
        .unwrap();
        let err = run_machine_tactic(
            &state,
            MachineTactic::SimpLite {
                goal_id: GoalId(0),
                rules: Vec::new(),
            },
        )
        .expect_err("simp-lite with no rules should report no progress");

        let rewrite = collect_rewrite_diagnostic(&err, rewrite_diagnostic_budget(4, 4, 4, 8, 4))
            .expect("simp no-progress should carry rewrite diagnostics");

        assert_eq!(rewrite.sites[0].kind, RewriteDiagnosticKind::NoProgress);
        assert_eq!(
            rewrite.no_progress_reason,
            Some(RewriteNoProgressReason::EqReflFailed)
        );
        assert!(rewrite.sites[0]
            .repair_operators
            .contains(&RewriteRepairOperator::ReduceSimpSet));
        assert!(rewrite.sites[0]
            .repair_operators
            .contains(&RewriteRepairOperator::Unfold));
    }

