    fn imported_constructor_head(import: &VerifiedImportRef, name: &str) -> TacticHead {
        TacticHead::Imported {
            name: Name::from_dotted(name),
            decl_interface_hash: export_interface_hash(import, name),
        }
    }

    fn verify_closed_theorem_with_import(
        state: &MachineProofState,
        import: &npa_cert::VerifiedModule,
    ) {
        let theorem = extract_closed_machine_theorem_decl(state).unwrap();
        let cert = npa_cert::build_module_cert(
            npa_cert::CoreModule {
                name: Name::from_dotted("Test"),
                declarations: vec![theorem],
            },
            std::slice::from_ref(import),
        )
        .expect("closed theorem should materialize with constructor import");
        let bytes = npa_cert::encode_module_cert(&cert).unwrap();
        let mut session = npa_cert::VerifierSession::new();
        session.register_verified_module(import.clone());
        npa_cert::verify_module_cert(&bytes, &mut session, &npa_cert::AxiomPolicy::normal())
            .expect("constructor-produced theorem should verify source-free");
    }

