    fn general_induction_payload(
        import: &VerifiedImportRef,
        major_local: &str,
        generalized_locals: &[&str],
        branch_names: &[&str],
        max_new_goals: u64,
    ) -> GeneralInductionPayload<MachineTermSource> {
        GeneralInductionPayload {
            major_local: major_local.to_owned(),
            recursor: imported_constructor_head(import, "Nat.rec"),
            motive: None,
            generalized_locals: generalized_locals
                .iter()
                .map(|name| (*name).to_owned())
                .collect(),
            branch_names: branch_names.iter().map(|name| (*name).to_owned()).collect(),
            max_new_goals,
        }
    }

