    #[test]
    fn local_context_hash_and_prefix_are_deterministic() {
        let context = vec![
            MachineLocalDecl::assumption("A", prop()),
            MachineLocalDecl::definition("x", Expr::bvar(0), Expr::bvar(0)),
        ];
        let extended = vec![
            MachineLocalDecl::assumption("A", prop()),
            MachineLocalDecl::definition("x", Expr::bvar(0), Expr::bvar(0)),
            MachineLocalDecl::assumption("y", Expr::bvar(1)),
        ];

        assert!(machine_local_context_is_prefix(&context, &extended));
        assert_eq!(
            machine_local_context_hash(&context),
            machine_local_context_hash(&context)
        );
        assert_ne!(
            machine_local_context_hash(&context),
            machine_local_context_hash(&extended)
        );
    }

    #[test]
    fn diagnostic_summary_basic_heads_and_binder_arity_are_structural() {
        let budget = DiagnosticSummaryBudget::default();
        let expected = Expr::apps(
            Expr::konst("Expected.Head", vec![Level::param("u")]),
            vec![Expr::bvar(0)],
        );
        let actual = Expr::konst("Actual.Head", Vec::new());

        let expected_summary = diagnostic_term_summary(&expected, budget);
        let actual_summary = diagnostic_term_summary(&actual, budget);

        assert_eq!(
            expected_summary.head_symbol.as_deref(),
            Some("Expected.Head")
        );
        assert_eq!(actual_summary.head_symbol.as_deref(), Some("Actual.Head"));
        assert_eq!(expected_summary.universe_summary.params, vec!["u"]);

        let binders = Expr::pi("x", prop(), Expr::pi("y", prop(), prop()));
        let binder_summary = diagnostic_term_summary(&binders, budget);
        assert_eq!(binder_summary.head_symbol.as_deref(), Some("Pi"));
        assert_eq!(binder_summary.binder_arity, 2);
    }

    #[test]
    fn diagnostic_summary_truncation_is_deterministic_and_visible() {
        let budget = DiagnosticSummaryBudget {
            max_term_nodes: 3,
            max_universe_params: 1,
            max_context_locals: 3,
            max_dependencies_per_local: 1,
        };
        let expr = Expr::apps(
            Expr::konst(
                "F",
                vec![Level::param("u"), Level::param("v"), Level::param("w")],
            ),
            vec![
                Expr::konst("A", Vec::new()),
                Expr::konst("B", Vec::new()),
                Expr::konst("C", Vec::new()),
            ],
        );

        let first = diagnostic_term_summary(&expr, budget);
        let second = diagnostic_term_summary(&expr, budget);
        assert_eq!(first, second);
        assert_eq!(first.node_count, 3);
        assert!(first.truncated);
        assert_eq!(first.universe_summary.params, vec!["u"]);
        assert!(first.universe_summary.truncated);

        let context = vec![
            MachineLocalDecl::assumption("A", prop()),
            MachineLocalDecl::assumption("B", prop()),
            MachineLocalDecl::assumption("z", Expr::app(Expr::bvar(1), Expr::bvar(0))),
        ];
        let context_first = diagnostic_local_context_summary(&context, budget);
        let context_second = diagnostic_local_context_summary(&context, budget);
        assert_eq!(context_first, context_second);
        assert!(context_first.truncated);
        assert_eq!(context_first.locals[2].dependency_ids, vec![0]);
        assert!(context_first.locals[2].dependencies_truncated);
    }

    #[test]
    fn diagnostic_summary_local_context_identity_ignores_display_names() {
        let context = vec![
            MachineLocalDecl::assumption("A", prop()),
            MachineLocalDecl::definition("x", Expr::bvar(0), Expr::bvar(0)),
            MachineLocalDecl::assumption("y", Expr::bvar(1)),
        ];
        let budget = DiagnosticSummaryBudget::default();
        let display_a = vec![
            Some("Alpha".to_owned()),
            Some("Readable x".to_owned()),
            Some("Readable y".to_owned()),
        ];
        let display_b = vec![
            Some("Renamed Alpha".to_owned()),
            Some("Renamed x".to_owned()),
            Some("Renamed y".to_owned()),
        ];

        let summary_a =
            diagnostic_local_context_summary_with_display_names(&context, &display_a, budget);
        let summary_b =
            diagnostic_local_context_summary_with_display_names(&context, &display_b, budget);
        let machine_only_summary = diagnostic_local_context_summary(&context, budget);

        assert_eq!(summary_a.identity_hash(), summary_b.identity_hash());
        assert_eq!(
            summary_a.identity_hash(),
            machine_only_summary.identity_hash()
        );
        assert_ne!(
            summary_a.locals[0].display_name,
            summary_b.locals[0].display_name
        );
        assert_eq!(summary_a.total_locals, 3);
        assert_eq!(
            summary_a
                .locals
                .iter()
                .map(|local| (
                    local.stable_id,
                    local.binder_index,
                    local.machine_name.as_str()
                ))
                .collect::<Vec<_>>(),
            vec![(0, 0, "A"), (1, 1, "x"), (2, 2, "y")]
        );
        assert_eq!(summary_a.locals[1].dependency_ids, vec![0]);
        assert_eq!(summary_a.locals[2].dependency_ids, vec![0]);
    }

