    struct TacticReplayFixture {
        name: &'static str,
        state: MachineProofState,
        goal_id: GoalId,
        candidate: MachineTacticCandidate,
        budget: TacticBudget,
    }

    #[derive(Clone, Debug, PartialEq, Eq)]
    struct ReplayDiagnosticKey {
        kind: MachineTacticDiagnosticKind,
        goal_id: Option<GoalId>,
        meta_id: Option<MetaVarId>,
        tactic_kind: Option<String>,
        expected_hash: Option<Box<Hash>>,
        actual_hash: Option<Box<Hash>>,
        primary_name: Option<Name>,
    }

    #[derive(Clone, Debug, PartialEq, Eq)]
    enum ReplayFixtureObservation {
        Success {
            candidate_hash: Hash,
            deterministic_budget_hash: Hash,
            input_state_fingerprint: Hash,
            proof_delta_hash: Hash,
            proof_expr_hash: Hash,
            added_goals: Vec<GoalId>,
            new_metas: Vec<MachineNewMetaDelta>,
            next_state_fingerprint: Hash,
            certificate_hash: Option<Hash>,
        },
        Error {
            candidate_hash: Option<Hash>,
            deterministic_budget_hash: Hash,
            input_state_fingerprint: Hash,
            diagnostic_hash: Hash,
            unchanged_state_fingerprint: Hash,
            unchanged_open_goals: Vec<GoalId>,
            unchanged_assignments: Vec<(MetaVarId, Option<Hash>)>,
            diagnostic: ReplayDiagnosticKey,
        },
    }

    impl ReplayFixtureObservation {
        fn diagnostic_kind(&self) -> Option<MachineTacticDiagnosticKind> {
            match self {
                Self::Error { diagnostic, .. } => Some(diagnostic.kind.clone()),
                Self::Success { .. } => None,
            }
        }

        fn failure_shape(&self) -> Option<(MachineTacticDiagnosticKind, Option<String>)> {
            match self {
                Self::Error { diagnostic, .. } => {
                    Some((diagnostic.kind.clone(), diagnostic.tactic_kind.clone()))
                }
                Self::Success { .. } => None,
            }
        }
    }

    fn encode_replay_optional_goal_id(out: &mut Vec<u8>, value: Option<GoalId>) {
        match value {
            Some(value) => {
                out.push(0x01);
                encode_goal_id_to(out, value);
            }
            None => out.push(0x00),
        }
    }

    fn encode_replay_optional_meta_id(out: &mut Vec<u8>, value: Option<MetaVarId>) {
        match value {
            Some(value) => {
                out.push(0x01);
                encode_meta_var_id_to(out, value);
            }
            None => out.push(0x00),
        }
    }

    fn encode_replay_optional_hash(out: &mut Vec<u8>, value: Option<&Hash>) {
        match value {
            Some(value) => {
                out.push(0x01);
                encode_hash_to(out, value);
            }
            None => out.push(0x00),
        }
    }

    fn encode_replay_optional_name(out: &mut Vec<u8>, value: Option<&Name>) {
        match value {
            Some(value) => {
                out.push(0x01);
                encode_name_to(out, value);
            }
            None => out.push(0x00),
        }
    }

    fn replay_diagnostic_key_hash(diagnostic: &ReplayDiagnosticKey) -> Hash {
        let mut out = Vec::new();
        encode_diagnostic_kind_to(&mut out, &diagnostic.kind);
        encode_replay_optional_goal_id(&mut out, diagnostic.goal_id);
        encode_replay_optional_meta_id(&mut out, diagnostic.meta_id);
        encode_optional_string_to(&mut out, diagnostic.tactic_kind.as_deref());
        encode_replay_optional_hash(&mut out, diagnostic.expected_hash.as_deref());
        encode_replay_optional_hash(&mut out, diagnostic.actual_hash.as_deref());
        encode_replay_optional_name(&mut out, diagnostic.primary_name.as_ref());
        hash_with_domain("npa.machine-tactic.replay-diagnostic.v1", &out)
    }

    fn replay_diagnostic_key(diagnostic: MachineTacticDiagnostic) -> ReplayDiagnosticKey {
        ReplayDiagnosticKey {
            kind: diagnostic.kind,
            goal_id: diagnostic.goal_id,
            meta_id: diagnostic.meta_id,
            tactic_kind: diagnostic.tactic_kind,
            expected_hash: diagnostic.expected_hash,
            actual_hash: diagnostic.actual_hash,
            primary_name: diagnostic.primary_name.map(|name| *name),
        }
    }

    fn replay_error_observation(
        candidate_hash: Option<Hash>,
        deterministic_budget_hash: Hash,
        input_state_fingerprint: Hash,
        state: &MachineProofState,
        diagnostic: MachineTacticDiagnostic,
    ) -> ReplayFixtureObservation {
        let diagnostic = replay_diagnostic_key(diagnostic);
        let diagnostic_hash = replay_diagnostic_key_hash(&diagnostic);
        ReplayFixtureObservation::Error {
            candidate_hash,
            deterministic_budget_hash,
            input_state_fingerprint,
            diagnostic_hash,
            unchanged_state_fingerprint: state.fingerprint,
            unchanged_open_goals: state.open_goals.clone(),
            unchanged_assignments: state_assignment_fingerprint(state),
            diagnostic,
        }
    }

    fn replay_fixture_observation(fixture: &TacticReplayFixture) -> ReplayFixtureObservation {
        let input_state_fingerprint = fixture.state.fingerprint;
        let deterministic_budget_hash = tactic_budget_hash(fixture.budget);
        let tactic =
            match validate_machine_tactic_candidate(fixture.goal_id, fixture.candidate.clone()) {
                Ok(tactic) => tactic,
                Err(diagnostic) => {
                    return replay_error_observation(
                        None,
                        deterministic_budget_hash,
                        input_state_fingerprint,
                        &fixture.state,
                        diagnostic,
                    );
                }
            };
        let candidate_hash = machine_tactic_hash(&tactic);
        let required_features = pua_m04_structural_features();
        if let Err(diagnostic) = validate_machine_tactic_for_state(
            &fixture.state,
            &tactic,
            MachineTacticValidationBudget::from(fixture.budget),
            MachineTacticProfileVersion::PuaM04V2,
            &required_features,
        ) {
            return replay_error_observation(
                Some(candidate_hash),
                deterministic_budget_hash,
                input_state_fingerprint,
                &fixture.state,
                diagnostic,
            );
        }

        match run_machine_tactic_transactional(&fixture.state, tactic, fixture.budget) {
            MachineTacticResult::Success { state, delta } => {
                let certificate_hash = if state.open_goals.is_empty() {
                    extract_closed_machine_certificate(&state)
                        .ok()
                        .map(|handoff| handoff.certificate.hashes.certificate_hash)
                } else {
                    None
                };
                ReplayFixtureObservation::Success {
                    candidate_hash,
                    deterministic_budget_hash,
                    input_state_fingerprint,
                    proof_delta_hash: delta.delta_hash,
                    proof_expr_hash: delta.proof_expr_hash,
                    added_goals: delta.added_goals,
                    new_metas: delta.new_metas,
                    next_state_fingerprint: state.fingerprint,
                    certificate_hash,
                }
            }
            MachineTacticResult::Error { diagnostic } => replay_error_observation(
                Some(candidate_hash),
                deterministic_budget_hash,
                input_state_fingerprint,
                &fixture.state,
                diagnostic,
            ),
        }
    }

    fn assert_replay_success_fixture(fixture: &TacticReplayFixture) {
        let first = replay_fixture_observation(fixture);
        let second = replay_fixture_observation(fixture);

        assert_eq!(first, second, "{} replay fields drifted", fixture.name);
        let ReplayFixtureObservation::Success {
            input_state_fingerprint,
            ..
        } = first
        else {
            panic!("{} should be a success fixture: {first:?}", fixture.name);
        };
        assert_eq!(input_state_fingerprint, fixture.state.fingerprint);
    }

    fn assert_replay_failure_fixture(fixture: &TacticReplayFixture) {
        let first = replay_fixture_observation(fixture);
        let second = replay_fixture_observation(fixture);

        assert_eq!(first, second, "{} failure replay drifted", fixture.name);
        let ReplayFixtureObservation::Error {
            input_state_fingerprint,
            diagnostic_hash,
            unchanged_state_fingerprint,
            unchanged_open_goals,
            unchanged_assignments,
            ..
        } = first
        else {
            panic!("{} should be a failure fixture: {first:?}", fixture.name);
        };
        assert_eq!(input_state_fingerprint, fixture.state.fingerprint);
        assert_ne!(diagnostic_hash, ZERO_HASH);
        assert_eq!(unchanged_state_fingerprint, fixture.state.fingerprint);
        assert_eq!(unchanged_open_goals, fixture.state.open_goals);
        assert_eq!(
            unchanged_assignments,
            state_assignment_fingerprint(&fixture.state)
        );
    }

    #[test]
    fn repair_chain_replay_diagnostic_identity_ignores_display_message() {
        let mut first =
            MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::SimpNoProgress, "first");
        first.goal_id = Some(GoalId(7));
        first.tactic_kind = Some("simp-lite".to_owned());
        first.expected_hash = Some(Box::new([1; 32]));
        first.actual_hash = Some(Box::new([2; 32]));

        let mut second =
            MachineTacticDiagnostic::new(MachineTacticDiagnosticKind::SimpNoProgress, "second");
        second.goal_id = first.goal_id;
        second.tactic_kind = first.tactic_kind.clone();
        second.expected_hash = first.expected_hash.clone();
        second.actual_hash = first.actual_hash.clone();

        let first_hash = replay_diagnostic_key_hash(&replay_diagnostic_key(first));
        let second_hash = replay_diagnostic_key_hash(&replay_diagnostic_key(second.clone()));
        assert_eq!(first_hash, second_hash);

        second.actual_hash = Some(Box::new([3; 32]));
        assert_ne!(
            first_hash,
            replay_diagnostic_key_hash(&replay_diagnostic_key(second))
        );
    }

