    #[test]
    fn pua_m04_replay_determinism_fixtures_cover_success_and_failure() {
        for fixture in pua_m04_success_replay_fixtures() {
            assert_replay_success_fixture(&fixture);
        }
        for fixture in pua_m04_failure_replay_fixtures() {
            assert_replay_failure_fixture(&fixture);
        }
    }

    #[test]
    fn pua_m04_replay_failure_classes_are_transactional() {
        let cases = [
            (
                TacticReplayFixture {
                    name: "validation",
                    state: start_trivial(),
                    goal_id: GoalId(0),
                    candidate: MachineTacticCandidate::Intro {
                        name: "bad-name".to_owned(),
                    },
                    budget: TacticBudget::default(),
                },
                MachineTacticDiagnosticKind::InvalidMachineTactic,
            ),
            (
                TacticReplayFixture {
                    name: "unsupported",
                    state: start_trivial(),
                    goal_id: GoalId(0),
                    candidate: MachineTacticCandidate::FiniteDecide,
                    budget: TacticBudget::default(),
                },
                MachineTacticDiagnosticKind::UnsupportedMachineTactic,
            ),
            (
                TacticReplayFixture {
                    name: "budget",
                    state: start_trivial(),
                    goal_id: GoalId(0),
                    candidate: MachineTacticCandidate::Refine(RefinePayload {
                        term: RawMachineTerm::new("Prop"),
                        max_holes: Some(2),
                    }),
                    budget: TacticBudget {
                        max_meta_allocations: 1,
                        ..TacticBudget::default()
                    },
                },
                MachineTacticDiagnosticKind::TacticFuelExhausted {
                    kind: TacticFuelKind::MetaAllocation,
                },
            ),
            (
                TacticReplayFixture {
                    name: "type-mismatch",
                    state: start_trivial(),
                    goal_id: GoalId(0),
                    candidate: MachineTacticCandidate::Exact {
                        term: RawMachineTerm::new("Type"),
                    },
                    budget: TacticBudget::default(),
                },
                MachineTacticDiagnosticKind::TypeMismatch,
            ),
        ];

        for (fixture, expected_kind) in cases {
            let observation = replay_fixture_observation(&fixture);
            assert_eq!(
                observation.diagnostic_kind(),
                Some(expected_kind),
                "{} failure class changed",
                fixture.name
            );
            assert_replay_failure_fixture(&fixture);
        }
    }

    #[test]
    fn pua_m04_replay_unresolved_meta_failure_is_deterministic() {
        let fixture = TacticReplayFixture {
            name: "unresolved-meta-refine",
            state: start_trivial(),
            goal_id: GoalId(0),
            candidate: MachineTacticCandidate::Refine(RefinePayload {
                term: RawMachineTerm::new("_"),
                max_holes: Some(1),
            }),
            budget: TacticBudget::default(),
        };
        let ReplayFixtureObservation::Success { .. } = replay_fixture_observation(&fixture) else {
            panic!("refine hole fixture should expand before extraction");
        };
        let tactic =
            validate_machine_tactic_candidate(fixture.goal_id, fixture.candidate.clone()).unwrap();
        let MachineTacticResult::Success { state, .. } =
            run_machine_tactic_transactional(&fixture.state, tactic, fixture.budget)
        else {
            panic!("refine hole should expand");
        };

        let first = extract_closed_machine_proof(&state).expect_err("open meta must block replay");
        let second =
            extract_closed_machine_proof(&state).expect_err("open meta replay must be stable");

        assert_eq!(replay_diagnostic_key(first), replay_diagnostic_key(second));
        assert_eq!(state.open_goals, vec![GoalId(1)]);
        assert_eq!(fixture.state.open_goals, vec![GoalId(0)]);
    }

    #[test]
    fn pua_m04_replay_minimization_fixtures_reproduce_core_errors() {
        let validation_full = TacticReplayFixture {
            name: "validation-full",
            state: start_prop_id_context(),
            goal_id: GoalId(0),
            candidate: MachineTacticCandidate::Intro {
                name: "bad-name".to_owned(),
            },
            budget: TacticBudget::default(),
        };
        let validation_min = TacticReplayFixture {
            name: "validation-min",
            state: start_trivial(),
            goal_id: GoalId(0),
            candidate: validation_full.candidate.clone(),
            budget: validation_full.budget,
        };
        let budget = TacticBudget {
            max_meta_allocations: 1,
            ..TacticBudget::default()
        };
        let budget_full = TacticReplayFixture {
            name: "budget-full",
            state: start_prop_id_context(),
            goal_id: GoalId(2),
            candidate: MachineTacticCandidate::Refine(RefinePayload {
                term: RawMachineTerm::new("Prop"),
                max_holes: Some(2),
            }),
            budget,
        };
        let budget_min = TacticReplayFixture {
            name: "budget-min",
            state: start_trivial(),
            goal_id: GoalId(0),
            candidate: budget_full.candidate.clone(),
            budget,
        };
        let type_full = TacticReplayFixture {
            name: "type-full",
            state: start_prop_id_context(),
            goal_id: GoalId(2),
            candidate: MachineTacticCandidate::Exact {
                term: RawMachineTerm::new("Type"),
            },
            budget: TacticBudget::default(),
        };
        let type_min = TacticReplayFixture {
            name: "type-min",
            state: start_trivial(),
            goal_id: GoalId(0),
            candidate: type_full.candidate.clone(),
            budget: type_full.budget,
        };

        for (full, minimized) in [
            (validation_full, validation_min),
            (budget_full, budget_min),
            (type_full, type_min),
        ] {
            let full_shape = replay_fixture_observation(&full)
                .failure_shape()
                .expect("full fixture should fail");
            let minimized_shape = replay_fixture_observation(&minimized)
                .failure_shape()
                .expect("minimized fixture should fail");

            assert_eq!(
                full_shape, minimized_shape,
                "{} should minimize to the same structured error",
                full.name
            );
        }
    }

    #[test]
    fn validation_feature_gate_covers_each_pua_m04_tactic_kind() {
        let state = start_trivial();
        let before = state.clone();

        for (expected_kind, candidate) in pua_m04_feature_gate_candidates() {
            let err = validate_machine_tactic_candidate_for_state(
                &state,
                GoalId(0),
                candidate,
                TacticBudget::default(),
                MachineTacticProfileVersion::PuaM04V2,
                &[],
            )
            .expect_err("PUA-M04 tactic should require its feature gate");

            assert_eq!(
                err.kind,
                MachineTacticDiagnosticKind::UnsupportedMachineTactic
            );
            assert_eq!(err.goal_id, Some(GoalId(0)));
            assert_eq!(err.tactic_kind.as_deref(), Some(expected_kind));
            assert_state_unchanged(&before, &state);
        }
    }

    #[test]
    fn solver_candidates_validate_feature_gate_budget_identity_and_fail_closed() {
        let state = start_trivial();
        let before = state.clone();
        let solver_cases = [
            (
                "finite-decide",
                MachineTacticCandidate::FiniteDecide,
                MachineTacticFeature::FiniteDecide,
            ),
            (
                "omega",
                MachineTacticCandidate::Omega,
                MachineTacticFeature::Omega,
            ),
            (
                "ring",
                MachineTacticCandidate::Ring,
                MachineTacticFeature::Ring,
            ),
            (
                "bitblast",
                MachineTacticCandidate::Bitblast,
                MachineTacticFeature::Bitblast,
            ),
        ];
        let over_budget = MachineTacticValidationBudget {
            max_term_nodes: 1_024,
            max_whnf_steps: 1_024,
            max_unification_steps: 1_024,
            max_new_goals: 0,
            max_rewrite_sites: 0,
            max_simp_steps: 0,
            max_solver_steps: 0,
            max_certificate_bytes: 1_024,
            max_meta_allocations: 0,
        };
        let mut payload_hashes = std::collections::BTreeSet::new();

        for (expected_kind, candidate, feature) in solver_cases {
            let tactic = validate_machine_tactic_candidate(GoalId(0), candidate.clone())
                .expect("solver candidate should parse to a typed machine tactic");
            let same_payload_other_goal =
                validate_machine_tactic_candidate(GoalId(9), candidate.clone())
                    .expect("solver candidate should validate for another goal");
            let tactic_hash = machine_tactic_hash(&tactic);
            assert_eq!(tactic_hash, machine_tactic_hash(&same_payload_other_goal));
            assert!(
                payload_hashes.insert(tactic_hash),
                "{expected_kind} should have a distinct typed candidate hash"
            );

            let missing_feature = validate_machine_tactic_candidate_for_state(
                &state,
                GoalId(0),
                candidate.clone(),
                TacticBudget::default(),
                MachineTacticProfileVersion::PuaM04V2,
                &[],
            )
            .expect_err("solver candidate should require its feature when disabled");
            assert_eq!(
                missing_feature.kind,
                MachineTacticDiagnosticKind::UnsupportedMachineTactic
            );
            assert_eq!(missing_feature.tactic_kind.as_deref(), Some(expected_kind));

            let validation = validate_machine_tactic_candidate_for_state(
                &state,
                GoalId(0),
                candidate,
                TacticBudget::default(),
                MachineTacticProfileVersion::PuaM04V2,
                &[feature],
            )
            .expect("enabled solver candidate should validate structurally");
            assert_eq!(machine_tactic_kind(&validation.tactic), Some(expected_kind));

            let budget_err = validate_machine_tactic_for_state(
                &state,
                &validation.tactic,
                over_budget,
                MachineTacticProfileVersion::PuaM04V2,
                &[feature],
            )
            .expect_err("solver candidates should reject over-budget validation");
            assert_eq!(
                budget_err.kind,
                MachineTacticDiagnosticKind::TacticFuelExhausted {
                    kind: TacticFuelKind::TacticStep,
                }
            );
            assert_eq!(budget_err.tactic_kind.as_deref(), Some(expected_kind));

            let execution_err =
                run_machine_tactic_with_budget(&state, validation.tactic, TacticBudget::default())
                    .expect_err("unsupported solver goal should fail closed");
            assert_eq!(execution_err.goal_id, Some(GoalId(0)));
            assert_eq!(execution_err.tactic_kind.as_deref(), Some(expected_kind));
            assert_state_unchanged(&before, &state);
        }

        let smt_validation = validate_machine_tactic_candidate_for_state(
            &state,
            GoalId(0),
            MachineTacticCandidate::Smt { lemmas: Vec::new() },
            TacticBudget::default(),
            MachineTacticProfileVersion::PuaM04V2,
            &[],
        )
        .expect("SMT candidate remains compatible with the existing feature profile");
        let smt_err =
            run_machine_tactic_with_budget(&state, smt_validation.tactic, TacticBudget::default())
                .expect_err("SMT without proof evidence should not close the goal");
        assert_eq!(smt_err.goal_id, Some(GoalId(0)));
        assert_eq!(smt_err.tactic_kind.as_deref(), Some("smt"));
        assert_state_unchanged(&before, &state);
    }

