    #[test]
    fn tactic_budget_v1_mapping_exposes_pua_m04_validation_fields() {
        let budget = TacticBudget {
            max_tactic_steps: 1,
            max_whnf_steps: 2,
            max_conversion_steps: 3,
            max_rewrite_steps: 4,
            max_meta_allocations: 5,
            max_expr_nodes: 6,
        };

        let validation_budget = MachineTacticValidationBudget::from_v1_budget(budget);

        assert_eq!(validation_budget.max_term_nodes, 6);
        assert_eq!(validation_budget.max_whnf_steps, 2);
        assert_eq!(validation_budget.max_unification_steps, 3);
        assert_eq!(validation_budget.max_new_goals, 5);
        assert_eq!(validation_budget.max_rewrite_sites, 4);
        assert_eq!(validation_budget.max_simp_steps, 4);
        assert_eq!(validation_budget.max_solver_steps, 6);
        assert_eq!(validation_budget.max_certificate_bytes, 6);
        assert_eq!(validation_budget.max_meta_allocations, 5);
    }

    #[test]
    fn core_hashes_ignore_display_binder_names() {
        let pi_x = Expr::pi("x", type0(), Expr::bvar(0));
        let pi_y = Expr::pi("y", type0(), Expr::bvar(0));
        assert_eq!(core_expr_hash(&pi_x), core_expr_hash(&pi_y));

        let decl_x = Decl::Theorem {
            name: "Test.A".to_owned(),
            universe_params: Vec::new(),
            ty: Expr::pi("x", type0(), type0()),
            proof: Expr::lam("x", type0(), Expr::bvar(0)),
        };
        let decl_y = Decl::Theorem {
            name: "Test.A".to_owned(),
            universe_params: Vec::new(),
            ty: Expr::pi("y", type0(), type0()),
            proof: Expr::lam("y", type0(), Expr::bvar(0)),
        };
        let checked_x = check_current_decl_for_machine_tactic_from_verified_imports(
            &[],
            &[],
            0,
            decl_x.clone(),
        )
        .unwrap();
        let checked_y =
            check_current_decl_for_machine_tactic_from_verified_imports(&[], &[], 0, decl_y)
                .unwrap();
        let cert_x = npa_cert::build_module_cert(
            CoreModule {
                name: Name::from_dotted("Test"),
                declarations: vec![decl_x],
            },
            &[],
        )
        .unwrap();

        assert_eq!(checked_x.core_decl_hash(), checked_y.core_decl_hash());
        assert_eq!(
            checked_x.core_decl_hash(),
            cert_x.declarations[0].hashes.decl_certificate_hash
        );
    }

    #[test]
    fn core_expr_hash_uses_kernel_core_machine_api_domain() {
        let mut payload = vec![0x00];
        payload.extend(kernel_core_level_hash(&Level::zero()));
        let mut hasher = Sha256::new();
        hasher.update(b"NPA-KERNEL-CORE-EXPR-0.1");
        hasher.update(&payload);
        let expected: Hash = hasher.finalize().into();

        assert_eq!(core_expr_hash(&prop()), expected);
        assert_ne!(core_expr_hash(&prop()), npa_cert::core_expr_hash(&prop()));
    }

    #[test]
    fn kernel_profile_hash_commits_to_semantic_profile_fields() {
        let old_profile_hash = hash_with_domain(
            "npa.machine-tactic.kernel-check-profile.v1",
            b"npa-kernel:core-spec-v0.1",
        );

        assert_ne!(
            kernel_check_profile_hash(MachineKernelProfile::BuiltinNatEqRec),
            old_profile_hash
        );
        assert_ne!(
            kernel_check_profile_hash(MachineKernelProfile::BuiltinNone),
            kernel_check_profile_hash(MachineKernelProfile::BuiltinNatEqRec)
        );
        assert_eq!(
            kernel_check_profile_hash(MachineKernelProfile::BuiltinNatEqRec),
            kernel_check_profile_hash(MachineKernelProfile::BuiltinNatEqRec)
        );
    }

