    #[test]
    fn cases_on_dependent_family_adds_structured_index_equations() {
        let (verified, state) = run_cases_on_tag_goal();

        let (state, delta) = run_machine_tactic(
            &state,
            MachineTactic::Cases {
                goal_id: GoalId(2),
                payload: cases_payload("x", &["zero_case", "succ_case"], Some(2)),
            },
        )
        .expect("indexed cases should create branch goals with equality locals");

        assert_eq!(state.open_goals, vec![GoalId(3), GoalId(4)]);
        assert_eq!(delta.added_goals, vec![GoalId(3), GoalId(4)]);
        let family = state.env.eq_family.as_ref().unwrap();
        for goal_id in [GoalId(3), GoalId(4)] {
            let branch = state.goal(goal_id).unwrap();
            assert_eq!(branch.target, case_r());
            assert!(
                branch
                    .context
                    .iter()
                    .any(|local| parse_eq_target_from_expr(family, &local.ty).is_some()),
                "branch {goal_id:?} should contain a checked Eq local"
            );
        }

        let (state, _) = assign_goal(
            &state,
            GoalId(3),
            ProofExpr::Core(Expr::konst("Case.r", Vec::new())),
            Vec::new(),
        )
        .unwrap();
        let (closed, _) = assign_goal(
            &state,
            GoalId(4),
            ProofExpr::Core(Expr::konst("Case.r", Vec::new())),
            Vec::new(),
        )
        .unwrap();
        assert!(closed.open_goals.is_empty());
        verify_closed_theorem_with_import(&closed, &verified);
    }

