    fn cases_rejects_unknown_non_inductive_and_unchecked_recursors() {
        let (_, state) = run_cases_on_color_goal();
        let unknown = run_machine_tactic(
            &state,
            MachineTactic::Cases {
                goal_id: GoalId(1),
                payload: cases_payload("missing", &["a", "b"], Some(2)),
            },
        )
        .expect_err("unknown major local must fail");
        assert_eq!(unknown.kind, MachineTacticDiagnosticKind::UnknownLocalName);

        let (verified, state) = start_cases_imported_goal(Expr::pi("p", case_r(), case_r()));
        let state = intro_state(&state, GoalId(0), "p");
        let non_inductive = run_machine_tactic(
            &state,
            MachineTactic::Cases {
                goal_id: GoalId(1),
                payload: cases_payload("p", &[], Some(0)),
            },
        )
        .expect_err("non-inductive major local type must fail");
        assert_eq!(
            non_inductive.kind,
            MachineTacticDiagnosticKind::TypeMismatch
        );
        drop(verified);

        let state = start_machine_proof(
            MachineProofSpec {
                theorem_type: Expr::pi("n", nat(), prop()),
                ..trivial_spec()
            },
            Vec::new(),
            Vec::new(),
            MachineTacticOptions::default(),
        )
        .unwrap();
        let state = intro_state(&state, GoalId(0), "n");
        let unchecked = run_machine_tactic(
            &state,
            MachineTactic::Cases {
                goal_id: GoalId(1),
                payload: cases_payload("n", &["zero_case", "succ_case"], Some(2)),
            },
        )
        .expect_err("builtin Nat.rec is not a checked import/current recursor");
        assert_eq!(
            unchecked.kind,
            MachineTacticDiagnosticKind::TacticPrimitiveUnavailable,
            "{}",
            unchecked.message
        );
    }

