    fn constructor_auto_creates_child_goals_for_unresolved_arguments() {
        let (verified, _, state) = start_constructor_goal(ctor_and(ctor_p(), ctor_q()));

        let (state, delta) = run_machine_tactic(
            &state,
            MachineTactic::Constructor {
                goal_id: GoalId(0),
                payload: ConstructorPayload {
                    selection: ConstructorSelection::Auto,
                    max_new_goals: Some(2),
                },
            },
        )
        .expect("constructor should infer parameters and create premise goals");

        assert_eq!(state.open_goals, vec![GoalId(1), GoalId(2)]);
        assert_eq!(delta.added_goals, vec![GoalId(1), GoalId(2)]);
        assert_eq!(state.goal(GoalId(1)).unwrap().target, ctor_p());
        assert_eq!(state.goal(GoalId(2)).unwrap().target, ctor_q());

        let (state, _) = assign_goal(
            &state,
            GoalId(1),
            ProofExpr::Core(Expr::konst("Ctor.p", Vec::new())),
            Vec::new(),
        )
        .expect("imported proof of left premise should close first child");
        let (closed, _) = assign_goal(
            &state,
            GoalId(2),
            ProofExpr::Core(Expr::konst("Ctor.q", Vec::new())),
            Vec::new(),
        )
        .expect("imported proof of right premise should close second child");

        assert!(closed.open_goals.is_empty());
        extract_closed_machine_proof(&closed).expect("closed constructor proof should extract");
        verify_closed_theorem_with_import(&closed, &verified);
    }

    #[test]
    fn constructor_rejects_non_inductive_target_and_family_mismatch() {
        let state = start_trivial();
        let non_inductive = run_machine_tactic(
            &state,
            MachineTactic::Constructor {
                goal_id: GoalId(0),
                payload: ConstructorPayload {
                    selection: ConstructorSelection::Auto,
                    max_new_goals: Some(0),
                },
            },
        )
        .expect_err("constructor on non-inductive target must fail");
        assert_eq!(
            non_inductive.kind,
            MachineTacticDiagnosticKind::TypeMismatch
        );

        let (_, import, state) = start_constructor_goal(ctor_true());
        let mismatch = run_machine_tactic(
            &state,
            MachineTactic::Constructor {
                goal_id: GoalId(0),
                payload: ConstructorPayload {
                    selection: ConstructorSelection::Explicit {
                        constructor: imported_constructor_head(&import, "Ctor.And.intro"),
                    },
                    max_new_goals: Some(2),
                },
            },
        )
        .expect_err("explicit constructor from another family must fail");
        assert_eq!(mismatch.kind, MachineTacticDiagnosticKind::TypeMismatch);
        assert_eq!(
            mismatch.primary_name.as_deref(),
            Some(&Name::from_dotted("Ctor.And.intro"))
        );
    }

    #[test]
    fn constructor_auto_ambiguity_is_deterministic() {
        let (_, _, state) = start_constructor_goal(ctor_ambig());
        let tactic = MachineTactic::Constructor {
            goal_id: GoalId(0),
            payload: ConstructorPayload {
                selection: ConstructorSelection::Auto,
                max_new_goals: Some(0),
            },
        };

        let first = run_machine_tactic(&state, tactic.clone())
            .expect_err("two nullary constructors should be ambiguous");
        let second = run_machine_tactic(&state, tactic)
            .expect_err("ambiguous constructor diagnostic should replay deterministically");

        assert_eq!(first.kind, MachineTacticDiagnosticKind::AmbiguousTacticHead);
        assert_eq!(first.message, second.message);
        assert!(first.message.contains("Ctor.Ambig.left"));
        assert!(first.message.contains("Ctor.Ambig.right"));
        assert_eq!(state.open_goals, vec![GoalId(0)]);
    }

    #[test]
    fn constructor_budget_failure_is_transactional() {
        let (_, _, state) = start_constructor_goal(ctor_and(ctor_p(), ctor_q()));
        let before = state.clone();

        let missing_bound = run_machine_tactic(
            &state,
            MachineTactic::Constructor {
                goal_id: GoalId(0),
                payload: ConstructorPayload {
                    selection: ConstructorSelection::Auto,
                    max_new_goals: None,
                },
            },
        )
        .expect_err("omitted constructor goal bound declares zero child goals");
        assert_eq!(
            missing_bound.kind,
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::MetaAllocation
            }
        );
        assert_eq!(state.fingerprint, before.fingerprint);

        let err = run_machine_tactic_with_budget(
            &state,
            MachineTactic::Constructor {
                goal_id: GoalId(0),
                payload: ConstructorPayload {
                    selection: ConstructorSelection::Auto,
                    max_new_goals: Some(2),
                },
            },
            TacticBudget {
                max_meta_allocations: 1,
                ..TacticBudget::default()
            },
        )
        .expect_err("two child goals should exceed one meta allocation");

        assert_eq!(
            err.kind,
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::MetaAllocation
            }
        );
        assert_eq!(state.fingerprint, before.fingerprint);
        assert_eq!(state.open_goals, before.open_goals);
        assert_eq!(state.metas, before.metas);
    }

    #[test]
