    #[test]
    fn subst_rewrites_local_eq_type_and_rejects_dependent_suffix() {
        let theorem_type = Expr::pi(
            "a",
            nat(),
            Expr::pi(
                "b",
                nat(),
                Expr::pi(
                    "h",
                    eq_nat(Expr::bvar(1), Expr::bvar(0)),
                    Expr::pi("g", eq_nat(Expr::bvar(1), Expr::bvar(1)), prop_id_type()),
                ),
            ),
        );
        let state = start_machine_proof(
            MachineProofSpec {
                theorem_type,
                ..trivial_spec()
            },
            Vec::new(),
            Vec::new(),
            MachineTacticOptions::default(),
        )
        .unwrap();
        let state = intro_state(&state, GoalId(0), "a");
        let state = intro_state(&state, GoalId(1), "b");
        let state = intro_state(&state, GoalId(2), "h");
        let state = intro_state(&state, GoalId(3), "g");

        let (state, delta) = run_machine_tactic(
            &state,
            MachineTactic::Subst {
                goal_id: GoalId(4),
                payload: SubstPayload {
                    equality_local: "h".to_owned(),
                    target: TacticTarget::Local {
                        name: "g".to_owned(),
                    },
                    direction: RewriteDirection::Backward,
                    occurrences: vec![OccurrencePath { indices: vec![0] }],
                },
            },
        )
        .expect("subst should transport the local equality proof before rebinding");

        assert_eq!(delta.added_goals, vec![GoalId(5)]);
        assert_eq!(state.open_goals, vec![GoalId(5)]);
        assert_eq!(state.goal(GoalId(5)).unwrap().context.len(), 3);
        let expected = Expr::pi("g", eq_nat(Expr::bvar(2), Expr::bvar(1)), prop_id_type());
        assert_eq!(state.goal(GoalId(5)).unwrap().target, expected);

        let state = intro_state(&state, GoalId(5), "g2");
        let state = intro_state(&state, GoalId(6), "p");
        let state = intro_state(&state, GoalId(7), "hp");
        let (closed, _) = run_machine_tactic(
            &state,
            MachineTactic::Exact {
                goal_id: GoalId(8),
                term: checked_term("hp"),
            },
        )
        .expect("rebuilt suffix goal should be solvable normally");
        assert!(closed.open_goals.is_empty());
        extract_closed_machine_proof(&closed).expect("local subst proof should extract");

        let dependent_type = Expr::pi(
            "a",
            nat(),
            Expr::pi(
                "b",
                nat(),
                Expr::pi(
                    "h",
                    eq_nat(Expr::bvar(1), Expr::bvar(0)),
                    Expr::pi(
                        "g",
                        eq_nat(Expr::bvar(1), Expr::bvar(1)),
                        Expr::pi(
                            "k",
                            npa_kernel::eq(
                                Level::zero(),
                                eq_nat(Expr::bvar(2), Expr::bvar(2)),
                                Expr::bvar(0),
                                Expr::bvar(0),
                            ),
                            prop(),
                        ),
                    ),
                ),
            ),
        );
        let dependent = start_machine_proof(
            MachineProofSpec {
                theorem_type: dependent_type,
                ..trivial_spec()
            },
            Vec::new(),
            Vec::new(),
            MachineTacticOptions::default(),
        )
        .unwrap();
        let dependent = intro_state(&dependent, GoalId(0), "a");
        let dependent = intro_state(&dependent, GoalId(1), "b");
        let dependent = intro_state(&dependent, GoalId(2), "h");
        let dependent = intro_state(&dependent, GoalId(3), "g");
        let dependent = intro_state(&dependent, GoalId(4), "k");
        let err = run_machine_tactic(
            &dependent,
            MachineTactic::Subst {
                goal_id: GoalId(5),
                payload: SubstPayload {
                    equality_local: "h".to_owned(),
                    target: TacticTarget::Local {
                        name: "g".to_owned(),
                    },
                    direction: RewriteDirection::Backward,
                    occurrences: vec![OccurrencePath { indices: vec![0] }],
                },
            },
        )
        .expect_err("subst must reject unsupported dependent context transport");
        assert_eq!(err.kind, MachineTacticDiagnosticKind::InvalidMetaDependency);
    }

    #[test]
    fn congr_decomposes_application_equality_into_argument_goal() {
        let state = start_machine_proof(
            MachineProofSpec {
                theorem_type: Expr::pi(
                    "a",
                    nat(),
                    Expr::pi(
                        "b",
                        nat(),
                        Expr::pi(
                            "h",
                            eq_nat(Expr::bvar(1), Expr::bvar(0)),
                            eq_nat(nat_succ(Expr::bvar(2)), nat_succ(Expr::bvar(1))),
                        ),
                    ),
                ),
                ..trivial_spec()
            },
            Vec::new(),
            Vec::new(),
            MachineTacticOptions::default(),
        )
        .unwrap();
        let state = intro_state(&state, GoalId(0), "a");
        let state = intro_state(&state, GoalId(1), "b");
        let state = intro_state(&state, GoalId(2), "h");
        let before = state.clone();

        let tactic = MachineTactic::Congr {
            goal_id: GoalId(3),
            payload: CongrPayload {
                target: TacticTarget::Goal,
                max_depth: Some(1),
                max_new_goals: Some(1),
            },
        };
        let (state, delta) =
            run_machine_tactic(&before, tactic.clone()).expect("congr should create one child");
        let (_, replay_delta) =
            run_machine_tactic(&before, tactic.clone()).expect("congr replay should match");

        assert_eq!(delta.added_goals, vec![GoalId(4)]);
        assert_eq!(delta.proof_expr_hash, replay_delta.proof_expr_hash);
        assert_eq!(delta.delta_hash, replay_delta.delta_hash);
        assert_eq!(
            state.goal(GoalId(4)).unwrap().target,
            eq_nat(Expr::bvar(2), Expr::bvar(1))
        );
        let (closed, _) = run_machine_tactic(
            &state,
            MachineTactic::Exact {
                goal_id: GoalId(4),
                term: checked_term("h"),
            },
        )
        .expect("congr child should be the original equality proof");
        assert!(closed.open_goals.is_empty());
        extract_closed_machine_proof(&closed).expect("congr proof should extract");
    }

