    #[test]
    fn refine_hole_creates_typed_child_goal_and_replays_order() {
        let state = start_machine_proof(
            MachineProofSpec {
                theorem_type: prop_id_type(),
                ..trivial_spec()
            },
            Vec::new(),
            Vec::new(),
            MachineTacticOptions::default(),
        )
        .unwrap();
        let state = intro_state(&state, GoalId(0), "p");
        let state = intro_state(&state, GoalId(1), "hp");

        let tactic = MachineTactic::Refine {
            goal_id: GoalId(2),
            payload: RefinePayload {
                term: checked_refine_term("_"),
                max_holes: Some(1),
            },
        };
        let (refined, delta) =
            run_machine_tactic(&state, tactic.clone()).expect("refine hole should create a goal");
        let (_, replay_delta) =
            run_machine_tactic(&state, tactic).expect("refine replay should be deterministic");

        assert_eq!(delta.added_goals, vec![GoalId(3)]);
        assert_eq!(delta.delta_hash, replay_delta.delta_hash);
        assert_eq!(refined.open_goals, vec![GoalId(3)]);
        assert_eq!(
            refined.metas.get(MetaVarId(2)).unwrap().assignment,
            Some(ProofExpr::Meta(MetaVarId(3)))
        );
        let child = refined.goal(GoalId(3)).unwrap();
        assert_eq!(child.context, state.goal(GoalId(2)).unwrap().context);
        assert_eq!(child.target, state.goal(GoalId(2)).unwrap().target);

        let proof_err = extract_closed_machine_proof(&refined)
            .expect_err("unresolved refine hole cannot extract");
        assert_eq!(proof_err.kind, MachineTacticDiagnosticKind::UnresolvedGoal);
        let cert_err = extract_closed_machine_certificate(&refined)
            .expect_err("unresolved refine hole cannot produce a certificate");
        assert_eq!(cert_err.kind, MachineTacticDiagnosticKind::UnresolvedGoal);

        let (closed, _) = run_machine_tactic(
            &refined,
            MachineTactic::Exact {
                goal_id: GoalId(3),
                term: checked_term("hp"),
            },
        )
        .expect("solving refine hole should close the proof");
        assert!(closed.open_goals.is_empty());
        assert_eq!(
            extract_closed_machine_proof(&closed).unwrap(),
            prop_id_proof()
        );
        extract_closed_machine_certificate(&closed)
            .expect("solved refine hole should pass certificate handoff");
    }

    #[test]
    fn refine_application_hole_uses_solved_child_proof() {
        let state = start_machine_proof(
            MachineProofSpec {
                theorem_type: prop_apply_type(),
                ..trivial_spec()
            },
            Vec::new(),
            Vec::new(),
            MachineTacticOptions::default(),
        )
        .unwrap();
        let state = intro_state(&state, GoalId(0), "p");
        let state = intro_state(&state, GoalId(1), "f");
        let state = intro_state(&state, GoalId(2), "hp");

        let (refined, delta) = run_machine_tactic(
            &state,
            MachineTactic::Refine {
                goal_id: GoalId(3),
                payload: RefinePayload {
                    term: checked_refine_term("f _"),
                    max_holes: Some(1),
                },
            },
        )
        .expect("refine application should type the argument hole");

        assert_eq!(delta.added_goals, vec![GoalId(4)]);
        assert_eq!(refined.open_goals, vec![GoalId(4)]);
        assert_eq!(
            refined.goal(GoalId(4)).unwrap().target,
            state.goal(GoalId(3)).unwrap().target
        );

        let (closed, _) = run_machine_tactic(
            &refined,
            MachineTactic::Exact {
                goal_id: GoalId(4),
                term: checked_term("hp"),
            },
        )
        .expect("hole should be solvable by the local proof");

        assert!(closed.open_goals.is_empty());
        extract_closed_machine_proof(&closed)
            .expect("final extracted proof should use the solved child proof");
    }

