    #[test]
    fn unfold_goal_occurrence_respects_delta_budget_and_replays() {
        let alias = checked_current_def("Test.PropAlias", type0(), prop(), Reducibility::Reducible);
        let head = TacticHead::CurrentModule {
            name: Name::from_dotted("Test.PropAlias"),
            decl_interface_hash: alias.signature().decl_interface_hash(),
        };
        let state = start_machine_proof(
            MachineProofSpec {
                source_index: 1,
                theorem_type: Expr::pi("x", Expr::konst("Test.PropAlias", Vec::new()), prop()),
                ..trivial_spec()
            },
            Vec::new(),
            vec![alias],
            MachineTacticOptions::default(),
        )
        .unwrap();
        let tactic = MachineTactic::Unfold {
            goal_id: GoalId(0),
            payload: UnfoldPayload {
                target: TacticTarget::Goal,
                constant: head.clone(),
                occurrences: vec![OccurrencePath { indices: vec![0] }],
                max_delta_steps: Some(1),
            },
        };

        let (unfolded, delta) =
            run_machine_tactic(&state, tactic.clone()).expect("reducible def should unfold");
        let (_, replay_delta) =
            run_machine_tactic(&state, tactic).expect("unfold replay should match");

        assert_eq!(delta.added_goals, vec![GoalId(1)]);
        assert_eq!(delta.delta_hash, replay_delta.delta_hash);
        assert_eq!(
            unfolded.goal(GoalId(1)).unwrap().target,
            Expr::pi("x", prop(), prop())
        );

        let err = run_machine_tactic(
            &state,
            MachineTactic::Unfold {
                goal_id: GoalId(0),
                payload: UnfoldPayload {
                    target: TacticTarget::Goal,
                    constant: head,
                    occurrences: vec![OccurrencePath { indices: vec![0] }],
                    max_delta_steps: Some(0),
                },
            },
        )
        .expect_err("unfold must reject insufficient explicit delta steps");

        assert_eq!(
            err.kind,
            MachineTacticDiagnosticKind::TacticFuelExhausted {
                kind: TacticFuelKind::Rewrite
            }
        );
    }

